# ============================================================
# FOCUS Strategy Manager
# ------------------------------------------------------------
# Independent manager (NOT a StrategyPlugin) that implements
# concentrated trading using GreenPen analysis on Bybit Futures.
#
# 6-State Machine (v2 — ADX/Conviction refactor 2026-04-07):
#   DORMANT → ALERT → HUNT → POSITIONED → CAUTION → COOLDOWN
#
# Key changes from v1:
#   - ADX filter: no entry when ADX < 20 (sideways = no trade)
#   - Conviction score (0-10) determines budget allocation
#   - DCA (SCOUT/REINFORCED/ALLIN) cycle removed entirely
#   - Same-direction re-entry blocked until market cycles
#   - Anti-Martingale and Time Volatility adjustments removed
#
# Features:
#   - Long + Short (linear perpetual)
#   - Isolated margin, configurable leverage
#   - GreenPen PA patterns + Market Structure + Zone + Cycle TP
#   - 3M discipline (max daily plans, max SL count)
#   - Budget physically isolated from other strategies
#   - Dynamic Trailing SL (preserved from v1)
# ============================================================
from __future__ import annotations

import json
import logging
import os
import threading
import time
from collections import deque
from dataclasses import asdict, dataclass, field
from enum import Enum
from typing import Any, Dict, List, Optional, Tuple

logger = logging.getLogger(__name__)

# ── State Machine ───────────────────────────────────────────

class FocusState(str, Enum):
    DORMANT = "DORMANT"       # ADX<15, no trend, check every 4 hours
    ALERT = "ALERT"           # sign of sideways ending, check every 30 min
    HUNT = "HUNT"             # ADX>20, trend confirmed, scan every 5 min
    POSITIONED = "POSITIONED" # holding a position (DT handles trailing)
    CAUTION = "CAUTION"       # holding + sign of sideways starting
    COOLDOWN = "COOLDOWN"     # cooldown after exit

# ── Legacy State Migration Map (compat with existing JSON files) ───────
_STATE_MIGRATION = {
    "IDLE": "DORMANT",
    "SELECTING": "HUNT",
    "ZONE_WAIT": "ALERT",
    "WATCHING": "HUNT",
    "TRAILING": "POSITIONED",
}


@dataclass
class FocusPosition:
    market: str = ""
    direction: str = ""          # "LONG" or "SHORT"
    entry_price: float = 0.0
    qty: float = 0.0
    leverage: int = 1
    tp1: float = 0.0
    tp2: float = 0.0
    sl: float = 0.0
    atr_used: float = 0.0
    partial_done: bool = False   # TP1 partial exit completed
    trailing_high: float = 0.0  # for LONG trailing
    trailing_low: float = 0.0   # for SHORT trailing
    entry_ts: float = 0.0
    # ★ H9 FIX: close-failure retry count (persisted)
    close_retry_count: int = 0
    # ── Conviction (v2) ──
    conviction_score: float = 0.0     # [2026-05-17 100-pt system] 0~100 conviction score (old 0~10 → converted to 100-pt. legacy_to_100pt compat logic)
    entry_source: str = "primary"   # "primary" or "scanner"
    # ── Dynamic Trailing SL fields ──
    peak_profit_price: float = 0.0    # best profit price (LONG: highest, SHORT: lowest)
    breakeven_locked: bool = False    # SL has been moved to breakeven
    original_sl: float = 0.0         # initial SL (original before dynamic move)
    original_tp1: float = 0.0        # initial TP1 (original before Decay)
    # ── SL Dodge (whale strategy: retreat when SL is near) ──
    sl_dodge_count: int = 0           # retreat count (max 3)
    # ── Morning Shield ──
    morning_shield_date: str = ""     # "YYYY-MM-DD" KST — once-per-day limit
    # ── Event Shield (economic event shield, 2026-06-08) ──
    event_shield_done: str = ""       # applied event label ("YYYY-MM-DD HH:MM") — once-per-event limit
    # ── BE Stall Exit (2026-04-19, user intuition) ──
    # Observation: if no new peak is made within N min after BE lock, 5-min-candle
    # watchers start sitting out → giving back. Defends the median 40% give-back.
    be_locked_ts: float = 0.0          # time BE lock fired
    last_peak_update_ts: float = 0.0   # time peak was updated (now() on each peak_profit_price update)
    # ── ★ [2026-05-21 Phase 6 Stage 8 re-redesign] score-recovery auto-exit baseline ──
    # Owner's real rule (5-21):
    #   "Exit only in profit; even if it can't reach BE, if the candle flow... i.e. the score
    #    shows signs of recovering, get out."
    # Condition: pnl > min_pnl_pct (in profit) + conv recovery (baseline + N increase) → small exit.
    # Existing guards (BE/SL/multi_be_lock) still work. No trigger while in loss (be patient).
    entry_baseline_conv: float = 0.0           # conv at entry (computed by Scanner, for recovery tracking)
    entry_baseline_trend: str = ""             # GreenPen trend label at entry (auxiliary info)
    # ── ★ Conviction Override Slot marker (2026-05-10 owner decision) ──
    is_override: bool = False          # if True, apply separate rules (small size / near SL / -10% Hard ROE cut)
    # ── ★ Entry Expectation (2026-05-14 owner — entry-expectation mechanism) ──
    reward_target: float = 0.0         # H4-structure-based target price (0 = not computed)
    risk_invalidation: float = 0.0     # H4-swing-based invalidation price (0 = not computed)
    rr_ratio: float = 0.0              # reward / risk
    expectation_source: str = ""       # computation source (e.g. "primary_zone/primary_swing")
    # ── ★ [2026-05-28 owner] marker for positions entered via guard_score 100-pt system ──
    # If True, bypass all the old EXIT guards (fast_reject/reverse_drift/pre_be_stall/long_hold_timeout/
    # trend_reversal/quick_tp/bb_macd_sw/thesis_invalidation etc.).
    # The new system manages exits only via SL/TP/BE and the new 5M emergency exit.
    guard_score_entry: bool = False
    # ── [2026-05-29 owner] Slot Auto Expand — marker for temporary +1 slot entry on strong signal ──
    # Old simple time-based version (rolled back) → strong-signal + tied-up + limited + capital-protection redesign.
    # If True: size shrunk (slot_auto_expand_size_ratio), holds a temporary slot until exit.
    is_slot_expand: bool = False


@dataclass
class FocusConfig:
    enabled: bool = True  # default ON — auto-enabled at boot
    budget_usdt: float = 0.0       # 0 = auto-allocate
    leverage: int = 3                     # [2026-04-25 default promotion] $1/min target, category 2 (3→7)
    direction_mode: str = "both"   # "long_only", "short_only", "both"
    max_positions: int = 3         # [2026-04-25 default promotion] multi-slot diversification (3→4)
    risk_pct: float = 5.0                 # restored to 04/15 optimal-performance baseline (8→5)
    rr_ratio: float = 3.0
    max_daily_plans: int = 999    # [2026-04-25 default promotion] DM Hard Block + Consec Pause replaces it (3→999)
    max_daily_sl: int = 999        # [2026-04-25 owner decision] stop on 10 SLs (50% capital limit, more lenient)
    primary_tf: str = "240"        # [2026-05-21 owner] H4 = "240" — re-switched to H4 judging exit guards sufficient. Only deep spots get in (reviewing the 5/15 H1-switch decision — accumulated a week of exit-guard hardening: raw_body/momentum_deriv/reverse_drift/BE_stall/expectation_progress etc.). To revert primary=H1 use "60".
    entry_tf: str = "5"            # M5 = "5"
    cooldown_sec: float = 600.0
    scan_interval_sec: float = 30.0
    cycle_tp1_mult: float = 1.8     # Safe baseline: TP1:SL=1.64:1 (old 0.5=1:1 → eaten by fees)
    cycle_tp2_mult: float = 3.0     # Safe baseline: TP2:SL=2.73:1 (runner target)
    cycle_sl_mult: float = 1.1      # [2026-04-25 Long Hold System] SL farther (1.1→2.5, 5% capital risk per trade)
    partial_exit_pct: float = 50.0
    trailing_pct: float = 1.5
    # ── ADX / Conviction filter (v2 2026-04-07) ──
    adx_filter_enabled: bool = True        # ADX-based entry filter
    min_adx_entry: int = 22               # min ADX: no entry below this
    dormant_adx_threshold: int = 15       # DORMANT threshold: no trend below this
    min_conviction: float = 35.0          # 2026-05-19 Phase 6 Step 1: 50→70 (old 7 of 10 = top-university admission bar; analysis of 1823 trades showed old conv 7+ holds 80% of big profit)
    phase3_context_bonus_enabled: bool = True  # Phase 3 time-of-day(±4) + coin(+2) bonus ON/OFF
    # ── Scanner Multi-Slot ──
    scanner_entry: bool = True            # [2026-04-25 default promotion] standardized multi-slot scanner entry (False→True)
    scanner_min_adx: int = 25             # [2026-04-18 evening] 25→18 ($1/min target, Anti-Knife+H4 ensure quality)
    scanner_min_conviction: float = 50.0  # 2026-05-19 Phase 6 Step 1: 30→70 (old 7 = top-university admission)
    scanner_max_exposure_pct: float = 70.0  # max % of balance used
    # ★ [2026-05-20 owner] 30M conflict conviction multiplier — exposed in UI (old hardcoded 0.5 → made a dataclass field)
    # On PRI(H1) vs 30M trend conflict, conviction × this multiplier. If both fire, ×product of the two (down to 1/4).
    # 1.0 = OFF / 0.7 = -30% (default) / 0.5 = -50% (old value) / 0.8 = -20%
    # [2026-05-27 owner] conflicts with the H4/H1 PA pulse philosophy → 1.0 (effectively disabled). 30M=timing TF, not core direction
    scanner_m30_primary_conflict_penalty: float = 1.0   # conviction multiplier on PRI(H1) vs 30M trend conflict (1.0 = no penalty)
    scanner_m30_direction_conflict_penalty: float = 1.0 # conviction multiplier on direction(LONG/SHORT) vs 30M trend conflict
    # ── ★ [2026-05-20 Phase 6 — owner redesign] two-choice Entry Mode ──
    #   Owner decision (5/20): "Choose between Score mode and entering opposite to the bot"
    #   - "score" (default): based on conviction 100-pt (existing, conv ≥ 70 = enter same direction)
    #   - "reverse": bot signal + low conv + low ADX → auto-enter opposite (owner's primary rule)
    #     condition: conv ≤ reverse_conv_threshold + ADX ≤ reverse_adx_max
    #     RSI/MACD/BB reinforcement = auto-combined Combo E (not required, optimistic)
    entry_mode: str = 'reverse'                # "score" | "reverse"
    # Reverse mode trigger thresholds
    reverse_conv_threshold: float = 35.0     # conv at/below this → reverse-entry trigger
    reverse_adx_max: float = 20.0            # ADX at/below this → reverse-entry trigger (low ADX = bouncy = owner's gut spot)
    # ★ [2026-04-25 universe expansion] owner: "See the coins lined up? Let's expand"
    scanner_min_turnover_24h: float = 1_000_000.0   # liquidity threshold (24h $1M)
    scanner_min_price_usdt: float = 0.2            # dust filter (5.0 → 0.10, allows strong-signal entries like APE/CHIP)
    scanner_top_n: int = 20                         # number of coins tracked (10 → 20)
    scanner_blacklist: list = field(default_factory=lambda: ['CLUSDT', 'XAGUSDT', 'XAUTUSDT', 'XAUUSDT'])  # permanently blocked coins (e.g. ["CLUSDT"] — Bybit terms not accepted, etc.)
    max_same_direction: int = 2            # max positions in the same direction (rest forced opposite) — Auto default
    # ── Per-direction slot limits (2026-04-20 this agent's directive) ──
    #   Control LONG/SHORT slots separately → portfolio-level direction lock.
    #   -1(Auto) = use max_same_direction (keep existing behavior). 0 = fully block that direction.
    #   e.g. LONG=Auto, SHORT=0 → SHORT fully blocked (force BULL market).
    #       LONG=max_positions, SHORT=max_positions → max on both sides (current structure).
    max_long_positions: int = -1           # LONG slot cap (-1=Auto, 0=block, N=explicit)
    max_short_positions: int = -1          # SHORT slot cap (-1=Auto, 0=block, N=explicit)
    auto_first_dir_lock: bool = False       # [2026-04-26 owner decision] lock direction of first entry in Auto mode
    # True (scalper spirit): lock first-entry direction + 4-line loss cap protection (4-25)
    # False (long-hold spirit): free both directions + same_dir cap auto skew protection (4-26)
    # ── Smart #2,#4,#5,#6,#7 (2026-04-26 owner stage-1 decision) ──
    # #7 Regime Reversal Pause — auto-detect inflection + temporarily halt new entries
    # [2026-05-27 owner] conflicts with H4/H1 PA pulse philosophy (15-min full pause on BTC trend reversal = miss pulse spots)
    regime_reversal_pause_enabled: bool = False      # old "inflection = expensive-tuition zone" → replaced by pulse guard
    regime_reversal_ema_gap_threshold_pct: float = 0.3  # BTC EMA gap < 0.3% (convergence)
    regime_reversal_adx_threshold: float = 20.0      # ADX < 20 (trend weakening)
    regime_reversal_pause_min: float = 15.0          # entry-halt duration (minutes)
    # #2 Conviction-Weighted Sizing — weight budget by signal strength
    conv_sizing_enabled: bool = True
    conv_sizing_low_threshold: float = 35.0  # [2026-05-17 100-pt ×10] 5→50. conv≤50 → budget × 0.5
    conv_sizing_high_threshold: float = 65.0 # [2026-05-17 100-pt ×10] 9→90. conv≥90 → budget × 1.5
    # ── ★ [2026-06-13 owner "entry score = conviction"] Conviction→Risk scale (inverted-U, entry-threshold anchor) ──
    #   Rationale: journal analysis 65-80=sweet(+9.04)/80+=topping(-5.65,41% win). entry threshold(guard_score_threshold)=conviction baseline(1.0x),
    #   grow the sweet spot, cut the top. Multiplied into risk_pct so it hits qty directly *without being capped* (budget×conv gets eaten by the cap). default OFF.
    #   ★ Not nailed to 50 — anchor=guard_score_threshold (change the threshold and the conviction baseline follows).
    conv_risk_scale_enabled: bool = True    # ON/OFF (must be on to fire)
    conv_risk_peak_conv: float = 60.0        # sweet-spot start (inverted-U peak) — linear rise from entry threshold to here
    conv_risk_peak_mult: float = 1.5         # sweet-spot risk multiplier
    conv_risk_chop_conv: float = 80.0        # topping line (above this = laggard/topping)
    conv_risk_chop_mult: float = 0.6         # topping risk-cut multiplier
    conv_risk_floor_mult: float = 0.5        # below entry threshold (anomalous) safety multiplier
    conv_risk_max_mult: float = 2.0          # factor safety cap (runaway prevention)
    # #4 BTC Trend-Aligned Conviction — on BTC UPTREND LONG +N / on DOWNTREND SHORT +N
    btc_trend_conv_bonus_enabled: bool = True
    btc_trend_conv_bonus: float = 20.0       # [2026-05-17 100-pt ×10] 2→20
    # #5 Winners Add Strength — add to a profitable coin when it reaches +X% (trigger beyond capital_threshold)
    winners_add_self_growth_enabled: bool = True
    winners_add_self_growth_pct: float = 1.5      # trigger when the coin itself reaches +1.5%
    winners_add_self_growth_ratio_pct: float = 50.0  # [2026-04-26 this agent's #1 fix] add-buy ratio (existing margin × N%) — adjustable from owner dashboard
    # #6 Multi-Stage BE Lock — auto-tighten SL by peak reached
    multi_be_lock_enabled: bool = True
    multi_be_lock_stage1_pct: float = 0.25      # [2026-06-04 owner] 0.4→0.25 (earlier BE fire, Home server verified: 34 wins of 38 +$30.27)
    multi_be_lock_stage2_pct: float = 1.0       # (fixed mode) peak ≥ 1.0% → SL=entry+0.3%
    multi_be_lock_stage3_pct: float = 2.0       # (fixed mode) peak ≥ 2.0% → SL=entry+1.0%
    multi_be_lock_stage4_pct: float = 3.0       # (fixed mode) peak ≥ 3.0% → SL=entry+2.0%
    # [2026-05-16 owner] stage1 fee-aware — SL=entry+cushion to protect fees (fee 0.11% + buffer)
    multi_be_lock_fee_cushion_pct: float = 0.05  # [2026-06-04 owner] verified value (loss per BE-then-loss case -$0.12, negligible)
    # [2026-05-21 owner] BE Lock ATR adaptive — high-volatility coins must move farther to BE (prevent early cut)
    multi_be_lock_atr_adaptive_enabled: bool = True   # True=ATR multiplier mode / False=fixed % mode (uses stage_pct above)
    multi_be_lock_atr_tf: str = "60"                  # ATR computation TF (H1)
    multi_be_lock_atr_period: int = 14                # ATR period
    multi_be_lock_stage1_atr_mult: float = 0.3        # (adaptive mode) stage1 trigger = ATR% × 0.3 (BTC~0.3%, HYPE~0.9%)
    multi_be_lock_stage2_atr_mult: float = 0.7        # (adaptive mode) stage2 trigger = ATR% × 0.7
    multi_be_lock_stage3_atr_mult: float = 1.4        # (adaptive mode) stage3 trigger = ATR% × 1.4
    multi_be_lock_stage4_atr_mult: float = 2.2        # (adaptive mode) stage4 trigger = ATR% × 2.2
    # [2026-05-29 owner 5th→6th fix] ATR-adaptive floor — protects low-volatility coins (HYPE peak 0.094% noise-cut incident)
    # If ATR×0.3 is too small, post-entry noise fires BE lock → pulls SL just above entry → 70-sec cut
    # Guarantee stage1 trigger of at least 0.3% (no BE lock if peak under 0.3%)
    multi_be_lock_atr_min_stage1_trigger_pct: float = 0.3  # [2026-06-04 owner] 0.3→0.2 (verified value, lowered stage1 floor)
    # [2026-06-13 owner "need a max cap / ride runner but lay in profit"] stage1 trigger cap — extreme-ATR coins (BEAT-type
    #   ADX52·Innovation Zone) push ATR×0.3 to 6%+ so BE is way too late → defenseless give-back. At this % always BE-lock.
    #   Paired with min(0.2%, low-vol noise guard). 0=no cap (old behavior). default 3.0 → only binds extreme coins with ATR%>10.
    multi_be_lock_atr_max_stage1_trigger_pct: float = 3.0
    # [2026-05-29 owner 7th fix] post-entry grace — Bybit fill slippage of 0.4% captured as peak fired BE lock (ZEC 21-sec SL hit)
    # The gap between bot order price vs Bybit fill price itself is read as a *post-entry peak* → BE lock fires → pulls SL near entry → noise hits instantly
    # For N sec after entry no BE lock fires (all 3 paths: dynamic_trail Stage1 / morning_shield / erosion_guard)
    be_lock_grace_sec: float = 60.0
    # ★★ [2026-06-17 owner] Naked SL hard-guard — when server-side SL is unconfirmed (set_trading_stop failed)
    #   and price nears/crosses SL, *immediately market-close*. Fundamental safety net for "passes through low SL → exit".
    #   (DIAGNOSIS_bybit_naked_sl_liquidation: server SL write-only → naked position → polling also weakened by load → passes through)
    #   ★ No-op when server SL is confirmed (_tp_sl_confirmed) — naked case only. Default ON (safety net).
    naked_sl_guard_enabled: bool = True
    naked_sl_guard_buffer_pct: float = 0.2   # SL-proximity buffer (after grace): if LONG price<=sl×(1+buf), pre-emptive cut
    # ★★ [2026-06-17] server SL read-verify (Fix ①) — on each SYNC, compare exchange's actual stopLoss against pos.sl.
    #   If missing(0) or differs by more than 0.1%, set _tp_sl_confirmed=False → re-place + activate naked guard. write-only → read-verify.
    server_sl_verify_enabled: bool = True
    # ★ [2026-06-04 owner] Smart BE Lock — fire only after confirming profit-direction momentum
    # "Firing BE without watching the wobble or the speed of moving into profit is unwise"
    # ① RSI check: defer if profit-direction RSI is strong (still running)
    # ② consecutive-candle check: defer if last N candles run in the profit direction (accelerating)
    # If ①② both OFF → fire immediately (existing behavior). Default: ①②ON
    be_lock_smart_rsi_check: bool = True       # ① RSI in profit direction → defer firing
    be_lock_smart_candle_check: bool = True    # ② last N candles consecutive in profit direction → defer firing
    be_lock_smart_rsi_long_min: float = 55.0   # LONG: RSI ≥ this value = still running
    be_lock_smart_rsi_short_max: float = 45.0  # SHORT: RSI ≤ this value = still running
    be_lock_smart_candle_count: int = 3        # last N candles (5M) consecutive in profit direction
    be_lock_smart_defer_giveback_pct: float = 0.3  # [2026-06-20] during smart_defer, if give-back from peak ≥ this %p, release defer & BE-lock (peak give-back failsafe). 0=failsafe OFF. Blocks 25-case -$35.71 leak.
    # [2026-05-29 owner] Smart Manual Entry — enter after confirming signal
    # Owner: "If the operator's leading-entry judgment is faster, turn OFF". Adjust enable / wait time per scenario.
    smart_manual_entry_enabled: bool = True            # ON/OFF (when OFF, hides L⏳/S⏳ buttons)
    smart_manual_entry_default_timeout_sec: float = 300.0   # wait time (sec). UI takes minutes → ×60
    # ── [2026-05-29 owner] Slot Auto Expand — redesign of old slot auto-expand (rolled back) ──
    # Owner 5-15 memory: simple time-based had no effect, rolled back. This time: strong-signal + tied-up + limited + capital-protection.
    # Condition: all slots tied up for lock_hours+ + new candidate conv ≥ min_conv + extras unused.
    # Effect: temporarily allow +max_extra slots (capital-protected via size_ratio). Held until exit.
    slot_auto_expand_enabled: bool = True             # default OFF (owner's optional decision)
    slot_auto_expand_lock_hours: float = 1.0           # condition: all slots tied up N hours
    slot_auto_expand_min_conviction: float = 55.0      # new-candidate min conv (strong signal)
    slot_auto_expand_max_extra: int = 1                # max extra slots (default +1, no infinite expansion)
    slot_auto_expand_size_ratio: float = 0.5           # 50% of average size (capital protection)
    # ── [2026-05-29 owner] Market Consensus Exit — exit a losing counter-trend position based on market consensus ──
    # Automates owner's manual exit pattern from today 11:58. "No entry impact / exit wisdom" — minimize loss.
    # Owner: "Since we didn't enter against D1, exiting on D1 change is inappropriate. Give 15 more min of chance."
    # Condition: Scanner dominant direction ≥ 70% + sustained N min + active position is opposite + in loss + min hold
    # Effect: blocks recurrence of the fix-5 pattern (won't be dragged to SL). Reduces owner's labor.
    market_consensus_exit_enabled: bool = True        # default OFF (owner's optional decision)
    market_consensus_threshold_pct: float = 70.0       # one-direction signal-ratio threshold (70%+)
    market_consensus_duration_min: float = 15.0        # consensus duration (15 min)
    market_consensus_min_hold_min: float = 20.0        # position min hold (post-entry protection)
    market_consensus_min_pnl_pct: float = -0.5         # exit only at PnL ≤ -0.5% (protects counter-trend in profit)
    # ★ #2A [2026-04-26 this agent's fix] Portfolio SL Rate guard — prevent simultaneous SL clusters
    portfolio_sl_rate_enabled: bool = True
    portfolio_sl_rate_window_min: int = 5         # recent N-min window
    portfolio_sl_rate_threshold: int = 3          # fires if M+ SL hits within the window
    portfolio_sl_rate_pause_min: int = 15         # new-entry block duration when fired
    # ★ #5A [2026-04-26 this agent's fix] BTC + B12 combined cap — addresses "+3 neutralizes other indicators" concern
    btc_b12_combined_cap_enabled: bool = True
    btc_b12_combined_cap_max: int = 2             # combined cap of cross_delta + #4_btc_bonus
    # ★★★ [2026-04-26 owner absolute order] no exit until ROE -31% — force SL price to the ROE -31% point
    parent_roe_guard_enabled: bool = True
    parent_max_roe_loss_pct: float = 31.0          # [2026-05-13 owner readjusted] 31% — matches UI label/help. lev 5→SL 6.2% / lev 7→4.43% / lev 10→3.1%. Lose at most 1/3 of margin (conservative)
    # ── Improvements taken from the Upbit friend system ──
    adaptive_cooldown: bool = False         # increase cooldown by losing-streak count
    emergency_tp_tiers: bool = False       # [2026-04-26 Long Hold default] BTC-crash auto-exit OFF
    lock_market: str = ''          # fixed coin (5-28 owner: gold-only first line) — empty = auto-scan
    # ── Dynamic Trailing SL (ON/OFF comparable) ──
    dynamic_trailing: bool = True         # [2026-04-26 Long Hold default] OFF (manual SL is the owner's)
    breakeven_trigger_pct: float = 0.3     # [2026-04-25 default promotion] fast BE lock (0.4→0.3)
    trailing_preserve_pct: float = 50.0    # [2026-04-18 night] 50→40 (more room for big profit, fixes giving-back-more-than-eaten)
    trailing_small_profit_preserve_pct: float = 40.0  # [2026-04-18 night] 40→60 (grip small profit tightly)
    trailing_accel_pct: float = 5.0       # [2026-04-18 night] 5→3 (tighten slowly on big profit → keep runner alive)
    # ── Trailing TP (hammer-handle defense) ──
    # 2026-04-17 real-data analysis: of 238 SERVER_SL, 114 (48%) were under $1 profit.
    # Peak avg 0.327% vs actual fill 0.182% → 55% capture rate.
    # Current regime where TP1 rarely hits → make TP follow behind peak as it comes down,
    # so even a small wick give-back fills near the peak.
    trailing_tp_enabled: bool = True
    trailing_tp_min_progress: float = 0.5   # fire when peak/TP1 progress is at/above this value
    trailing_tp_follow_low: float = 0.93     # follow ratio at 40~60% progress (TP at 93% of peak)
    trailing_tp_follow_mid: float = 0.90     # at 60~80% progress
    trailing_tp_follow_high: float = 0.87    # at 80%+ progress
    # ── BE Stall Exit (2026-04-19 user intuition) ──
    # Real-data observation: median 40% give-back after BE lock.
    # Measured pattern (2026-04-19, this agent's server live): BE → 23 sec = decisive fork. Past it, can't get back to that high.
    # User observation: even after 2 min, doesn't recover the original high. No repeated pullback-and-rerise pattern.
    # Solution: 30 sec measured from max(be_locked_ts, last_peak_update_ts) = 23s fork + 7s confirmation margin.
    #       If a new high is made the timer resets (protects uptrends, only cuts confirmed reversals).
    be_stall_exit_enabled: bool = True      # [2026-04-26 Long Hold default] OFF (can't leave if no profit)
    be_stall_exit_sec: float = 60.0          # 23s fork + 7s margin. Coin volatility: 25 (high vol) ~ 35 (low vol).
    be_stall_intelligent_enabled: bool = True  # [2026-05-15 owner] momentum (MACD/RSI/BB)-linked intelligent — live implemented
    # Intelligent BE Stall: if our-side momentum is strong ignore stall (hold), if opposite is strong ignore time (exit now), neutral falls back to the 30s rule.
    be_stall_intelligent_rsi_strong: float = 55.0    # LONG: RSI >= 55 = our side / SHORT: RSI <= 45
    be_stall_intelligent_rsi_weak: float = 45.0      # LONG: RSI <= 45 = opposite side / SHORT: RSI >= 55
    # ── ★ min TP fee-guard (2026-05-15 owner, prevent instant TP hit + fee loss right after entry) ──
    # cycle_tp is ATR-based, but on low-volatility coins TP lands right next to entry.
    # Bybit Taker round-trip 0.11% × ~3 = guarantee min 0.30% distance. Passed to cycle_tp.compute_cycle_targets.
    min_tp_distance_enabled: bool = True
    min_tp_distance_pct: float = 0.30
    # ── ★ 5m Microtiming Gate (2026-05-16 owner, "WAIT not BLOCK — enter at the exact spot") ──
    #   Micro-time a conviction-passing candidate via 3 5m RSI/MACD/BB inflections.
    #   If under N/3 score, WAIT (defer) not BLOCK: re-evaluate after defer_sec.
    #   Don't cling to one coin; meanwhile keep scanning other candidates.
    #   Decision:
    #     LONG  → RSI(14) prev≤rsi_long_threshold AND current upward inflection = +1
    #             MACD hist prev negative → positive OR negative absolute value shrinking = +1
    #             BB position prev lower band (<bb_low_pct%) → current recovery (≥bb_recover_pct%) = +1
    #     SHORT → RSI prev≥rsi_short_threshold AND current downward inflection / MACD pos→neg / BB upper→recovery
    #   If score ≥ min_score (default 2/3) GO, else WAIT.
    microtiming_5m_enabled: bool = True
    microtiming_5m_min_score: int = 2                # GO when N of 3 met (default 2)
    microtiming_5m_defer_sec: float = 600.0          # re-eval interval after WAIT (default 10 min)
    microtiming_5m_max_defers: int = 3               # max defer count (default 3 → natural expiry, no BLOCK count accrued)
    microtiming_5m_rsi_long_threshold: float = 35.0  # LONG: prev RSI ≤ this value + current upward inflection
    microtiming_5m_rsi_short_threshold: float = 65.0 # SHORT: prev RSI ≥ this value + current downward inflection
    microtiming_5m_bb_low_pct: float = 20.0          # BB position % (price-low)/(high-low)*100, < this = lower-band zone
    microtiming_5m_bb_recover_pct: float = 30.0      # prev lower-band → current ≥ this = recovery starting (LONG / reversed for SHORT)
    microtiming_5m_phase_k_exempt: bool = True       # Phase K (regime transition) entries exempt — prioritize catching market transitions
    # ── ★ [2026-06-05 owner] 1M micro-check — "direction is right but is it this exact moment" verification ──
    # Even at conv 100, entering at the end of a 5M candle = instant reversal. Confirm real-time timing with 1M.
    # ① last 1M candle direction (wait if opposite)
    # ② 1M volume decline (3 consecutive declines = momentum exhausted)
    # ③ 1M RSI extreme (LONG RSI>70 / SHORT RSI<30 = overheated)
    micro_1m_check_enabled: bool = True            # 1M micro-check ON/OFF
    micro_1m_candle_check: bool = True             # ① last 1M candle direction check
    # ★ [2026-06-11 owner plan B] if trend is strong (ADX≥this=riding the wall) ignore 1M candle ripples → prevent late entry (enter early).
    #   0=off (existing). e.g. 30 = if ADX 30+, exempt candle_check (direction+body). volume/rsi stay. Addresses STG/BEAT late-entry evidence.
    micro_1m_candle_trend_exempt_adx: float = 40.0  # ADX at/above this = strong trend → exempt 1M candle direction check (0=disabled)
    micro_1m_volume_check: bool = True             # ② 1M volume-decline check
    micro_1m_rsi_check: bool = True                # ③ 1M RSI-extreme check
    micro_1m_rsi_long_max: float = 70.0            # LONG: RSI > this value = overheated → wait
    micro_1m_rsi_short_min: float = 35.0           # SHORT: RSI < this value = overheated → wait
    micro_1m_vol_decline_bars: int = 3             # consecutive volume-decline bars
    # ④ [2026-06-06 owner] 1M candle body strength — "it's now" ignition confirmation.
    #   0 = off (direction only → weak doji passes too = a beat off). If >0, enter only when the 1M candle body
    #   is ≥ this % of price (a 'real pushing candle'; weak candle = wait for next tick). Suggested start 0.05~0.10.
    micro_1m_body_min_pct: float = 0.05            # ★default ON (2026-06-06 owner approved) — filters weak dojis, only 'real pushing candles'
    # ── ★ Pre-BE Stall Exit (2026-04-23 owner direct request) ──
    #   "Take profit when it stalls a bit before reaching BE, while still short of the BE trigger"
    #   Sibling of BE Stall Exit — exit on small profit stall at the pre-BE-lock stage.
    #   AUTO mode: fires only when the entered coin's ATR% indicates sideways (<2%); follows trend on sharp moves (≥2%).
    #   Avoids infinite holding of a sideways lone LONG like BNB.
    pre_be_stall_exit_mode: str = 'AUTO'                # [2026-04-25 Long Hold System] "AUTO"→"OFF" (be patient until BE reached)
    pre_be_stall_min_profit_pct: float = 0.10          # fires only above +0.10% (lock in small profit)
    pre_be_stall_sec: float = 240.0                     # [2026-04-25 default promotion] owner "91 sec too early" (60→240)
    pre_be_stall_volatility_threshold_pct: float = 2.0 # ATR% splitting sideways/sharp-move in AUTO (per entered coin)
    # [2026-05-16 added] same as reverse_drift incident pattern — stale-peak protection
    # Incident: pre_be_stall_146886s_peak+0.40%_atr1.7% (force-exit on a 40-hour-old peak)
    # Peaks older than 30 min are stale → won't fire
    pre_be_stall_max_since_peak_sec: float = 1800.0    # max time after peak (default 30 min)

    # ── 🐢 ★ Pre-BE loss-prevention line (2026-06-09 owner "right now") ──
    # Blind spot of pre_be_stall (stall)·reverse_drift (drift): a flounder (🐢) that never lifted peak above 0.1 slips into entry-based loss.
    # Evidence (2026-06-09): 10 cases of peak<0.1 going straight to SL -21.87, BElock all False. Measure by entry-based loss% (avoid the peak denominator).
    pre_be_loss_guard_enabled: bool = True            # default OFF — owner must enable (live after paper observation)
    pre_be_loss_guard_peak_max_pct: float = 0.10       # peak ≤ this value = flounder (never lifted) target
    pre_be_loss_guard_trigger_loss_pct: float = 0.5    # if pushed -this(%) vs entry, small cut (half of SL's -1~2%)
    pre_be_loss_guard_min_hold_sec: float = 60.0       # min hold after entry (extra safety beyond grace)
    pre_be_loss_guard_max_age_sec: float = 7200.0      # [2026-06-09 owner] 1800→7200(2h) — flounder -63 (over 30 min) didn't fire under stale rule; entry-based so safe with no stale-peak incident

    # ── ★ Reverse Drift Exit (2026-05-16 owner direct request) ──
    # Covers pre_be_stall's weakness: AUTO mode doesn't fire on high ATR → loss if trend slowly drifts against us.
    # Difference: pre_be_stall = "stall (peak not updating)" / reverse_drift = "drift (moving away from peak)"
    # i.e. cut even when ATR is high if that trend flows toward entry.
    # Protects cases like BTC SHORT peak 0.19%→-0.09%, SOL SHORT peak 0.28%→-0.23%.
    # [2026-05-16 post-incident fix] FARTCOIN 3-day-old peak(0.395)+drift 17% force-exit -$120.
    #   Defect 1: no cap on since_peak → added max_since_peak_sec
    #   Defect 2: peak_max(0.4) == BE_trigger(0.4) → blind spot of BE-lock-short peak → 0.4→0.35 to secure a gap
    reverse_drift_exit_enabled: bool = True            # [2026-05-16] owner ON immediately (skip observation, go live)
    reverse_drift_peak_min_pct: float = 0.10           # [2026-05-20 owner] 0.05→0.10 (raise noise floor, prevent residual-noise cuts)
    reverse_drift_peak_max_pct: float = 0.35           # [2026-05-16 0.4→0.35] 0.05 gap from BE_trigger(0.4), avoid blind spot
    reverse_drift_min_since_peak_sec: float = 180.0    # min stall time after peak made (3 min)
    reverse_drift_max_since_peak_sec: float = 1800.0   # [2026-05-16 added] peak older than 30 min is stale → won't fire (prevents FARTCOIN incident)
    # ── ATR adaptive (inherited from tight_trail spec) ──
    reverse_drift_atr_adaptive_enabled: bool = True
    reverse_drift_atr_tf: str = "5"                     # 5m
    reverse_drift_atr_period: int = 14
    reverse_drift_atr_multiplier: float = 0.2           # atr_pct × 0.2 = adaptive drift threshold
    reverse_drift_atr_cap_pct: float = 0.4              # cap (protects high-volatility spots)
    reverse_drift_pct: float = 0.26                     # [2026-05-20 owner] 0.10→0.26 raise base drift floor (prevent short-cut accumulation)

    # ── ★★★ Block topping-chase (Overextension) — 2026-06-07 owner directive (live ON) ──
    # Case: at TON +15%/24H high (94.9% of range) the bot chased LONG → peak 0.82% then SL −2.23.
    #   The owner said "nothing to do but watch" and didn't buy; the bot fired into the ceiling there.
    # Hole: DayBox ceiling-LONG block only works during box lock (sideways) → defenseless during a trend surge.
    # Signal: position within 24H range (pos) + 24H move size (move). LONG=top+surge / SHORT=bottom+crash → penalty.
    # ★ Asymmetric (BB wall-riding philosophy): ADX≥exempt = strong breakout → penalty exempt ('if strong, ride the wall').
    #   No hard block, soft conviction penalty (strong signal still gets in). Not a coin block (situational penalty).
    overextension_enabled: bool = True                 # live ON (owner 2026-06-07 "live, not paper")
    overextension_range_pos_pct: float = 0.85          # LONG: above this ratio of 24H range top / SHORT: bottom (1-this) below
    overextension_min_move_pct: float = 8.0            # 24H move |%| must be at least this to judge 'topping' (excludes small moves)
    overextension_penalty: float = 20.0                # conviction penalty points
    overextension_adx_exempt: float = 30.0             # ADX at/above this = strong breakout → penalty exempt (0=no exemption)
    # ── ★ [2026-06-13 owner "build the #1 topping filter now"] Blow-off 24h surge/crash chase block ──
    #   Covers overextension's ADX-exemption hole — pumps explode ADX → get exempted. This is based on *24h move size* +
    #   penalizes only the chase direction (same direction) + ★*no* ADX exemption. Blocks junk-coin pump chasing like ESPORTS+55%. default OFF.
    #   (Tickers share the _get_24h_ticker cache — avoids duplicate fetch with overextension, protects rate-limit.)
    blowoff_filter_enabled: bool = True               # ON/OFF (must be on to fire)
    blowoff_move_pct: float = 30.0                     # 24h |move| ≥ this % = blow-off candidate (chase penalty starts)
    blowoff_penalty: float = 20.0                      # base penalty (at the move_pct point)
    blowoff_extreme_pct: float = 45.0                  # 24h |move| ≥ this % = extreme (max penalty). Lowered 80→45 (2026-06-26): hyper-volatile new/Innovation-Zone coins (e.g. a coin -65% on the day) must hit the extreme tier, not slip through with a small penalty.
    blowoff_max_penalty: float = 40.0                  # max penalty at the extreme
    blowoff_chase_only: bool = False                   # 2026-06-26: was True (chase-only). A coin that has blown off ±45% is too wild in BOTH directions — penalize fade entries too (a short into a -65% crash bounced +8.7% and blew up at 7x).

    # ── ★ Profit-headroom penalty (Headroom) — 2026-06-09 owner "penalize even if direction is right but nowhere to go" ──
    #   Owner's insight: the scoreboard gives 48 pts to lagging alignment but only penalty-free bonuses for 'how far it can go (headroom)' → high score = topping.
    #   Subtract conviction (negative) for no-headroom spots (right at resistance/support · RSI extreme · BB band edge) to filter topping entries.
    #   Existing score functions (S/R·RSI·BB) unchanged — added only via isolated _compute_headroom_penalty. default OFF.
    headroom_penalty_enabled: bool = True              # [2026-06-10 owner "you input it and turn it on"] fleet default ON
    headroom_sr_penalty: float = 6.0                   # penalty for LONG entry right at resistance / SHORT right at support
    headroom_sr_near_pct: float = 1.5                  # within this % of resistance/support = no headroom
    headroom_rsi_penalty: float = 6.0                  # penalty for LONG overbought / SHORT oversold entry
    headroom_rsi_overbought: float = 70.0              # LONG: RSI at/above this = nowhere to go
    headroom_rsi_oversold: float = 30.0                # SHORT: RSI at/below this = nowhere to go
    headroom_bb_penalty: float = 4.0                   # penalty for LONG at BB top / SHORT at BB bottom entry
    headroom_bb_hi_pctb: float = 0.80                  # %b at/above this = band top (no LONG headroom)
    headroom_bb_lo_pctb: float = 0.20                  # %b at/below this = band bottom (no SHORT headroom)

    # ── 🎯 Inflection setup score (Inflection Setup) — 2026-06-12 owner "the score betrays the chart" ──
    #   The bot doesn't look at candles — only at the score. The score must encode "position within move × momentum direction"
    #   to distinguish ceiling stall (LONG late/SHORT good) · bottom inflection (LONG good) · wall-riding (exempt if momentum alive).
    #   Owner's model: rising-then-stalling=SHORT top/LONG risk, falling-then-stalling=LONG bottom/SHORT risk. Direction-symmetric.
    #   ★ Position (height) alone can't tell ceiling 'wall-riding' from 'topping' → adjust by momentum direction.
    #   5m 288 bars: pos (position within 24h range) × up (=0.75·tanh(slope15m/scale)+0.25·sign(MACD histo Δ)).
    #   L=W·(at_high·(up-base)+at_low·(base+up)) / S=mirror. Trigger (microtiming) is separate = outside the score.
    #   guard_eval sim-verified (XRP/SOL/HYPE ceiling stall→SHORT, VELVET wall-riding→exempt). default OFF.
    inflection_setup_enabled: bool = True             # if on, adds the ㉒ Inflect item to the guard score
    inflection_setup_weight: float = 20.0              # W: max-magnitude scale of the inflection modifier
    inflection_setup_cap: float = 20.0                 # output clamp ±cap
    inflection_setup_base: float = 0.45                # base: default adjustment from position alone (when momentum is 0)
    inflection_setup_slope_scale: float = 0.40         # slope15m tanh normalization scale (%)

    # ── 🎣 Retest setup score — 2026-06-12 owner (sibling-session opinion) "breakout→pullback→support = good spot" ──
    #   Pair of the inflection axis (filter topping, both ±) = 'catching good entries' (bonus-focused). Owner "spot that pulls back then goes again".
    #   3 beats: ①breakout (clears prior swing high / breaks low) ②retracement (pullback from post-breakout high, not ceiling chasing)
    #          ③support confirm (holds above/below breakout level + turning in direction). All three = bonus. Breakout only (ceiling)·fail=0.
    #   Interaction with inflection: retest=bonus on pullback / inflection=penalty on momentum↓ → at ideal entry (end of pullback+turn) both align.
    #   5m pivot (±width) breakout+retracement. guard_eval sim-verified (ETH/ZEC/XRP retest, ceiling·fail 0). default OFF.
    retest_setup_enabled: bool = True                 # if on, adds the ㉓ Retest item to the guard score
    retest_setup_weight: float = 12.0                  # max retest bonus magnitude (× retracement quality)
    retest_setup_turn_bonus: float = 4.0               # extra bonus when turning in direction after retracement
    retest_retr_lo: float = 0.30                       # min retracement ratio (below = ceiling chasing, no signal)
    retest_retr_hi: float = 0.90                       # ideal retracement cap (beyond +0.3 = too-deep fail)
    retest_pivot_width: int = 2                        # pivot high/low left-right width
    retest_fail_pct: float = 0.005                     # retest fails if breakout level breached by this %

    # ── 🌊 Macro-downtrend active SHORT entry, stage 2 (Macro Short Timing) — 2026-06-11 owner "complete the channel" ──
    #   Stage 1 (breadth direction gate:8088) only gives a bonus to SHORT alignment = reactive (waits for a good spot). Here, macro RISK_OFF +
    #   an individual coin's 5m 'bounce (dead-cat) then turn-down' state is an *active signal* giving SHORT conviction bonus → passing the guard_score(65) gate
    #   = active entry realized (focus_manager:8087 [stage 2] implemented). ★ Topping-chase prevention: premise is 'there was a bounce and it turned down' —
    #   pure decline (no bounce) = 0. SHORT only (LONG keeps the stage-1 -25 block). default OFF — owner turns on in the v3 Guards tab.
    macro_short_timing_enabled: bool = True           # stage 2 ON/OFF (live the moment it's on)
    macro_short_timing_delta: float = 12.0             # SHORT conviction bonus magnitude (actual value)
    macro_short_timing_min_signals: int = 2            # min met of the 3 turn-down signals (neg-cross/MACD<0/PA bearish)
    macro_short_timing_bounce_pct: float = 0.3         # 'bounce exists' premise — min % bounce from 5m low to high
    macro_short_timing_lookback: int = 12              # 5m bounce-search bar count

    # ── 🌋 Volatility-awakening SL adaptation (Volatility Awakening) — 2026-06-11 owner "set it far and trail in" ──
    #   When a sluggish coin awakens (volatility expansion) + entering with the Day trend, set SL *wide* to the new volatility →
    #   risk-based sizing (qty=risk/sl_distance) auto-shrinks size = risk($) fixed. Ride the trend while avoiding noise cuts.
