    awaken_sl_enabled: bool = True                    # awakening SL adaptation ON/OFF (must be on to work)
    awaken_sl_mode: str = 'atr'                       # atr / structure / both (SL-distance basis, owner's 3 modes)
    awaken_atr_ratio: float = 1.3                      # awakening decision — current ATR / past ATR ratio
    awaken_atr_lookback: int = 20                      # past-ATR average bar count (primary_tf=H4)
    awaken_max_sl_mult: float = 2.5                    # max SL multiplier (prevent infinite expansion)
    awaken_require_day_align: bool = True              # only Day (coin D1) alignment qualifies to endure (excludes against/undecided)
    awaken_swing_lookback: int = 10                    # structure-point (awakening's foot) swing-search bar count
    awaken_atr_buffer: float = 0.5                     # ATR-room multiplier on the structure point

    # ── ② ★ Topping ceiling penalty (Conviction Ceiling) — 2026-06-09 owner "90+=topping=50↓, wall-riding exception" ──
    # conviction 90+ = all indicators aligned = lagging/topping (signal complete = 1~2 5-min candles late). Data: 75-80 sweet(62%)/90+ worst(39%).
    # Cap topping to target(50) → under the 65 gate = entry blocked. But wall-riding (ADX≥exempt) is exempt (strong breakout = keeps going).
