    conviction_ceiling_target: float = 50.0            # cap topping to this score (drive it under the 65 gate)
    conviction_ceiling_adx_exempt: float = 30.0        # ADX at/above this = wall-riding → exempt (0=no exemption)

    # ── ★ [2026-06-13 score-system patch v1] additive cap / ceiling order / bypass basis ──
    #   Rationale: measured scores 50~159 (designed 0~100) — unlimited additive summing erodes the scale·ceiling·bypass entirely.
    #   All default OFF/existing values — owner must enable. On incident, toggle OFF = instant revert.
    guard_score_total_cap_enabled: bool = False        # clamp the guard additive-points total ON/OFF
    guard_score_total_cap: float = 30.0                # total clamp ±N (this limit for both additions and deductions)
    conviction_ceiling_post_guards: bool = True       # True = apply topping ceiling *after* base+guard summing (blocks additive revival)
    final_bypass_use_base: bool = False                # True = compare score-absorption bypass against base conviction (inflation-independent)

    # ── ★★★ Entry Grace Period (2026-05-18 owner vision #6) — time to read the mood after entry ──
    # Owner's words: "Need more time to read the mood after entry"
    # Case: office-1 BTC SHORT 15:20→15:23 reverse_drift_peak+0.10% cut in 3 min — too fast.
    # A/B probability game (memory feedback_exit_guard_A_B_probability_game_2026-05-18):
    #   A = long-term stuck → fast cut is the answer
    #   B = small valley then hill → endure a bit and profit
    #   At entry we don't know which → buy judgment time with the grace period
    # Applied guards: pre_be_stall_exit + reverse_drift_exit (the two too-fast-cut guards only)
    # Not affected: be_stall_exit (the only profit guard), long_hold_timeout (time-unit guard), SL, Hard ROE
    # default 0 = OFF — owner must explicitly enable (naturally guarantees a verification phase)
    entry_grace_period_sec: float = 0.0                 # disable fast-cut guards for N sec after entry. 0=OFF, 300=5 min recommended.
    # ★★★ [2026-05-18 owner vision #6 aux] cut immediately if market_bias is opposite during grace
    # Owner "read the neighboring servers" — A/B-discrimination aid. Force exit when A pattern (opposite dominance) is detected.
    # Reuses the market_bias module (used for entry-time penalty) = exit-time force exit
    # Works only during the grace period — after grace ends, existing guards work normally
    market_bias_grace_exit_enabled: bool = False        # default OFF — must be enabled together with entry_grace_period_sec
    # ★★★ [2026-05-18 owner vision #6 aux — news revival] cut immediately if news sentiment is opposite during grace
    # Owner "a way to revive the news.. not just an entry variable but also an exit variable"
    # Entry-time integration = focus_manager.py 4305 (needs focus_enabled=True to activate)
    # Exit-time integration = this option (separate activation)
    # Reuses get_sentiment() of the news_sentiment module (app/core/news_sentiment.py)
    news_grace_exit_enabled: bool = False               # default OFF
    news_grace_exit_threshold: float = 0.5              # force exit if |sentiment| >= threshold (1.0=extreme)
    # ★★★★ [2026-05-18 owner vision #6 option B — time-independent OR condition] (evening patch B)
    # Owner's spirit: "time cut → small consecutive losses / even enduring = a long-term unrealized-loss coin" = time-based itself is not the answer
    # When an existing guard (reverse_drift, pre_be_stall) fires, combine neighboring-server + news opinions:
    #   - both same direction → "hold" → ignore guard (endure, B pattern)
    #   - both opposite or mixed → "exit" or "neutral" → follow guard (cut, A pattern or default)
    # Time-independent = aligns with owner's time-based skepticism
    exit_consensus_enabled: bool = True                # default OFF
    exit_consensus_news_threshold: float = 0.3          # news sentiment-strength threshold (0.3=mild, 0.5=strong)

    # ── ★ Long Hold Timeout (2026-04-25 owner new) ──
    # Auto-cut on long neglect. The "peak going up and down + long hold" pattern that Pre-BE Stall can't catch.
    # Dawn cases: XAUT 128 min peak 0.26% → -$6.73 / ETH 164 min peak 0.17% → -$12.81
    # 3-tier: 60min/120min/180min absolute cutoff.
    long_hold_timeout_enabled: bool = False     # [2026-04-25 Long Hold System] side effect of instant cut when tier1/2=0 → all OFF
    # ★ [2026-04-25 Long Hold System] Hard ROE Cap — hardcoded -10% forced-exit safety net
    # Owner's finding: conflicts with the intent to endure to SL (force-cut at just -1.43% price on LAB lev7)
    hard_roe_cap_enabled: bool = True           # default OFF (Long Hold consistency)
    hard_roe_cap_roe_pct: float = -25.0          # firing-threshold ROE %. Tightened -50→-25 (2026-06-26) as a tail-risk backstop: a single trade riding to -50%+ ROE wipes a day of gains. -25 catches a slide earlier when the normal SL is bypassed (e.g. paper SL lag / restart).
    # ── ★★★ Conviction Override Slot (2026-05-10 owner decision) ──
    #   Allow extra slots equal to slots tied up beyond the set window(h) (max +N).
    #   window is a user knob (default 24h, owner adjusts to the market).
    #   Entry eligibility: very strict (100% conviction).
    #   Betrayal countermeasure: small size + near SL + Hard ROE cut (sensitive exit).
    #   Two systems coexist: "tied-up slot = essence endurance" / "expansion slot = short-term conviction bet".
    override_slot_enabled: bool = True
    override_min_conviction: float = 55.0        # [2026-05-17 100-pt ×10] 8→80. Override Slot entry conviction threshold
    override_min_adx: float = 40.0               # ★ 2026-05-11 owner option A (50→40 relaxed)
    override_min_mtf_align: int = 4              # all TFs aligned (Phase 2B)
    override_min_b12_n: int = 7                  # 7+ of 8 coins agree (Phase 2B)
    override_require_btc_trend_match: bool = True  # BTC trend match required (Phase 2B)
    override_max_extra_slots: int = 3            # max +3 (expansion cap)
    override_locked_slot_min_hours: float = 6.0  # ★ window(h) — count only slots tied up beyond the set time (user knob)
    override_size_cap_pct: float = 8.0           # 8% of capital (less than half of the usual 20%)
    override_max_sl_distance_pct: float = 5.0    # SL 5% (1/4 of the usual 20%)
    override_breakeven_trigger_pct: float = 0.3  # BE locks fast (0.3%)
    override_hard_roe_cut_pct: float = -10.0     # ★ Hard ROE -10% instant cut (against betrayal)

    # ── Momentum Reversal (Phase 4's hard penalty 18) ──
    momentum_reversal_enabled: bool = True             # detect 1~3-bar 5m reversal right before entry (default ON)
    momentum_reversal_strong_atr: float = 1.0          # 5m 1-bar reversal ≥ ATR×1.0 → strong reversal
    momentum_reversal_medium_atr: float = 0.5          # 5m 1-bar reversal ≥ ATR×0.5 → medium reversal
    momentum_reversal_strong_weight: float = -30.0     # [2026-05-17 100-pt ×10] -3→-30. strong-reversal penalty
    momentum_reversal_medium_weight: float = -20.0     # [2026-05-17 100-pt ×10] -2→-20. medium-reversal penalty
    momentum_reversal_lookback_bars: int = 3           # 5m cumulative lookback bars

    long_hold_timeout_tier1_min: float = 5.0           # [2026-05-13] T1 Never-Green: 5 min + peak<0.01% — cut if never green right after entry (loss-side symmetry of BE Stall)
    long_hold_timeout_tier1_peak_pct: float = 0.01     # effectively "never green"
    long_hold_timeout_tier2_min: float = 15.0          # [2026-05-13] T2 "block the 5-min graduation amnesty": 15 min + peak<0.05% — slightly green but no further progress
    long_hold_timeout_tier2_peak_pct: float = 0.05
    long_hold_timeout_tier3_min: float = 30.0          # [2026-05-13] T3 BE-distant: 30 min + peak<0.2% — didn't reach even half the BE trigger (0.4%) = no momentum
    long_hold_timeout_tier3_peak_pct: float = 0.2      # [2026-05-13 new] added a peak condition to tier3 too (abandoned absolute-time cut)

    # ── ★ Entry Expectation (2026-05-14 owner — entry-expectation mechanism) ──
    # At entry, compute reward_target/risk_invalidation from H4 S/R structure → unify with exchange TP/SL.
    # Exit by progress % toward target, not by time (LHT). Scientific replacement for the LHT time cut.
    # [2026-05-20 owner decision] default ON — Zone-aware SL/TP is the *default*. The owner's manual-exit spots (resistance/support lines)
    # and the bot's automation work at the same spots. ATR fallback when not computable (safe).
    entry_expectation_enabled: bool = True             # compute reward/risk at entry + unify with exchange TP/SL
    expectation_progress_exit_enabled: bool = True    # progress-based exit (replaces LHT time cut)
    # [2026-05-15 owner] H1-close-aligned defaults: t1=60 min (1 bar) / t2=120 min (2 bars). Live config takes JSON priority.
    expectation_progress_t1_min: float = 240.0          # T1: after N min
    expectation_progress_t1_pct: float = 30.0          # T1: cut if target progress < M%
    expectation_progress_t2_min: float = 480.0         # T2: after N min
    expectation_progress_t2_pct: float = 50.0          # T2: cut if target progress < M%
    # ── ★ Negative-progress instant cut (2026-05-15 owner) ──
    # Large negative progress = clearly going the opposite of target → fast cut, don't wait for the time cut.
    # Cases like XRP -628% / DOGE -32% get cut around -100% at the 30-min mark (smaller loss than SL).
    expectation_progress_neg_cut_enabled: bool = True
    expectation_progress_neg_cut_pct: float = -50.0    # progress at/below this (e.g. -50 = 50% progress opposite the target)
    expectation_progress_neg_cut_min: float = 30.0     # cut if held at least this long + above condition met
    # ── ★ Entry Quality Gates (2026-05-15 owner) ──
    # #1 entry_expectation Gate: RR floor + risk_pct cap — block junk entries like SIREN RR=0.18
    # #2 FLIP alignment: scanner LONG→Anti-Knife block→on SHORT flip, block if both H1+30M are UPTR
    #    (targets the DOGE "signal long / position short" pattern)
    # Both default OFF — enable via UI toggle and adjust thresholds. #1 works only if entry_expectation_enabled is ON.
    entry_expectation_gate_enabled: bool = True       # ★ #1: RR/risk/reward threshold block
    entry_expectation_min_rr: float = 1.0              # [2026-05-20 owner operational] spec 1.5 → owner relaxed to 1.0 (entry bar too high)
    entry_expectation_max_risk_pct: float = 6.0        # block entry if risk_pct > this value(%) (5/15 SIREN-incident safety net)
    entry_expectation_min_reward_pct: float = 0.8      # [2026-05-20 5-14 spec Phase 2] block if reward < 0.8% (insufficient reach potential)
    # ── 🌍 [2026-06-02 macro regime = direction gate] Market Breadth (top-10 tsunami). Owner's essence. UI-adjustable ──
    #   Broad decline/rise = SHORT/LONG opportunity (alignment bonus) / against = falling knife (block). Not 'stop' but 'read direction'.
    breadth_strong_n: int = 10              # STRONG threshold: N/10 coins in unison = strong tsunami
    breadth_mid_n: int = 8                 # MID threshold: N/10 = medium tsunami
    breadth_aligned_strong: float = 12.0   # aligned (follow the flow) STRONG bonus (opportunity) — owner "actively contrarian"
    breadth_aligned_mid: float = 6.0       # aligned MID bonus
    breadth_counter_strong: float = -24.0  # counter (against the flow = falling knife) STRONG penalty (block)
    breadth_counter_mid: float = -12.0      # counter MID penalty
    # ★ [2026-06-08 owner ⑤] conviction cap on macro STRONG counter (tsunami = confirmed falling knife) —
    #   blocks individual strength (trend/PA) from overwhelming the macro-counter penalty (-25) so the score won't drop.
    #   Solves both "score won't drop so it keeps trying + entering a bad spot on a stale score when the knife releases" (owner's chained insights).
    regime_counter_strong_cap_enabled: bool = True   # on macro STRONG counter, cap counter-direction conviction ON
    regime_counter_strong_cap: float = 50.0          # cap value (below scanner/guard threshold → no entry + score definitely drops)
    # ★ [2026-06-08 owner "stand on two legs"] SHORT release — corrects the bot's LONG bias (4 servers 100% LONG).
    #   If macro decline is confirmed (release_n, mid-grade 7), let SHORT alignment pass through the final gate (15M=UPTR counter) = balance at LONG's level.
    regime_short_release_enabled: bool = True   # on macro decline, let SHORT alignment pass the final gate
    regime_short_release_n: int = 6             # [2026-06-09 owner] 7→6 — removes the one-step gap from the MID threshold (crash judgment): release SHORT once RISK_OFF appears (rule: release_n ≤ MID threshold)
    # ── 🦵 [2026-06-11 owner "free both legs"] per-coin decoupling SHORT release ──
    #   Diagnosis: if BTC=BULL, btc_regime applies a uniform LONG+10/SHORT-20 to *all coins* → even if a coin collapses on its own,
    #         SHORT can't fill the -20 hole + HTF lag (-9) so it can never win on score = one leg tied.
    #   Fix (owner "per-coin decoupling only"): only when the market (BTC 6TF) is one direction but the coin's own 6TF structure is *clearly opposite*,
    #         release the suppressed weaker leg (SHORT release+ / counter-leg penalty-). 0 effect on coins following the trend (coin==btc).
    #   ★ Both coin and BTC use _compute_regime_direction (6TF composite, owner "perfect") = consistent. default OFF.
    coin_decouple_enabled: bool = True          # per-coin decoupling SHORT release ON/OFF (2026-06-12 owner "default ON")
    coin_decouple_short_release: float = 22.0   # on decoupling, bonus to the coin's structural direction (weaker leg) (offsets the btc -20 hole +α)
    coin_decouple_long_penalty: float = 12.0    # on decoupling, penalty to the counter leg (catching a falling knife)
    coin_decouple_min_strength: float = 0.5     # min coin 6TF conviction (0~1) — excludes weak wobble (bouncy-coin guard)
    coin_decouple_btc_cache_sec: float = 120.0  # BTC 6TF direction cache TTL (sec) — compute once per scan
    # ── 🦵🌊 [2026-06-12 owner "catch both up and down"] momentum decouple — the *leading* version of coin_decouple ──
    #   Problem: coin_decouple above decides decoupling via _compute_regime_direction (analyze_structure=structural classification) → structure
    #         waits for a *confirmed* lower-high/low so it lags. A ceiling coin's 6TF structure is still UP (it climbed) → never fires (0 logs).
    #   Fix: make the detection primitive the inflection up (slope15m+MACD histo Δ = momentum derivative, *leading*). Owner's gut "if the score
    #         55→…→75→73→71 turns down, SHORT right there" = the moment up turns negative at the ceiling.
    #   Gate (per-coin isolation): BTC 6TF regime vs coin momentum *opposite* + divergence from BTC momentum (div) + position extended.
    #         → 0 for coins still climbing fine on the wall (momentum alive), 0 for those pulling back with the market (insufficient div).
    #   Value: inflection-formula scale (the higher the ceiling strength pos × momentum-death, owner's "if 75 then -75 firmly" magnitude gut) → *conviction*
    #         addition (reflected in dual direction selection = *choose* SHORT. guard inflection ㉒ is a gate, so it was irrelevant to direction choice).
    #   Whip defense = 2-stage trigger (final_5m/1m). Sim: sim_fast_decouple.py. default OFF — owner turns on in v3 + restart.
    mom_decouple_enabled: bool = False           # momentum-decouple conviction release ON/OFF (live the moment it's on)
    mom_decouple_weight: float = 30.0            # W: conviction adjustment scale (inflection formula). ~30 to flip a 50-pt gap (sim)
    mom_decouple_cap: float = 35.0              # output clamp ±cap
    mom_decouple_base: float = 0.45             # base: default adjustment from position alone (momentum 0). same as inflection
    mom_decouple_up_thr: float = 0.40           # min |momentum up| — below this = 'not a turn' (noise), won't fire
    mom_decouple_div_thr: float = 0.20          # min coin divergence from BTC momentum — excludes market-wide pullback (per-coin isolation)
    mom_decouple_pos_hi: float = 0.60           # SHORT-release position floor (ceiling) — prevents bottom shorts
    mom_decouple_pos_lo: float = 0.40           # LONG-release position cap (bottom) — prevents ceiling longs
    mom_decouple_btc_cache_sec: float = 60.0    # BTC 5m momentum cache TTL (sec) — compute once per scan
    # ── 🧭 [2026-06-06 owner P2] regime-compass RECOVERING bonus — keep LONG alive on post-crash recovery turn ('macro signal of a pullback') ──
    #   RISK_OFF/RISK_ON counter·aligned are already handled by the breadth additions above. Only the missing RECOVERING (recovery turn) is new.
    #   SOL high pre-empt=RISK_OFF (keeps counter -25) / TON pullback=RECOVERING (bonus). Fake recovery=only with DI+ADX together (dead-cat defense).
    macro_compass_enabled: bool = False             # default OFF (ON after paper verification)
    macro_recovering_conv_delta: float = 0.0        # RECOVERING LONG bonus / SHORT penalty magnitude (default 0=paper observe)
    macro_recovering_require_di_adx: bool = True     # dead-cat defense: LONG bonus only with +DI>-DI flip + ADX≥threshold together
    macro_recovering_min_adx: float = 20.0          # min ADX to confirm recovery (trend alive)
    # ── 🔄 [2026-06-02 Phase 3 live] M/W/H&S reversal-pattern score ──
    #   reversal direction == entry direction (aligned) → +reversal_score / counter → −. forming ×0.5, confirmed (BOS breakout) ×1.0
    reversal_score: float = 10.0
    # ★ [2026-06-03 owner] TF trend weight — default 1.0 (×6 = max 6). 0=off. exposed in UI Entry tab
    d1_trend_weight: float = 1.0   # D1 (daily) weight — big-picture direction (owner 2026-06-03)
    h4_trend_weight: float = 1.5   # H4 (4-hour) weight — adjustable in UI (owner 2026-06-03)
    h1_trend_weight: float = 1.5
    m30_trend_weight: float = 1.4
    m15_trend_weight: float = 1.4
    m5_trend_weight: float = 1.0
    # ★ [2026-06-14 owner BEAT incident] Fix A — cr direction-decision speed-sign guard.
    #   _compute_tf_change_rate decides direction (dominant_dir) by "count of up/down among 5 candles",
    #   but if the count is UP yet the actual net change rate (speed) is negative = fake UP → treat as neutral (FLAT).
    #   BEAT: H1 count UP but actually -4.52% decline → directly hit the label-vs-actual gap that gave LONG cr_H1 a + bonus.
    #   Direction-symmetric (neutralizes dominant_dir itself regardless of LONG/SHORT). default OFF.
    cr_speed_sign_guard_enabled: bool = True
    # ★ [2026-06-14 owner BEAT incident] Fix B — handle extreme surge/crash (blow-off) topping.
    #   if speed_ratio (change rate/ATR) exceeds the extreme = unsustainable topping → don't trust direction → neutral (FLAT).
    #   BEAT: directly hit where the D1 +103% surge afterglow gave cr_D1 9 pts to LONG. Direction-symmetric. default OFF.
    cr_blowoff_extreme_guard_enabled: bool = True
    cr_blowoff_extreme_ratio: float = 4.0   # speed/ATR at/above this = topping (lower = judges topping more often)
    # ★ [2026-06-14 owner BEAT incident] Fix C — cr big-trend-agreement guard.
    #   if the 5-candle dominant_dir (count) is opposite the net trend of a longer window (lookback), neutral (FLAT).
    #   directly hits the bot's cr view narrowed to 5 candles mistaking a relief bounce in a downtrend for UP.
    #   "build it and turn it on if A/B still fails" (owner). Direction-symmetric. default OFF.
    cr_trend_agree_guard_enabled: bool = False
    cr_trend_agree_lookback: int = 20   # candle count for the big-trend decision (wider than 5 candles — whole-chart direction)
    # ── 🌍 [2026-06-02] breadth direction-decision thresholds (when setting +1/0/−1 per coin) — exposed in UI (avoid burial) ──
    breadth_dir_chg1h_pct: float = 0.3    # 1-hour change-rate threshold % (primary)
    breadth_dir_ema_pct: float = 0.10     # 5-min EMA spread threshold % (secondary)
    entry_flip_require_alignment: bool = True         # ★ #2: block if the FLIP direction is opposite on both H1+30M
    # ── ★ [2026-05-28 owner ICP incident] block auto-entry FLIP ──
    # ICPUSDT LONG eval → MTF fail → auto SHORT FLIP → SHORT entry against the owner's intent.
    # Applied consistently with the FLIP block for manual entry (_is_manual=True) (5-20 fix) — auto is blocked too.
    # Owner's principle: "original-direction fail = fail as is. No auto-entry in the opposite direction."
    # Set True to restore old behavior (absolutely not recommended — ICP incident recurs).
    entry_auto_flip_enabled: bool = False              # ★ permanently block auto FLIP after the ICP incident

    # ── ★ Gap-check gate (2026-06-03 owner "no point entering without enough gap") ──
    # Before entry: if distance to the selected TF (5/15/30/60M) × N-bar high (LONG)/low (SHORT) < min_pct → reject entry.
    # After entry: pre-emptive exit when approaching the same TF's ceiling/bottom.
    gap_check_enabled: bool = True             # pre-entry gap check (default ON)
    gap_check_tf: str = "15"                   # check-TF choice: 5 / 15 / 30 / 60
    gap_check_lookback_bars: int = 12          # recent N bars (12×15M=3h / 12×30M=6h)
    gap_check_min_pct: float = 0.3             # min gap % (0=OFF, default 0.3% — 2026-06-04 owner decision)
    # ★ [2026-06-07 owner] gap ATR adaptation — a fixed 0.3% is the ceiling for high-swing coins. Make the required gap dynamic to the swing range (ATR).
    #   XLM case: 2% swing range yet passed with a 0.3% gap → entered at the ceiling → repeated SL. With ATR adaptation, high-swing coin = bigger required gap = ceiling blocked.
    #   Required gap = max(gap_check_min_pct, ATR% × gap_check_atr_mult), capped at gap_check_atr_cap_pct. Reuses the coin's own ATR.
    gap_check_atr_adaptive_enabled: bool = True    # swing-range adaptation ON (blocks ceiling-chasing in choppy markets)
    gap_check_atr_mult: float = 0.7                # required gap = ATR% × this (larger = enter only farther below)
    gap_check_atr_cap_pct: float = 1.5             # cap on ATR-adaptive required gap (prevents over-blocking volatility-explosion coins)
    gap_proximity_exit_enabled: bool = False   # exit on ceiling/bottom approach (default OFF)
    gap_proximity_exit_tf: str = "15"          # approach-exit basis TF: 5 / 15 / 30 / 60
    gap_proximity_exit_pct: float = 0.2        # approach threshold % (exit when within this)

    # ── ★ Volatility-reachability gate (2026-05-23 owner "can it reach TP with enough swing") ──
    # 29% bad-entry diagnosis: even if the reward distance (resistance) is far, *if volatility is dead it can't get there* (peak=0 → 4h endurance → loss).
    # Solution: at entry, verify recent actual swing is enough to cover the reward distance. Blocks dead sideways spots.
    entry_volatility_gate_enabled: bool = True         # verify volatility reachability right before entry (default ON)
    entry_volatility_lookback_tf: str = "5"            # swing-measurement TF (5-min)
    entry_volatility_lookback_bars: int = 12           # recent N bars (12×5min = 1 hour)
    entry_volatility_min_reach_ratio: float = 0.6      # recent swing / reward distance ≥ this ratio to enter (0.6 = need 60% of reward in volatility)

