    btc_regime_bear_short_delta: float = 10.0    # BTC BEAR + SHORT → no bonus (each on their own)
    btc_regime_trans_delta: float = -10.0         # BTC TRANS → transition uncertain = no penalty
    #
    # (D) Market Bias — recent N EXIT-direction skew tally
    # [2026-05-27 owner] conflicts with the H4/H1 PA pulse philosophy (recent-trade-skew penalty = ignore pulse signals)
    market_bias_enabled: bool = False       # old "go against the skew" → abandoned (PA pulse decides entry direction)
    mb_lookback_trades: int = 12               # recent N trades
    mb_lookback_hours: float = 6.0             # max time range
    mb_dominance_threshold: float = 0.5        # skew basis (0~1)
    mb_min_total: int = 4                      # min sample count
    mb_against_delta: float = -3.0            # [2026-05-17 100-pt ×10] -1→-10. penalty on entering against
    mb_cache_ttl_sec: float = 180.0            # 3-min cache

    # ── Pair Group Block (2026-04-19 user proposal, default OFF) ────────────────
    # User philosophy: "pair coins in opposite directions = only a fee loss" (offset 0.85+ correlated groups)
    # mode: "aggressive" = allow up to N same-direction, block only opposite
    #       "conservative" = 1 per group (block any direction)
    # Opposite-direction block is common to both modes. The user's goal ($1/min) fits aggressive.
    # ─ default OFF: don't enable without observation data. Turn on via toggle.
    pair_block_enabled: bool = True           # ★ default OFF — when enabled, blocks opposite direction
    pair_block_mode: str = 'conservative'        # "aggressive" | "conservative"
    pair_block_same_limit: int = 3             # max N same-direction within a group in aggressive mode

    # ── Coin Profit Lock-in (2026-04-19 user proposal, default OFF) ─────────────
    # Symmetric concept of the existing coin_loss_cap. Exit if it drops below the "cumulative-profit protection line".
    # Logic: exit if realized_N_hour + unrealized_current < realized_N_hour × protect_ratio
    # Fee guard: don't apply below min_realized (excludes meaningless small-profit protection)
    # H4-strategy conflict prevention: activate only after breakeven_locked (protects the normal pre-BE drawdown band)
    # ─ default OFF: skeleton only, needs parameter tuning after data accumulates.
    coin_profit_lockin_enabled: bool = True   # ★ default OFF
    coin_profit_lockin_window_hours: float = 4.0   # cumulative-computation window
    coin_profit_lockin_min_realized: float = 30.0  # min realized profit ($). Below this, Lock-in doesn't apply
    coin_profit_lockin_protect_ratio: float = 0.7  # protection-line ratio (70% = allow giving back only 30% of cumulative profit)
    coin_profit_lockin_require_be: bool = True     # activate only after BE lock (H4-strategy conflict prevention)

    # ── PA Pattern Conviction Weight (2026-04-24, owner decision) ──────────────
    # Thai GreenPen's original 5 patterns + new BOS → added to conviction.
    # "PA = formula, fee = variable" → the stronger the PA, the larger the size to dilute fees.
    # Post-addition conviction range: 0~10 → 0~16 (PA 0~6).
    #
    # ★ HARPOON ↔ FOCUS differentiation (owner's gut):
    #   - FOCUS = feeds on H4 swings → favors STAR_V1 (Morning/Evening Star)
    #   - HARPOON = M1/M5 short-term → favors PIN_BAR/ENGULFING/SQUEEZE/BOS
    #   focus_manager._compute_pa_weight() uses these values when caller="focus",
    #   and HarpoonConfig's pa_weight_* when "harpoon".
    pa_weight_enabled: bool = True             # default ON (owner decision)
    # [2026-05-19 owner decision] "UI value = actual conviction effect" — removed the old 1/2/3 ×1.67 trick.
    # New values = 0~10 native (cap 10). The UI value goes straight into the conviction PA region (0~10).
    pa_weight_pin_bar: int = 2                 # PIN_BAR (short-term signal, possibly noise)
    pa_weight_engulfing: int = 3               # ENGULFING (2-bar reversal)
    pa_weight_star_v1: int = 5                 # STAR_V1 (3-bar reversal, strong)
    pa_weight_star_v2: int = 5                 # STAR_V2 (3-bar variant, equivalent)
    pa_weight_squeeze_break: int = 3           # SQUEEZE_BREAK (volatility breakout)
    pa_weight_bos: int = 3                     # BOS_BULLISH/BEARISH (structure breakout)
    pa_weight_zone_bonus: int = 2              # Zone-proximity extra bonus
    pa_zone_proximity_atr: float = 0.5         # within 0.5 ATR of zone = counts as "near"
    pa_location_penalty_far: float = 0.5       # beyond 0.5 ATR of zone, PA score × 0.5 (emphasized in the Thai original)
    # ── config migration version (2026-06-20 new, mirrors the spot pattern) ──
