class FocusManager:
    """Standalone FOCUS strategy manager."""

    def __init__(self, system: Any = None):
        self.system = system
        self._lock = threading.RLock()
        # ── [2026-05-15 Tick lock separation] config-only lock ──
        #   Problem: update_config shares self._lock with tick (16-coin scan·MTF·network I/O)
        #         → dashboard config save waits out a whole heavy tick (feels like 30~60 sec).
        #   Fix: update_config grabs only _config_lock and returns immediately + sets _config_dirty.
        #         The actual file save (_save_config) flushes while holding _lock at the start of the next tick.
        #         → config reflects in memory immediately, file persistence lags ≤5 sec (acceptable for a tuning knob).
        self._config_lock = threading.Lock()
        self._config_dirty = False

        # Config
        self.config = FocusConfig()
        # ★ [2026-06-23] exchange isolation — config/state file path. If a subclass (BinanceFutures)
        #   sets self._config_path *before* super().__init__(), that value is preserved (getattr or).
        #   default=Bybit futures (existing behavior). _save_config/_load_config use this path.
        self._config_path = getattr(self, "_config_path", None) or CONFIG_PATH

        # near-miss ring buffer for score-passing but last-minute-blocked entries (for peer brief exposure, 2026-06-07 owner)
        self._recent_near_miss = deque(maxlen=20)

        # State
        self.state = FocusState.DORMANT
