        self.recent_skips: List[Dict] = []   # [{ts, market, direction, conviction, pa, reason}]
        self.recent_skips_max: int = 50
        # ★ [2026-06-23] per-exchange journal isolation — unified via self._journal/self._journal_path.
        #   Bybit (default)=global singleton·self._journal_path as-is (get_journal returns the same instance=0 change).
        #   If a subclass (BinanceFutures) sets self._journal_path before super(), it uses a dedicated journal.
        from app.manager.trade_journal import get_journal as _get_journal, JOURNAL_PATH as _DEFAULT_JOURNAL_PATH
        self._journal_path = getattr(self, "_journal_path", None) or _DEFAULT_JOURNAL_PATH
        self._journal = _get_journal(self._journal_path)
        # ★ [2026-06-15 solution B / master §9.2-B] GateLedger — visualize "why it stayed silent today" (F3).
        #   Doesn't touch entry logic (observe only). The ledger object is always created (in-memory, cheap) → records only when
        #   config.gate_ledger_enabled (UI toggle = no restart needed). One record() call at reject/entry points.
        self._gate_ledger = None
        try:
            from app.manager.focus_gate_ledger import GateLedger
            _gl_flush = float(os.getenv("FOCUS_GATE_LEDGER_FLUSH_SEC", "60") or "60")
            # ★ [2026-06-23 audit medium#5] derive flush_path from the journal directory — fixes the isolation gap
            #   where Bybit/Binance futures overwrote the same runtime/focus_gate_stats.json every 60 sec (same
            #   pattern as spot). Bybit=dirname(runtime/focus_harpoon_journal.jsonl)=runtime → existing path 0 change.
            _gl_path = os.path.join(os.path.dirname(self._journal_path) or "runtime", "focus_gate_stats.json")
            self._gate_ledger = GateLedger(flush_path=_gl_path, flush_sec=_gl_flush)
            # ★ register a sink on the journal BLOCKED single funnel — tallies all core gates (BB_REGIME/guard_score/
            #   auto_flip/micro_1m/pair_block). Records only when config.gate_ledger_enabled.
            from app.manager.trade_journal import journal as _jnl

            def _gate_sink(strategy, market, direction, reason):
                if (str(strategy).upper() == "FOCUS"
                        and self._gate_ledger is not None
                        and self.config.gate_ledger_enabled):
                    self._gate_ledger.record(market, str(reason or "-"), passed=False, direction=str(direction or "-"))
            self._journal._gate_sink = _gate_sink
        except Exception as _gl_exc:  # noqa: BLE001 — FocusManager runs fine even if ledger creation fails
            logger.debug("[FOCUS] GateLedger init skipped: %s", _gl_exc)
        # ★ [2026-06-15 solution C / master §9.2-C] detect weak-server grade once (RAM, INV-7) → cache.
