    # ── Trade Client ────────────────────────────────────────

    @staticmethod
    def _is_live_mode() -> bool:
        """Whether in live-trading mode — single source of truth.

        [2026-05-25 owner] LIVE = TRADING_MODE=LIVE AND AUTOBOT_LIVE=1 (both required, safe side).
        Otherwise (PAPER or AUTOBOT_LIVE=0) = paper/dry. Judged only here so that the paper
        decisions of _get_client / SYNC / entry-validation don't diverge.
        """
        import os
        return (os.getenv("TRADING_MODE", "PAPER").upper() == "LIVE"
                and os.getenv("AUTOBOT_LIVE", "0") == "1")

    def _live_active(self) -> bool:
        """Whether the live client is *actually* active — env LIVE judgment + subclass paper opt-out.

        [2026-06-23 audit] _is_live_mode() (env: TRADING_MODE+AUTOBOT_LIVE) is a global judgment, so it can't
        reflect a subclass's (BinanceFutures) _force_paper (per-exchange paper-first).
        Gates that touch the real account (position sync / entry validation / margin query) must use this method
        to prevent real API calls · phantom-position deletion · DORMANT incidents when paper is intended.
        Bybit FocusManager has no _force_paper → getattr False → same as _is_live_mode() (0 change).
        """
        return self._is_live_mode() and not getattr(self, "_force_paper", False)

    def _make_real_client(self):
        """Create the live client — exchange swap seam. Overridden by a subclass (BinanceFutures).
        Default=Bybit futures (linear). The paper wrap (FocusDryClient) is handled by _get_client."""
        from app.integrations.bybit_trade import BybitTradeClient
        return BybitTradeClient(category="linear")

    def _get_client(self):
        """Lazy-init separate trade client for linear perpetual (exchange=_make_real_client).

        [2026-05-25 owner] in paper/dry mode (TRADING_MODE=PAPER or AUTOBOT_LIVE=0),
        wrap with FocusDryClient — prices are real Bybit, orders/balance are virtual.
        LIVE requires both TRADING_MODE=LIVE AND AUTOBOT_LIVE=1 (safe side).
        """
        if self._client is None:
            import os
            _real = self._make_real_client()
            logger.info("[FOCUS] Linear perpetual client initialized (%s)", getattr(_real, "EXCHANGE_TYPE", "bybit"))
            # ★ [audit bug#1] _force_paper = block real orders until a subclass (BinanceFutures) explicitly opts in.
            #   Bybit FocusManager has no this attr → getattr False → 0 change to existing behavior.
            if self._is_live_mode() and not getattr(self, "_force_paper", False):
                self._client = _real
            else:
                from app.integrations.focus_dry_client import FocusDryClient
                _vusdt = float(os.getenv("DRY_INITIAL_USDT", "1000") or "1000")
                _slip_bps = max(0.0, float(getattr(self.config, "paper_slippage_bps", 0.0) or 0.0))
                self._client = FocusDryClient(_real, virtual_usdt=_vusdt, slippage_bps=_slip_bps)
        return self._client

    # ── [2026-05-26 owner] TF-round anchor TP/SL + endure (faithful to the textbook) ──
    def _tf_round_active(self) -> bool:
        """Whether TF-round TP/SL is active — checks only enabled (owner 2026-05-28 simplification)."""
        return bool(getattr(self.config, "tf_round_tpsl_enabled", False))

    def _hold_mode_active(self) -> bool:
        """Endure mode — endure to the real TP2/SL with no short-cuts (TF-round active + hold ON)."""
        return bool(self._tf_round_active()
                    and getattr(self.config, "tf_round_hold_enabled", True))

    def _compute_tf_round_targets(self, market: str, direction: str, tf_override: str = None):
        """Textbook (internal-note/GreenPen) TP/SL: anchor=trade-TF recent high, TP=ATR×mult (100% round), SL=⅓ (RR 1:3).
        Returns (tp1, tp2, sl, atr) or None (falls back to cycle_tp on failure).
        ★ [2026-05-27 owner] added tf_override — split H4/H1 anchor per entry["_pa_via"].
           Owner's spirit "by the resistance line each H4, H1 candle indicates".
        """
        cfg = self.config
        # use tf_override if present, else the config default ("240")
        tf = str(tf_override) if tf_override else str(getattr(cfg, "tf_round_anchor_tf", "240") or "240")
        period = max(2, int(getattr(cfg, "tf_round_atr_period", 14)))
        tp_mult = float(getattr(cfg, "tf_round_tp_atr_mult", 1.0))
        tp2_mult = float(getattr(cfg, "tf_round_tp2_atr_mult", 2.0))
        sl_ratio = float(getattr(cfg, "tf_round_sl_ratio", 1.0 / 3.0)) or (1.0 / 3.0)
        anchor_lb = max(1, int(getattr(cfg, "tf_round_anchor_lookback", 2)))
        raw = self._get_client().get_kline(market, interval=tf, limit=period + anchor_lb + 6)
        if not raw or len(raw) < period + 2:
            return None
        ordered = list(raw)  # oldest-first; [start,open,high,low,close,...]
        trs = []
        for i in range(1, len(ordered)):
            h = float(ordered[i][2]); l = float(ordered[i][3]); pc = float(ordered[i - 1][4])
            trs.append(max(h - l, abs(h - pc), abs(l - pc)))
        if len(trs) < period:
            return None
        atr = sum(trs[-period:]) / period
        if atr <= 0:
            return None
        round1 = atr * tp_mult
        round2 = atr * tp2_mult
        sl_dist = round1 * sl_ratio
        # ★ Owner's rule (2026-05-26 corrected): anchor = the extreme of the "H4 candle after PA" (= textbook ไส้หลัง Sig rear-tail).
        #   Long = that candle's Low is the start → TP=Low+round, SL=Low−⅓round
        #   Short = that candle's High is the start → TP=High−round, SL=High+⅓round
        #   offset = how many candles behind forming (ordered[-1]) to use as the anchor.
        #   ※ Textbook precision: Pat1/2/3 → 2nd/3rd/4th candle after PA. Currently an offset approximation (PA-candle tracking is follow-up) — paper tuning.
        offset = max(0, int(getattr(cfg, "tf_round_anchor_offset", 0)))
        idx = -1 - offset
        if len(ordered) < abs(idx):
            return None
        a_high = float(ordered[idx][2]); a_low = float(ordered[idx][3])
        if direction == "LONG":
            anchor = a_low
            tp1 = anchor + round1; tp2 = anchor + round2; sl = anchor - sl_dist
        else:
            anchor = a_high
            tp1 = anchor - round1; tp2 = anchor - round2; sl = anchor + sl_dist
        logger.info("[FOCUS] TF-round %s %s: anchor=%.4f ATR(%s,%d)=%.4f round1=%.4f → TP1=%.4f TP2=%.4f SL=%.4f RR=%.1f",
                    market, direction, anchor, tf, period, atr, round1, tp1, tp2, sl,
                    (1.0 / sl_ratio) if sl_ratio > 0 else 0.0)
        return (tp1, tp2, sl, atr)

    def _frame_guard_option_b_active(self) -> bool:
        """Whether Frame Guard option B is active — checks only enabled (owner 2026-05-28 simplification)."""
        return bool(getattr(self.config, "frame_guard_option_b_enabled", False))

    def _check_frame_guard(self, market: str, direction: str) -> tuple:
        """Frame guard — position within the 24h range. Owner's 2026-05-26 diagnosis.
        Enforces the "Frame" of the textbook "Trend > Frame(S/R) > Sig".
        ★ Option B (2026-05-27, paper only): default 50→60%/40% + 70%/30% on strong-trend alignment.
        LIVE keeps the existing 50%/50% (protects the office).
        Returns (blocked: bool, reason: str)"""
        cfg = self.config
        if not getattr(cfg, "frame_guard_enabled", True):
            return (False, "")
        tf = str(getattr(cfg, "frame_guard_range_tf", "240") or "240")
        n = max(1, int(getattr(cfg, "frame_guard_range_bars", 6)))
        option_b = self._frame_guard_option_b_active()
        if option_b:
            # option B (paper): default cutoff 60%/40% + 70%/30% on strong-trend alignment
            short_min = float(getattr(cfg, "frame_guard_short_min_pos_b", 0.40))
            long_max = float(getattr(cfg, "frame_guard_long_max_pos_b", 0.60))
        else:
            # LIVE: existing 50%/50% (owner's 5/26 verified value)
            short_min = float(getattr(cfg, "frame_guard_short_min_pos", 0.50))
            long_max = float(getattr(cfg, "frame_guard_long_max_pos", 0.50))
        # strong-trend-alignment cutoff (used only when option B is active)
        short_min_aligned = float(getattr(cfg, "frame_guard_trend_aligned_short_min_pos", 0.30))
        long_max_aligned = float(getattr(cfg, "frame_guard_trend_aligned_long_max_pos", 0.70))
        slope_thr = float(getattr(cfg, "frame_guard_trend_slope_pct", 1.5))
        try:
            raw = self._get_client().get_kline(market, interval=tf, limit=n + 2)
            if not raw or len(raw) < 2:
                return (False, "")  # insufficient data = pass safely
            ordered = list(raw)  # oldest-first
            win = ordered[-(n + 1):]  # recent (n+1) bars (incl. forming)
            hi = max(float(c[2]) for c in win)
            lo = min(float(c[3]) for c in win)
            if hi <= lo:
                return (False, "")  # flat = skip
            first_close = float(win[0][4])
            last_close = float(win[-1][4])
            pos = (last_close - lo) / (hi - lo)
            mid = (hi + lo) / 2.0
            slope_pct = ((last_close - first_close) / first_close * 100.0) if first_close > 0 else 0.0
            d = (direction or "").upper()
            # trend-alignment decision (only when option B is active — strong trend + entry direction matches + past box middle)
            long_aligned = option_b and (d == "LONG" and slope_pct >= slope_thr and last_close > mid)
            short_aligned = option_b and (d == "SHORT" and slope_pct <= -slope_thr and last_close < mid)
            # decide cutoff
            if long_aligned:
                cutoff = long_max_aligned
                tag = "B-STRONG-UPTREND+LONG slope=+%.1f%%" % slope_pct
            elif short_aligned:
                cutoff = short_min_aligned
                tag = "B-STRONG-DOWNTREND+SHORT slope=%.1f%%" % slope_pct
            elif d == "LONG":
                cutoff = long_max
                tag = ("B-DEFAULT" if option_b else "LIVE") + " slope=%+.1f%%" % slope_pct
            elif d == "SHORT":
                cutoff = short_min
                tag = ("B-DEFAULT" if option_b else "LIVE") + " slope=%+.1f%%" % slope_pct
            else:
                return (False, "")
            # block decision
            if d == "SHORT" and pos < cutoff:
                return (True, "frame_guard: SHORT rejected - range position %.0f%% < %.0f%% [%s] (forcing a bottom-catch)"
                        % (pos * 100, cutoff * 100, tag))
            if d == "LONG" and pos > cutoff:
                return (True, "frame_guard: LONG rejected - range position %.0f%% > %.0f%% [%s] (forcing a top-catch)"
                        % (pos * 100, cutoff * 100, tag))
            return (False, "frame_guard OK %s pos=%.0f%% cutoff=%.0f%% [%s]"
                    % (d, pos * 100, cutoff * 100, tag))
        except Exception as exc:
            logger.debug("[FOCUS] _check_frame_guard error: %s", exc)
            return (False, "")  # pass safely on error

