    def _check_5m_emergency_exit(self, market: str, direction: str) -> tuple:
        """Emergency exit on a 5M RSI/MACD/BB reversal signal ("stop here!").
        Owner's spirit (2026-05-27): time/peak-independent, exit on 5M visual reversal alone.
        LONG exit: RSI > overbought + downward inflection / MACD hist positive→negative / BB top reached
        SHORT exit: RSI < oversold + upward inflection / MACD hist negative→positive / BB bottom reached
        Exit when N of 3 are met (default 2/3).
        Returns (should_exit: bool, reason: str).
        """
        try:
            raw = self._get_mtf_kline(market, "5", limit=30)
            if not raw or len(raw) < 27:
                return (False, "")
            closes = [float(r[4]) for r in raw]
            from app.strategy.indicators import rsi_with_prev, macd_hist_pair, bollinger_bands as _bb_fn
            rsi_now, rsi_prev = rsi_with_prev(closes, length=14)
            hist_now, hist_prev = macd_hist_pair(closes)
            bb_now = _bb_fn(closes, length=20, k=2.0)
            if not bb_now or bb_now.get("upper", 0) <= bb_now.get("lower", 0):
                return (False, "")
            bb_pct = ((closes[-1] - bb_now["lower"]) / (bb_now["upper"] - bb_now["lower"])) * 100.0
            cfg = self.config
            rsi_overbought = float(getattr(cfg, "exit_5m_rsi_overbought", 70.0))
            rsi_oversold = float(getattr(cfg, "exit_5m_rsi_oversold", 30.0))
            bb_top_pct = float(getattr(cfg, "exit_5m_bb_top_pct", 90.0))
            bb_bot_pct = float(getattr(cfg, "exit_5m_bb_bottom_pct", 10.0))
            min_score = int(getattr(cfg, "exit_5m_min_score", 2))
            d = (direction or "").upper()
            score = 0
            signals = []
            if d == "LONG":
                # ① RSI overbought + downward inflection
                if rsi_now is not None and rsi_prev is not None:
                    if rsi_now > rsi_overbought and rsi_now < rsi_prev:
                        score += 1
                        signals.append("RSI%.0f>%.0f↓" % (rsi_now, rsi_overbought))
                # ② MACD hist positive→negative or shrinking positive
                if hist_now is not None and hist_prev is not None and hist_prev > 0:
                    if hist_now < 0 or hist_now < hist_prev:
                        score += 1
                        signals.append("MACD%.3f→%.3f↓" % (hist_prev, hist_now))
                # ③ BB top reached
                if bb_pct > bb_top_pct:
                    score += 1
                    signals.append("BB%.0f%%>%.0f%%" % (bb_pct, bb_top_pct))
            elif d == "SHORT":
                # ① RSI oversold + upward inflection
                if rsi_now is not None and rsi_prev is not None:
                    if rsi_now < rsi_oversold and rsi_now > rsi_prev:
                        score += 1
                        signals.append("RSI%.0f<%.0f↑" % (rsi_now, rsi_oversold))
                # ② MACD hist negative→positive or shrinking negative
                if hist_now is not None and hist_prev is not None and hist_prev < 0:
                    if hist_now > 0 or hist_now > hist_prev:
                        score += 1
                        signals.append("MACD%.3f→%.3f↑" % (hist_prev, hist_now))
                # ③ BB bottom reached
                if bb_pct < bb_bot_pct:
                    score += 1
                    signals.append("BB%.0f%%<%.0f%%" % (bb_pct, bb_bot_pct))
            else:
                return (False, "")
            if score >= min_score:
                return (True, "5M_EMERGENCY_%s:%s(%d/3)" % (d, ",".join(signals), score))
            return (False, "5M_emergency_partial(%d/3):%s" % (score, ",".join(signals) if signals else "no_sig"))
        except Exception as exc:
            logger.debug("[FOCUS] _check_5m_emergency_exit error %s: %s", market, exc)
            return (False, "")

