    def execute_amnesty(self) -> dict:
        """★ 2026-04-23 owner direct directive: General Amnesty.
        "It was done when the law was lacking, so let's release them for now"

        Release all accumulated-penalty records from the B11 single-judge era:
        1. _last_exit_*  : release the re-entry block
        2. _manual_exit_penalties : fully release manual-exit penalties
        3. _amnesty_ts   : only journal events after this time count toward penalties
                          (affects direction_exhaustion / profit_exit_block / coin_loss_cap
                           / coin_repeat_brake / dm_streak_block / B12 vote)

        The journal records themselves are preserved (keep the audit trail).
        Returns: amnesty-result summary dict."""
        prev_manual = dict(self._manual_exit_penalties)
        prev_last_exit = {
            "market": self._last_exit_market,
            "direction": self._last_exit_direction,
            "ts": self._last_exit_ts,
        }
        # 1. immediate penalty release
        self._manual_exit_penalties.clear()
        self._last_exit_market = ""
        self._last_exit_direction = ""
        self._last_exit_ts = 0.0
        self._last_exit_price = 0.0
        # 2. restart the journal-based penalty clock
        self._amnesty_ts = time.time()
        logger.info(
            "[FOCUS] ★ GENERAL AMNESTY executed at %.0f — "
            "cleared %d manual_penalties, cleared last_exit_* (%s %s), "
            "journal penalty filter now >= %s",
            self._amnesty_ts,
            len(prev_manual),
            prev_last_exit["market"] or "-",
            prev_last_exit["direction"] or "-",
            time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(self._amnesty_ts)),
        )
        # ★ [2026-05-11 agent-miss fix] persist state immediately after AMNESTY
        #   if missed: restart -> _amnesty_ts=0 -> consecutive_loss_pause re-applies (an owner incident)
        try:
            self._save_config()
            logger.info("[FOCUS] AMNESTY state persisted to disk (_amnesty_ts=%.0f)", self._amnesty_ts)
        except Exception as exc:
            logger.warning("[FOCUS] AMNESTY save_config failed: %s", exc)
        return {
            "ok": True,
            "amnesty_ts": self._amnesty_ts,
            "cleared_manual_penalties": len(prev_manual),
            "cleared_last_exit": prev_last_exit,
            "message": "General Amnesty executed. All coin-level penalties released.",
        }

    def _get_b12_breadth_vote(self) -> dict:
        """B12: direction count of the entry attempts the scanner saw within the recent b12_window_sec.

        Extract (market, direction) from journal BLOCKED + ENTRY events -> latest 1 per market.

        ★ 2026-04-23 02:30 owner-found chicken-and-egg fix:
           Right after a B11->B12 switch, BLOCKED events haven't accumulated so vote 0/0 -> a forever-NEUTRAL trap.
           Fix: auto-expand the window (3x -> 12x) when the primary window lacks data (<2 markets).
           e.g. 20 min short -> 60 min -> 240 min. Voice an opinion even with old data.
           The actual window used is exposed in UI as 'window_sec_used'.

        Returns: {
            'long_count': int, 'short_count': int, 'total_active': int,
            'verdict': 'BREADTH_BULL'/'BREADTH_BEAR'/'NEUTRAL',
            'window_sec': float (configured), 'window_sec_used': float (actual fallback),
            'threshold_n': int,
            'markets_long': [...], 'markets_short': [...]
        }
        """
        cfg = self.config
        n = int(getattr(cfg, "b12_threshold_n", 6))
        primary_window = float(getattr(cfg, "b12_window_sec", 1200.0))
        # Fallback ladder: 1x -> 3x -> 12x. Prefer voting even with old data.
        windows_to_try = [primary_window, primary_window * 3, primary_window * 12]
        latest_by_market = {}
        actual_window_sec = primary_window
        try:
            from app.manager.trade_journal import journal
            # ★ [2026-06-05] dashboard freeze fix -- replaced raw-open + full json.loads parsing of the 47MB journal
            #   on every status poll/scan with iterating the in-memory (write-through) cache.
            #   A recurrence of feedback_journal_cache_leak_fix (2026-05-15): only b12 was bypassing the cache.
            #   Same result (extract ts/market/direction of BLOCKED/ENTRY), 0.6~4.7 sec/call -> ~ms.
            self._journal._ensure_cache()
            if self._journal._cache:
                # iterate the cache -- evaluate all windows at once (no file I/O). Same pattern as get_trades/get_markets.
                all_records = []
                # ★ amnesty filter -- exclude events before amnesty_ts from the B12 vote
                amnesty_cutoff = float(getattr(self, "_amnesty_ts", 0.0))
                for rec in self._journal._cache:
                    try:
                        ts = rec.get("ts", 0)
                        if ts < amnesty_cutoff:   # ignore pre-amnesty records
                            continue
                        evt = rec.get("event", "")
                        if evt not in ("BLOCKED", "ENTRY"):
                            continue
                        mkt = (rec.get("market", "") or "").upper()
                        d = (rec.get("direction", "") or "").upper()
                        if not mkt or d not in ("LONG", "SHORT"):
                            continue
                        all_records.append((ts, mkt, d))
                    except Exception:
                        continue
                # apply a sliding window from the newest -- expand until enough data accumulates
                for window_sec in windows_to_try:
                    cutoff = time.time() - window_sec
                    candidates = {}
                    for ts, mkt, d in all_records:
                        if ts < cutoff:
                            continue
                        prev = candidates.get(mkt)
                        if not prev or ts > prev[1]:
                            candidates[mkt] = (d, ts)
                    if len(candidates) >= 2:  # min 2 markets -- vote possible
                        latest_by_market = candidates
                        actual_window_sec = window_sec
                        break
                # last resort: if all windows are short, use the largest window's data (whatever exists)
                if not latest_by_market and all_records:
                    cutoff = time.time() - windows_to_try[-1]
                    for ts, mkt, d in all_records:
                        if ts < cutoff:
                            continue
                        prev = latest_by_market.get(mkt)
                        if not prev or ts > prev[1]:
                            latest_by_market[mkt] = (d, ts)
                    actual_window_sec = windows_to_try[-1]
        except Exception as exc:
            logger.debug("[B12] vote scan error: %s", exc)
        long_markets = [m for m, (d, _) in latest_by_market.items() if d == "LONG"]
        short_markets = [m for m, (d, _) in latest_by_market.items() if d == "SHORT"]
        long_count = len(long_markets)
        short_count = len(short_markets)
        total_active = long_count + short_count
        # ★ 2026-04-23 owner v3: Net Consensus (subtract the opposite) -- strengthen "close-call NEUTRAL".
        #   old: long >= N AND long > short -> BULL  (even a close 6 vs 5 -> BULL -- risky)
        #   new: long - short >= N           -> BULL  (require +1 more per opposing vote)
        #   owner gut: "what if we require as many more as the opposing signals?"
        net_long = long_count - short_count       # + = LONG dominant, - = SHORT dominant
        if net_long >= n:
            verdict = "BREADTH_BULL"
        elif -net_long >= n:                       # = short - long >= n
            verdict = "BREADTH_BEAR"
        else:
            verdict = "NEUTRAL"
        return {
            "long_count": long_count,
            "short_count": short_count,
            "total_active": total_active,
            "net_long": net_long,                  # ★ new: shown in UI as "Net +X"
            "verdict": verdict,
            "window_sec": primary_window,
            "window_sec_used": actual_window_sec,
            "threshold_n": n,
            "markets_long": long_markets,
            "markets_short": short_markets,
        }

    def _check_market_breadth_lock(self, direction: str, market: str) -> tuple:
        """B12: direction enforcement based on the scanner chorus (2026-04-23 owner direct request).
        'if N+ of the 11 point the same direction, that direction only; if not met, don't interfere'

        - LONG_count >= N AND > SHORT_count -> BREADTH_BULL -> block SHORT
        - SHORT_count >= N AND > LONG_count -> BREADTH_BEAR -> block LONG
        - neither reaches N -> NEUTRAL -> no interference (both allowed, "a barrier-lowering tool")
        - lock_market bypass -- same policy as B11

        Returns: (blocked: bool, reason: str)"""
        cfg = self.config
        # lock_market bypass
        lock_mkt = (getattr(cfg, "lock_market", "") or "").upper()
        if lock_mkt and market.upper() == lock_mkt:
            return (False, "")
        vote = self._get_b12_breadth_vote()
        n = vote["threshold_n"]
        verdict = vote["verdict"]
        long_c = vote["long_count"]
        short_c = vote["short_count"]
        total = vote["total_active"]
        if verdict == "BREADTH_BULL" and direction.upper() == "SHORT":
            return (True, f"market_breadth_lock: BREADTH_BULL (LONG {long_c}/{total} >= N={n}) -> SHORT blocked")
        if verdict == "BREADTH_BEAR" and direction.upper() == "LONG":
            return (True, f"market_breadth_lock: BREADTH_BEAR (SHORT {short_c}/{total} >= N={n}) -> LONG blocked")
        # NEUTRAL or agreeing direction -- no interference
        return (False, "")

    def _detect_imminent_flip(self, target_regime: str) -> str:
        """[2026-05-16 owner insight] allow a step-ahead entry even within the freeze window.

        3 AND signals:
          (a) BTC EMA20-50 gap < imminent_flip_ema_gap_pct (reuses existing _btc_ema_gap_pct)
          (b) H1 (+30M option) EMA20-50 gap is narrowing -- smaller than lookback bars ago
          (c) ADX turning up -- >= +imminent_flip_adx_rise_min vs lookback bars ago

        direction = +DI > -DI -> BULL_IMMINENT / -DI > +DI -> BEAR_IMMINENT.
        Returns: "BULL_IMMINENT" | "BEAR_IMMINENT" | "NONE"
        """
        cfg = self.config
        if not getattr(cfg, "imminent_flip_enabled", False):
            return "NONE"
        try:
            # (a) BTC EMA gap (already updated as self._btc_ema_gap_pct in _check_regime_direction_lock)
            ema_gap = float(getattr(self, "_btc_ema_gap_pct", 999.0))
            gap_thr = float(getattr(cfg, "imminent_flip_ema_gap_pct", 0.3))
            if ema_gap >= gap_thr:
                return "NONE"

            # (b) H1 EMA gap narrowing trend
            h1_candles = self._get_btc_regime_candles()
            ema_short_n = int(getattr(cfg, "btc_regime_ema_short", 20))
            ema_long_n = int(getattr(cfg, "btc_regime_ema_long", 50))
            lookback = max(1, int(getattr(cfg, "imminent_flip_gap_lookback", 3)))
            if not h1_candles or len(h1_candles) < ema_long_n + lookback + 2:
                return "NONE"
            h1_closes = [float(c[4]) for c in h1_candles]

            def _ema_at(closes, period, end_idx):
                sub = closes[:end_idx]
                if len(sub) < period:
                    return None
                k = 2.0 / (period + 1.0)
                v = sum(sub[:period]) / period
                for p in sub[period:]:
                    v = p * k + v * (1 - k)
                return v

            es_now = _ema_at(h1_closes, ema_short_n, len(h1_closes))
            el_now = _ema_at(h1_closes, ema_long_n, len(h1_closes))
            es_prev = _ema_at(h1_closes, ema_short_n, len(h1_closes) - lookback)
            el_prev = _ema_at(h1_closes, ema_long_n, len(h1_closes) - lookback)
            if any(x is None for x in (es_now, el_now, es_prev, el_prev)):
                return "NONE"
            gap_now_h1 = abs(es_now - el_now)
            gap_prev_h1 = abs(es_prev - el_prev)
            if gap_now_h1 >= gap_prev_h1:
                return "NONE"

            # 30M auxiliary (option)
            if getattr(cfg, "imminent_flip_use_30m", True):
                try:
                    m30_raw = self._get_client().get_kline("BTCUSDT", interval="30", limit=ema_long_n + lookback + 5)
                    if m30_raw and len(m30_raw) >= ema_long_n + lookback + 2:
                        m30_closes = [float(c[4]) for c in m30_raw]
                        m_es_now = _ema_at(m30_closes, ema_short_n, len(m30_closes))
                        m_el_now = _ema_at(m30_closes, ema_long_n, len(m30_closes))
                        m_es_prev = _ema_at(m30_closes, ema_short_n, len(m30_closes) - lookback)
                        m_el_prev = _ema_at(m30_closes, ema_long_n, len(m30_closes) - lookback)
                        if all(x is not None for x in (m_es_now, m_el_now, m_es_prev, m_el_prev)):
                            if abs(m_es_now - m_el_now) >= abs(m_es_prev - m_el_prev):
                                return "NONE"
                        else:
                            return "NONE"
                    else:
                        return "NONE"
                except Exception as exc:
                    logger.debug("[FOCUS] imminent_flip 30M check failed: %s", exc)
                    return "NONE"

            # (c) ADX turning up + direction (DI comparison)
            try:
                from app.strategy.indicators import adx_series
            except Exception as exc:
                logger.debug("[FOCUS] imminent_flip adx_series import failed: %s", exc)
                return "NONE"
            h1_highs = [float(c[2]) for c in h1_candles]
            h1_lows = [float(c[3]) for c in h1_candles]
            adx_data = adx_series(h1_highs, h1_lows, h1_closes, 14)
            if not adx_data or len(adx_data) < lookback + 1:
                return "NONE"
            adx_now = float(adx_data[-1].get("adx", 0.0))
            adx_prev = float(adx_data[-1 - lookback].get("adx", 0.0))
            adx_rise_min = float(getattr(cfg, "imminent_flip_adx_rise_min", 2.0))
            if (adx_now - adx_prev) < adx_rise_min:
                return "NONE"

            plus_di = float(adx_data[-1].get("plus_di", 0.0))
            minus_di = float(adx_data[-1].get("minus_di", 0.0))
            if plus_di > minus_di:
                return "BULL_IMMINENT"
            if minus_di > plus_di:
                return "BEAR_IMMINENT"
            return "NONE"
        except Exception as exc:
            logger.debug("[FOCUS] _detect_imminent_flip error: %s", exc)
            return "NONE"

    def _check_same_coin_flip_cooldown(self, market: str, direction: str) -> tuple:
        """[2026-05-16 owner] N-min cooldown on new same-coin LONG<->SHORT entry.

        TAO case: 23:16 LONG -$10 -> 47 min later SHORT -$2.48 = lost both directions.
        BLOCK if the same coin's last EXIT was within N min and the direction is opposite.
        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "same_coin_flip_cooldown_enabled", True):
            return (False, "")
        cooldown_min = int(getattr(cfg, "same_coin_flip_cooldown_min", 60))
        if cooldown_min <= 0:
            return (False, "")
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(self._journal_path):
                return (False, "")
            mkt_upper = (market or "").upper()
            dir_upper = (direction or "").upper()
            cutoff_ts = time.time() - (cooldown_min * 60)
            # finding just the most recent EXIT is enough (reverse order)
            last_exit_dir = ""
            last_exit_ts = 0.0
            with open(self._journal_path, "r", encoding="utf-8") as f:
                lines = f.readlines()
            for line in reversed(lines[-500:]):  # cap at the recent 500 lines
                line = line.strip()
                if not line:
                    continue
                try:
                    rec = json.loads(line)
                except Exception:
                    continue
                if (rec.get("strategy") or "").upper() != "FOCUS":
                    continue
                if (rec.get("event") or "").upper() != "EXIT":
                    continue
                if (rec.get("market") or "").upper() != mkt_upper:
                    continue
                ts = float(rec.get("ts") or 0.0)
                if ts < cutoff_ts:
                    break  # ignore older ones
                last_exit_dir = (rec.get("direction") or "").upper()
                last_exit_ts = ts
                break
            if not last_exit_dir or last_exit_ts <= 0:
                return (False, "")
            # same direction = ignore cooldown (re-entry is handled by other guards)
            if last_exit_dir == dir_upper:
                return (False, "")
            elapsed_min = (time.time() - last_exit_ts) / 60.0
            remain_min = cooldown_min - elapsed_min
            return (True, f"same_coin_flip_cooldown: {last_exit_dir}->{dir_upper} {elapsed_min:.1f}m ago -> wait {remain_min:.1f}m more")
        except Exception as exc:
            logger.debug("[FOCUS] _check_same_coin_flip_cooldown error: %s", exc)
            return (False, "")

    def _check_raw_body_guard(self, market: str, direction: str) -> tuple:
        """[2026-05-16 owner insight] 5m raw-candle body = the "energy" guard.

        Sum of open->close over the recent N bars (5m). BLOCK if the net direction is opposite the entry direction.
        Catches spots that passed microtiming (RSI/MACD processed values) but whose raw price action is opposite.

        BILL case: 5m buy energy still alive yet SHORT entry -> instant +2% against (peak -0.17%).
        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "raw_body_guard_enabled", True):
            return (False, "")
        lookback = max(1, int(getattr(cfg, "raw_body_guard_lookback", 3)))
        min_net_pct = float(getattr(cfg, "raw_body_guard_min_net_pct", 0.0))
        try:
            client = self._get_client()
            # the most recent (lookback + 1) bars -- the last may be forming, so use the prior N bars
            raw = client.get_kline(market, interval="5", limit=lookback + 1)
            if not raw or len(raw) < lookback + 1:
                return (False, "")
            # Bybit kline: [start, open, high, low, close, volume, turnover] (newest at [0])
            # use only the prior lookback bars (index 1 ~ lookback)
            recent = raw[1:lookback + 1]
            net_sum = 0.0
            ref_price = float(recent[0][4]) if recent[0][4] else 0.0
            if ref_price <= 0:
                return (False, "")
            for bar in recent:
                open_p = float(bar[1])
                close_p = float(bar[4])
                net_sum += (close_p - open_p)
            net_pct = (net_sum / ref_price) * 100.0
            dir_upper = (direction or "").upper()
            # LONG entry but net sell (<0) / SHORT entry but net buy (>0) -> BLOCK
            if dir_upper == "LONG" and net_pct < -abs(min_net_pct):
                return (True, f"raw_body_guard: {lookback}-bar net={net_pct:+.3f}% (sell) -> block LONG")
            if dir_upper == "SHORT" and net_pct > abs(min_net_pct):
                return (True, f"raw_body_guard: {lookback}-bar net={net_pct:+.3f}% (buy) -> block SHORT")
            return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _check_raw_body_guard error: %s", exc)
            return (False, "")

    def _check_momentum_derivative_guard(self, market: str, direction: str) -> tuple:
        """[2026-05-16] Cache wrapper -- 25s TTL per (market, direction). Prevents duplicate state_machine calls."""
        cfg = self.config
        if not getattr(cfg, "momentum_deriv_guard_enabled", True):
            return (False, "")
        if not hasattr(self, '_guard_cache'):
            self._guard_cache = {}
        _key = ('mdg', (market or "").upper(), (direction or "").upper())
        _now = time.time()
        _cached = self._guard_cache.get(_key)
        if _cached and (_now - _cached[0]) < 25.0:
            return _cached[1]
        _result = self._check_momentum_derivative_guard_impl(market, direction)
        self._guard_cache[_key] = (_now, _result)
        return _result

    def _check_momentum_derivative_guard_impl(self, market: str, direction: str) -> tuple:
        """[2026-05-16 owner vision] RSI/MACD change-rate (1st-derivative) guard.

        Distinguishes "same RSI=50 but rising vs turning down".
        Compares the recent N-bar average vs the prior N-bar average -> BLOCK if accelerating/decelerating against the entry direction.

        - LONG entry but RSI is in a downtrend by >= -min_slope -> BLOCK
        - SHORT entry but RSI is in an uptrend by >= +min_slope -> BLOCK
        - if require_both=True, block only when both RSI+MACD are against; False, block if either is against

        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "momentum_deriv_guard_enabled", True):
            return (False, "")
        tf = str(getattr(cfg, "momentum_deriv_guard_tf", "5") or "5")
        lookback = max(2, int(getattr(cfg, "momentum_deriv_guard_lookback", 5)))
        rsi_slope_thr = float(getattr(cfg, "momentum_deriv_guard_rsi_min_slope", 2.0))
        macd_slope_thr = float(getattr(cfg, "momentum_deriv_guard_macd_min_slope", 0.0))
        require_both = bool(getattr(cfg, "momentum_deriv_guard_require_both", False))
        try:
            # fetch enough 5m bars (need RSI 14 + lookback*2 bars)
            need = 14 + lookback * 2 + 5
            raw = self._get_client().get_kline(market, interval=tf, limit=need)
            if not raw or len(raw) < need:
                return (False, "")
            # Bybit kline: [start, open, high, low, close, ...] (newest at [0])
            closes = [float(c[4]) for c in raw]  # old->new order

            try:
                from app.strategy.indicators import rsi_series, macd_hist_series
            except Exception as exc:
                logger.debug("[FOCUS] momentum_deriv import failed: %s", exc)
                return (False, "")

            rsi_vals = rsi_series(closes, 14)
            macd_hist = macd_hist_series(closes, 12, 26, 9)
            if not rsi_vals or len(rsi_vals) < lookback * 2:
                return (False, "")
            if not macd_hist or len(macd_hist) < lookback * 2:
                return (False, "")

            # recent N-bar average vs prior N-bar average
            rsi_recent = sum(rsi_vals[-lookback:]) / lookback
            rsi_prev = sum(rsi_vals[-2 * lookback:-lookback]) / lookback
            rsi_delta = rsi_recent - rsi_prev

            macd_recent = sum(macd_hist[-lookback:]) / lookback
            macd_prev = sum(macd_hist[-2 * lookback:-lookback]) / lookback
            macd_delta = macd_recent - macd_prev

            dir_upper = (direction or "").upper()

            # LONG: RSI down by >= -rsi_slope_thr or MACD hist down by >= -macd_slope_thr -> against
            # SHORT: RSI up by >= +rsi_slope_thr or MACD hist up by >= +macd_slope_thr -> against
            rsi_against = False
            macd_against = False
            if dir_upper == "LONG":
                rsi_against = rsi_delta < -abs(rsi_slope_thr)
                macd_against = macd_delta < -abs(macd_slope_thr)
            elif dir_upper == "SHORT":
                rsi_against = rsi_delta > abs(rsi_slope_thr)
                macd_against = macd_delta > abs(macd_slope_thr)
            else:
                return (False, "")

            if require_both:
                blocked = rsi_against and macd_against
            else:
                blocked = rsi_against or macd_against

            if blocked:
                reason = (f"momentum_deriv_guard: {dir_upper} counter flow "
                          f"(RSI Δ={rsi_delta:+.2f} {'AGAINST' if rsi_against else 'ok'}, "
                          f"MACD Δ={macd_delta:+.4f} {'AGAINST' if macd_against else 'ok'}, "
                          f"mode={'AND' if require_both else 'OR'})")
                return (True, reason)
            return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _check_momentum_derivative_guard error: %s", exc)
            return (False, "")

    def _classify_coin_state(self, market: str, direction: str) -> tuple:
        """[2026-05-16 owner vision #4] classify the coin's state at entry.

        Classification priority:
          1. CFID IMMINENT direction match -> FLIP_IMMINENT (strongest signal)
          2. momentum_deriv & mtf_align both BLOCK -> DECEL (most conservative)
          3. only one BLOCK -> STEADY (ambiguous)
          4. both OK -> ACCEL (normal)

        Returns: (state_label, conv_adjust)
          - state_label: "FLIP_IMMINENT" | "DECEL" | "STEADY" | "ACCEL" | ""
          - conv_adjust: dataclass value (per-stage conviction adjustment)
        """
        cfg = self.config
        # ★ [2026-05-28 evening owner] yellow master toggle -- skip in green-only mode (DECEL/STEADY penalty OFF)
        if not self._is_yellow_guard_active("entry"):
            return ("", 0)
        if not getattr(cfg, "coin_state_machine_enabled", True):
            return ("", 0)
        dir_upper = (direction or "").upper()
        if dir_upper not in ("LONG", "SHORT"):
            return ("", 0)
        try:
            # 1. CFID first (highest priority)
            cfid_dir, _cfid_str = self._detect_coin_flip_imminent(market)
            if ((dir_upper == "LONG" and cfid_dir == "BULL_IMMINENT") or
                (dir_upper == "SHORT" and cfid_dir == "BEAR_IMMINENT")):
                return ("FLIP_IMMINENT", int(getattr(cfg, "coin_state_flip_imminent_conv_adj", 1)))

            # 2/3. count momentum_deriv + mtf_align BLOCK
            md_blocked, _ = self._check_momentum_derivative_guard(market, direction)
            mtf_blocked, _ = self._check_mtf_momentum_alignment(market, direction)

            if md_blocked and mtf_blocked:
                return ("DECEL", int(getattr(cfg, "coin_state_decel_conv_adj", -2)))
            if md_blocked or mtf_blocked:
                return ("STEADY", int(getattr(cfg, "coin_state_steady_conv_adj", -1)))
            return ("ACCEL", int(getattr(cfg, "coin_state_accel_conv_adj", 0)))
        except Exception as exc:
            logger.debug("[FOCUS] _classify_coin_state error: %s", exc)
            return ("", 0)

    def _detect_coin_flip_imminent(self, market: str) -> tuple:
        """[2026-05-16] Cache wrapper -- 25s TTL per market. CFID is heavy (60+30 TF fetch)."""
        cfg = self.config
        if not getattr(cfg, "cfid_enabled", True):
            return ("NONE", 0.0)
        if not hasattr(self, '_guard_cache'):
            self._guard_cache = {}
        _key = ('cfid', (market or "").upper())
        _now = time.time()
        _cached = self._guard_cache.get(_key)
        if _cached and (_now - _cached[0]) < 25.0:
            return _cached[1]
        _result = self._detect_coin_flip_imminent_impl(market)
        self._guard_cache[_key] = (_now, _result)
        return _result

    def _detect_coin_flip_imminent_impl(self, market: str) -> tuple:
        """[2026-05-16 owner vision #3] per-coin imminent-inflection detection (generalizes imminent_flip).

        3 signals:
          (a) EMA20-50 gap / price * 100 < cfid_ema_gap_thr_pct  (narrowing -> cross imminent)
          (b) recent N-bar volume avg vs prior N-bar -> spike (>= cfid_volume_spike_ratio)
          (c) |ADX change rate| >= cfid_adx_change_min  (trend change in progress)
        When all 3 met: +DI > -DI -> BULL_IMMINENT / opposite -> BEAR_IMMINENT.

        Returns: (direction_label, strength_score)
          - direction_label: "BULL_IMMINENT" | "BEAR_IMMINENT" | "NONE"
          - strength_score: 0.0 ~ 3.0 (sum of met signal strengths, for diagnostics/logging)
        """
        cfg = self.config
        if not getattr(cfg, "cfid_enabled", True):
            return ("NONE", 0.0)
        tf = str(getattr(cfg, "cfid_tf", "60") or "60")
        ema_gap_thr = float(getattr(cfg, "cfid_ema_gap_thr_pct", 0.4))
        vol_spike_ratio = float(getattr(cfg, "cfid_volume_spike_ratio", 1.5))
        adx_change_min = float(getattr(cfg, "cfid_adx_change_min", 1.0))
        lookback = max(3, int(getattr(cfg, "cfid_lookback", 5)))
        try:
            client = self._get_client()
            need = 50 + lookback * 2 + 5  # EMA50 + ADX 14 + lookback*2
            raw = client.get_kline(market, interval=tf, limit=need)
            if not raw or len(raw) < need:
                return ("NONE", 0.0)
            # Bybit kline: [start, open, high, low, close, volume, ...] (newest at [0])
            ordered = list(raw)  # old->new
            closes = [float(c[4]) for c in ordered]
            highs = [float(c[2]) for c in ordered]
            lows = [float(c[3]) for c in ordered]
            volumes = [float(c[5]) for c in ordered if len(c) > 5]
            if not volumes or len(volumes) < lookback * 2:
                return ("NONE", 0.0)

            # EMA20 / EMA50
            def _ema(prices, period):
                if len(prices) < period:
                    return None
                k = 2.0 / (period + 1.0)
                v = sum(prices[:period]) / period
                for p in prices[period:]:
                    v = p * k + v * (1 - k)
                return v
            ema_short = _ema(closes, 20)
            ema_long = _ema(closes, 50)
            if ema_short is None or ema_long is None:
                return ("NONE", 0.0)
            last_price = closes[-1]
            if last_price <= 0:
                return ("NONE", 0.0)
            ema_gap_pct = abs(ema_short - ema_long) / last_price * 100.0

            # (a) narrow-gap check
            gap_ok = ema_gap_pct < ema_gap_thr

            # (b) volume spike
            vol_recent = sum(volumes[-lookback:]) / lookback
            vol_prev = sum(volumes[-2 * lookback:-lookback]) / lookback
            vol_ratio = (vol_recent / vol_prev) if vol_prev > 0 else 0.0
            vol_ok = vol_ratio >= vol_spike_ratio

            # (c) ADX change rate + DI comparison (decides direction)
            try:
                from app.strategy.indicators import adx_series
            except Exception:
                return ("NONE", 0.0)
            adx_data = adx_series(highs, lows, closes, 14)
            if not adx_data or len(adx_data) < lookback + 1:
                return ("NONE", 0.0)
            adx_now = float(adx_data[-1].get("adx", 0.0))
            adx_prev = float(adx_data[-1 - lookback].get("adx", 0.0))
            adx_change = adx_now - adx_prev
            adx_ok = abs(adx_change) >= adx_change_min

            plus_di = float(adx_data[-1].get("plus_di", 0.0))
            minus_di = float(adx_data[-1].get("minus_di", 0.0))

            strength = (1.0 if gap_ok else 0.0) + (1.0 if vol_ok else 0.0) + (1.0 if adx_ok else 0.0)

            if not (gap_ok and vol_ok and adx_ok):
                return ("NONE", strength)

            if plus_di > minus_di:
                return ("BULL_IMMINENT", strength)
            if minus_di > plus_di:
                return ("BEAR_IMMINENT", strength)
            return ("NONE", strength)
        except Exception as exc:
            logger.debug("[FOCUS] _detect_coin_flip_imminent error: %s", exc)
            return ("NONE", 0.0)

    def _check_mtf_momentum_alignment(self, market: str, direction: str) -> tuple:
        """[2026-05-16] Cache wrapper -- 25s TTL. mtf_align is the heaviest (3 TFs × API calls)."""
        cfg = self.config
        if not getattr(cfg, "mtf_momentum_align_enabled", True):
            return (False, "")
        if not hasattr(self, '_guard_cache'):
            self._guard_cache = {}
        _key = ('mtf', (market or "").upper(), (direction or "").upper())
        _now = time.time()
        _cached = self._guard_cache.get(_key)
        if _cached and (_now - _cached[0]) < 25.0:
            return _cached[1]
        _result = self._check_mtf_momentum_alignment_impl(market, direction)
        self._guard_cache[_key] = (_now, _result)
        return _result

    def _check_mtf_momentum_alignment_impl(self, market: str, direction: str) -> tuple:
        """[2026-05-16 owner vision #2] verify multi-TF momentum-flow consistency.

        Measure RSI Δ (optional: MACD hist Δ) on each of H1/30M/5M.
        BLOCK if the count of TFs whose acceleration matches the entry direction is below threshold.
        - while momentum_deriv #1 is single-TF (5m), this is the multi-TF consensus.
        - "the TFs say different things" = no flow consistency = risky.

        Returns: (blocked: bool, reason: str)
        """
        cfg = self.config
        if not getattr(cfg, "mtf_momentum_align_enabled", True):
            return (False, "")
        tfs_csv = str(getattr(cfg, "mtf_momentum_align_tfs", "60,30,5") or "60,30,5")
        tfs = [t.strip() for t in tfs_csv.split(",") if t.strip()]
        if not tfs:
            return (False, "")
        lookback = max(2, int(getattr(cfg, "mtf_momentum_align_lookback", 5)))
        min_aligned = int(getattr(cfg, "mtf_momentum_align_min_aligned", 2))
        use_macd = bool(getattr(cfg, "mtf_momentum_align_use_macd", True))
        rsi_thr = float(getattr(cfg, "mtf_momentum_align_rsi_slope_thr", 0.5))
        dir_upper = (direction or "").upper()
        if dir_upper not in ("LONG", "SHORT"):
            return (False, "")
        try:
            from app.strategy.indicators import rsi_series, macd_hist_series
        except Exception as exc:
            logger.debug("[FOCUS] mtf_momentum_align import failed: %s", exc)
            return (False, "")
        try:
            client = self._get_client()
            need = 14 + lookback * 2 + 5
            per_tf_results = []  # (tf, rsi_delta, macd_delta, aligned_bool)
            for tf in tfs:
                try:
                    raw = client.get_kline(market, interval=tf, limit=need)
                    if not raw or len(raw) < need:
                        per_tf_results.append((tf, None, None, None))
                        continue
                    closes = [float(c[4]) for c in raw]
                    rsi_vals = rsi_series(closes, 14)
                    if not rsi_vals or len(rsi_vals) < lookback * 2:
                        per_tf_results.append((tf, None, None, None))
                        continue
                    rsi_recent = sum(rsi_vals[-lookback:]) / lookback
                    rsi_prev = sum(rsi_vals[-2 * lookback:-lookback]) / lookback
                    rsi_delta = rsi_recent - rsi_prev

                    macd_delta = 0.0
                    if use_macd:
                        macd_hist = macd_hist_series(closes, 12, 26, 9)
                        if macd_hist and len(macd_hist) >= lookback * 2:
                            m_recent = sum(macd_hist[-lookback:]) / lookback
                            m_prev = sum(macd_hist[-2 * lookback:-lookback]) / lookback
                            macd_delta = m_recent - m_prev

                    # judge acceleration-direction match
                    rsi_aligned_for_dir = False
                    if dir_upper == "LONG":
                        rsi_aligned_for_dir = rsi_delta > rsi_thr
                    else:  # SHORT
                        rsi_aligned_for_dir = rsi_delta < -rsi_thr

                    macd_aligned_for_dir = True  # passes by default if use_macd=False
                    if use_macd:
                        if dir_upper == "LONG":
                            macd_aligned_for_dir = macd_delta > 0
                        else:
                            macd_aligned_for_dir = macd_delta < 0

                    # that TF is truly "aligned" only when both RSI and MACD match
                    tf_aligned = rsi_aligned_for_dir and macd_aligned_for_dir
                    per_tf_results.append((tf, rsi_delta, macd_delta, tf_aligned))
                except Exception as exc:
                    logger.debug("[FOCUS] mtf_momentum_align tf=%s failed: %s", tf, exc)
                    per_tf_results.append((tf, None, None, None))
                    continue

            # count only TFs with valid data
            valid = [r for r in per_tf_results if r[3] is not None]
            if not valid:
                return (False, "")
            aligned_count = sum(1 for r in valid if r[3])
            if aligned_count < min_aligned:
                detail = " | ".join(
                    f"TF{r[0]}: RSIΔ={r[1]:+.2f}, MACDΔ={r[2]:+.4f} ({'OK' if r[3] else 'NO'})"
                    for r in valid
                )
                reason = f"mtf_momentum_align: {aligned_count}/{len(valid)} TF aligned < {min_aligned} [{detail}]"
                return (True, reason)
            return (False, "")
        except Exception as exc:
            logger.debug("[FOCUS] _check_mtf_momentum_alignment error: %s", exc)
            return (False, "")

    def _check_regime_direction_lock(self, direction: str, market: str) -> tuple:
        """B11: direction enforcement based on BTC H4 regime (2026-04-19 this agent's direct directive).
        'BULL = LONG only, BEAR = SHORT only, otherwise REST'
        + 'if the regime stalls or shows signs of flipping, all-stop'

        Uses BTC H4 EMA20/EMA50 + slope (reuses existing btc_regime_* settings).
        - clearly_above + slope_up -> BULL -> block SHORT
        - clearly_below + slope_dn -> BEAR -> block LONG
        - otherwise (narrow distance or flat slope) -> NEUTRAL -> block both (REST)
        - block both for freeze_sec right after a regime change (whipsaw defense)
        - lock_market(XAUTUSDT) bypass -- gold is a separate market

        ★ 2026-04-23 owner directive: added a regime_lock_mode dispatcher
           - mode=="B11" : existing behavior (this function body)
           - mode=="B12" : delegate to _check_market_breadth_lock
           - mode=="OFF" : both off (pass immediately)
        Returns: (blocked: bool, reason: str)"""
        cfg = self.config
        # ★ B11/B12/OFF dispatcher (2026-04-23 owner direct request)
        mode = (getattr(cfg, "regime_lock_mode", "B11") or "B11").upper()
        if mode == "OFF":
            return (False, "")
        if mode == "B12":
            return self._check_market_breadth_lock(direction, market)
        # mode == "B11" (default) -- run the body below
        if not getattr(cfg, "regime_direction_lock_enabled", True):
            return (False, "")
        # lock_market bypass
        lock_mkt = (getattr(cfg, "lock_market", "") or "").upper()
        if lock_mkt and market.upper() == lock_mkt:
            return (False, "")
        try:
            candles = self._get_btc_regime_candles()
            ema_long_n = int(getattr(cfg, "btc_regime_ema_long", 50))
            if not candles or len(candles) < ema_long_n + 3:
                return (True, f"regime_direction_lock: insufficient BTC regime data ({len(candles) if candles else 0} bars) → REST")
            closes = [float(c[4]) for c in candles]
            ema_short_n = int(getattr(cfg, "btc_regime_ema_short", 20))
            trans_band = float(getattr(cfg, "btc_regime_trans_band_pct", 1.0))
            slope_thr = float(getattr(cfg, "btc_regime_slope_flat_thr_pct", 0.3))
            freeze_sec = float(getattr(cfg, "regime_direction_lock_freeze_sec", 1800.0))
            neutral_block = bool(getattr(cfg, "regime_direction_lock_neutral_block", True))
            # 3-axis toggles (a disabled axis ignores that check = treated as "pass")
            use_slope = bool(getattr(cfg, "regime_lock_use_slope", True))
            use_distance = bool(getattr(cfg, "regime_lock_use_distance", True))
            use_cross = bool(getattr(cfg, "regime_lock_use_cross", True))

            def _ema(prices, period):
                if len(prices) < period:
                    return None
                k = 2.0 / (period + 1.0)
                v = sum(prices[:period]) / period
                for p in prices[period:]:
                    v = p * k + v * (1 - k)
                return v

            ema_short = _ema(closes, ema_short_n)
            ema_long = _ema(closes, ema_long_n)
            ema_short_prev = _ema(closes[:-3], ema_short_n)
            if ema_short is None or ema_long is None or ema_short_prev is None:
                return (True, "regime_direction_lock: EMA calc failed → REST")
            last_close = closes[-1]
            dist_pct = (last_close - ema_long) / ema_long * 100.0 if ema_long > 0 else 0.0
            slope_pct = (ema_short - ema_short_prev) / ema_short_prev * 100.0 if ema_short_prev > 0 else 0.0

            # per-axis direction decision -- a disabled axis is True both ways (pass)
            cross_bull = (ema_short > ema_long) if use_cross else True
            cross_bear = (ema_short < ema_long) if use_cross else True
            dist_bull = (dist_pct > trans_band) if use_distance else True
            dist_bear = (dist_pct < -trans_band) if use_distance else True
            slope_bull = (slope_pct > slope_thr) if use_slope else True
            slope_bear = (slope_pct < -slope_thr) if use_slope else True

            clearly_above = cross_bull and dist_bull and slope_bull
            clearly_below = cross_bear and dist_bear and slope_bear

            # with all axes OFF both are True -- tiebreak by price sign
            if clearly_above and clearly_below:
                if dist_pct > 0 or ema_short > ema_long:
                    clearly_below = False
                elif dist_pct < 0 or ema_short < ema_long:
                    clearly_above = False
                else:
                    clearly_above = clearly_below = False

            if clearly_above:
                regime = "BULL"
            elif clearly_below:
                regime = "BEAR"
            else:
                regime = "NEUTRAL"

            # show which axes were enabled in the log
            axes_used = "+".join([a for a, on in [("cross", use_cross), ("dist", use_distance), ("slope", use_slope)] if on]) or "none"

            # ★ Phase K (2026-04-21): store BTC EMA gap -- consumed by detect_regime_transition
            # gap = |EMA20-EMA50|/price*100. under 0.3% = a leading imminent-transition signal (proven 72% hit)
            if last_close > 0:
                self._btc_ema_gap_pct = abs(ema_short - ema_long) / last_close * 100.0
            else:
                self._btc_ema_gap_pct = 999.0
            # ★ store BTC-only ADX (for regime_reversal_pause, 2026-06-04 bug fix)
            # _last_adx_value is the last-scanned coin's ADX -- separate a BTC-only one
            try:
                from app.strategy.indicator_cache import compute_adx
                _btc_h4 = self._get_btc_regime_candles()
                if _btc_h4 and len(_btc_h4) >= 16:
                    _highs = [float(c[2]) for c in _btc_h4]
                    _lows  = [float(c[3]) for c in _btc_h4]
                    _cls   = [float(c[4]) for c in _btc_h4]
                    _adx_r = compute_adx(_highs, _lows, _cls, period=14)
                    if _adx_r:
                        self._btc_adx_value = float(_adx_r.get("adx", 0))
            except Exception:
                pass

            now = time.time()
            prev_regime, _prev_change_ts = getattr(self, "_b11_regime_state", ("", 0.0))
            if regime != prev_regime:
                if prev_regime:
                    # actual regime change -> start the 30-min freeze timer
                    self._b11_regime_state = (regime, now)
                    logger.info("[FOCUS] 🔄 BTC Regime change: %s → %s (dist=%.2f%%, slope=%.2f%%)",
                                prev_regime, regime, dist_pct, slope_pct)
                else:
                    # first observation right after restart -- expire freeze immediately (prevents a fake "->NEUTRAL change")
                    self._b11_regime_state = (regime, now - freeze_sec)
                # ★ Phase D-2 (2026-04-20): persist -- restore on next restart (closes the whipsaw window)
                # ★ Phase H (this agent's letter#3 A-6): on silent failure, restart whipsaw recurs -> incidents like AAVE 07:05
                try:
                    from app.core.io_utils import safe_write_json
                    safe_write_json(B11_STATE_PATH, {"regime": regime, "change_ts": self._b11_regime_state[1]})
                    if getattr(self, "_b11_save_fail_count", 0) > 0:
                        logger.info("[FOCUS] B11 state save recovered after %d failures", self._b11_save_fail_count)
                        self._b11_save_fail_count = 0
                except Exception as exc:
                    self._b11_save_fail_count = getattr(self, "_b11_save_fail_count", 0) + 1
                    logger.warning("[FOCUS] B11 state save failed (%d consecutive): %s", self._b11_save_fail_count, exc, exc_info=True)
                    if self._b11_save_fail_count >= 3:
                        logger.error("[FOCUS] ⚠ B11 state save %d consecutive failures -- whipsaw risk on restart (AAVE 07:05 incident family)", self._b11_save_fail_count)
            last_change_ts = self._b11_regime_state[1]
            elapsed = now - last_change_ts
            # sign detection: in the freeze window after a regime change, always block both directions
            if prev_regime and elapsed < freeze_sec:
                remain = freeze_sec - elapsed
                # ★ [2026-05-16 owner] on imminent-flip detection, lift the freeze -- "a step-ahead entry"
                imminent = self._detect_imminent_flip(regime)
                aligned = (
                    (regime == "BULL" and imminent == "BULL_IMMINENT") or
                    (regime == "BEAR" and imminent == "BEAR_IMMINENT")
                )
                if aligned:
                    logger.info("[FOCUS] 🚀 imminent flip aligned (%s, regime=%s, gap=%.3f%%) → freeze lifted (%.1fm/%.1fm) [axes=%s]",
                                imminent, regime, float(getattr(self, "_btc_ema_gap_pct", 0.0)),
                                elapsed/60, freeze_sec/60, axes_used)
                    # freeze passed -- proceed to the BULL/BEAR/NEUTRAL branches below (no return)
                else:
                    if imminent != "NONE":
                        logger.info("[FOCUS] imminent flip detected (%s) but regime=%s mismatch → freeze maintained", imminent, regime)
                    return (True, f"regime_direction_lock: regime change ({prev_regime}->{regime}) {elapsed/60:.1f}m ago -> freeze {remain/60:.1f}m more (ALL STOP) [axes={axes_used}]")
            # NEUTRAL -> block both directions
            if regime == "NEUTRAL" and neutral_block:
                return (True, f"regime_direction_lock: REGIME=NEUTRAL (dist={dist_pct:.2f}%, slope={slope_pct:.2f}%, axes={axes_used}) → REST (both dir blocked)")
            # BULL -> block SHORT
            if regime == "BULL" and direction.upper() == "SHORT":
                return (True, f"regime_direction_lock: REGIME=BULL -> SHORT blocked (dist={dist_pct:.2f}%, slope={slope_pct:.2f}%, axes={axes_used})")
            # BEAR -> block LONG
            if regime == "BEAR" and direction.upper() == "LONG":
                return (True, f"regime_direction_lock: REGIME=BEAR -> LONG blocked (dist={dist_pct:.2f}%, slope={slope_pct:.2f}%, axes={axes_used})")
            return (False, "")
        except Exception as exc:
            logger.warning("[FOCUS] regime_direction_lock error: %s", exc)
            # conservative on error: block
            return (True, f"regime_direction_lock: error -> REST ({exc})")

    def _compute_reentry_penalty(self, market: str, direction: str) -> float:
        """[2026-05-17 100-pt ×10] B6: same market+direction re-entry ENTRY count within recent N min × -penalty.
        Returns: penalty (<=0, float)"""
        cfg = self.config
        if not getattr(cfg, "coin_reentry_penalty_enabled", True):
            return 0.0
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            if not os.path.exists(self._journal_path):
                return 0.0
            window = getattr(cfg, "coin_reentry_penalty_window_sec", 900.0)
            per_count = float(getattr(cfg, "coin_reentry_penalty_per_count", 10.0))  # [100-pt ×10]
            mkt_upper = market.upper()
            dir_upper = direction.upper()
            now = time.time()
            cutoff = now - window
            entry_count = 0
            with open(self._journal_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        if rec.get("event") != "ENTRY":
                            continue
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if rec.get("market", "").upper() != mkt_upper:
                            continue
                        if rec.get("direction", "").upper() != dir_upper:
                            continue
                        entry_count += 1
                    except (json.JSONDecodeError, KeyError, ValueError):
                        continue
            if entry_count > 0:
                return -float(per_count * entry_count)  # [100-pt ×10] returns float
            return 0.0
        except Exception as exc:
            logger.warning("[FOCUS] reentry_penalty error: %s", exc)
            return 0.0

    def _get_coin_loss_total(self, market: str, direction: str = "") -> float:
        """Cumulative realized loss for the coin within 24 hours (negative).
        Profits don't offset -- a poison coin can have a high win rate yet one trade swallows all profit.
        [2026-04-18] when direction is given, accumulate only that direction -- stops LONG losses from also blocking SHORT"""
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            window_sec = self.config.coin_loss_cap_window_hours * 3600
            cutoff = time.time() - window_sec
            mkt_upper = market.upper()
            dir_upper = direction.upper() if direction else ""
            total_loss = 0.0
            if not os.path.exists(self._journal_path):
                return 0.0
            with open(self._journal_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if (rec.get("market", "").upper() == mkt_upper
                                and rec.get("event") == "EXIT"
                                and rec.get("strategy") == "FOCUS"):
                            # [2026-04-18] direction filter -- separates so a same-coin LONG loss no longer blocks SHORT entry
                            if dir_upper and rec.get("direction", "").upper() != dir_upper:
                                continue
                            pnl = rec.get("pnl_net", 0)
                            if pnl < 0:
                                total_loss += pnl  # accumulate negatives
                    except (json.JSONDecodeError, KeyError):
                        continue
            return total_loss
        except Exception as exc:
            logger.warning("[FOCUS] coin_loss_total error: %s", exc)
            return 0.0

    # ── Pair Group Helpers (2026-04-19) ──────────────────────────────
    def _get_pair_group(self, market: str) -> str:
        """Return the group name the coin belongs to. Empty if none (isolated coin)."""
        mkt_upper = market.upper()
        for group_name, coins in self.PAIR_GROUPS.items():
            if mkt_upper in coins:
                return group_name
        return ""

    def _check_pair_block(self, market: str, direction: str) -> tuple:
        """Pair-group-based entry-block check.
        Returns (blocked: bool, reason: str).
        - aggressive: allow up to N same-direction within the group, block opposite
        - conservative: only 1 per group in any direction (block if any position exists)
        """
        if not self.config.pair_block_enabled:
            return (False, "")
        group = self._get_pair_group(market)
        if not group:
            return (False, "")  # don't check isolated coins
        group_coins = set(c.upper() for c in self.PAIR_GROUPS[group])
        same_dir_count = 0
        for pos in self.positions:  # [2026-05-30 fix] self.state(FocusState enum).positions = AttributeError → self.positions
            if pos.market.upper() not in group_coins:
                continue
            if pos.market.upper() == market.upper():
                continue  # same coin is handled by the re-entry gate (elsewhere)
            if pos.direction != direction:
                # an opposite-direction position exists -> block (common to both modes)
                return (True, f"pair_opposite:{group}:{pos.market}_{pos.direction}")
            else:
                same_dir_count += 1
        # reaching here means no opposite-direction position
        if self.config.pair_block_mode == "conservative" and same_dir_count > 0:
            return (True, f"pair_conservative:{group}:same_dir_{same_dir_count}")
        if self.config.pair_block_mode == "aggressive" and same_dir_count >= self.config.pair_block_same_limit:
            return (True, f"pair_aggressive_limit:{group}:{same_dir_count}/{self.config.pair_block_same_limit}")
        return (False, "")

    # ── Coin Profit Lock-in Helpers (2026-04-19) ─────────────────────
    def _get_coin_realized_pnl_window(self, market: str, hours: float) -> float:
        """Sum of the coin's realized PnL within N hours (profit+loss, net after fees)."""
        try:
            from app.manager.trade_journal import JOURNAL_PATH
            window_sec = hours * 3600
            cutoff = time.time() - window_sec
            mkt_upper = market.upper()
            total = 0.0
            if not os.path.exists(self._journal_path):
                return 0.0
            with open(self._journal_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                        ts = rec.get("ts", 0)
                        if ts < cutoff:
                            continue
                        if (rec.get("market", "").upper() == mkt_upper
                                and rec.get("event") == "EXIT"
                                and rec.get("strategy") == "FOCUS"):
                            total += rec.get("pnl_net", 0)
                    except (json.JSONDecodeError, KeyError):
                        continue
            return total
        except Exception as exc:
            logger.warning("[FOCUS] coin_realized_pnl_window error: %s", exc)
            return 0.0

    def _check_profit_lockin(self, pos, current_unrealized_usd: float) -> tuple:
        """Per-coin cumulative-profit protection. Returns (trigger: bool, info: dict).
        Logic:
          realized_N = sum of the coin's realized PnL over the last N hours
          total = realized_N + current_unrealized
          threshold = realized_N × protect_ratio
          skip if realized_N is below min_realized (exclude meaningless small-profit protection)
          if total < threshold, TRIGGER -> recommend exit
        """
        info = {"realized_n": 0.0, "unrealized": current_unrealized_usd, "total": 0.0, "threshold": 0.0}
        if not self.config.coin_profit_lockin_enabled:
            return (False, info)
        # H4-strategy conflict prevention: activate only after BE lock
        if self.config.coin_profit_lockin_require_be and not pos.breakeven_locked:
            return (False, info)
        realized_n = self._get_coin_realized_pnl_window(
            pos.market, self.config.coin_profit_lockin_window_hours)
        info["realized_n"] = realized_n
        # don't apply if realized profit is below the minimum threshold
        if realized_n < self.config.coin_profit_lockin_min_realized:
            return (False, info)
        total = realized_n + current_unrealized_usd
        threshold = realized_n * self.config.coin_profit_lockin_protect_ratio
        info["total"] = total
        info["threshold"] = threshold
        if total < threshold:
            return (True, info)
        return (False, info)

    # -- Direction Block (runtime-file-based coin×direction lock) --
    #   Editing focus_config.json while the bot runs risks a race condition
    #   (memory: 2026-04-11), so this is split into a separate file runtime/direction_blocks.json.
    #   Data-driven blocking: "block only this direction of this coin for a while".
    #   Schema:
    #     { "ETHUSDT": { "LONG": { "until_ts": 1234567890.0, "reason": "..." } } }
    #   until_ts == 0 = permanent (until manually released).
    DIRECTION_BLOCK_PATH = os.path.join("runtime", "direction_blocks.json")

    # -- Pair Groups (2026-04-19) --
    # Estimated correlation 0.85+. Opposite-direction positions within a group = only a fee loss.
    # aggressive mode: up to N same-direction OK, block only opposite
    # conservative mode: only 1 per group (any direction)
    # Opposite-block is common to both modes.
    PAIR_GROUPS = {
        "L1_ALT":   ["ETHUSDT", "SOLUSDT", "SUIUSDT", "APTUSDT", "AVAXUSDT", "NEARUSDT"],
        "L2":       ["ARBUSDT", "OPUSDT", "STRKUSDT"],
        "DEFI":     ["UNIUSDT", "AAVEUSDT", "LDOUSDT", "MKRUSDT", "COMPUSDT"],
        "AI":       ["WLDUSDT", "TAOUSDT", "FETUSDT", "OCEANUSDT"],
        "MEME":     ["DOGEUSDT", "SHIBUSDT", "PEPEUSDT", "WIFUSDT", "BONKUSDT", "FLOKIUSDT"],
        "ORACLE":   ["LINKUSDT", "BANDUSDT", "PYTHUSDT"],
        "GAMING":   ["AXSUSDT", "SANDUSDT", "MANAUSDT", "IMXUSDT"],
        "BTC_CORR": ["BTCUSDT", "ETHUSDT"],  # max BTC-ETH beta
    }

    # -- H4 Context Filter (check higher-timeframe context) --
    # [2026-04-18 evening] user note: "Don't take LONG when ETH is caught mid-cloud after a 5-bar H4 decline.
    #   Look a bit longer and the answer appears." Looking at M5 alone misses the slide context.
    #   Conditions:
    #     LONG: 4+ of the recent 5 H4 bars are down-candles -> BLOCK
    #     LONG: recent 5-H4-bar cumulative drop exceeds -3% -> BLOCK
    #     SHORT: reverse (4+ up-candles / exceeds +3%)
    #   This means that whatever the direction signal (BUY/SELL), the **timing** isn't right yet.
    #   No SW_BB exemption -- a mean-reversion LONG during a strong H4 decline is just taking more hits.
    def _primary_context_filter(self, market: str, direction: str) -> tuple:
        """[2026-05-15 H1 switch] check primary_tf(H1) 5-bar context. Returns (pass=True/False, reason)."""
        try:
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=6)
        except Exception as exc:
            logger.debug("[FOCUS] primary_context: fetch fail → PASS: %s", exc)
            return (True, "")
        if not raw or len(raw) < 5:
            return (True, "")

        from app.strategy.greenpen.pa_detector import OHLCV
        candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                   for r in raw if len(r) >= 5]
        if len(candles) < 5:
            return (True, "")

        last5 = candles[-5:]
        first_open = last5[0].open
        last_close = last5[-1].close
        net_pct = (last_close - first_open) / first_open * 100 if first_open > 0 else 0

        if direction == "LONG":
            declining = sum(1 for c in last5 if c.close < c.open)
            if declining >= 4:
                return (False, f"primary_5bar_bear:{declining}of5_red")
            if net_pct <= -3.0:
                return (False, f"primary_5bar_netdown:{net_pct:.1f}%")
        else:  # SHORT
            rising = sum(1 for c in last5 if c.close > c.open)
            if rising >= 4:
                return (False, f"primary_5bar_bull:{rising}of5_green")
            if net_pct >= 3.0:
                return (False, f"primary_5bar_netup:{net_pct:.1f}%")

        return (True, "")

    # -- Anti-Falling-Knife (bottom-confirm filter) --
    # [2026-04-18 evening] user note: "catching LONG off one long-wick candle at the bottom of the slide"
    #   When 4/13-14 was profitable there were no such entries -> recently-added logic (SIDEWAYS BB
    #   mean reversion, Entry Quality removal, etc.) is allowing "catching a falling knife".
    #   Block entry if any of the 3 conditions hits:
    #     (1) current M5 bar is a new low/high among the recent 5 -- still sliding
    #     (2) all of the recent 3 bars are counter-direction (LONG but 3 down-candles, SHORT but 3 up-candles) -- crashing/spiking
    #     (3) recent 3-bar closes are monotonically down/up -- a staircase decline/rise
    #   Applied to all entry paths (Primary + Scanner + SW_BB). 1 M5 API call.
    def _anti_falling_knife_check(self, market: str, direction: str) -> tuple:
        """Bottom (ceiling) confirm filter. Returns (pass=True/False, reason).
        On failure, the reason string tells which condition hit.
        """
        try:
            raw = self._get_client().get_kline(market, interval=self.config.entry_tf, limit=10)
        except Exception as exc:
            logger.debug("[FOCUS] anti_knife: kline fetch fail → PASS: %s", exc)
            return (True, "")
        if not raw or len(raw) < 5:
            return (True, "")

        from app.strategy.greenpen.pa_detector import OHLCV
        candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                   for r in raw if len(r) >= 5]
        if len(candles) < 5:
            return (True, "")

        last = candles[-1]

        if direction == "LONG":
            # condition 1: current bar is the lowest among the recent 5 -> new low = still falling
            lows5 = [c.low for c in candles[-5:]]
            if last.low <= min(lows5):
                return (False, f"new_low_5bar:{last.low:.6f}")
            # condition 2: all of the recent 3 are down-candles -> crashing
            last3 = candles[-3:]
            reds = sum(1 for c in last3 if c.close < c.open)
            if reds >= 3:
                return (False, "3red_falling")
            # condition 3: 3-bar closes monotonically down -> staircase decline
            c1, c2, c3 = [c.close for c in last3]
            if c1 > c2 > c3:
                return (False, f"monotonic_down:{c1:.6f}>{c2:.6f}>{c3:.6f}")
        else:  # SHORT
            highs5 = [c.high for c in candles[-5:]]
            if last.high >= max(highs5):
                return (False, f"new_high_5bar:{last.high:.6f}")
            last3 = candles[-3:]
            greens = sum(1 for c in last3 if c.close > c.open)
            if greens >= 3:
                return (False, "3green_rising")
            c1, c2, c3 = [c.close for c in last3]
            if c1 < c2 < c3:
                return (False, f"monotonic_up:{c1:.6f}<{c2:.6f}<{c3:.6f}")

        return (True, "")

    # ── Entry Quality Filter ──────────────────────────────────
    def _entry_quality_check(self, market: str, direction: str, price: float) -> tuple:
        """M5 microtiming triple filter. (pass=True, fail=False+reason)
        [2026-04-18] user request "open everything to run 24h" -- fully disable Entry Quality
        [2026-05-28 evening owner] yellow master toggle -- skip in green-only mode
        """
        # green-only mode: Entry Quality fully OFF (yellow guard bundle)
        if not self._is_yellow_guard_active("entry"):
            return (True, "yellow_off")
        return (True, "disabled_per_user_20260418")
        if not self.config.entry_quality_enabled:
            return (True, "")
        # one M5 candle fetch (shared by the 3 filters)
        try:
            raw = self._get_client().get_kline(market, interval=self.config.entry_tf, limit=30)
            if not raw or len(raw) < 5:
                return (True, "")
        except Exception as exc:
            logger.debug("[FOCUS] EntryQuality: M5 fetch fail — PASS: %s", exc)
            return (True, "")

        from app.strategy.greenpen.pa_detector import OHLCV
        candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                   for r in raw if len(r) >= 5]
        if len(candles) < 5:
            return (True, "")

        # -- (1) M5 momentum: K+ of the recent N bars in our direction --
        if self.config.eq_momentum_enabled:
            n = min(self.config.eq_momentum_count, len(candles))
            recent = candles[-n:]
            if direction == "LONG":
                agree = sum(1 for c in recent if c.close > c.open)
            else:
                agree = sum(1 for c in recent if c.close < c.open)
            if agree < self.config.eq_momentum_min_agree:
                reason = f"m5_momentum:{agree}/{n}_in_{direction}"
                return (False, reason)

        # -- (2) BB position: block top/bottom extremes --
        if self.config.eq_bb_enabled:
            from app.strategy.indicators import bollinger_bands
            closes = [c.close for c in candles]
            bb = bollinger_bands(closes, 20, 2.0)
            if bb and bb["upper"] > bb["lower"]:
                bb_pct = (price - bb["lower"]) / (bb["upper"] - bb["lower"]) * 100
                if direction == "LONG" and bb_pct > self.config.eq_bb_upper_pct:
                    reason = f"bb_position:LONG@{bb_pct:.0f}%>limit{self.config.eq_bb_upper_pct:.0f}%"
                    return (False, reason)
                if direction == "SHORT" and bb_pct < self.config.eq_bb_lower_pct:
                    reason = f"bb_position:SHORT@{bb_pct:.0f}%<limit{self.config.eq_bb_lower_pct:.0f}%"
                    return (False, reason)

        # -- (3) N-bar trend: HH/HL majority over the last N bars + with-direction --
        if self.config.eq_nbar_enabled:
            n = min(self.config.eq_nbar_count, len(candles))
            if n >= 3:
                bars = candles[-n:]
                pairs = n - 1
                if direction == "LONG":
                    hh = sum(1 for i in range(1, n) if bars[i].high > bars[i-1].high)
                    net = bars[-1].close - bars[0].open
                    if hh / pairs < self.config.eq_nbar_min_ratio or net <= 0:
                        reason = f"nbar_trend:LONG_HH={hh}/{pairs}_net={net:.4f}"
                        return (False, reason)
                else:
                    lh = sum(1 for i in range(1, n) if bars[i].high < bars[i-1].high)
                    net = bars[-1].close - bars[0].open
                    if lh / pairs < self.config.eq_nbar_min_ratio or net >= 0:
                        reason = f"nbar_trend:SHORT_LH={lh}/{pairs}_net={net:.4f}"
                        return (False, reason)

        logger.debug("[FOCUS] EntryQuality PASS: %s %s @ %.4f", direction, market, price)
        return (True, "")

    def _is_direction_blocked(self, market: str, direction: str) -> tuple:
        """Returns (blocked: bool, reason: str).

        No file/empty file/parse error -> don't block (safe default).
        mtime-based TTL cache minimizes repeated-call cost.
        """
        try:
            path = self.DIRECTION_BLOCK_PATH
            if not os.path.exists(path):
                return False, ""
            mtime = os.path.getmtime(path)
            cache = getattr(self, "_dir_block_cache", None)
            if cache is None or cache[0] != mtime:
                with open(path, "r", encoding="utf-8") as f:
                    data = json.load(f) or {}
                self._dir_block_cache = (mtime, data)
            else:
                data = cache[1]

            entry = (data.get(market.upper(), {}) or {}).get(direction.upper())
            if not entry:
                return False, ""
            until_ts = float(entry.get("until_ts", 0) or 0)
            # until_ts == 0 -> permanent; > 0 -> expiry check
            if until_ts > 0 and time.time() >= until_ts:
                return False, ""
            reason = str(entry.get("reason", "no reason"))
            return True, reason
        except Exception as exc:
            logger.debug("[FOCUS] direction_block check failed: %s", exc)
            return False, ""

