    def _check_cfid_leading_entry(self, market: str, direction: str) -> tuple:
        """[Leading CFID] verify a lead-entry candidate on imminent CFID inflection.

        Returns: (eligible: bool, reason: str)
          - mode != CFID -> False
          - cfid_dir == direction (BULL=LONG/BEAR=SHORT) AND strength >= threshold -> True
        """
        cfg = self.config
        if (getattr(cfg, "leading_entry_mode", "OFF") or "OFF").upper() != "CFID":
            return False, "mode_not_CFID"
        if not getattr(cfg, "cfid_enabled", True):
            return False, "cfid_disabled"
        try:
            cfid_dir, cfid_strength = self._detect_coin_flip_imminent(market)
        except Exception as exc:
            return False, f"cfid_err:{exc.__class__.__name__}"
        if cfid_dir == "NONE":
            return False, "no_cfid_signal"
        expected_dir = "LONG" if cfid_dir == "BULL_IMMINENT" else "SHORT"
        if (direction or "").upper() != expected_dir:
            return False, f"dir_mismatch({cfid_dir} vs {direction})"
        min_strength = float(getattr(cfg, "cfid_leading_min_strength", 70.0))
        if cfid_strength < min_strength:
            return False, f"strength_low({cfid_strength:.0f}<{min_strength:.0f})"
        return True, f"CFID_LEAD({cfid_dir},s={cfid_strength:.0f})"

    def _check_pattern_leading_entry(self, market: str, direction: str,
                                       candles_primary: list,
                                       zones: Optional[Tuple[float, float]] = None) -> tuple:
        """[Leading PATTERN] verify the 5step retest + sr proximity + mtf align pattern.

        Auto-recognizes the owner's SOL test spot (near support + strong UPTREND).
        Returns: (eligible: bool, reason: str)
        """
        cfg = self.config
        if (getattr(cfg, "leading_entry_mode", "OFF") or "OFF").upper() != "PATTERN":
            return False, "mode_not_PATTERN"
        # 1) 5step score (auto-fetch entry_tf M5)
        try:
            from app.strategy.greenpen.pa_5step import _pa_5step_score_impl
            entry_tf = getattr(cfg, "entry_tf", "5")
            raw = self._get_mtf_kline(market, entry_tf, limit=30)
            if not raw or len(raw) < 8:
                return False, "no_5m_candles"
            candles_5m = []
            for k in raw:
                if isinstance(k, (list, tuple)) and len(k) >= 6:
                    candles_5m.append({
                        'o': float(k[1]), 'h': float(k[2]), 'l': float(k[3]),
                        'c': float(k[4]), 'v': float(k[5]),
                    })
            if len(candles_5m) < 8:
                return False, "5m_parse_short"
            score_5s, label_5s = _pa_5step_score_impl(direction, candles_5m, zones)
            min_5s = int(getattr(cfg, "pattern_leading_min_5step_score", 6))
            if score_5s < min_5s:
                return False, f"5step_low({score_5s}<{min_5s})"
        except Exception as exc:
            return False, f"5step_err:{exc.__class__.__name__}"
        # 2) sr proximity (near support/resistance)
        if not zones or len(zones) < 2:
            return False, "no_zones"
        try:
            support, resistance = float(zones[0]), float(zones[1])
        except Exception:
            return False, "zones_invalid"
        if not candles_primary:
            return False, "no_candles"
        try:
            last_c = candles_primary[-1]
            if hasattr(last_c, 'close'):
                last_price = float(last_c.close)
            elif isinstance(last_c, (list, tuple)) and len(last_c) >= 4:
                last_price = float(last_c[3])
            else:
                return False, "price_extract_fail"
        except Exception:
            return False, "price_err"
        if last_price <= 0:
            return False, "no_price"
        max_sr_pct = float(getattr(cfg, "pattern_leading_max_sr_pct", 1.0))
        dir_up = (direction or "").upper()
        if dir_up == "LONG":
            sr_dist_pct = abs(last_price - support) / last_price * 100
        elif dir_up == "SHORT":
            sr_dist_pct = abs(resistance - last_price) / last_price * 100
        else:
            return False, "no_dir"
        if sr_dist_pct > max_sr_pct:
            return False, f"sr_far({sr_dist_pct:.2f}%>{max_sr_pct:.1f}%)"
        # 3) mtf_align alignment (1 TF = align +1 = +4 pts, threshold = min_aligned × 4)
        try:
            mtf_score, mtf_label = self._compute_mtf_alignment_matrix(market, direction, candles_primary)
        except Exception as exc:
            return False, f"mtf_err:{exc.__class__.__name__}"
        min_align = int(getattr(cfg, "pattern_leading_min_mtf_align", 2))
        if mtf_score < (min_align * 4):
            return False, f"mtf_low({mtf_score}<{min_align*4})"
        return True, f"PATTERN_LEAD(5s={score_5s},sr={sr_dist_pct:.2f}%,mtf={mtf_score})"

    def detect_regime_transition(
        self,
        market: str,
        scanner_direction: str,
        conviction: int,
        adx_now: float,
        adx_past: float,
        candles_primary: list,
    ) -> tuple:
        """Phase K -- detect a regime-transition pre-emptive entry.

        Returns: (allow_flip: bool, opposite_direction: str, reason: str)

        7 AND conditions:
          1. ADX declining: adx_now < adx_past * decline_ratio (default 5%)
          2. BTC EMA gap < threshold (default 0.3%)  -- sibling-proven: 72% hit
          3. PA pattern exists + reversal type (PIN/ENGULFING/BOS)
          4. PA direction != scanner direction
          5. conviction >= regime_transition_min_conviction (default 8)
          6. 3 MTF aligned (scanner already checks H4/H1 -- here approximated by PA existence)
          7. last_regime_change_age > 3h (prevent consecutive flips)

        Don't ON simultaneously with J v2 -- the caller guarantees that here.
        """
        if not getattr(self.config, "regime_transition_enabled", False):
            return False, "", "disabled"

        # condition 1: ADX declining
        decline_ratio = float(getattr(self.config, "regime_transition_adx_decline_ratio", 0.95))
        if adx_past <= 0:
            return False, "", "no_adx_past"
        if adx_now >= adx_past * decline_ratio:
            return False, "", f"adx_not_declining: now={adx_now:.1f} past={adx_past:.1f} ratio={adx_now/adx_past:.3f}"

        # condition 2: BTC EMA gap
        gap_thr = float(getattr(self.config, "regime_transition_ema_gap_threshold_pct", 0.3))
        btc_gap = getattr(self, "_btc_ema_gap_pct", None)
        if btc_gap is None:
            return False, "", "btc_gap_not_computed"
        if btc_gap >= gap_thr:
            return False, "", f"btc_gap_wide: {btc_gap:.3f}% >= {gap_thr}%"

        # conditions 3-4: PA reversal pattern + scanner-direction mismatch
        pa_dir = ""
        pa_name = ""
        try:
            if candles_primary and len(candles_primary) >= 15:
                from app.strategy.greenpen import full_analysis as _k_full
                _k_ana = _k_full(candles_primary)
                _k_pas = getattr(_k_ana, "pa_signals", []) or []
                if _k_pas:
                    best = _k_pas[0]
                    pa_name = getattr(best.pattern, "value", str(best.pattern)) if hasattr(best, "pattern") else ""
                    pa_dir = getattr(best.direction, "value", str(best.direction)) if hasattr(best, "direction") else ""
        except Exception as exc:
            logger.debug("[FOCUS] Phase K PA detect failed %s: %s", market, exc)
            return False, "", f"pa_detect_failed: {exc}"

        if not pa_dir or not pa_name:
            return False, "", "no_pa"

        _reversal_set = ("PIN_BAR", "ENGULFING", "BOS_BULLISH", "BOS_BEARISH", "STAR_V1")
        if pa_name not in _reversal_set:
            return False, "", f"pa_not_reversal: {pa_name}"

        if pa_dir.upper() == scanner_direction.upper():
            return False, "", f"pa_agrees_with_scanner: pa={pa_dir} scan={scanner_direction}"

        # condition 5: conviction
        min_conv = float(getattr(self.config, "regime_transition_min_conviction", 80.0))  # [100-pt ×10] 8->80
        if conviction < min_conv:
            return False, "", f"conv_too_low: {conviction:.1f}<{min_conv:.1f}"

        # condition 7: last regime change age
        min_age_min = float(getattr(self.config, "regime_transition_last_change_age_min", 180.0))
        _b11_state = getattr(self, "_b11_regime_state", ("", 0.0))
        last_change_ts = _b11_state[1] if _b11_state and len(_b11_state) > 1 else 0.0
        age_min = (time.time() - last_change_ts) / 60.0 if last_change_ts > 0 else 9999.0
        if age_min < min_age_min:
            return False, "", f"regime_change_too_recent: {age_min:.0f}min<{min_age_min:.0f}min"

        reason = (f"regime_transition: adx_decl={adx_now:.1f}/{adx_past:.1f} "
                  f"gap={btc_gap:.3f}% pa={pa_name}({pa_dir}) conv={conviction} age={age_min:.0f}min")
        return True, pa_dir.upper(), reason

