    def _get_taker_fee_rate(self, market: str) -> float:
        """Bybit taker fee rate (edge ②: fallback on API error)."""
        try:
            client = self._get_client()
            # Bybit linear perpetual taker fee default 0.055%, maker -0.01% (rebate)
            # Market entry is taker. Market exit is also taker.
            rate = getattr(client, "get_taker_fee_rate", lambda m: None)(market)
            if rate is None or not (0 < rate < 0.01):
                return 0.00055  # fallback 0.055%
            return float(rate)
        except Exception as exc:
            logger.debug("[S3_GATE] fee rate fetch failed (%s), fallback 0.055%%: %s", market, exc)
            return 0.00055  # hardcode fallback (taker)

    def _check_s3_fee_gate(
        self,
        market: str,
        direction: str,
        price: float,
        atr: float,
        size_usdt: float,
        leverage: int,
        tp_mult: float,
        sl_mult: float,
        pa_double_confirmed: bool = False,  # Phase L.3 input (optional)
    ) -> tuple:
        """fee-aware net-expected-value gate right before entry.

        Returns: (allow: bool, reason: str, stats: dict)
          - allow=True  : allow entry (in paper_mode only the virtual counter increments)
          - allow=False : block (effective in live mode only, self._journal.record_blocked)
          - reason      : "[S3_GATE] ..." standard format
          - stats       : measurement dict (for persistence)

        Edge handling (this agent's letter #11, 7 cases):
          ① div-by-zero -- guard that qty/price/ATR are all > 0
          ② fee API error -- _get_taker_fee_rate fallback
          ③ leverage changing -- use the leverage input as-is (caller's responsibility)
          ④ size_usdt undefined -- None or 0 -> reject (skip)
          ⑤ paper->live boundary -- use cfg values as of call time
          ⑥ restart restore -- don't read an external stats file (caller accumulates)
          ⑦ concurrency -- writes are done by the caller within a lock

        Complies with review items #1~#10.
        """
        cfg = self.config
        # ① enabled check
        if not getattr(cfg, "s3_gate_enabled", False):
            return True, "s3_gate_disabled", {}

        paper = bool(getattr(cfg, "s3_gate_paper_mode", True))

        # ① div-by-zero guard
        if price <= 0 or atr <= 0 or size_usdt is None or size_usdt <= 0 or leverage <= 0:
            reason = (f"[S3_GATE] {market} {direction} INPUT_INVALID "
                      f"price={price} atr={atr} size={size_usdt} lev={leverage}")
            logger.warning(reason)
            return True, reason, {"input_invalid": True}  # safe fallback: pass (so S3 Gate doesn't block trading)

        # ② fee computation (round-trip ×2)
        fee_rate = self._get_taker_fee_rate(market)
        fee_mult = float(getattr(cfg, "s3_gate_fee_multiplier", 2.0))
        # estimate qty: size_usdt × leverage / price = notional / price
        notional = size_usdt * leverage
        qty = notional / price
        fee_one_side = notional * fee_rate
        fee_total = fee_one_side * fee_mult  # round-trip ×2 (this agent's review item #1)

        # slippage estimate (5bp = 0.05%)
        slippage_bps = float(getattr(cfg, "s3_gate_slippage_bps", 5.0))
        slippage = notional * (slippage_bps / 10000.0)

        # net_ev computation (review item #2)
        # expected PnL = ATR × tp_mult × qty (notional change)
        # Phase L.3: weight net_ev +10% on PA double confirm
        gross_ev = atr * tp_mult * qty
        if pa_double_confirmed and getattr(cfg, "pa_double_confirm_enabled", False):
            gross_ev *= 1.10  # quality weighting

        net_ev = gross_ev - fee_total - slippage

        # decide threshold (LINK gambling guard)
        threshold = float(getattr(cfg, "s3_gate_min_net_ev_usdt", 0.0))
        if market.upper() == "LINKUSDT":
            link_mult = float(getattr(cfg, "s3_gate_link_multiplier", 1.3))
            threshold *= link_mult
            # if threshold is 0, apply a separate minimum to LINK only (1.3x the fee)
            if threshold <= 0:
                threshold = fee_total * (link_mult - 1.0)

        # decision
        passed = net_ev > threshold
        mode_str = "paper" if paper else "live"
        passed_str = "passed" if passed else "blocked"

        # review-item #9 standard log format
        reason = (f"[S3_GATE] {market} {direction} "
                  f"net_ev={net_ev:.4f} fee×{fee_mult}={fee_total:.4f} "
                  f"slip={slippage:.4f} gross_ev={gross_ev:.4f} "
                  f"th={threshold:.4f} gate={passed_str} mode={mode_str}")

        stats = {
            "ts": time.time(),
            "market": market,
            "direction": direction,
            "net_ev": round(net_ev, 4),
            "gross_ev": round(gross_ev, 4),
            "fee_total": round(fee_total, 4),
            "slippage": round(slippage, 4),
            "threshold": round(threshold, 4),
            "fee_rate": round(fee_rate, 6),
            "passed": passed,
            "mode": mode_str,
            "link_boosted": (market.upper() == "LINKUSDT"),
            "pa_double_confirmed": bool(pa_double_confirmed),
        }

        if passed:
            # passed (same for live/paper)
            logger.info(reason)
            return True, reason, stats

        # block case
        if paper:
            # Paper mode (review item #5): allow entry but only count "would have skipped"
            logger.info("%s [PAPER skip-counted, entry ALLOWED]", reason)
            return True, reason + " [paper_skip_counted]", stats
        else:
            # Live mode: real block
            logger.warning("%s [LIVE BLOCKED]", reason)
            # review item #4: self._journal.record_blocked
            try:
                from app.manager.trade_journal import journal
                self._journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="s3_fee_gate",
                    detail=f"net_ev={net_ev:.4f} th={threshold:.4f} fee={fee_total:.4f}"
                )
            except Exception as exc:
                logger.debug("[S3_GATE] record_blocked failed: %s", exc)
            return False, reason, stats

    def _persist_s3_gate_stats(self, stats_entry: dict) -> None:
        """Review item #8 -- persist via safe_write_json + jsonl append.

        Edge ⑦ concurrency: assumes the caller (_execute_entry) holds self._lock.
        Edge ⑥ restart: if the stats file is missing, init with an empty dict.
        """
        try:
            # 1) jsonl append (time-series data -- kept forever)
            os.makedirs(os.path.dirname(S3_GATE_LOG_PATH), exist_ok=True)
            with open(S3_GATE_LOG_PATH, "a", encoding="utf-8") as f:
                f.write(json.dumps(stats_entry, ensure_ascii=False) + "\n")

            # 2) summary stats (atomic, cumulative counters)
            from app.core.io_utils import safe_write_json
            summary = {}
            if os.path.exists(S3_GATE_STATS_PATH):
                try:
                    with open(S3_GATE_STATS_PATH, "r", encoding="utf-8") as f:
                        summary = json.load(f) or {}
                except Exception:
                    summary = {}  # reset on corruption (edge ⑥)

            # cumulative update
            mode = stats_entry.get("mode", "?")
            passed = bool(stats_entry.get("passed", False))
            virtual_net_saved = 0.0
            if not passed and mode == "paper":
                # on paper skip, accumulate the "absolute value of the net_ev it would have saved"
                virtual_net_saved = abs(stats_entry.get("net_ev", 0.0))

            summary.setdefault("totals", {"checks": 0, "passed": 0, "blocked": 0,
                                         "paper_skips": 0, "live_blocks": 0})
            summary.setdefault("virtual_net_saved", 0.0)
            summary.setdefault("link_bypass_count", 0)
            summary.setdefault("first_ts", stats_entry.get("ts"))
            summary["last_ts"] = stats_entry.get("ts")

            t = summary["totals"]
            t["checks"] += 1
            if passed:
                t["passed"] += 1
                if stats_entry.get("link_boosted") and stats_entry.get("net_ev", 0) > 0:
                    # LINK passing the gate = a bypass (promotion-condition ④ counter)
                    summary["link_bypass_count"] += 1
            else:
                t["blocked"] += 1
                if mode == "paper":
                    t["paper_skips"] += 1
                    summary["virtual_net_saved"] += virtual_net_saved
                else:
                    t["live_blocks"] += 1

            safe_write_json(S3_GATE_STATS_PATH, summary)
        except Exception as exc:
            logger.warning("[S3_GATE] persist stats failed: %s", exc)

    def _in_entry_grace_period(self, pos, now: float) -> bool:
        """Time to read the mood after entry (owner vision #6, 2026-05-18).

        Owner's words: "Need more time to read the mood after entry"
        A/B probability game -- right after entry we don't know whether it's A (long-term stuck) or B (small valley then hill).
        Disable fast-cut guards for N sec -> buy discrimination time.

        Applied guards: pre_be_stall_exit + reverse_drift_exit (conditions added at the call sites)
        Not affected: be_stall_exit (profit guard), long_hold_timeout (time-unit), SL, Hard ROE
        """
        grace_sec = float(getattr(self.config, "entry_grace_period_sec", 0.0))
        if grace_sec <= 0:
            return False
        if not pos or getattr(pos, "entry_ts", 0) <= 0:
            return False
        return (now - pos.entry_ts) < grace_sec

    def _check_news_force_exit(self, pos, now: float) -> tuple:
        """During grace, if news sentiment is strongly opposite the entry direction, cut immediately (owner vision #6 aux).

        Owner's words: "a way to revive the news... not just an entry variable but an exit variable too"
        Entry-time = focus_manager.py 4305 (conviction formula) -- already integrated, only needs focus_enabled=True
        Exit-time = this helper -- a force-exit trigger during grace

        A/B probability game:
          - sentiment strongly opposite (LONG but below -0.5 / SHORT but above +0.5) -> A pattern -> cut immediately
          - sentiment same direction or NEUTRAL -> endure (possible B pattern)

        Returns: (force_exit: bool, reason: str)
        """
        try:
            from app.core.news_sentiment import get_news_sentiment
            _ns = get_news_sentiment()
            if not _ns or not _ns.config.get("focus_enabled"):
                return False, ""  # news itself is dormant
            coin = pos.market.replace("USDT", "").replace("USD", "")
            result = _ns.get_sentiment(coin=coin)
            if not result or result.source == "fallback":
                return False, ""  # untrustworthy data
            sentiment_score = float(result.score)  # -1.0 ~ +1.0
            threshold = float(getattr(self.config, "news_grace_exit_threshold", 0.5))
            dir_up = (pos.direction or "").upper()
            if dir_up == "LONG" and sentiment_score <= -threshold:
                return True, f"news_grace_against_LONG_s{sentiment_score:+.2f}"
            elif dir_up == "SHORT" and sentiment_score >= threshold:
                return True, f"news_grace_against_SHORT_s{sentiment_score:+.2f}"
        except Exception as exc:
            logger.debug("[FOCUS] _check_news_force_exit error: %s", exc)
        return False, ""

    def _check_grace_force_exit(self, pos, now: float) -> tuple:
        """Integrated force-exit check during grace (market_bias + news_sentiment).

        Owner vision #6 first attempt (time-based). Per the owner's correction, unused (default OFF).
        Use _check_exit_consensus instead (time-independent).
        """
        # 1. market_bias
        if getattr(self.config, "market_bias_grace_exit_enabled", False):
            force, reason = self._check_market_bias_force_exit(pos, now)
            if force:
                return True, reason
        # 2. news_sentiment
        if getattr(self.config, "news_grace_exit_enabled", False):
            force, reason = self._check_news_force_exit(pos, now)
            if force:
                return True, reason
        return False, ""

    def _check_exit_consensus(self, pos, now: float) -> str:
        """When an existing exit guard fires, combine neighbor + news opinions (owner vision #6 option B, 2026-05-18 evening).

        Owner's spirit: "time cuts gave small consecutive losses / even enduring = a long-term unrealized-loss coin" = not time-based.
        Solution: when an existing guard fires, *combine* neighbor + news opinions then decide cut/endure.

        A/B probability game:
          - both opposite (or same-direction dominance) -> A pattern -> "exit" (agree with the guard)
          - both same direction (or strong entry-direction sentiment) -> B pattern -> "hold" (ignore the guard)
          - mixed or no signal -> "neutral" (default = follow the guard)

        Time-independent = aligns with the owner's *time-based skepticism*.

        Returns: "exit" / "hold" / "neutral"
        """
        if not getattr(self.config, "exit_consensus_enabled", False):
            return "neutral"
        votes_exit = 0
        votes_hold = 0
        # 1. market_bias opinion
        try:
            engine = self._get_context_engine()
            if engine and getattr(engine, "bias", None) and getattr(self.config, "market_bias_enabled", False):
                result = engine.bias.evaluate(pos.market, pos.direction, now)
                delta = float(result.get("delta", 0))
                if delta < 0:
                    votes_exit += 1  # opposite dominance = A signal
                elif delta == 0:
                    bias = result.get("bias", "NEUTRAL")
                    dir_up = (pos.direction or "").upper()
                    if bias == dir_up:
                        votes_hold += 1  # same-direction dominance = B signal
        except Exception as exc:
            logger.debug("[FOCUS] exit_consensus mb error: %s", exc)
        # 2. news sentiment opinion
        try:
            from app.core.news_sentiment import get_news_sentiment
            _ns = get_news_sentiment()
            if _ns and _ns.config.get("focus_enabled"):
                coin = pos.market.replace("USDT", "").replace("USD", "")
                result = _ns.get_sentiment(coin=coin)
                if result and result.source != "fallback":
                    sentiment = float(result.score)
                    threshold = float(getattr(self.config, "exit_consensus_news_threshold", 0.3))
                    dir_up = (pos.direction or "").upper()
                    if dir_up == "LONG":
                        if sentiment <= -threshold:
                            votes_exit += 1
                        elif sentiment >= threshold:
                            votes_hold += 1
                    elif dir_up == "SHORT":
                        if sentiment >= threshold:
                            votes_exit += 1
                        elif sentiment <= -threshold:
                            votes_hold += 1
        except Exception as exc:
            logger.debug("[FOCUS] exit_consensus news error: %s", exc)
        # combined decision
        if votes_exit > votes_hold:
            return "exit"
        elif votes_hold > votes_exit:
            return "hold"
        return "neutral"

    def _check_market_bias_force_exit(self, pos, now: float) -> tuple:
        """During grace, if market_bias is opposite the entry direction, recommend an immediate cut (owner vision #6 aux).

        Owner's words: "following the direction of other linked coins is a bit safer.. reading the neighboring servers"

        A/B probability game:
          - neighbors (market_bias) same direction -> B pattern -> endure (keep grace)
          - neighbors opposite direction -> A pattern -> cut immediately (avoid the old -$1063)

        Reuses the market_bias module (entry-time penalty -> extended to exit-time force exit).
        Returns: (force_exit: bool, reason: str)
        """
        try:
            engine = self._get_context_engine()
            if not engine or not getattr(engine, "bias", None):
                return False, ""
            if not getattr(self.config, "market_bias_enabled", False):
                return False, ""
            result = engine.bias.evaluate(pos.market, pos.direction, now)
            delta = float(result.get("delta", 0))
            # delta < 0 = opposite-direction dominance = A-pattern signal
            if delta < 0:
                bias = result.get("bias", "?")
                dom = float(result.get("dominance", 0))
                return True, f"mb_grace_against_{bias}_dom{dom:.2f}"
        except Exception as exc:
            logger.debug("[FOCUS] _check_market_bias_force_exit error: %s", exc)
        return False, ""

    def _check_reentry_allowed(self, direction: str, market: str, price: float) -> bool:
        """Block immediate same-direction re-entry -- allow once the market cycles.

        Block: direction == _last_exit_direction AND market == _last_exit_market

        Allow conditions (any one suffices):
        1. always allow a different direction
        2. price moved >= 2x the round-trip fee from the exit price (|current-exit|/exit > 0.22%)
        3. ADX dropped below dormant then rose back above min_adx_entry (new trend starting)
        4. completed a full DORMANT->ALERT->HUNT cycle
        """
        # ★ manual-exit penalty top-priority check -- a coin the user exited by hand is banned for 4 hours
        # [2026-04-18 night] reflecting this agent's review: on toggle OFF, immediately clear existing penalties too (option A)
        #   user UX expectation: "OFF = release all blocks immediately". Don't leave a dead dict; clear it all.
        mkt_upper = market.upper()
        if not getattr(self.config, "manual_exit_penalty_enabled", True):
            if self._manual_exit_penalties:
                logger.info("[FOCUS] Manual penalty DISABLED — clearing %d existing penalty(s)", len(self._manual_exit_penalties))
                self._manual_exit_penalties.clear()
        elif mkt_upper in self._manual_exit_penalties:
            expire_ts = self._manual_exit_penalties[mkt_upper]
            remaining = expire_ts - time.time()
            if remaining > 0:
                hours_left = remaining / 3600
                logger.info("[FOCUS] ⛔ MANUAL PENALTY: %s blocked for %.1fh more (user manually closed)", mkt_upper, hours_left)
                return False
            else:
                # expired -> remove
                del self._manual_exit_penalties[mkt_upper]
                logger.info("[FOCUS] Manual penalty expired for %s — re-entry allowed", mkt_upper)

        # ★ [2026-04-24] Consecutive Loss Pause -- owner's simple idea
        # N consecutive losses -> auto-pause M min (all coins / all directions). Full block regardless of market/direction.
        # A time-based safety net between max_daily_sl (done for the day) and dm_streak_block (permanent).
        consec_blocked, consec_reason = self._check_consecutive_loss_pause()
        if consec_blocked:
            logger.info("[FOCUS] ⛔ %s", consec_reason)
            try:
                from app.manager.trade_journal import journal
                self._journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="consecutive_loss_pause",
                    detail=consec_reason,
                )
            except Exception:
                pass
            return False

        # ★ [2026-06-04 owner] per-direction regime-window failure block
        # N cumulative failures in that direction within N hours -> block only that direction / allow opposite
        dir_fail_blocked, dir_fail_reason = self._check_direction_fail_window(direction)
        if dir_fail_blocked:
            logger.info("[FOCUS] ⛔ %s", dir_fail_reason)
            try:
                from app.manager.trade_journal import journal
                self._journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="dir_fail_window",
                    detail=dir_fail_reason,
                )
            except Exception:
                pass
            return False

        # -- 🛡️ [2026-06-11 owner] fleet dir_fail -- share neighbor failures (block same coin+direction cumulatively) --
        #   Prevents today's VELVET LONG sequential wipeout (server-b->server-a->home, 50-min stagger). default OFF.
        try:
            from app.core.peer_brief import (
                check_peer_direction_fail_caution, get_peer_fleet_dirfail_window_min,
            )
            _fleet_lc = self._count_coin_dir_loss(
                market, direction, get_peer_fleet_dirfail_window_min() / 60.0)
            _fleet_blocked, _fleet_src = check_peer_direction_fail_caution(
                market, direction, local_count=_fleet_lc)
            if _fleet_blocked:
                logger.info("[FOCUS] ⛔ %s", _fleet_src)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="peer_fleet_dirfail", detail=_fleet_src,
                    )
                except Exception:
                    pass
                return False
        except Exception as exc:
            logger.debug("[FOCUS] peer fleet dirfail check error: %s", exc)

        # ★ Phase L.2 (2026-04-22, Harpoon 0-7 -> ported to FOCUS):
        # On SL/Fast-Reject/Fast-Reject-v2, block (market, direction) for 30 min.
        # A stricter extra layer than B9 post_trade_pause (loss 600s / fast_reject 900s).
        # Reason: the trap where a coin like AAVE retries the same setup within 5~15 min (Harpoon forensic ③).
        # default OFF -- activate after owner approval.
        if getattr(self.config, "reentry_cooldown_v2_enabled", False):
            try:
                from app.manager.trade_journal import journal
                cd_min = float(getattr(self.config, "reentry_cooldown_v2_min", 30.0))
                cd_sec = cd_min * 60.0
                _now = time.time()
                # check recent EXITs of the SL/Fast-Reject family + same (market, direction)
                # use self._journal.get_trades (get_recent_exits doesn't exist)
                _resp = self._journal.get_trades(
                    limit=20, strategy="FOCUS", market=mkt_upper, include_blocked=False, page=1
                ) or {}
                recent = _resp.get("trades", [])
                for e in recent:
                    if e.get("event") != "EXIT":
                        continue
                    if e.get("direction", "").upper() != direction.upper():
                        continue
                    er = (e.get("exit_reason", "") or "").lower()
                    if not any(k in er for k in ("sl", "fast_reject", "stop_loss")):
                        continue
                    age = _now - float(e.get("ts", 0) or 0)
                    if 0 <= age < cd_sec:
                        remain_min = (cd_sec - age) / 60.0
                        logger.info(
                            "[FOCUS] ⛔ Phase L.2 reentry_cooldown_v2: %s %s blocked %.1fmin more "
                            "(SL/fast_reject %.1fmin ago, cd=%.0fmin)",
                            mkt_upper, direction, remain_min, age/60.0, cd_min
                        )
                        try:
                            self._journal.record_blocked(
                                "FOCUS", market, direction,
                                reason="reentry_cooldown_v2",
                                detail=f"SL {age/60:.1f}min ago, cd {cd_min:.0f}min",
                            )
                        except Exception:
                            pass
                        return False
            except Exception as exc:
                logger.debug("[FOCUS] Phase L.2 cooldown check failed: %s", exc)

        # ★ [2026-04-19] B9 -- Post-Trade Pause (journal-based, prevents SERVER_SL bypass)
        # The `self._last_exit_*` memory has a bug where it isn't updated on the SERVER_SL path.
        # -> reconstruct via a full journal EXIT scan. Different cooldown per prior-exit type:
        #   profit       -> 300s (defend revenge entry on an exhausted direction)
        #   loss         -> 600s (defend re-entry without learning)
        #   fast_reject  -> 900s (defend chasing right after a quick exit)
        # "everything is a result of the settings" -- a calculated cooldown, not chance
        if getattr(self.config, "post_trade_pause_enabled", True):
            pause_blocked, pause_reason = self._check_post_trade_pause(market, direction)
            if pause_blocked:
                logger.info("[FOCUS] ⛔ Post-Trade Pause: %s %s — %s", market, direction, pause_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="post_trade_pause",
                        detail=pause_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] post_trade_pause journal failed: %s", exc)
                return False

        # ★ [2026-04-19] B8 -- Direction Exhaustion (same direction exhausted after consecutive profits)
        # M+ profitable exits on the same coin×direction within recent N min -> block that direction.
        # Philosophy: "a direction with consecutive profits can be treated as near end-of-life" (this agent)
        #       "use both long and short -> missing one isn't a loss" (the opposite-direction chance is alive)
        if getattr(self.config, "direction_exhaustion_enabled", True):
            exh_blocked, exh_reason = self._check_direction_exhaustion(market, direction)
            if exh_blocked:
                logger.info("[FOCUS] ⛔ Direction Exhaustion: %s %s — %s", market, direction, exh_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="direction_exhaustion",
                        detail=exh_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] direction_exhaustion journal failed: %s", exc)
                return False

        # ★ [2026-04-19 -> 2026-04-20 Phase F restore] B10 -- Profit-Exit Coin Block
        # This agent's intent: same coin + same direction + N consecutive profits -> block only that direction
        # Defends the "go in and out then lose big" pattern -- FLIP (opposite direction) is allowed
        if getattr(self.config, "profit_exit_block_enabled", True):
            peb_blocked, peb_reason = self._check_profit_exit_block(market, direction)
            if peb_blocked:
                logger.info("[FOCUS] ⛔ Profit-Exit Block: %s %s — %s", market, direction, peb_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="profit_exit_block",
                        detail=peb_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] profit_exit_block journal failed: %s", exc)
                return False

        # ★ [2026-04-19] B11 -- Regime Direction Lock (this agent's direct directive, friend's advice)
        # "BULL = LONG only, BEAR = SHORT only, otherwise REST"
        # + "all-stop on signs" -- block at the code level the greed of trying to catch both sides.
        # Root diagnosis of 4/13~14 +$200/+$300 -> giving back −$264/−$37 over the next days.
        if getattr(self.config, "regime_direction_lock_enabled", True):
            rdl_blocked, rdl_reason = self._check_regime_direction_lock(direction, market)
            if rdl_blocked:
                logger.info("[FOCUS] ⛔ Regime Lock: %s %s — %s", market, direction, rdl_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="regime_direction_lock",
                        detail=rdl_reason,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] regime_direction_lock journal failed: %s", exc)
                return False

        # condition 0: always allow if there's no exit history
        if not self._last_exit_direction or not self._last_exit_market:
            return True

        # ★ [2026-04-18] per-market min re-entry interval: 300-sec wait only for same market + same direction
        # old: direction-agnostic block -> even a SHORT flip after a LONG exit was blocked 5 min (bias cause #5)
        # fix: block only same-direction re-entry -- FLIP allowed immediately
        # [note] self._last_exit_* may not update on the SERVER_SL path, so B9 is the main defense line
        if (market.upper() == self._last_exit_market.upper()
                and direction == self._last_exit_direction):
            elapsed = time.time() - self._last_exit_ts
            if elapsed < 300:
                logger.info("[FOCUS] Reentry BLOCKED: %s %s exited %.0fs ago (min 300s, same dir)",
                            market, direction, elapsed)
                return False

        # ★ Coin Repeat Brake: same coin N+ times -> cooldown base × (N-free) sec, max 1800 sec
        #   free up to 5, brake from the 6th (frequent farts mean a turd is coming)
        # [2026-04-18] direction-separated -- stops repeated LONG from also triggering the SHORT brake
        # [2026-04-18] user request "open everything to run 24h" -- fully disable Repeat Brake
        # [2026-04-18 20:50] ★ re-enabled -- after the RAVE 7-in-3-min -$74 massacre
        #   live proof that what "open everything" turned off was the repeat-loss shield
        if self.config.coin_repeat_brake_enabled:
            repeat_count, coin_last_exit_ts = self._get_coin_repeat_info(market, direction)
            free = self.config.coin_repeat_free_count
            if repeat_count >= free and coin_last_exit_ts > 0:
                excess = repeat_count - free  # penalize only the excess (6th->1x, 8th->3x)
                required_cd = min(self.config.coin_repeat_cooldown_base * excess, 1800.0)  # 30-min cap
                elapsed_since_coin_exit = time.time() - coin_last_exit_ts
                if elapsed_since_coin_exit < required_cd:
                    remaining = required_cd - elapsed_since_coin_exit
                    logger.info(
                        "[FOCUS] Repeat Brake: %s traded %d times in %dh — cooldown %.0fs (%.0fx%d excess), %.0fs remaining",
                        market, repeat_count, int(self.config.coin_repeat_window_hours),
                        required_cd, self.config.coin_repeat_cooldown_base, excess, remaining
                    )
                    # ★ journal record -- persist the block reason
                    try:
                        from app.manager.trade_journal import journal
                        self._journal.record_blocked(
                            "FOCUS", market, direction,
                            reason="repeat_brake",
                            detail=f"count={repeat_count},cooldown={required_cd:.0f}s,remaining={remaining:.0f}s",
                        )
                    except Exception as exc:
                        logger.debug("[FOCUS] import journal failed: %s", exc)
                    return False
                else:
                    logger.info(
                        "[FOCUS] Repeat Brake: %s traded %d times, cooldown %.0fs elapsed (need %.0fs) — allowed",
                        market, repeat_count, elapsed_since_coin_exit, required_cd
                    )

        # ★ Direction Block (runtime-file-based coin×direction lock)
        #   For data-driven emergency blocking. e.g. ETH LONG bled -$29 in 24h -> block 12h.
        #   Blocks only a "specific direction", not the whole coin, so the opposite chance stays.
        #   Compatible with the "no coin blacklist" principle (a temporary hurdle, not a blacklist).
        _dir_blocked, _dir_reason = self._is_direction_blocked(market, direction)
        if _dir_blocked:
            logger.info(
                "[FOCUS] ⛔ Direction Block: %s %s — %s",
                market, direction, _dir_reason,
            )
            try:
                from app.manager.trade_journal import journal
                self._journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="direction_block",
                    detail=_dir_reason,
                )
            except Exception as exc:
                logger.debug("[FOCUS] import journal failed: %s", exc)
            return False

        # ★ Coin Loss Cap: block when 24h cumulative loss is exceeded
        # [2026-04-18] direction-separated -- stops LONG cumulative loss from also blocking SHORT
        if self.config.coin_loss_cap_enabled:
            total_loss = self._get_coin_loss_total(market, direction)
            cap = self._effective_coin_loss_cap()
            if total_loss < 0 and abs(total_loss) >= cap:
                logger.info(
                    "[FOCUS] Coin Loss Cap: %s 24h loss $%.2f exceeds cap $%.2f — BLOCKED",
                    market, total_loss, cap,
                )
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked(
                        "FOCUS", market, direction,
                        reason="coin_loss_cap",
                        detail=f"24h_loss=${total_loss:.2f},cap=${cap:.2f}",
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] import journal failed: %s", exc)
                return False

        # ★ [2026-04-19] Pair Group Block (default OFF, user opt-in)
        # Pair coins in opposite directions = fee offset. Supports aggressive/conservative modes.
        # When pair_block_enabled=False, _check_pair_block returns (False, "") immediately.
        _pair_blocked, _pair_reason = self._check_pair_block(market, direction)
        if _pair_blocked:
            logger.info("[FOCUS] ⛔ Pair Block: %s %s — %s", market, direction, _pair_reason)
            try:
                from app.manager.trade_journal import journal
                self._journal.record_blocked(
                    "FOCUS", market, direction,
                    reason="pair_block",
                    detail=_pair_reason,
                )
            except Exception as exc:
                logger.debug("[FOCUS] pair_block journal failed: %s", exc)
            return False

        # condition 1: always allow a different direction
        if direction != self._last_exit_direction:
            return True

        # allow a different market
        if market.upper() != self._last_exit_market.upper():
            return True

        # -- below: same direction + same market = re-entry block target --

        # condition 2: allow if price moved enough (round-trip fee × 2 = 0.22%)
        if self._last_exit_price > 0 and price > 0:
            price_change_pct = abs(price - self._last_exit_price) / self._last_exit_price * 100
            if price_change_pct >= 0.22:
                logger.info("[FOCUS] Reentry allowed: price moved %.3f%% from exit (>0.22%%)", price_change_pct)
                return True

        # condition 3: ADX dropped below dormant then rose again -> new trend
        # (_last_adx_value went below dormant then is now >= min_adx_entry)
        # this is auto-handled in the _handle_dormant->_handle_hunt cycle

        # condition 4: completed a DORMANT->ALERT->HUNT cycle
        if self._completed_dormant_cycle:
            logger.info("[FOCUS] Reentry allowed: completed DORMANT→ALERT→HUNT cycle")
            self._completed_dormant_cycle = False
            return True

        logger.info("[FOCUS] Reentry BLOCKED: same direction=%s same market=%s, price_diff=%.3f%%",
                     direction, market,
                     abs(price - self._last_exit_price) / self._last_exit_price * 100 if self._last_exit_price > 0 else 0)
        return False

    def apply_manual_exit_penalty(self, market: str, hours: float = 4.0):
        """On a manual exit, apply a re-entry ban penalty to that coin.
        Args:
            market: coin symbol (e.g. ZECUSDT)
            hours: ban duration (default 4 hours)
        """
        mkt = market.upper()
        expire_ts = time.time() + hours * 3600
        self._manual_exit_penalties[mkt] = expire_ts
        self._save_config()
        logger.warning("[FOCUS] ⛔ MANUAL EXIT PENALTY: %s banned for %.1fh (until %s)",
                       mkt, hours, time.strftime("%H:%M", time.localtime(expire_ts)))
        self._notify(f"⛔ {mkt} manual exit -> entry banned for {hours:.0f}h\nrelease: {time.strftime('%H:%M', time.localtime(expire_ts))}")

    def _detect_sideways_ending(self, market: str) -> bool:
        """Detect signs of sideways ending. Triggers the DORMANT -> ALERT transition.

        True if 2+ signs present:
        1. BB extreme squeeze (bollinger_squeeze)
        2. ADX bottom bounce (turns up after declining, still < 25)
        3. MACD histogram expanding off the zero line
        4. volume surge (kline volume > 20-period average × 1.5)
        """
        signs = 0
        try:
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            if not raw or len(raw) < 25:
                return False

            closes = [float(r[4]) for r in raw if len(r) >= 5]
            highs = [float(r[2]) for r in raw if len(r) >= 5]
            lows = [float(r[3]) for r in raw if len(r) >= 5]
            volumes = [float(r[5]) for r in raw if len(r) >= 6]

            # 1) BB squeeze
            from app.strategy.indicators import bollinger_squeeze
            if len(closes) >= 20:
                sq = bollinger_squeeze(closes)
                if sq and sq.get("is_squeeze"):
                    signs += 1

            # 2) ADX bottom bounce
            from app.strategy.indicators import adx_series as _adx_series_fn
            if len(closes) >= 30:
                adx_s = _adx_series_fn(highs, lows, closes, period=14)
                if len(adx_s) >= 3:
                    a1, a2, a3 = adx_s[-3]["adx"], adx_s[-2]["adx"], adx_s[-1]["adx"]
                    # turns up after declining, still under 25
                    if a1 > a2 and a3 > a2 and a3 < 25:
                        signs += 1

            # 3) MACD hist expanding off the zero line
            from app.strategy.indicators import macd_hist_series
            if len(closes) >= 35:
                hist_s = macd_hist_series(closes)
                if len(hist_s) >= 3:
                    h1, h2, h3 = abs(hist_s[-3]), abs(hist_s[-2]), abs(hist_s[-1])
                    if h3 > h2 > h1 and h1 < closes[-1] * 0.001:  # expanding near zero
                        signs += 1

            # 4) volume surge
            if len(volumes) >= 21:
                avg_vol = sum(volumes[-21:-1]) / 20
                if avg_vol > 0 and volumes[-1] > avg_vol * 1.5:
                    signs += 1

        except Exception as exc:
            logger.debug("[FOCUS] sideways ending detection error: %s", exc)

        return signs >= 2

    def _detect_sideways_starting(self, market: str) -> bool:
        """Detect signs of sideways starting. Triggers the POSITIONED -> CAUTION transition.

        True if 2+ signs present:
        1. ADX declining 3 candles in a row
        2. BB width shrinking 3 candles in a row
        3. |MACD hist| shrinking 3 candles in a row
        4. Market structure = SIDEWAYS
        """
        signs = 0
        try:
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            if not raw or len(raw) < 30:
                return False

            closes = [float(r[4]) for r in raw if len(r) >= 5]
            highs = [float(r[2]) for r in raw if len(r) >= 5]
            lows = [float(r[3]) for r in raw if len(r) >= 5]

            # 1) ADX declining 3 candles in a row
            from app.strategy.indicators import adx_series as _adx_series_fn
            if len(closes) >= 30:
                adx_s = _adx_series_fn(highs, lows, closes, period=14)
                if len(adx_s) >= 3:
                    a1, a2, a3 = adx_s[-3]["adx"], adx_s[-2]["adx"], adx_s[-1]["adx"]
                    if a1 > a2 > a3:
                        signs += 1

            # 2) BB width shrinking 3 candles in a row
            from app.strategy.indicators import bollinger_bands as _bb_fn
            if len(closes) >= 23:
                bw_series = []
                for i in range(3):
                    end_idx = len(closes) - (2 - i)
                    bb = _bb_fn(closes[:end_idx], 20, 2.0)
                    if bb and bb.get("bandwidth"):
                        bw_series.append(bb["bandwidth"])
                if len(bw_series) == 3 and bw_series[0] > bw_series[1] > bw_series[2]:
                    signs += 1

            # 3) |MACD hist| shrinking 3 candles in a row
            from app.strategy.indicators import macd_hist_series
            if len(closes) >= 35:
                hist_s = macd_hist_series(closes)
                if len(hist_s) >= 3:
                    h1, h2, h3 = abs(hist_s[-3]), abs(hist_s[-2]), abs(hist_s[-1])
                    if h1 > h2 > h3:
                        signs += 1

            # 4) Market structure = SIDEWAYS
            from app.strategy.greenpen.pa_detector import OHLCV as _O
            from app.strategy.greenpen.market_structure import analyze_structure as _as
            candles = [_O(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
            if len(candles) >= 10:
                struct = _as(candles)
                trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                if trend_val == "SIDEWAYS":
                    signs += 1

        except Exception as exc:
            logger.debug("[FOCUS] sideways starting detection error: %s", exc)

        return signs >= 2

    # ── State Handlers ──────────────────────────────────────

    def _handle_dormant(self, now: float) -> Dict:
        """DORMANT: ADX < dormant_threshold.
        Scan interval: ADX < 10 -> 1 hour, 10~14 -> 30 min, 15+ -> ALERT immediately."""
        # daily-limit check
        if self.daily_plans_used >= self.config.max_daily_plans:
            return {"state": "DORMANT", "reason": "daily_plan_limit"}
        if self.daily_sl_count >= self.config.max_daily_sl:
            return {"state": "DORMANT", "reason": "daily_sl_limit"}

        # dynamic scan interval: shortens with ADX level
        # if Scanner ON, shorten the interval to catch opportunities
        scanner_active = self.config.scanner_entry and self.config.max_positions > 1
        last_adx = self._last_adx_value
        if last_adx <= 0 or last_adx < 10:
            dormant_interval = 600.0 if scanner_active else 3600.0   # Scanner: 10 min, default: 1 hour
        elif last_adx < self.config.dormant_adx_threshold:
            dormant_interval = 300.0 if scanner_active else 1800.0   # Scanner: 5 min, default: 30 min
        elif last_adx >= self.config.min_adx_entry:
            # [2026-04-09] ADX already enterable -> switch to HUNT fast
            dormant_interval = self.config.scan_interval_sec  # 60 sec
        else:
            dormant_interval = 120.0 if scanner_active else 300.0  # 2 min/5 min

        if now - self.last_scan_ts < dormant_interval:
            remaining = dormant_interval - (now - self.last_scan_ts)
            return {"state": "DORMANT", "next_scan_in": round(remaining)}

        self.last_scan_ts = now

        # if the ADX filter is off, go straight to HUNT
        if not self.config.adx_filter_enabled:
            self.state = FocusState.HUNT
            self._save_config()
            logger.info("[FOCUS] DORMANT → HUNT (ADX filter disabled)")
            return {"state": "HUNT"}

        # use lock_market's coin if set, else BTCUSDT
        check_market = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
        adx_data = self._fetch_primary_adx(check_market)

        if not adx_data:
            return {"state": "DORMANT", "reason": "adx_fetch_failed"}

        adx_val = adx_data["adx"]
        logger.info("[FOCUS] DORMANT check: %s ADX=%.1f (entry=%d, dormant=%d)",
                     check_market, adx_val, self.config.min_adx_entry, self.config.dormant_adx_threshold)

        if adx_val >= self.config.min_adx_entry:
            # trend confirmed -> straight to HUNT
            self.state = FocusState.HUNT
            self._completed_dormant_cycle = True
            self.last_scan_ts = 0  # [2026-04-09] scan immediately after switching to HUNT
            self._save_config()
            logger.info("[FOCUS] DORMANT → HUNT (ADX %.1f >= %d)", adx_val, self.config.min_adx_entry)
            return {"state": "HUNT", "adx": round(adx_val, 1)}

        if adx_val >= self.config.dormant_adx_threshold:
            # ADX >= dormant threshold -> ALERT immediately (no extra condition)
            self.state = FocusState.ALERT
            self._save_config()
            # also log sideways-ending signs (for reference, not a gate)
            target_market = self.config.lock_market.upper() if self.config.lock_market else check_market
            sw_ending = self._detect_sideways_ending(target_market)
            logger.info("[FOCUS] DORMANT → ALERT (ADX %.1f >= %d, sideways_ending=%s)",
                         adx_val, self.config.dormant_adx_threshold, sw_ending)
            return {"state": "ALERT", "adx": round(adx_val, 1)}

        # -- Scanner-independent HUNT: even if gold sleeps, wake if another coin moves --
        if self.config.scanner_entry and self.config.max_positions > 1:
            try:
                candidates = self._get_scanner_candidates()
                hunt_ready = [c for c in candidates
                              if c.get("adx", 0) >= self.config.scanner_min_adx]
                if hunt_ready:
                    best = max(hunt_ready, key=lambda c: c.get("adx", 0))
                    self.state = FocusState.HUNT
                    self.last_scan_ts = 0  # [2026-04-09] scan immediately
                    self._save_config()
                    logger.info("[FOCUS] DORMANT → HUNT (primary %s ADX=%.1f dormant, "
                                "but scanner found %s ADX=%.1f)",
                                check_market, adx_val,
                                best["market"], best["adx"])
                    return {"state": "HUNT", "adx": round(adx_val, 1),
                            "scanner_trigger": best["market"]}
            except Exception as exc:
                logger.debug("[FOCUS] Scanner check in DORMANT failed: %s", exc)

        return {"state": "DORMANT", "adx": round(adx_val, 1)}

    def _handle_alert(self, now: float) -> Dict:
        """ALERT: signs of sideways ending. 3-min interval if Scanner ON, 15-min if OFF."""
        # shorter if Scanner ON: ALERT is closer to HUNT than DORMANT, so check more often
        scanner_active = self.config.scanner_entry and self.config.max_positions > 1
        alert_interval = 180.0 if scanner_active else 900.0  # 3 min / 15 min
        if now - self.last_scan_ts < alert_interval:
            remaining = alert_interval - (now - self.last_scan_ts)
            return {"state": "ALERT", "next_scan_in": round(remaining)}

        self.last_scan_ts = now
        check_market = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
        adx_data = self._fetch_primary_adx(check_market)

        if not adx_data:
            return {"state": "ALERT", "reason": "adx_fetch_failed"}

        adx_val = adx_data["adx"]

        if adx_val >= self.config.min_adx_entry:
            # trend confirmed -> HUNT
            self.state = FocusState.HUNT
            self._completed_dormant_cycle = True
            self.last_scan_ts = 0  # [2026-04-09] scan immediately after switching to HUNT
            self._save_config()
            logger.info("[FOCUS] ALERT → HUNT (ADX %.1f >= %d)", adx_val, self.config.min_adx_entry)
            return {"state": "HUNT", "adx": round(adx_val, 1)}

        if adx_val < self.config.dormant_adx_threshold:
            # dropped again -> DORMANT
            self.state = FocusState.DORMANT
            self._save_config()
            logger.info("[FOCUS] ALERT → DORMANT (ADX %.1f < %d)", adx_val, self.config.dormant_adx_threshold)
            return {"state": "DORMANT", "adx": round(adx_val, 1)}

        # -- Scanner-independent HUNT: from ALERT too, go HUNT if a scanner coin is strong --
        if self.config.scanner_entry and self.config.max_positions > 1:
            try:
                candidates = self._get_scanner_candidates()
                hunt_ready = [c for c in candidates
                              if c.get("adx", 0) >= self.config.scanner_min_adx]
                if hunt_ready:
                    best = max(hunt_ready, key=lambda c: c.get("adx", 0))
                    self.state = FocusState.HUNT
                    self._save_config()
                    logger.info("[FOCUS] ALERT → HUNT (primary %s ADX=%.1f, "
                                "scanner %s ADX=%.1f triggered)",
                                check_market, adx_val,
                                best["market"], best["adx"])
                    return {"state": "HUNT", "adx": round(adx_val, 1),
                            "scanner_trigger": best["market"]}
            except Exception as exc:
                logger.debug("[FOCUS] Scanner check in ALERT failed: %s", exc)

        return {"state": "ALERT", "adx": round(adx_val, 1)}

    def _handle_hunt(self, now: float, btc_price: float) -> Dict:
        """HUNT: combines the old SELECTING + WATCHING + ZONE_WAIT. scan_interval_sec interval."""
        # scan-interval check
        if now - self.last_scan_ts < self.config.scan_interval_sec:
            remaining = self.config.scan_interval_sec - (now - self.last_scan_ts)
            return {"state": "HUNT", "next_scan_in": round(remaining)}

        self.last_scan_ts = now

        # -- ADX recheck: return to DORMANT if below threshold (but keep if a Scanner coin is strong) --
        if self.config.adx_filter_enabled:
            check_market = self.config.lock_market.upper() if self.config.lock_market else "BTCUSDT"
            adx_data = self._fetch_primary_adx(check_market)
            if adx_data and adx_data["adx"] < self.config.dormant_adx_threshold:
                # keep HUNT if any Scanner coin is strong
                scanner_keeps_hunt = False
                if self.config.scanner_entry and self.config.max_positions > 1:
                    try:
                        cands = self._get_scanner_candidates()
                        scanner_keeps_hunt = any(
                            c.get("adx", 0) >= self.config.scanner_min_adx for c in cands)
                    except Exception as exc:
                        logger.debug("[FOCUS] cands failed: %s", exc)
                if not scanner_keeps_hunt:
                    self.state = FocusState.DORMANT
                    self._save_config()
                    logger.info("[FOCUS] HUNT → DORMANT (ADX %.1f < %d, no scanner candidates)",
                                adx_data["adx"], self.config.dormant_adx_threshold)
                    return {"state": "DORMANT", "reason": "adx_below_threshold"}
                else:
                    logger.info("[FOCUS] HUNT maintained: primary %s ADX=%.1f low, "
                                "but scanner has active candidates",
                                check_market, adx_data["adx"])

        # -- slot + daily-limit check --
        open_count = len(self.positions)
        if open_count >= self.config.max_positions:
            # [2026-05-29 owner] Slot Auto Expand possibility -- allow +1 entry on a strong signal even when slots are full
            if not self._slot_auto_expand_can_try():
                return {"state": "HUNT", "skip": f"full({open_count}/{self.config.max_positions})"}
        if self.daily_plans_used >= self.config.max_daily_plans or \
           self.daily_sl_count >= self.config.max_daily_sl:
            return {"state": "HUNT", "skip": "daily_limit"}

        # -- balance pre-check: skip scanning if no money even with empty slots (avoid wasting API) --
        _skip_new_entry = False
        if open_count < self.config.max_positions:
            try:
                _bal = self._get_client().get_balance("USDT")
                _avail = float(_bal) if not isinstance(_bal, dict) else float(
                    _bal.get("available", 0) or _bal.get("availableBalance", 0) or 0)
                if _avail < 5.0:
                    _skip_new_entry = True
                    # on insufficient balance, defer the next scan 5 min (save API)
                    self.last_scan_ts = now + 240  # 60s base + 240 = 5 min later
                    logger.info("[FOCUS] No budget ($%.2f) — skipping scan, retry in 5min", _avail)
            except Exception as exc:
                logger.debug("[FOCUS] _bal failed: %s", exc)  # on balance-query failure, proceed with the scan

        if not _skip_new_entry:
            # -- analyze the lock_market coin or auto-select --
            if self.config.lock_market:
                result = self._hunt_locked_market(now, btc_price)
            else:
                result = self._hunt_scan_market(now, btc_price)

            # -- Scanner multi-slot --
            # [2026-05-29 owner] when Slot Auto Expand, allow the scanner to run even when slots are full
            _slot_room_ok = (
                len(self.positions) < self.config.max_positions
                or self._slot_auto_expand_can_try()
            )
            if (self.config.scanner_entry
                    and _slot_room_ok
                    and self.daily_plans_used < self.config.max_daily_plans):
                try:
                    scanner_result = self._hunt_scanner_candidates(now, btc_price)
                    result.update(scanner_result)
                except Exception as exc:
                    logger.warning("[FOCUS] scanner hunt error: %s", exc)
        else:
            result = {"state": "HUNT", "skip": "no_budget"}

        return result

    def _hunt_locked_market(self, now: float, btc_price: float) -> Dict:
        """In HUNT, analyze the lock_market coin + enter."""
        locked = self.config.lock_market.upper()

        # -- H4 analysis --
        direction = "HOLD"  # [2026-04-17] LONG -> HOLD: don't enter on analysis failure
        candles_primary = []
        atr_val = 0
        _primary_trend = ""  # H4 trend (to limit whale override)
        _trend_pa_conflict = False  # [2026-04-17] PA<->trend conflict flag
        try:
            from app.strategy.greenpen import full_analysis
            from app.strategy.greenpen.pa_detector import OHLCV
            raw = self._get_client().get_kline(locked, interval=self.config.primary_tf, limit=100)
            candles_primary = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
            if len(candles_primary) >= 20:
                analysis = full_analysis(candles_primary)
                pa_list = getattr(analysis, 'pa_signals', []) or []
                struct = getattr(analysis, 'structure', None)
                trend_val = ""
                if struct and hasattr(struct, 'trend'):
                    trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                    _primary_trend = trend_val
                if pa_list:
                    best_pa = pa_list[0]
                    direction = best_pa.direction.value
                    # [2026-04-17] on trend-PA conflict: keep PA direction + conviction penalty (removed forced trend override)
                    if trend_val and (
                        (direction == "SHORT" and trend_val == "UPTREND") or
                        (direction == "LONG" and trend_val == "DOWNTREND")
                    ):
                        # respect the reversal signal PA detected -- especially a PA SHORT at the top matters
                        logger.info("[FOCUS] HUNT %s: PA=%s vs trend=%s — keeping PA direction, conviction -3",
                                    locked, direction, trend_val)
                        # the conviction penalty is applied after the conviction computation below (store the flag)
                        _trend_pa_conflict = True
                    else:
                        _trend_pa_conflict = False
                elif trend_val == "DOWNTREND":
                    direction = "SHORT"
                elif trend_val == "UPTREND":
                    direction = "LONG"
                elif trend_val == "SIDEWAYS":
                    # [2026-04-18] SIDEWAYS BB direction decision -- extend Phase 2-1 to locked HUNT too
                    # BB 70%+ -> near top -> SHORT / BB 30%- -> near bottom -> LONG
                    # 30~70% -> HOLD (keep direction)
                    # safety net: conviction check + BB hardblock (15%-) + M5 counter-trend check
                    try:
                        from app.strategy.indicators import bollinger_bands as _lsw_bb_fn
                        _lsw_closes = [c.close for c in candles_primary]
                        _lsw_bb = _lsw_bb_fn(_lsw_closes, 20, 2.0)
                        if _lsw_bb and _lsw_bb["upper"] > _lsw_bb["lower"]:
                            _lsw_bb_pct = (_lsw_closes[-1] - _lsw_bb["lower"]) / (_lsw_bb["upper"] - _lsw_bb["lower"]) * 100
                            if _lsw_bb_pct > 70:
                                direction = "SHORT"
                                logger.info("[FOCUS] HUNT locked %s: SIDEWAYS + BB%.0f%% > 70 -> SHORT (mean reversion)", locked, _lsw_bb_pct)
                            elif _lsw_bb_pct < 30:
                                direction = "LONG"
                                logger.info("[FOCUS] HUNT locked %s: SIDEWAYS + BB%.0f%% < 30 -> LONG (mean reversion)", locked, _lsw_bb_pct)
                            # 30~70% -> keep HOLD (skipped at line 2573 via direction="HOLD")
                    except Exception as exc:
                        logger.debug("[FOCUS] HUNT locked SIDEWAYS BB check failed: %s", exc)

                if self.config.direction_mode == "long_only":
                    direction = "LONG"
                elif self.config.direction_mode == "short_only":
                    direction = "SHORT"

                atr_val = getattr(analysis, 'atr', 0) or 0
                self.primary_sig = {
                    "pattern": pa_list[0].pattern.value if pa_list else "-",
                    "direction": direction,
                    "confidence": pa_list[0].confidence if pa_list else 0,
                    "atr": atr_val,
                }
                zones_raw = getattr(analysis, 'zones', []) or []
                self.zones = [{"type": getattr(z, 'type', {}).value if hasattr(getattr(z, 'type', None), 'value') else str(getattr(z, 'type', '')),
                               "price_low": getattr(z, 'price_low', 0), "price_high": getattr(z, 'price_high', 0),
                               "strength": getattr(z, 'strength', 1.0)}
                              for z in zones_raw]
        except Exception as exc:
            logger.warning("[FOCUS] HUNT lock analysis failed: %s — direction=HOLD (no blind entry)", exc)

        # [2026-04-17] HOLD state = analysis failed -- don't enter
        if direction == "HOLD":
            logger.info("[FOCUS] HUNT %s: direction=HOLD after analysis — skipping entry", locked)
            return {"state": "HUNT", "market": locked, "skip": "no_direction(HOLD)"}

        self.selected_market = locked
        self.selected_direction = direction

        # -- dual-direction eval (Phase 2) -- finalize direction + conviction (the BB penalty·reentry below apply to the new direction) --
        _signal_dir = direction
        direction, conviction, _dd_info = self._pick_best_direction(locked, candles_primary, self._zones_for_pa(), _signal_dir)
        if _dd_info.get("flipped"):
            self.selected_direction = direction
            logger.info("[FOCUS] DualDir(locked) direction switch: %s->%s (conv %.0f)", _signal_dir, direction, conviction)

        # ★ Peak Fade penalty -- deduct conviction when the peak turns down
        _pf_penalty = self._peak_fade_penalty(candles_primary, direction)
        if _pf_penalty:
            conviction = max(0, conviction + _pf_penalty)

        # ★ [2026-04-17] PRIMARY BB-position penalty: penalize trend-direction entry in the overbought/oversold zone
        # BB 75%+ & LONG -> -2, BB 25%- & SHORT -> -2
        _bb_pos_penalty = 0
        if candles_primary and len(candles_primary) >= 20:
            try:
                from app.strategy.indicators import bollinger_bands as _bb_conv_fn
                _conv_closes = [c.close for c in candles_primary]
                _conv_bb = _bb_conv_fn(_conv_closes, 20, 2.0)
                if _conv_bb and _conv_bb["upper"] > _conv_bb["lower"]:
                    _conv_bb_pct = (_conv_closes[-1] - _conv_bb["lower"]) / (_conv_bb["upper"] - _conv_bb["lower"]) * 100
                    # ★ [2026-04-17] BB hardblock (ORDI lesson)
                    # [2026-05-19 owner decision] made a dataclass -- UI-adjustable, symmetric assumption (LONG > X / SHORT < 100-X)
                    _bb_block_t = float(getattr(self.config, 'bb_block_threshold_pct', 85.0))
                    _bb_pen_t = float(getattr(self.config, 'bb_penalty_threshold_pct', 75.0))
                    _bb_pen_amt = float(getattr(self.config, 'bb_penalty_amount', 20.0))
                    if direction == "LONG" and _conv_bb_pct > _bb_block_t:
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _conv_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(LONG) — guard_score_mode bypass", locked, _conv_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(LONG) BUT ADX%.0f>=strong-trend wall-riding -> pass", locked, _conv_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% > %.0f%% + LONG → BLOCKED (extreme overbought)",
                                        locked, _conv_bb_pct, _bb_block_t)
                            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                                              f"bb_extreme_overbought(BB={_conv_bb_pct:.0f}%)")
                            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "bb_extreme_overbought"}
                    elif direction == "SHORT" and _conv_bb_pct < (100.0 - _bb_block_t):
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _conv_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(SHORT) — guard_score_mode bypass", locked, _conv_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT %s: BB%.0f%% extreme(SHORT) BUT ADX%.0f>=strong-trend wall-riding -> pass", locked, _conv_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → BLOCKED (extreme oversold)",
                                        locked, _conv_bb_pct, 100.0 - _bb_block_t)
                            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                                              f"bb_extreme_oversold(BB={_conv_bb_pct:.0f}%)")
                            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "bb_extreme_oversold"}
                    elif direction == "LONG" and _conv_bb_pct > _bb_pen_t:
                        _bb_pos_penalty = -int(_bb_pen_amt)
                        conviction = max(0.0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% > %.0f%% + LONG → conviction -%.0f → %.1f",
                                    locked, _conv_bb_pct, _bb_pen_t, _bb_pen_amt, conviction)
                    elif direction == "SHORT" and _conv_bb_pct < (100.0 - _bb_pen_t):
                        _bb_pos_penalty = -int(_bb_pen_amt)
                        conviction = max(0.0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → conviction -%.0f → %.1f",
                                    locked, _conv_bb_pct, 100.0 - _bb_pen_t, _bb_pen_amt, conviction)
            except Exception as _bbe:
                logger.debug("[FOCUS] PRIMARY BB conviction penalty error: %s", _bbe)

        # ★ [2026-04-17 -> 2026-05-17 100-pt ×10] trend-PA conflict penalty: keep PA direction but conviction -30 (old -3)
        if _trend_pa_conflict:
            conviction = max(0.0, conviction - 30.0)
            logger.info("[FOCUS] HUNT %s: trend-PA conflict penalty → conviction=%.1f", locked, conviction)

        # ★ WhaleRadar -- disabled (2026-04-12): observe only, no conviction/direction effect
        _whale_score = 0
        # try:
        #     from app.core.whale_radar import whale_radar
        #     raw_5m = self._get_client().get_kline(locked, interval="5", limit=120)
        #     _wsig = whale_radar.scan(locked, raw_5m)
        #     if _wsig:
        #         _whale_score = _wsig.score
        # except Exception:
        #     pass

        logger.info("[FOCUS] HUNT %s: direction=%s conviction=%d whale=%d (min=%d)",
                     locked, direction, conviction, _whale_score, self.config.min_conviction)

        # -- Event Shield: hard-block new entries in the economic-event window (conviction-independent) --
        _es_label = self._event_shield_label()
        if _es_label:
            logger.info("[FOCUS] Event Shield(%s): entry blocked %s — event window", _es_label, locked)
            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                              f"event_shield({_es_label})")
            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "event_shield"}

        _min_conv = self.config.min_conviction
        if self._is_morning_guard_active():
            _min_conv += self.config.morning_guard_conviction_boost
        if conviction < _min_conv:
            if _min_conv > self.config.min_conviction:
                logger.info("[FOCUS] Morning Guard: entry blocked %s, conviction %d < %d (morning +%d)",
                             locked, conviction, _min_conv, self.config.morning_guard_conviction_boost)
            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                              f"low_conviction({conviction}<{_min_conv})")
            return {"state": "HUNT", "market": locked, "conviction": conviction, "skip": "low_conviction"}

        # -- re-entry block check --
        price = self._get_current_price(locked)
        if not price or price <= 0:
            return {"state": "HUNT", "error": "no_price"}
        if not self._check_reentry_allowed(direction, locked, price):
            self._record_skip(locked, direction, conviction, (self.primary_sig or {}).get("pattern", "-"),
                              "reentry_blocked")
            return {"state": "HUNT", "market": locked, "skip": "reentry_blocked"}

        # -- M5 entry confirmation --
        try:
            from app.manager.focus_entry_signal import check_m5_entry
            entry = check_m5_entry(
                self._get_client(), locked, direction, self.config.entry_tf,
                btc_price=btc_price, zones=self.zones,
            )
        except Exception as exc:
            logger.warning("[FOCUS] HUNT M5 check failed: %s", exc)
            entry = None

        if entry and entry.get("enter"):
            entry.setdefault("market", locked)
            entry["conviction_score"] = conviction
            # ★ [2026-05-11 Phase 1+2] stamp mtf/mom/zone/align info into phase (for journal analysis)
            _p1_mods = getattr(self, '_last_conviction_breakdown', {}) or {}
            _mtf_pen = _p1_mods.get('mtf_pen', 0)
            _mom_pen = _p1_mods.get('mom_pen', 0)
            _zone_pos = _p1_mods.get('zone_pos', 0)
            _mom_align = _p1_mods.get('mom_align', 0)
            entry["_conviction_modifiers"] = f"peak_fade={_pf_penalty},bb_pos={_bb_pos_penalty},whale={_whale_score},mtf={_mtf_pen},mom={_mom_pen},zone={_zone_pos},align={_mom_align}"
            budget = self._compute_entry_budget(conviction, locked)
            entry["conviction_budget"] = budget
            # ★ min-budget check: can't enter below $5
            if budget < 5.0:
                logger.info("[FOCUS] HUNT %s budget $%.1f < $5 — skip entry", locked, budget)
                return {"state": "HUNT", "market": locked, "skip": f"budget_too_low(${budget:.1f})"}
            return self._execute_entry(entry)

        # H4 high-confidence direct entry (keep existing logic)
        primary_conf = float((self.primary_sig or {}).get("confidence", 0) or 0)
        if primary_conf >= 0.85:
            # M5 trend confirmation
            try:
                from app.strategy.greenpen.pa_detector import OHLCV
                from app.strategy.greenpen.market_structure import analyze_structure as _az
                m5_raw = self._get_client().get_kline(locked, interval=self.config.entry_tf, limit=20)
                m5_candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in m5_raw if len(r) >= 5]
                if len(m5_candles) >= 10:
                    _m5s = _az(m5_candles, lookback=3)
                    _m5t = _m5s.trend.value if hasattr(_m5s.trend, 'value') else str(_m5s.trend)
                    if (direction == "LONG" and _m5t == "DOWNTREND") or \
                       (direction == "SHORT" and _m5t == "UPTREND"):
                        return {"state": "HUNT", "market": locked, "skip": "m5_against"}
            except Exception as exc:
                logger.debug("[FOCUS] import OHLCV failed: %s", exc)

            atr = atr_val if atr_val > 0 else price * 0.02
            primary_budget = self._compute_entry_budget(conviction, locked)
            if primary_budget < 5.0:
                return {"state": "HUNT", "market": locked, "skip": f"primary_budget_too_low(${primary_budget:.1f})"}
            return self._execute_entry({
                "enter": True, "direction": direction,
                "market": locked, "price": price, "atr": atr,
                "reason": f"primary_high_conf:{primary_conf:.0%}",
                "conviction_score": conviction,
                "conviction_budget": primary_budget,
            })

        return {"state": "HUNT", "market": locked, "direction": direction, "conviction": conviction}

    def _hunt_scan_market(self, now: float, btc_price: float) -> Dict:
        """In HUNT, auto-select a coin + enter."""
        try:
            from app.manager.focus_coin_selector import select_focus_coin
            result = select_focus_coin(
                self.system, self._get_client(),
                direction_mode=self.config.direction_mode,
                primary_tf=self.config.primary_tf,
            )
        except Exception as exc:
            logger.warning("[FOCUS] HUNT scan failed: %s", exc)
            return {"state": "HUNT", "error": str(exc)}

        if not result or not result.get("market"):
            return {"state": "HUNT", "result": "no_candidate"}

        market = result["market"]
        # [2026-04-18] removed LONG fallback -- skip if no direction
        direction = result.get("direction")
        if not direction or direction not in ("LONG", "SHORT"):
            logger.info("[FOCUS] HUNT scan skip %s: no valid direction", market)
            return {"state": "HUNT", "skip": "no_direction"}
        conf = float(result.get("confidence", 0) or 0)

        # ★ dust filter (config-adjustable, 2026-04-25 default 0.10)
        _min_price_filter = float(getattr(self.config, "scanner_min_price_usdt", 0.10))
        _scan_price = float(result.get("price", 0) or 0)
        if 0 < _scan_price < _min_price_filter:
            logger.info("[FOCUS] HUNT scan skip %s: price $%.4f < $%.2f", market, _scan_price, _min_price_filter)
            return {"state": "HUNT", "skip": f"low_price(${_scan_price:.2f})"}

        # blacklist check
        bl = getattr(self, '_temp_blacklist', {})
        if market in bl and bl[market] > time.time():
            return {"state": "HUNT", "skip": "blacklisted"}

        # already-held check
        held = {p.market for p in self.positions}
        if market in held:
            return {"state": "HUNT", "skip": "already_held"}

        # ★ Cross-strategy guard: can't enter if Nunnaya already holds this market
        try:
            from app.core.cross_strategy_guard import is_market_owned_by_other
            _other = is_market_owned_by_other(self.system, market, "FOCUS")
            if _other:
                logger.warning("[FOCUS] BLOCKED: %s already held by %s (qty=%.4f) — cross-strategy guard",
                               market, _other.owner, _other.qty)
                return {"state": "HUNT", "skip": "cross_strategy_conflict"}
        except Exception as exc:
            logger.debug("[FOCUS] cross_strategy_guard scan check: %s", exc)

        # register with price_store
        try:
            if self.system:
                feed = getattr(self.system, "price_feed", None)
                if feed and hasattr(feed, "add_symbol"):
                    feed.add_symbol(market)
        except Exception as exc:
            logger.debug("[FOCUS] if self.system: failed: %s", exc)

        self.selected_market = market
        self.selected_direction = direction
        self.zones = result.get("zones", [])
        self.primary_sig = result.get("primary_sig")

        # compute conviction
        candles_primary = []
        try:
            from app.strategy.greenpen.pa_detector import OHLCV
            raw = self._get_client().get_kline(market, interval=self.config.primary_tf, limit=60)
            candles_primary = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw if len(r) >= 5]
        except Exception as exc:
            logger.debug("[FOCUS] import OHLCV failed: %s", exc)
        # -- dual-direction eval (Phase 2) -- finalize direction + conviction (the gates below apply to the new direction) --
        _signal_dir = direction
        direction, conviction, _dd_info = self._pick_best_direction(market, candles_primary, self._zones_for_pa(), _signal_dir)
        if _dd_info.get("flipped"):
            self.selected_direction = direction
            logger.info("[FOCUS] DualDir(scan) direction switch: %s->%s (conv %.0f)", _signal_dir, direction, conviction)

        # ★ Peak Fade penalty
        _pf_penalty = self._peak_fade_penalty(candles_primary, direction)
        if _pf_penalty:
            conviction = max(0, conviction + _pf_penalty)

        # ★ [2026-04-17] PRIMARY BB-position penalty: penalize trend-direction entry in the overbought/oversold zone
        if candles_primary and len(candles_primary) >= 20:
            try:
                from app.strategy.indicators import bollinger_bands as _bb_scan_fn
                _scan_bb_closes = [c.close for c in candles_primary]
                _scan_bb = _bb_scan_fn(_scan_bb_closes, 20, 2.0)
                if _scan_bb and _scan_bb["upper"] > _scan_bb["lower"]:
                    _scan_bb_pct = (_scan_bb_closes[-1] - _scan_bb["lower"]) / (_scan_bb["upper"] - _scan_bb["lower"]) * 100
                    # ★ [2026-04-17] BB hardblock (ORDI lesson) / [2026-05-19] made a dataclass
                    _bb_block_t = float(getattr(self.config, 'bb_block_threshold_pct', 85.0))
                    _bb_pen_t = float(getattr(self.config, 'bb_penalty_threshold_pct', 75.0))
                    _bb_pen_amt = float(getattr(self.config, 'bb_penalty_amount', 20.0))
                    # Scanner's old code was -2 (missed in the Phase 5 fix) -- use _bb_pen_amt for consistency with main
                    if direction == "LONG" and _scan_bb_pct > _bb_block_t:
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scan_bb_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(LONG) — guard_score_mode bypass", market, _scan_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(LONG) BUT ADX%.0f>=strong-trend wall-riding -> pass", market, _scan_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% > %.0f%% + LONG → BLOCKED (extreme overbought)",
                                        market, _scan_bb_pct, _bb_block_t)
                            return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "bb_extreme_overbought"}
                    elif direction == "SHORT" and _scan_bb_pct < (100.0 - _bb_block_t):
                        _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scan_bb_closes)
                        if self._guard_score_mode_active():
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(SHORT) — guard_score_mode bypass", market, _scan_bb_pct)
                        elif _tr_byp:
                            logger.info("[FOCUS] HUNT scan %s: BB%.0f%% extreme(SHORT) BUT ADX%.0f>=strong-trend wall-riding -> pass", market, _scan_bb_pct, _tr_adx)
                        else:
                            logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → BLOCKED (extreme oversold)",
                                        market, _scan_bb_pct, 100.0 - _bb_block_t)
                            return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "bb_extreme_oversold"}
                    elif direction == "LONG" and _scan_bb_pct > _bb_pen_t:
                        conviction = max(0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% > %.0f%% + LONG → conviction -%.0f → %d",
                                    market, _scan_bb_pct, _bb_pen_t, _bb_pen_amt, conviction)
                    elif direction == "SHORT" and _scan_bb_pct < (100.0 - _bb_pen_t):
                        conviction = max(0, conviction - _bb_pen_amt)
                        logger.info("[FOCUS] HUNT scan %s: PRIMARY BB%.0f%% < %.0f%% + SHORT → conviction -%.0f → %d",
                                    market, _scan_bb_pct, 100.0 - _bb_pen_t, _bb_pen_amt, conviction)
            except Exception as exc:
                logger.debug("[FOCUS] import bollinger_bands as _bb_scan_fn failed: %s", exc)

        # -- Event Shield: hard-block new entries in the economic-event window (conviction-independent) --
        _es_label = self._event_shield_label()
        if _es_label:
            logger.info("[FOCUS] Event Shield(%s): scan entry blocked %s — event window", _es_label, market)
            self._record_skip(market, direction, conviction, str(result.get("pa_pattern", "-")),
                              f"event_shield({_es_label})")
            return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "event_shield"}

        _min_conv = self.config.min_conviction
        if self._is_morning_guard_active():
            _min_conv += self.config.morning_guard_conviction_boost
        if conviction < _min_conv:
            if self._guard_score_mode_active():
                logger.info("[FOCUS] HUNT scan %s: conv=%d<%d -- guard_score_mode bypass (defer to score evaluation)",
                            market, conviction, _min_conv)
            else:
                if _min_conv > self.config.min_conviction:
                    logger.info("[FOCUS] Morning Guard: scan entry blocked %s, conviction %d < %d (morning +%d)",
                                 market, conviction, _min_conv, self.config.morning_guard_conviction_boost)
                self._record_skip(market, direction, conviction, str(result.get("pa_pattern", "-")),
                                  f"scan_low_conviction({conviction}<{_min_conv})")
                return {"state": "HUNT", "market": market, "conviction": conviction, "skip": "low_conviction"}

        # re-entry block check
        price = float(result.get("price", 0) or 0)
        if not price or price <= 0:
            price = self._get_current_price(market) or 0
        if price <= 0:
            return {"state": "HUNT", "error": "no_price"}
        if not self._check_reentry_allowed(direction, market, price):
            self._record_skip(market, direction, conviction, str(result.get("pa_pattern", "-")),
                              "scan_reentry_blocked")
            return {"state": "HUNT", "market": market, "skip": "reentry_blocked"}

        if conf >= 0.85:
            atr = float(result.get("atr", 0) or price * 0.02)
            scan_budget = self._compute_entry_budget(conviction, market)
            if scan_budget < 5.0:
                logger.info("[FOCUS] HUNT scan %s budget $%.1f < $5 — skip", market, scan_budget)
                return {"state": "HUNT", "market": market, "skip": f"budget_too_low(${scan_budget:.1f})"}
            logger.info("[FOCUS] HUNT scan: %s %s conf=%.0f%% conviction=%d budget=$%.1f",
                        direction, market, conf * 100, conviction, scan_budget)
            entry_result = self._execute_entry({
                "enter": True, "market": market, "direction": direction,
                "price": price, "atr": atr,
                "reason": f"hunt_scan_conf:{conf:.0%}",
                "conviction_score": conviction,
                "conviction_budget": scan_budget,
                "_conviction_modifiers": f"peak_fade={_pf_penalty}",
            })
            if entry_result.get("state") == "POSITIONED":
                self.last_scan_ts = 0  # re-scan immediately
            return entry_result

        return {"state": "HUNT", "market": market, "conviction": conviction}

    # ── Scanner Multi-Slot helpers ─────────────────────────────

    def _get_scanner_candidates(self) -> list:
        """Top 10 scanner candidates for multi-slot entry."""
        try:
            from app.strategy.greenpen import full_analysis
            from app.strategy.greenpen.pa_detector import OHLCV
            from app.strategy.indicators import adx as _adx_fn

            tickers = self._get_client().get_market_tickers()

            # ★ [2026-04-25 universe expansion] config-adjustable
            min_turnover = float(getattr(self.config, "scanner_min_turnover_24h", 1_000_000.0))
            min_price = float(getattr(self.config, "scanner_min_price_usdt", 0.10))
            top_n = int(getattr(self.config, "scanner_top_n", 20))

            scored = []
            for t in tickers:
                if not isinstance(t, dict):
                    continue
                symbol = str(t.get("symbol", ""))
                if not symbol.endswith("USDT"):
                    continue
                turnover = float(t.get("turnover24h", 0) or 0)
                if turnover < min_turnover:
                    continue
                last_price = float(t.get("lastPrice", 0) or 0)
                # ★ dust filter (config-adjustable)
                if last_price < min_price:
                    continue
                scored.append({"symbol": symbol, "turnover": turnover,
                              "price": last_price})

            scored.sort(key=lambda x: -x["turnover"])
            candidates = scored[:top_n]

            results = []
            client = self._get_client()
            for c in candidates:
                symbol = c["symbol"]
                try:
                    raw = client.get_kline(symbol, interval=self.config.primary_tf, limit=60)
                    candles = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]),
                               volume=float(r[5]) if len(r) > 5 else 0)
                              for r in raw if len(r) >= 5]
                    if len(candles) < 10:
                        continue
                    gp = full_analysis(candles)
                    # -- [2026-05-20 Phase 6 Stage 0] Energy-bar time-series cache --
                    #   Based on the owner's gut rule: load per-coin (ts, trend, confidence).
                    #   _get_trend_velocity computes the change rate from this -> Energy-mode trigger.
                    try:
                        _gp_trend = gp.structure.trend.value  # UPTREND/DOWNTREND/SIDEWAYS
                        _gp_conf = float(getattr(gp.structure, "confidence", 0.0))
                        _hist = self._confidence_history.get(symbol)
                        if _hist is None:
                            _hist = deque(maxlen=self._confidence_history_maxlen)
                            self._confidence_history[symbol] = _hist
                        _hist.append((time.time(), _gp_trend, _gp_conf))
                    except Exception:
                        pass
                    signal = "HOLD"
                    pa_name = "-"
                    _sw_flag = False  # [2026-04-18] SIDEWAYS BB mean-reversion flag
                    if gp.pa_signals:
                        best = gp.pa_signals[0]
                        signal = "BUY" if best.direction.value == "LONG" else "SELL"
                        pa_name = best.pattern.value
                    else:
                        # [2026-04-09] Market structure fallback -- BOS / Trend
                        _struct = gp.structure
                        _bos = getattr(_struct, "bos", None)
                        if _bos and getattr(_bos, "detected", False):
                            signal = "BUY" if _bos.direction == "BULLISH" else "SELL"
                            pa_name = f"BOS_{_bos.direction}"
                        elif _struct.trend.value == "UPTREND":
                            signal = "BUY"
                            pa_name = "TREND_UP"
                        elif _struct.trend.value == "DOWNTREND":
                            signal = "SELL"
                            pa_name = "TREND_DN"
                        elif _struct.trend.value == "SIDEWAYS":
                            # [2026-04-18] SIDEWAYS BB direction decision -- create mean-reversion SHORT/LONG opportunities
                            # BB 70%+ -> near top -> SELL / BB 30%- -> near bottom -> BUY
                            # 30~70% -> HOLD (center = direction unclear)
                            # triple safety net: (1) conservative BB 70/30 (2) conviction check (3) lower BB hard block 85/15
                            # -- [2026-05-29 owner] blocked when entry_auto_flip_enabled=False --
                            # Owner principle: "permanently no auto direction FLIP" (extends the 5-28 ICP incident).
                            # mean reversion also *decides a direction outside the expected signal* -- same intent as FLIP.
                            if not bool(getattr(self.config, "entry_auto_flip_enabled", False)):
                                logger.debug("[FOCUS] Scanner %s: SIDEWAYS BB mean reversion skip (entry_auto_flip_enabled=False)", symbol)
                                # keep HOLD (signal undecided -> next candidate)
                            else:
                                try:
                                    from app.strategy.indicators import bollinger_bands as _sw_bb_fn
                                    _sw_closes = [c.close for c in candles]
                                    _sw_bb = _sw_bb_fn(_sw_closes, 20, 2.0)
                                    if _sw_bb and _sw_bb["upper"] > _sw_bb["lower"]:
                                        _sw_bb_pct = (_sw_closes[-1] - _sw_bb["lower"]) / (_sw_bb["upper"] - _sw_bb["lower"]) * 100
                                        if _sw_bb_pct > 70:
                                            signal = "SELL"
                                            pa_name = "SW_UPPER_BB"
                                            _sw_flag = True
                                            logger.info("[FOCUS] Scanner %s: SIDEWAYS + BB%.0f%% > 70 -> SELL (mean reversion)", symbol, _sw_bb_pct)
                                        elif _sw_bb_pct < 30:
                                            signal = "BUY"
                                            pa_name = "SW_LOWER_BB"
                                            _sw_flag = True
                                            logger.info("[FOCUS] Scanner %s: SIDEWAYS + BB%.0f%% < 30 -> BUY (mean reversion)", symbol, _sw_bb_pct)
                                        # 30~70% -> keep HOLD
                                except Exception as exc:
                                    logger.debug("[FOCUS] SIDEWAYS BB check failed %s: %s", symbol, exc)
                    # ★ [2026-04-16] PRIMARY BB extreme flip -- overbought->SHORT / oversold->LONG
                    # BB% > 110 = top extreme -> flip BUY to SELL (ORDI -$20 lesson)
                    # BB% < -10 = bottom extreme -> flip SELL to BUY
                    # ※ must run before the BB gate -- the gate must not swallow the FLIP chance at 110%+
                    _bb_flipped = False
                    _cached_bb_pct = None  # gate and flip share the BB computation
                    # -- [2026-05-29 owner] block PRIMARY BB FLIP when entry_auto_flip_enabled=False --
                    # Owner principle: "permanently no auto direction FLIP" (the 5-28 ICP incident).
                    # NEAR 5-29 incident: PIN_BAR SELL -> PRIMARY BB FLIP -> BUY entry = owner-recognized contradiction.
                    # BB computation proceeds (for the cached_bb_pct gate), but the FLIP itself is blocked.
                    _auto_flip_ok = bool(getattr(self.config, "entry_auto_flip_enabled", False))
                    if signal in ("BUY", "SELL"):
                        try:
                            from app.strategy.indicators import bollinger_bands as _bb_fn
                            _primary_closes = [c.close for c in candles]
                            _primary_bb = _bb_fn(_primary_closes, 20, 2.0)
                            if _primary_bb and _primary_bb["upper"] > _primary_bb["lower"]:
                                _primary_bb_pct = (_primary_closes[-1] - _primary_bb["lower"]) / (_primary_bb["upper"] - _primary_bb["lower"]) * 100
                                _cached_bb_pct = _primary_bb_pct
                                if _primary_bb_pct > 110 and signal == "BUY":
                                    if _auto_flip_ok:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% > 110%% → FLIP BUY→SELL (overbought)", symbol, _primary_bb_pct)
                                        signal = "SELL"
                                        pa_name = f"{pa_name}→PRIMARY_BB_FLIP_SHORT"
                                        _bb_flipped = True
                                    else:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% > 110%% BUY FLIP skip (entry_auto_flip_enabled=False) -> keep signal BUY", symbol, _primary_bb_pct)
                                elif _primary_bb_pct < -10 and signal == "SELL":
                                    if _auto_flip_ok:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% < -10%% → FLIP SELL→BUY (oversold)", symbol, _primary_bb_pct)
                                        signal = "BUY"
                                        pa_name = f"{pa_name}→PRIMARY_BB_FLIP_LONG"
                                        _bb_flipped = True
                                    else:
                                        logger.info("[FOCUS] Scanner %s: PRIMARY BB %.0f%% < -10%% SELL FLIP skip (entry_auto_flip_enabled=False) -> keep signal SELL", symbol, _primary_bb_pct)
                        except Exception as exc:
                            logger.debug("[FOCUS] import bollinger_bands as _bb_fn failed: %s", exc)

                    # -- [2026-05-20 owner redesign] abandon Energy mode -- replaced by Reverse mode --
                    # Old Energy FLIP (confidence-change-rate based) -> owner's new insight "low conv + low ADX is itself the spot".
                    # The Reverse-mode logic moved to the post-Scanner-conv area (works when entry_mode == "reverse").

                    # ★ [2026-04-17] PRIMARY BB-position gate -- block the overbought/oversold zone in the trend/BOS fallback
                    # BUY(TREND_UP/BOS_BULLISH) + BB 75~110% -> HOLD (a top that isn't a FLIP target)
                    # SELL(TREND_DN/BOS_BEARISH) + BB -10~25% -> HOLD (a bottom that isn't a FLIP target)
                    # ※ runs after the BB FLIP -- 110%+ already flipped, the gate handles only the 75~110% zone
                    if signal in ("BUY", "SELL") and not _bb_flipped and pa_name in ("TREND_UP", "TREND_DN", "BOS_BULLISH", "BOS_BEARISH"):
                        try:
                            if _cached_bb_pct is not None:
                                _gate_bb_pct = _cached_bb_pct
                            else:
                                from app.strategy.indicators import bollinger_bands as _bb_gate_fn
                                _gate_closes = [c.close for c in candles]
                                _gate_bb = _bb_gate_fn(_gate_closes, 20, 2.0)
                                _gate_bb_pct = None
                                if _gate_bb and _gate_bb["upper"] > _gate_bb["lower"]:
                                    _gate_bb_pct = (_gate_closes[-1] - _gate_bb["lower"]) / (_gate_bb["upper"] - _gate_bb["lower"]) * 100
                            if _gate_bb_pct is not None:
                                _tr_byp, _tr_adx = self._bb_trend_riding(signal, _gate_closes)
                                if signal == "BUY" and _gate_bb_pct > 75:
                                    if _tr_byp:
                                        logger.info("[FOCUS] Scanner %s: BB gate BUY BB%.0f%% BUT ADX%.0f>=strong-trend wall-riding -> pass",
                                                    symbol, _gate_bb_pct, _tr_adx)
                                    else:
                                        logger.info("[FOCUS] Scanner %s: BB gate — %s BB%.0f%% > 75%% → HOLD (overbought for trend-buy)",
                                                    symbol, pa_name, _gate_bb_pct)
                                        signal = "HOLD"
                                        pa_name = f"{pa_name}→BB_GATE_HOLD"
                                        c["_block_reason"] = f"BB_GATE({int(_gate_bb_pct)}%)"  # ★ for scan-list UI display
                                elif signal == "SELL" and _gate_bb_pct < 25:
                                    if _tr_byp:
                                        logger.info("[FOCUS] Scanner %s: BB gate SELL BB%.0f%% BUT ADX%.0f>=strong-trend wall-riding -> pass",
                                                    symbol, _gate_bb_pct, _tr_adx)
                                    else:
                                        logger.info("[FOCUS] Scanner %s: BB gate — %s BB%.0f%% < 25%% → HOLD (oversold for trend-sell)",
                                                    symbol, pa_name, _gate_bb_pct)
                                        signal = "HOLD"
                                        pa_name = f"{pa_name}→BB_GATE_HOLD"
                                        c["_block_reason"] = f"BB_GATE({int(_gate_bb_pct)}%)"  # ★ for scan-list UI display
                        except Exception as exc:
                            logger.debug("[FOCUS] operation failed: %s", exc)

                    # ★ [2026-04-15] 30M composite check -- HOLD on a primary(H1)<->30M direction conflict
                    # [2026-05-15] H1 switch: as primary_tf becomes H1 the old "H4<->H1" comparison became H1<->H1 dup -> shift one down to primary<->30M.
                    # [2026-05-17 owner vision #3] exempt when BOS + CFID FLIP_IMMINENT match (prioritize inflection prediction -- "BOS_BEARISH = trend reversal starting = opportunity")
                    _primary_signal = signal
                    if signal in ("BUY", "SELL") and not _bb_flipped and pa_name in ("TREND_UP", "TREND_DN", "BOS_BULLISH", "BOS_BEARISH"):
                        # BOS + CFID combined exemption check
                        _bos_cfid_exempt = False
                        if pa_name in ("BOS_BULLISH", "BOS_BEARISH"):
                            try:
                                _cfid_dir, _cfid_strength = self._detect_coin_flip_imminent_impl(symbol)
                                if (signal == "BUY" and _cfid_dir == "BULL_IMMINENT") or \
                                   (signal == "SELL" and _cfid_dir == "BEAR_IMMINENT"):
                                    _bos_cfid_exempt = True
                                    logger.info("[FOCUS] Scanner %s %s + CFID %s match -> exempt 30M conflict (prioritize inflection prediction)",
                                                symbol, pa_name, _cfid_dir)
                            except Exception as _bce:
                                logger.debug("[FOCUS] Scanner BOS+CFID check %s: %s", symbol, _bce)

                        # ★ [2026-05-21 owner] in Reverse mode, bypass the 30M conflict -- don't change signal to HOLD.
                        # Owner rule: "low conv + low ADX -> reverse entry" -- independent of the 30M conflict.
                        # keep signal=BUY/SELL -> can reach the reverse check later.
                        _rev_mode_m30_bypass = getattr(self.config, "entry_mode", "score") == "reverse"
                        if not _bos_cfid_exempt and not _rev_mode_m30_bypass:
                            try:
                                from app.strategy.greenpen.market_structure import analyze_structure as _az_m30s
                                _raw_m30 = client.get_kline(symbol, interval="30", limit=30)
                                if _raw_m30 and len(_raw_m30) >= 10:
                                    _m30c = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                                             for r in _raw_m30 if len(r) >= 5]
                                    if len(_m30c) >= 10:
                                        _m30s = _az_m30s(_m30c, lookback=3)
                                        _m30t = _m30s.trend.value if hasattr(_m30s.trend, 'value') else str(_m30s.trend)
                                        # primary UPTREND + 30M DOWNTREND -> LONG risk, HOLD
                                        if signal == "BUY" and _m30t == "DOWNTREND":
                                            signal = "HOLD"
                                            pa_name = f"{pa_name}→M30_DN_HOLD"
                                            logger.info("[FOCUS] Scanner candidate %s: PRIMARY %s but 30M DOWNTREND → HOLD",
                                                        symbol, _primary_signal)
                                        # primary DOWNTREND + 30M UPTREND -> SHORT risk, HOLD
                                        elif signal == "SELL" and _m30t == "UPTREND":
                                            signal = "HOLD"
                                            pa_name = f"{pa_name}→M30_UP_HOLD"
                                            logger.info("[FOCUS] Scanner candidate %s: PRIMARY %s but 30M UPTREND → HOLD",
                                                        symbol, _primary_signal)
                            except Exception as _m30e:
                                logger.debug("[FOCUS] Scanner 30M check failed %s: %s", symbol, _m30e)
                        elif _rev_mode_m30_bypass:
                            logger.debug("[FOCUS] Scanner %s: Reverse-mode 30M conflict bypass (signal=%s preserved)", symbol, signal)

                    _adx_val = 0
                    _adx_past_val = 0
                    # meaning of adx_past (answer to this agent's letter 2026-04-21 review 3-2):
                    #   candles = the primary_tf (H4) OHLCV list. Current adx_val = based on the last H4 bar.
                    #   _adx_past_val = the ADX from N H4 bars **ago**. lookback_bars=3 -> ADX 12 hours ago.
                    #   i.e. not "last-tick change" but **3 H4 bars ago vs the current bar**.
                    #   Both Phase J v2 (2% decline) + Phase K (5% decline) consume this value.
                    try:
                        _h = [cd.high for cd in candles]
                        _l = [cd.low for cd in candles]
                        _c = [cd.close for cd in candles]
                        _r = _adx_fn(_h, _l, _c, period=14)
                        if _r:
                            _adx_val = round(_r.get("adx", 0), 1)
                        # ★ Phase J (2026-04-21): also compute the ADX from N bars ago (for the slope check)
                        _lookback = int(getattr(self.config, "adx_slope_lookback_bars", 3))
                        if len(_h) >= 14 + _lookback:
                            # [:-_lookback] = exclude the last _lookback bars -> compute the ADX as of N bars ago
                            _r_past = _adx_fn(_h[:-_lookback], _l[:-_lookback], _c[:-_lookback], period=14)
                            if _r_past:
                                _adx_past_val = round(_r_past.get("adx", 0), 1)
                    except Exception as exc:
                        logger.debug("[FOCUS] _h failed: %s", exc)
                    results.append({"market": symbol, "signal": signal,
                                   "pa_pattern": pa_name, "adx": _adx_val,
                                   "adx_past": _adx_past_val,
                                   "atr": round(gp.atr, 2), "price": c["price"],
                                   "bb_flipped": _bb_flipped,
                                   "sw_flag": _sw_flag})
                except Exception as exc:
                    logger.debug("[FOCUS] _h failed: %s", exc)
                    continue

            # [2026-04-18] removed BUY-first sort -- sort by ADX only (prevent LONG bias)
            # old: signal_order BUY=0/SELL=1 -> BUY candidates always before SELL
            #       -> once slots fill, SHORT chances are root-blocked
            # fix: try highest-ADX coins first, regardless of direction
            results.sort(key=lambda x: -x.get("adx", 0))
            return results
        except Exception as exc:
            logger.warning("[FOCUS] scanner candidates failed: %s", exc)
            return []

    def _hunt_scanner_candidates(self, now: float, btc_price: float) -> Dict:
        """Fill remaining slots with scanner candidates."""
        if not self.config.scanner_entry:
            return {}

        open_count = len(self.positions)
        # ★ Conviction Override Slot (2026-05-10): keep open the possibility of an override-eligible candidate -> use effective max
        # [2026-05-29 owner] also allow Slot Auto Expand (allow_slot_expand=True)
        eff_max = self._get_effective_max_positions(is_override=True, allow_slot_expand=True)
        if open_count >= eff_max:
            return {"scanner": f"slots_full({open_count}/{eff_max})"}

        # Exposure cap check — [2026-04-09] get_balance("USDT") returns float
        client = self._get_client()
        try:
            _bal = client.get_balance("USDT")
            available = float(_bal) if not isinstance(_bal, dict) else float(
                _bal.get("available", 0) or _bal.get("availableBalance", 0) or 0)
        except Exception as _be:
            logger.warning("[FOCUS] Scanner balance check failed: %s", _be)
            # Fallback: query margin
            try:
                available = self._get_available_margin()
            except Exception as exc:
                logger.debug("[FOCUS] available failed (fallback): %s", exc)
                available = 100.0  # assume available if can't check
        if available < 5.0:
            logger.info("[FOCUS] Scanner: no_budget (available=$%.2f)", available)
            return {"scanner": "no_budget"}

        held = {p.market.upper() for p in self.positions}
        if self.config.lock_market:
            held.add(self.config.lock_market.upper())

        candidates = self._get_scanner_candidates()
        if not candidates:
            return {"scanner": "no_candidates"}

        entered = []
        _scan_log = []  # [2026-04-09] debug: track scanner blocks
        _pipeline_syms = set()  # ★ [2026-06-15 solution B] symbols already tallied via self._journal.record_blocked through _execute_entry (avoid gate_ledger dup)
        # ★ [2026-05-17] cache the Scanner's final conviction (to unify the UI CONV column)
        self._last_scan_conviction = {}
        if not hasattr(self, '_last_guard_score'):
            self._last_guard_score = {}  # ★ [2026-05-28] guard-score cache -- for the scan-list API's separate column
        for c in candidates:
            # ★ Conviction Override Slot (2026-05-10): per-candidate eligibility check + effective-max branch
            _is_override_candidate = self._is_override_qualified(c)
            # [2026-05-29 owner] Slot Auto Expand eligibility check -- strong signal (conv >= min) + all slots tied up
            _c_conv = float(c.get("conviction_score", 0) or 0)
            _is_slot_expand_candidate = (
                not _is_override_candidate  # Override priority -- avoid duplication
                and self._slot_auto_expand_eligible(_c_conv)
            )
            _eff_max_for_c = self._get_effective_max_positions(
                is_override=_is_override_candidate,
                allow_slot_expand=_is_slot_expand_candidate,
            )
            if open_count >= _eff_max_for_c:
                if _is_override_candidate or _is_slot_expand_candidate:
                    # override / slot_expand eligible but effective max is full -> stop
                    break
                else:
                    # normal eligibility -- the next candidate may be override/expand eligible, so continue
                    continue
            # override marker on entry (for the size/SL/Hard ROE branch)
            if _is_override_candidate:
                c["_is_override"] = True
            # [2026-05-29 owner] Slot Auto Expand marker (for the size-shrink branch)
            if _is_slot_expand_candidate:
                c["_slot_expand"] = True
                logger.warning("[FOCUS] ★ Slot Auto Expand SIGNAL: %s conv=%.1f (all slots tied up + strong signal) -> temp +1 slot entry",
                               c.get("market", ""), _c_conv)
            symbol = c.get("market", "").upper()
            if symbol in held:
                _scan_log.append(f"{symbol}:held")
                continue
            # ★ blacklist check (permanent + temporary)
            # ★ [2026-06-02] suffix(USDT/USDC)-insensitive match -- even just "XAUT" blocks "XAUTUSDT" (fixes the owner-blacklist-miss bug)
            _bl = self.config.scanner_blacklist or []
            _sym_base = symbol.upper().replace("USDT", "").replace("USDC", "").replace("PERP", "")
            if symbol in _bl or _sym_base in _bl:
                _scan_log.append(f"{symbol}:blacklisted")
                continue
            _tbl = getattr(self, '_temp_blacklist', {})
            if symbol in _tbl and _tbl[symbol] > time.time():
                _scan_log.append(f"{symbol}:temp_blocked")
                continue
            if c.get("signal") not in ("BUY", "SELL"):
                # ★ [2026-05-28 owner] when guard_score_mode is active, evaluate HOLD too -- estimate direction from H4 trend then defer to the score
                if self._guard_score_mode_active():
                    _h4_t = str(c.get("h4_trend", "") or c.get("primary_trend", "") or "").upper()
                    if "DOWN" in _h4_t:
                        c["signal"] = "SELL"
                    elif "UP" in _h4_t:
                        c["signal"] = "BUY"
                    else:
                        # ★ [2026-06-02 owner] SIDEWAYS/undecided -> estimate from the macro breadth direction.
                        #   The old unconditional BUY = evaluating LONG even in a downtrend (root of the morning 95% bias). On breadth BEAR, evaluate SELL
                        #   -> let SHORT "wedge in" during a downtrend. Paired with the breadth reinforcement (1h change rate). (Not a direction flip: originally HOLD)
                        try:
                            _bdir = self._compute_market_breadth().get("dir", 0)
                        except Exception:
                            _bdir = 0
                        c["signal"] = "SELL" if _bdir < 0 else "BUY"   # macro decline->evaluate SHORT / else BUY
                    logger.info("[FOCUS] Scanner %s: sig=HOLD -> guard_score_mode bypass estimate %s (h4_trend=%s)",
                                symbol, c["signal"], _h4_t or "?")
                else:
                    # ★ prefer the detailed block reason like the BB gate (else sig=HOLD)
                    _sig_reason = c.get("_block_reason") or f"sig={c.get('signal')}"
                    _scan_log.append(f"{symbol}:{_sig_reason}")
                    continue

            # ★ dust filter (config-adjustable, 2026-04-25 default 0.10)
            _min_price_filter2 = float(getattr(self.config, "scanner_min_price_usdt", 0.10))
            _cprice = float(c.get("price", 0))
            if _cprice > 0 and _cprice < _min_price_filter2:
                _scan_log.append(f"{symbol}:low_price(${_cprice:.2f})")
                continue

            # ★ ADX/PA filter -- relax if whale is strong (whale scan below)
            # 1st filter: ADX >= 15 passes (whale-relaxable range)
            # ADX < 15 is too weak even with whale -> always block
            # ★ [2026-05-21 owner] Reverse mode = low ADX = bouncy = the spot. Bypass even ADX<15.
            _coin_adx = c.get("adx", 0)
            _rev_mode_dormant_bypass = (
                getattr(self.config, "entry_mode", "score") == "reverse"
                and _coin_adx <= float(getattr(self.config, "reverse_adx_max", 20.0))
            )
            if _coin_adx < 15 and not _rev_mode_dormant_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:adx={_coin_adx}<15")
                continue
            # ★ Phase J v2 (2026-04-21 clarified user intent): if ADX is declining, skip regardless of direction
            # Rationale: "the cooling tail-end of the market" = the imminent-regime-transition zone
            # While staying in 1-10 min after entry, a regime transition causes loss
            # -> prevent entry at a trend-weakening point in any direction
            # This agent's letter #6: block on a 2-3%+ drop vs peak (absorbs noise)
            # ★ J/K mutual exclusion (2026-04-21, this agent's letter #9 option A fix):
            #   skip J v2 only when K is live (on the same ADX-decline signal, K=flip takes priority).
            #   When K is paper_mode, coexist with J v2 -- paper is log-only, J v2 handles the real entry block.
            #   The original mutex (J off if K=True regardless of paper) left an ADX-decline defense gap during the K paper period.
            _k_enabled = getattr(self.config, "regime_transition_enabled", False)
            _k_paper_mode = getattr(self.config, "regime_transition_paper_mode", True)
            _k_live_active = _k_enabled and not _k_paper_mode
            if getattr(self.config, "adx_slope_check_enabled", True) and not _k_live_active:
                _adx_past = c.get("adx_past", 0)
                _signal = c.get("signal","HOLD")
                _intended_dir = "LONG" if _signal == "BUY" else ("SHORT" if _signal == "SELL" else None)
                if _adx_past > 0 and _intended_dir and _coin_adx < _adx_past:
                    _decl_pct = (_adx_past - _coin_adx) / _adx_past * 100
                    _threshold = float(getattr(self.config, "adx_slope_decline_threshold_pct", 2.0))
                    if _decl_pct >= _threshold and not self._guard_score_mode_active():
                        logger.info("[FOCUS] Scanner %s: ADX decline %.1f%% (%.1f->%.1f) + %s -> SKIP (market cooling)",
                                    symbol, _decl_pct, _adx_past, _coin_adx, _intended_dir)
                        _scan_log.append(f"{symbol}:adx_decl-{_decl_pct:.1f}pct_{_intended_dir}_skip")
                        continue
            # ADX 15~22: passes if whale >= 5, else blocked (re-checked after the whale scan below)
            # [2026-04-18 evening] removed the hard cap -- use the config value as-is (transparency)
            _effective_scan_adx = self.config.scanner_min_adx
            _adx_soft_pass = _coin_adx >= _effective_scan_adx
            _pa_soft_pass = c.get("pa_pattern", "-") != "-"

            # ★ [2026-05-20 owner] Reverse mode = low ADX is itself the *condition* (bouncy spot).
            # Bypass the ADX block -- passes when entry_mode=reverse + ADX <= reverse_adx_max.
            _rev_mode_adx_bypass = (
                getattr(self.config, "entry_mode", "score") == "reverse"
                and _coin_adx <= float(getattr(self.config, "reverse_adx_max", 20.0))
            )

            # if both ADX and PA fail there's no whale chance either (except Reverse mode / guard_score_mode bypass)
            if not _adx_soft_pass and not _pa_soft_pass and not _rev_mode_adx_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:adx={_coin_adx},no_pa")
                continue
            if _rev_mode_adx_bypass and not _adx_soft_pass:
                logger.info("[FOCUS] Scanner %s: Reverse-mode ADX bypass (ADX=%.1f <= %.0f, bouncy spot)",
                            symbol, _coin_adx, float(getattr(self.config, "reverse_adx_max", 20.0)))

            direction = "LONG" if c["signal"] == "BUY" else "SHORT"
            _is_bb_flip = c.get("bb_flipped", False)
            _is_sw_bb = c.get("sw_flag", False)  # [2026-04-18] for SW_UPPER_BB/SW_LOWER_BB mean-reversion exemption
            # ★ direction diversification: per-direction slot cap -- 2026-04-20 Long/Short split (this agent's directive)
            # [2026-04-19 Option B] pass if only the original direction is saturated (MTF FLIP tries the opposite).
            #   Only truly skip when both are saturated.
            # ★ Override Slot (2026-05-10 owner decision -- option A, free): expansion slots are same_dir-exempt.
            #   "being tied up means it's already not that direction" -- a separate mode from tied-up slots, free to enter in the market direction.
            if c.get("_is_override", False):
                _scan_log.append(f"{symbol}:override_same_dir_exempt({direction})")
            else:
                same_dir_count = sum(1 for p in self.positions if p.direction == direction)
                opp_dir = "SHORT" if direction == "LONG" else "LONG"
                opp_dir_count = sum(1 for p in self.positions if p.direction == opp_dir)
                _same_cap = self._effective_dir_cap(direction)
                _opp_cap = self._effective_dir_cap(opp_dir)
                if same_dir_count >= _same_cap and opp_dir_count >= _opp_cap:
                    _scan_log.append(f"{symbol}:dir_limit_both({direction}={same_dir_count}/{_same_cap},{opp_dir}={opp_dir_count}/{_opp_cap})")
                    continue
                if same_dir_count >= _same_cap:
                    # only the original direction is full -> _execute_entry's MTF FLIP tries the opposite. The scanner doesn't block.
                    _scan_log.append(f"{symbol}:dir_full_try_flip({direction}={same_dir_count}/{_same_cap})")
            price = float(c.get("price", 0))
            if price <= 0:
                _scan_log.append(f"{symbol}:no_price")
                continue
            if not self._check_reentry_allowed(direction, symbol, price):
                _scan_log.append(f"{symbol}:reentry_blocked")
                continue

            # ★ WhaleRadar -- disabled (2026-04-12): removed all conviction/direction/filter relaxation
            _whale_score = 0
            _whale_boost = 0
            _whale_type = ""

            # ADX/PA filter -- apply the original bar with no whale relaxation
            # ★ [2026-05-21 owner] Reverse mode = low ADX is itself the condition. Bypass both ADX/PA.
            _rev_mode_filter_bypass = (
                getattr(self.config, "entry_mode", "score") == "reverse"
                and _coin_adx <= float(getattr(self.config, "reverse_adx_max", 20.0))
            )
            if not _adx_soft_pass and not _rev_mode_filter_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:adx={_coin_adx}<{_effective_scan_adx}")
                continue
            if not _pa_soft_pass and not _rev_mode_filter_bypass and not self._guard_score_mode_active():
                _scan_log.append(f"{symbol}:no_pa")
                continue

            # Conviction -- need H4 candles for this coin
            try:
                raw_primary = client.get_kline(symbol, interval=self.config.primary_tf, limit=60)
                from app.strategy.greenpen.pa_detector import OHLCV
                candles_primary = [OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw_primary if len(r) >= 5]
            except Exception as exc:
                logger.debug("[FOCUS] raw_primary failed (fallback): %s", exc)
                candles_primary = []

            # -- dual-direction eval (Phase 2, 2026-06-09 owner GO) -- *finalize direction* right after acquiring candles --
            #   ★ direction must be set here so the PRIMARY counter-trend·30M penalty·conviction below apply to the correct direction.
            #   If dual OFF, keep the signal direction + conviction once (existing behavior). Reuse zones·conviction (no dup).
            _sym_zones = self._compute_zones_for_symbol(symbol, candles_primary)
            _signal_dir = direction
            direction, conviction, _dd_info = self._pick_best_direction(symbol, candles_primary, _sym_zones, _signal_dir)
            if _dd_info.get("flipped"):
                # direction switched -> re-check dir cap·reentry with the *new direction* (lines 12636~ above judged on the old direction)
                if not self._check_reentry_allowed(direction, symbol, price):
                    _scan_log.append(f"{symbol}:reentry_blocked(dual {direction})")
                    continue
                _nd = sum(1 for p in self.positions if p.direction == direction)
                _od = "SHORT" if direction == "LONG" else "LONG"
                _odc = sum(1 for p in self.positions if p.direction == _od)
                if _nd >= self._effective_dir_cap(direction) and _odc >= self._effective_dir_cap(_od):
                    _scan_log.append(f"{symbol}:dir_limit_both(dual {direction})")
                    continue
                logger.info("[FOCUS] DualDir entry-direction switch: %s %s->%s (conv %.0f)", symbol, _signal_dir, direction, conviction)

            # ★ H4 counter-trend -- [2026-04-18 evening] block -> pass (defer to FLIP)
            # user note: "don't just block; trade LONG or SHORT per the H1/M30/M15 flow"
            # before: continue if (direction vs H4) is counter-trend -> the signal vanished
            # change: send the signal to _execute_entry where the MTF gate (Anti-Knife + H4 Context) decides
            #       - if the original direction fits -> enter
            #       - original direction unfit + opposite fit -> FLIP entry
            #       - both unfit -> truly skip
            # Removing the old continue finally activates the MTF FLIP logic.
            # The BB FLIP / SW exemptions still matter (to keep intentional counter-direction signals in the log)
            _primary_t = ""
            if len(candles_primary) >= 10:
                try:
                    from app.strategy.greenpen.market_structure import analyze_structure as _az_s
                    _primary_s = _az_s(candles_primary, lookback=3)
                    _primary_t = _primary_s.trend.value if hasattr(_primary_s.trend, 'value') else str(_primary_s.trend)
                    if not _is_bb_flip and not _is_sw_bb:
                        if (direction == "LONG" and _primary_t == "DOWNTREND") or \
                           (direction == "SHORT" and _primary_t == "UPTREND"):
                            _scan_log.append(f"{symbol}:PRIMARY_cnt_defer({direction}vs{_primary_t})→MTF_FLIP")
                            logger.info("[FOCUS] Scanner PRIMARY counter-trend noted (will be handled by MTF FLIP): %s %s vs PRI %s",
                                        symbol, direction, _primary_t)
                            # [2026-04-18 evening] removed continue -- defer to _execute_entry's MTF gate
                except Exception as exc:
                    logger.debug("[FOCUS] import analyze_structure as _az_s failed: %s", exc)

            # ★ 30M trend alignment -- conviction penalty on a primary(H1)<->30M conflict
            # [2026-05-15] H1 switch: the old "H4<->H1" comparison became H1<->H1 dup -> shift one down to primary<->30M.
            # BB FLIP exempt: an extreme flip is intentionally counter, so a 30M conflict is expected
            # [2026-04-18] SW exempt: SIDEWAYS mean reversion naturally conflicts with the 30M trending-TF bias
            _m30_penalty = 1.0
            if not _is_bb_flip and not _is_sw_bb:
                try:
                    raw_m30 = client.get_kline(symbol, interval="30", limit=30)
                    if raw_m30 and len(raw_m30) >= 10:
                        from app.strategy.greenpen.pa_detector import OHLCV as _O1
                        from app.strategy.greenpen.market_structure import analyze_structure as _az_m30
                        _m30_candles = [_O1(float(r[1]), float(r[2]), float(r[3]), float(r[4])) for r in raw_m30 if len(r) >= 5]
                        if len(_m30_candles) >= 10:
                            _m30s = _az_m30(_m30_candles, lookback=3)
                            _m30t = _m30s.trend.value if hasattr(_m30s.trend, 'value') else str(_m30s.trend)
                            # [2026-05-20 owner] made a dataclass -- old hardcoded 0.5 -> UI-exposed
                            _pri_pen = float(getattr(self.config, "scanner_m30_primary_conflict_penalty", 0.7))
                            _dir_pen = float(getattr(self.config, "scanner_m30_direction_conflict_penalty", 0.7))
                            # primary<->30M conflict -> conviction × _pri_pen
                            if (_primary_t == "UPTREND" and _m30t == "DOWNTREND") or \
                               (_primary_t == "DOWNTREND" and _m30t == "UPTREND"):
                                _m30_penalty *= _pri_pen
                                logger.info("[FOCUS] Scanner 30M conflict %s: PRI=%s 30M=%s → penalty×%.2f", symbol, _primary_t, _m30t, _pri_pen)
                            # direction<->30M conflict -> conviction × _dir_pen
                            if (direction == "LONG" and _m30t == "DOWNTREND") or \
                               (direction == "SHORT" and _m30t == "UPTREND"):
                                _m30_penalty *= _dir_pen
                                logger.info("[FOCUS] Scanner 30M dir conflict %s: %s vs 30M=%s → penalty×%.2f", symbol, direction, _m30t, _dir_pen)
                except Exception as exc:
                    logger.debug("[FOCUS] Scanner 30M check failed %s: %s", symbol, exc)

            # [2026-04-18] pass direction for News Sentiment direction-awareness
            # [2026-04-24] pass zones for PA Pattern weight (location bonus/penalty)
            # [2026-05-17 Phase 4.7] Scanner = per-coin dynamic zone computation (fixes XAUT-zone misuse)
            # conviction·_sym_zones·direction = finalized in _pick_best_direction above (no recompute · observation also recorded there)
            # apply the 30M penalty [2026-05-17 100-pt float -- removed int truncation (preserve granularity)]
            if _m30_penalty < 1.0:
                conviction = float(conviction) * _m30_penalty
                logger.info("[FOCUS] Scanner %s conviction after 30M penalty: %.1f (×%.2f)", symbol, conviction, _m30_penalty)

            # ★★★ [2026-05-18 owner vision #5] Leading Entry pre-evaluation
            # Owner: "lead by even a minute -- get in ahead, in the direction it's already going to move"
            # Evaluate once per mode -- used later to decide the BB_REGIME/conv-block bypass
            _leading_eligible = False
            _leading_mode = ""
            _leading_reason = ""
            _leading_bypass_microtiming = False
            _leading_bypass_bb_regime = False
            _leading_size_pct = 0.0
            _le_mode = (getattr(self.config, "leading_entry_mode", "OFF") or "OFF").upper()
            if _le_mode == "CFID":
                _le_ok, _le_reason = self._check_cfid_leading_entry(symbol, direction)
                if _le_ok:
                    _leading_eligible = True
                    _leading_mode = "CFID"
                    _leading_reason = _le_reason
                    _leading_bypass_microtiming = bool(getattr(self.config, "cfid_leading_bypass_microtiming", True))
                    _leading_bypass_bb_regime = bool(getattr(self.config, "cfid_leading_bypass_bb_regime", True))
                    _leading_size_pct = float(getattr(self.config, "cfid_leading_size_pct", 5.0))
                    logger.info("[FOCUS] Leading CFID possible: %s %s -- %s", symbol, direction, _le_reason)
            elif _le_mode == "PATTERN":
                _le_ok, _le_reason = self._check_pattern_leading_entry(symbol, direction, candles_primary, _sym_zones)
                if _le_ok:
                    _leading_eligible = True
                    _leading_mode = "PATTERN"
                    _leading_reason = _le_reason
                    _leading_bypass_microtiming = bool(getattr(self.config, "pattern_leading_bypass_microtiming", True))
                    _leading_bypass_bb_regime = bool(getattr(self.config, "pattern_leading_bypass_bb_regime", True))
                    _leading_size_pct = float(getattr(self.config, "pattern_leading_size_pct", 5.0))
                    logger.info("[FOCUS] Leading PATTERN possible: %s %s -- %s", symbol, direction, _le_reason)

            # ★ Peak Fade penalty -- detect the peak turning down
            # [2026-04-18] SW-signal exempt -- SIDEWAYS mean reversion conflicts with the trending assumption
            #   Peak Fade was designed on an UPTREND/DOWNTREND assumption, but SW is SIDEWAYS
            #   the same structural contradiction existed in the H4 counter_trend and was exempted via _is_sw_bb
            #   exempt Peak Fade the same way -- consistency + resolves the 5-hour 0-entry
            if _is_sw_bb:
                _pf_penalty = 0
            else:
                _pf_penalty = self._peak_fade_penalty(candles_primary, direction)
            if _pf_penalty:
                conviction = max(0, conviction + _pf_penalty)

            # ★ [2026-04-17] PRIMARY BB-position penalty: penalize trend-direction entry in the overbought/oversold zone
            if candles_primary and len(candles_primary) >= 20:
                try:
                    from app.strategy.indicators import bollinger_bands as _bb_scanner_fn
                    _scnr_bb_closes = [c.close for c in candles_primary]
                    _scnr_bb = _bb_scanner_fn(_scnr_bb_closes, 20, 2.0)
                    if _scnr_bb and _scnr_bb["upper"] > _scnr_bb["lower"]:
                        _scnr_bb_pct = (_scnr_bb_closes[-1] - _scnr_bb["lower"]) / (_scnr_bb["upper"] - _scnr_bb["lower"]) * 100
                        # ★ Phase I (2026-04-20 option D relaxation): if regime BULL/BEAR is clear, allow trend continuation
                        # before: BB 85%+ LONG / BB 15%- SHORT was always fully blocked (ORDI -$18 lesson)
                        # change: if regime is the same direction, just conv -3 instead of blocking (preserve trend follow)
                        # keep the old block only on NEUTRAL/counter regime (avoid tops/bottoms)
                        _current_regime = getattr(self, "_b11_regime_state", ("", 0.0))[0]
                        if direction == "LONG" and _scnr_bb_pct > 85:
                            _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scnr_bb_closes)
                            if _current_regime == "BULL" or _tr_byp:
                                # BULL or strong trend (ADX) = trend continuation = BB wall-riding. conv -3 instead of blocking
                                conviction = max(0, conviction - 3)
                                _tr_why = "BULL regime" if _current_regime == "BULL" else f"ADX{_tr_adx:.0f}>=strong-trend wall-riding"
                                logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% > 85%% + LONG (%s) -> allow trend follow, conv -3 -> %d",
                                            symbol, _scnr_bb_pct, _tr_why, conviction)
                            else:
                                # NEUTRAL/BEAR + BB 85%+ LONG = top risk (keep the ORDI lesson)
                                # ★ [2026-05-18] Leading Entry bypass -- passes when CFID/PATTERN mode + bypass option ON
                                if _leading_eligible and _leading_bypass_bb_regime:
                                    logger.info("[FOCUS] Scanner %s: BB%.0f%% > 85%% LONG (top) BUT %s_LEAD bypass -> conv -5",
                                                symbol, _scnr_bb_pct, _leading_mode)
                                    conviction = max(0, conviction - 5)
                                else:
                                    logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% > 85%% + LONG -> BLOCKED (regime=%s, top risk)",
                                                symbol, _scnr_bb_pct, _current_regime or "?")
                                    _scan_log.append(f"{symbol}:BB_REGIME({int(_scnr_bb_pct)}%>85,top)")  # ★ UI STATUS
                                    continue
                        elif direction == "LONG" and _scnr_bb_pct > 75:
                            conviction = max(0, conviction - 2)
                            logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% > 75%% + LONG → conviction -2 → %d",
                                        symbol, _scnr_bb_pct, conviction)
                        elif direction == "SHORT" and _scnr_bb_pct < 15:
                            _tr_byp, _tr_adx = self._bb_trend_riding(direction, _scnr_bb_closes)
                            if _current_regime == "BEAR" or _tr_byp:
                                # BEAR or strong trend (ADX) = downtrend continuation = BB wall-riding. conv -3 instead of blocking
                                conviction = max(0, conviction - 3)
                                _tr_why = "BEAR regime" if _current_regime == "BEAR" else f"ADX{_tr_adx:.0f}>=strong-trend wall-riding"
                                logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% < 15%% + SHORT (%s) -> allow trend follow, conv -3 -> %d",
                                            symbol, _scnr_bb_pct, _tr_why, conviction)
                            else:
                                # NEUTRAL/BULL + BB 15%- SHORT = bottom risk
                                # ★ [2026-05-18] Leading Entry bypass -- passes when CFID/PATTERN mode + bypass option ON
                                if _leading_eligible and _leading_bypass_bb_regime:
                                    logger.info("[FOCUS] Scanner %s: BB%.0f%% < 15%% SHORT (bottom) BUT %s_LEAD bypass -> conv -5",
                                                symbol, _scnr_bb_pct, _leading_mode)
                                    conviction = max(0, conviction - 5)
                                else:
                                    logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% < 15%% + SHORT -> BLOCKED (regime=%s, bottom risk)",
                                                symbol, _scnr_bb_pct, _current_regime or "?")
                                    _scan_log.append(f"{symbol}:BB_REGIME({int(_scnr_bb_pct)}%<15,bottom)")  # ★ UI STATUS
                                    continue
                        elif direction == "SHORT" and _scnr_bb_pct < 25:
                            conviction = max(0, conviction - 2)
                            logger.info("[FOCUS] Scanner %s: PRIMARY BB%.0f%% < 25%% + SHORT → conviction -2 → %d",
                                        symbol, _scnr_bb_pct, conviction)
                except Exception as exc:
                    logger.debug("[FOCUS] import bollinger_bands as _bb_scanner failed: %s", exc)

            # ★ Coin Report Card grade penalty -- [2026-04-18] disabled per user request
            # try:
            #     from app.manager.coin_report_card import CoinReportCard
            #     _crc = CoinReportCard()
            #     _coin_scores = _crc.get_coin_scores()
            #     _cscore = _coin_scores.get(symbol, 50.0)
            #     if _cscore < 25:
            #         conviction = max(0, conviction - 3)
            #     elif _cscore < 40:
            #         conviction = max(0, conviction - 2)
            # except Exception as _cge:
            #     logger.debug("[FOCUS] Coin grade check failed: %s", _cge)

            # whale boost disabled (2026-04-12)

            # [2026-04-18 evening] removed the hard cap -- use the config value as-is (transparency)
            #   learned the hard-cap-overrides-config risk from this agent's server config=6 case
            #   the sibling server set the config value itself low (=3) to achieve the same effect
            # -- Event Shield: hard-block new entries in the economic-event window (conviction-independent) --
            _es_label = self._event_shield_label()
            if _es_label:
                self._record_skip(symbol, direction, conviction, "-", f"event_shield({_es_label})")
                continue  # event window -- exclude this coin candidate

            _effective_min_conv = self.config.scanner_min_conviction

            # Morning Guard: raise conviction during the risky morning window
            if self._is_morning_guard_active():
                _effective_min_conv += self.config.morning_guard_conviction_boost

            # ★ [2026-05-17] cache the Scanner's final conviction (to unify the UI CONV)
            self._last_scan_conviction[symbol] = float(conviction)

            # ★ [Phase 7 2026-05-28] signal_history -- for owner's 5-condition rule #1 (track previous signals)
            # for the "what was a SELL..." rule. Store only BUY/SELL (exclude HOLD).
            # ★ FIX (2026-05-28 15:25): in this scope the variable is _signal (underscore) -- signal would NameError.
            try:
                if _signal in ("BUY", "SELL"):
                    _sig_hist = self._signal_history.get(symbol)
                    if _sig_hist is None:
                        _sig_hist = deque(maxlen=self._signal_history_maxlen)
                        self._signal_history[symbol] = _sig_hist
                    _sig_hist.append((time.time(), _signal))
            except NameError:
                # _signal-undefined path (defensive) -- skip silently
                pass

            # -- ★ [2026-05-20 owner redesign + 5-21 00:08 variable fix] Reverse mode -- auto-enter opposite the bot signal --
            # Owner's primary rule: "bot signal + low conv (<= 50) + low ADX (<= 20) -> reverse entry = certain".
            # The bounciness (low ADX) is itself the *condition* -- the owner's gut spot. Always enter (no opposite-conv check).
            # Safety guard = _execute_entry's _mtf_gate (Anti-Knife/primary_context work for the opposite direction too).
            # ★ [fix 23:53] removed the conv < _effective_min_conv condition -- reverse triggers even if the owner lowers min_conv.
            # ★ [fix 00:08] _adx_val -> _coin_adx (different function scope, NameError fix).
            _entry_mode_cycle = getattr(self.config, "entry_mode", "score")
            _rev_conv_threshold = float(getattr(self.config, "reverse_conv_threshold", 50.0))
            _rev_adx_max = float(getattr(self.config, "reverse_adx_max", 20.0))
            if (_entry_mode_cycle == "reverse"
                    and getattr(self.config, "direction_mode", "both") == "both"  # ★ [2026-06-21 owner] no reverse for long_only/short_only -- direction enforcement is absolute. Fixes the bug where reverse flipped a long_only LONG candidate into a SHORT entry.
                    and conviction <= _rev_conv_threshold
                    and _coin_adx <= _rev_adx_max):
                _opp_dir_rev = "SHORT" if direction == "LONG" else "LONG"
                logger.warning(
                    "[FOCUS] ★ REVERSE MODE: %s %s conv=%.1f<=%.0f ADX=%.1f<=%.0f -> auto-enter opposite %s (owner's primary rule)",
                    symbol, direction, conviction, _rev_conv_threshold, _coin_adx, _rev_adx_max, _opp_dir_rev)
                # switch direction + bypass conv threshold (reverse mode = owner's always-enter rule)
                direction = _opp_dir_rev
                conviction = float(_effective_min_conv)  # for bypass (the real safety guard is _execute_entry _mtf_gate)
                self._last_scan_conviction[symbol] = conviction

            # ★ [2026-05-18] Leading Entry -- pass even on conviction shortfall (the lead-entry path)
            # ★ [2026-05-28 owner] when guard_score_mode is active, bypass the Scanner conv gate (defer to score evaluation)
            if conviction < _effective_min_conv:
                if self._guard_score_mode_active():
                    logger.info("[FOCUS] Scanner %s %s: conv=%.1f<%d -- guard_score_mode bypass (defer to score evaluation)",
                                symbol, direction, float(conviction), _effective_min_conv)
                elif _leading_eligible:
                    logger.info("[FOCUS] %s_LEAD fired: %s %s conv=%.1f<%d short BUT proceeding with lead entry (%s)",
                                _leading_mode, symbol, direction, float(conviction), _effective_min_conv, _leading_reason)
                else:
                    if self._is_morning_guard_active():
                        logger.info("[FOCUS] Morning Guard: scanner blocked %s, conviction %d < %d (morning +%d)",
                                     symbol, conviction, _effective_min_conv, self.config.morning_guard_conviction_boost)
                    _scan_log.append(f"{symbol}:conv={float(conviction):.1f}")  # ★ omit the <50 marker (the threshold is the same per coin)
                    continue

            # ★ [2026-05-18] Leading Entry size override -- equity × leading_size_pct
            if _leading_eligible and _leading_size_pct > 0:
                _avail = self.config.budget_usdt
                if _avail <= 0:
                    _avail = self._get_available_margin()
                if _avail <= 0:
                    _avail = self._get_effective_budget(symbol)
                budget = max(5.0, _avail * (_leading_size_pct / 100.0))
                logger.info("[FOCUS] %s_LEAD size: $%.2f (%.1f%% × $%.2f equity)",
                            _leading_mode, budget, _leading_size_pct, _avail)
            else:
                budget = self._compute_entry_budget(conviction, symbol)
            if budget < 5.0:
                _scan_log.append(f"{symbol}:budget=${budget:.1f}")
                continue

            atr = float(c.get("atr", 0)) or price * 0.02
            _reason = f"scanner:adx={c.get('adx')},conv={conviction},pa={c.get('pa_pattern')}"
            if _whale_score >= 3:
                _reason += f",whale={_whale_score}({_whale_type})"

            # ★ Phase K (2026-04-21): Regime Transition Preemptive Entry ★
            # Double-verified (this agent 88%/sibling 94%/BTC 500-bar 72%). If on simultaneously with J v2, K takes priority (J auto-ignored).
            # If enabled=False the hook itself is a NoOp. In paper_mode, skip entry + only log JSONL.
            _phase_k_active = False
            _phase_k_flip_dir = ""
            _phase_k_reason = ""
            if getattr(self.config, "regime_transition_enabled", False):
                try:
                    _k_allow, _k_opp, _k_reason = self.detect_regime_transition(
                        market=symbol,
                        scanner_direction=direction,
                        conviction=conviction,
                        adx_now=float(c.get("adx", 0) or 0),
                        adx_past=float(c.get("adx_past", 0) or 0),
                        candles_primary=candles_primary,
                    )
                    if _k_allow and _k_opp:
                        _phase_k_active = True
                        _phase_k_flip_dir = _k_opp
                        _phase_k_reason = _k_reason
                        _paper = bool(getattr(self.config, "regime_transition_paper_mode", True))
                        self._phase_k_paper_log({
                            "ts": time.time(),
                            "market": symbol,
                            "scanner_dir": direction,
                            "flip_dir": _k_opp,
                            "conviction": conviction,
                            "adx_now": c.get("adx", 0),
                            "adx_past": c.get("adx_past", 0),
                            "btc_ema_gap_pct": getattr(self, "_btc_ema_gap_pct", None),
                            "reason": _k_reason,
                            "paper_mode": _paper,
                        })
                        if _paper:
                            logger.info("[FOCUS] Phase K PAPER: %s flip %s->%s %s (skip entry, log only)",
                                        symbol, direction, _k_opp, _k_reason)
                            _scan_log.append(f"{symbol}:phase_k_paper_flip_{_k_opp}")
                            continue
                        else:
                            logger.info("[FOCUS] Phase K LIVE: %s flip %s→%s %s (size×%.2f tp×%.2f sl×%.2f)",
                                        symbol, direction, _k_opp, _k_reason,
                                        self.config.regime_transition_size_mult,
                                        self.config.regime_transition_tp_mult,
                                        self.config.regime_transition_sl_mult)
                            direction = _k_opp  # ★ actual direction switch
                            _reason = f"phase_k_regime_transition:{_k_reason}"
                except Exception as exc:
                    logger.debug("[FOCUS] Phase K detect failed %s: %s", symbol, exc)

            # ★ [2026-04-26] BTC Emergency Aligned entry acceleration -- block counter-trend
            _em_aligned_dir = getattr(self, "_emergency_aligned_dir", None)
            _em_aligned_until = getattr(self, "_emergency_aligned_until", 0)
            if _em_aligned_dir and time.time() < _em_aligned_until:
                if getattr(self.config, "btc_emergency_aggressive_entry", True) and direction != _em_aligned_dir:
                    logger.info("[FOCUS] BTC Emergency Aligned: %s %s skip (aligned=%s, %.0fs left)",
                                direction, symbol, _em_aligned_dir, _em_aligned_until - time.time())
                    _scan_log.append(f"{symbol}:btc_em_skip_opp")
                    continue
            elif _em_aligned_dir and time.time() >= _em_aligned_until:
                # time expired -> reset (so it can fire again)
                logger.info("[FOCUS] BTC Emergency Aligned reset (duration expired)")
                self._emergency_aligned_dir = None
                self._btc_emergency_fired = False

            # ★ #7 [2026-04-26] Regime Reversal Pause -- avoid the inflection tuition
            _rrp_paused, _rrp_reason = self._check_regime_reversal_pause()
            if _rrp_paused:
                _scan_log.append(f"{symbol}:{_rrp_reason}")
                continue
            # ★ #2A [2026-04-26 this agent's fix] Portfolio SL Rate Pause -- defend against simultaneous SLs
            _psl_paused, _psl_reason = self._check_portfolio_sl_rate_pause()
            if _psl_paused:
                _scan_log.append(f"{symbol}:{_psl_reason}")
                continue
            # ★ #4 [2026-04-26] BTC trend-aligned conviction bonus
            _btc_bonus = self._btc_trend_conv_bonus(direction)
            # ★ #5A [2026-04-26 this agent's fix] BTC + B12 combined cap -- addresses the "+3 neutralizes other indicators" concern
            if _btc_bonus > 0 and getattr(self.config, "btc_b12_combined_cap_enabled", True):
                cap = int(getattr(self.config, "btc_b12_combined_cap_max", 2))
                last_cross = int(getattr(self, "_last_cross_delta", 0))
                if last_cross > 0 and (last_cross + _btc_bonus) > cap:
                    _orig = _btc_bonus
                    _btc_bonus = max(0, cap - last_cross)
                    logger.info("[FOCUS] BTC bonus capped: +%d → +%d (cross+%d, cap +%d)",
                                _orig, _btc_bonus, last_cross, cap)
            if _btc_bonus > 0:
                conviction += _btc_bonus
                logger.info("[FOCUS] BTC trend bonus +%d for %s %s → conv=%d", _btc_bonus, direction, symbol, conviction)
            logger.info("[FOCUS] Scanner attempting: %s %s adx=%.1f conv=%d whale=%d budget=$%.1f",
                        direction, symbol, c.get("adx", 0), conviction, _whale_score, budget)
            _entry_payload = {
                "enter": True, "market": symbol, "direction": direction,
                "price": price, "atr": atr,
                "reason": _reason,
                "conviction_score": conviction,
                "conviction_budget": budget,
                "_conviction_modifiers": (lambda _m=getattr(self, '_last_conviction_breakdown', {}) or {}: f"peak_fade={_pf_penalty},whale={_whale_score},mtf={_m.get('mtf_pen', 0)},mom={_m.get('mom_pen', 0)},zone={_m.get('zone_pos', 0)},align={_m.get('mom_align', 0)}")(),
                "_scanner_entry": True,
                "_is_sw_bb": _is_sw_bb,  # [2026-04-18] for Entry Quality exemption
            }
            # ★ [2026-05-18] Leading Entry flag -- _execute_entry bypass + journal marking
            if _leading_eligible:
                _entry_payload["_leading_entry"] = True
                _entry_payload["_leading_mode"] = _leading_mode  # "CFID" / "PATTERN"
                _entry_payload["_leading_reason"] = _leading_reason
                _entry_payload["_bypass_microtiming"] = _leading_bypass_microtiming
                _entry_payload["_bypass_bb_regime"] = _leading_bypass_bb_regime
                # also mark the reason (journal/log tracking)
                _entry_payload["reason"] = f"{_reason}|{_leading_mode}_LEAD:{_leading_reason}"
            if _phase_k_active:
                _entry_payload["_phase_k"] = True
                _entry_payload["_phase_k_reason"] = _phase_k_reason
                _entry_payload["_phase_k_size_mult"] = float(self.config.regime_transition_size_mult)
                _entry_payload["_phase_k_tp_mult"] = float(self.config.regime_transition_tp_mult)
                _entry_payload["_phase_k_sl_mult"] = float(self.config.regime_transition_sl_mult)
                # apply size_mult: shrink conviction_budget
                _entry_payload["conviction_budget"] = budget * float(self.config.regime_transition_size_mult)
            # ★ Phase L.3 (2026-04-22) -- PA double confirm (merged into the S3 Gate quality gate)
            # Uses in-memory PA history. 2+ same-(symbol, direction) PA within the window = double confirmed.
            # default OFF -- payload always False (S3 Gate weight 0). Works only when enabled.
            _pa_double = False
            if getattr(self.config, "pa_double_confirm_enabled", False):
                try:
                    _win_sec = float(getattr(self.config, "pa_double_confirm_window_sec", 60.0))
                    _pa_hist = getattr(self, "_pa_signal_history", {})
                    if not _pa_hist:
                        self._pa_signal_history = {}
                        _pa_hist = self._pa_signal_history
                    _key = (symbol.upper(), direction)
                    _now = time.time()
                    # keep only existing ts within the window
                    _hist = [t for t in _pa_hist.get(_key, []) if (_now - t) <= _win_sec]
                    _hist.append(_now)
                    _pa_hist[_key] = _hist
                    if len(_hist) >= 2:
                        _pa_double = True
                        logger.info("[FOCUS] Phase L.3 PA double confirmed: %s %s (%d signals in %.0fs)",
                                    symbol, direction, len(_hist), _win_sec)
                except Exception as _l3_exc:
                    logger.debug("[FOCUS] Phase L.3 PA double check failed: %s", _l3_exc)
            _entry_payload["_pa_double_confirmed"] = _pa_double

            # ★ [2026-05-18] Leading Entry -- also show info in _scan_log (UI STATUS green/purple badge)
            if _leading_eligible:
                _scan_log.append(f"{symbol}:{_leading_mode}_LEAD({_leading_reason})")

            result = self._execute_entry(_entry_payload)
            if result.get("state") == "POSITIONED":
                entered.append(symbol)
                held.add(symbol)
                open_count += 1
                logger.info("[FOCUS] Scanner ENTERED: %s %s adx=%.1f conv=%d%s",
                           direction, symbol, c.get("adx", 0), conviction,
                           f" [{_leading_mode}_LEAD]" if _leading_eligible else "")
                break  # success -> one entry per tick
            elif result.get("microtiming_deferred"):
                # [2026-05-16] 5m Microtiming Gate defer -- a quiet wait with no BLOCK count accrued
                _scan_log.append(f"{symbol}:microtiming_defer")
                # no state change -- naturally proceed to the next candidate
                if self.state != FocusState.HUNT and self.state != FocusState.POSITIONED:
                    self.state = FocusState.HUNT
                continue
            else:
                # [2026-04-09] on failure, try the next coin (removed break)
                # ★ [2026-05-17] for UI STATUS -- extract the _execute_entry reject reason (don't expose the whole result dict)
                _err_reason = ""
                if isinstance(result, dict):
                    _err_reason = (result.get("error") or result.get("skip") or result.get("reason") or "exec_fail")
                else:
                    _err_reason = "exec_fail"
                _scan_log.append(f"{symbol}:{_err_reason}")
                _pipeline_syms.add(symbol)  # ★ this symbol is tallied via record_blocked->sink inside _execute_entry (excluded from the prefilter tally below)
                logger.warning("[FOCUS] Scanner entry FAILED: %s %s → %s — trying next", direction, symbol, result)
                # _execute_entry may have switched to DORMANT -> restore HUNT
                if self.state != FocusState.HUNT and self.state != FocusState.POSITIONED:
                    self.state = FocusState.HUNT
                continue  # try the next coin

        if _scan_log:
            # ★ Phase H (2026-04-20 this agent's letter#3 B-1): [:8] cap -> [:25]
            # an SW_LOWER_BB signal like ZEC's, if past the 8th, isn't visible and looks dead
            logger.info("[FOCUS] Scanner filter (%d items): %s", len(_scan_log), " | ".join(_scan_log[:25]))
        # ★ [2026-05-17] cache block reasons for the scan-list API (UI STATUS column)
        _block_dict = {}
        for entry in _scan_log:
            if ':' in entry:
                _sym, _reason = entry.split(':', 1)
                _block_dict[_sym] = _reason
        self._last_scan_filter = {'ts': time.time(), 'items': _block_dict}
        # ★ [2026-06-15 solution B] also tally the scanner pre-filter (BB_REGIME top/blacklisted/held/reentry/adx/conv etc.)
        #   into the gate_ledger -- completes 'why it stayed silent'. Exclude _pipeline_syms (already counted by the record_blocked sink) = 0 dup.
        if self._gate_ledger is not None and self.config.gate_ledger_enabled:
            for _sym, _reason in _block_dict.items():
                if _sym in _pipeline_syms:
                    continue
                # normalize the label: first token only (BB_REGIME(..)->BB_REGIME, adx=13<15->adx, dir_limit_both(..)->dir_limit_both)
                _label = _reason.split('(')[0].split(':')[0].split(',')[0].split('=')[0].split('<')[0].split('>')[0].split(' ')[0].strip()[:40] or "-"
                try:
                    self._gate_ledger.record(_sym, _label, passed=False)
                except Exception:  # noqa: BLE001
                    pass

        return {"scanner_entered": entered} if entered else {"scanner": "no_match"}

    def _handle_idle(self, now: float) -> Dict:
        # Check daily plan limit
        if self.daily_plans_used >= self.config.max_daily_plans:
            return {"state": "DORMANT", "reason": "daily_plan_limit"}
        if self.daily_sl_count >= self.config.max_daily_sl:
            return {"state": "DORMANT", "reason": "daily_sl_limit"}

        # Time for next scan?
        if now - self.last_scan_ts >= self.config.scan_interval_sec:
            self.state = FocusState.HUNT
            self.last_scan_ts = now
            self._save_config()
            logger.info("[FOCUS] IDLE → SELECTING")

        return {"state": "DORMANT", "next_scan_in": max(0, self.config.scan_interval_sec - (now - self.last_scan_ts))}

    def _handle_selecting(self, now: float) -> Dict:
        """Run 3-point confirmation coin scan."""
        # ★ lock_market: if a fixed coin is set, skip the scan and enter directly
        if self.config.lock_market:
            locked = self.config.lock_market.upper()
            logger.info("[FOCUS] LOCKED to %s — skipping scan", locked)
            # [2026-04-18] removed LONG fallback -- don't enter on H4 analysis failure
            direction = "HOLD"
            try:
                from app.strategy.greenpen import full_analysis
                from app.strategy.greenpen.pa_detector import OHLCV
                raw = self._get_client().get_kline(locked, interval=self.config.primary_tf, limit=100)
                candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                if len(candles) >= 20:
                    analysis = full_analysis(candles)
                    # full_analysis returns GreenPenAnalysis dataclass, not dict
                    pa_list = getattr(analysis, 'pa_signals', []) or []
                    struct = getattr(analysis, 'structure', None)
                    trend_val = ""
                    if struct and hasattr(struct, 'trend'):
                        trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                    if pa_list:
                        best_pa = pa_list[0]
                        direction = best_pa.direction.value  # "LONG" or "SHORT"
                        # ★ on trend-PA direction conflict, prefer trend (prevent counter-trend entry)
                        if trend_val and (
                            (direction == "SHORT" and trend_val == "UPTREND") or
                            (direction == "LONG" and trend_val == "DOWNTREND")
                        ):
                            logger.warning("[FOCUS] PA %s → %s conflicts with %s — overriding to trend direction",
                                          best_pa.pattern.value, direction, trend_val)
                            direction = "LONG" if trend_val == "UPTREND" else "SHORT"
                    elif trend_val == "DOWNTREND":
                        direction = "SHORT"
                    elif trend_val == "UPTREND":
                        direction = "LONG"
                    if self.config.direction_mode == "long_only":
                        direction = "LONG"
                    elif self.config.direction_mode == "short_only":
                        direction = "SHORT"
                    self.primary_sig = {
                        "pattern": pa_list[0].pattern.value if pa_list else "-",
                        "direction": direction,
                        "confidence": pa_list[0].confidence if pa_list else 0,
                        "atr": getattr(analysis, 'atr', 0) or 0,
                    }
                    zones_raw = getattr(analysis, 'zones', []) or []
                    self.zones = [{"type": getattr(z, 'type', {}).value if hasattr(getattr(z, 'type', None), 'value') else str(getattr(z, 'type', '')),
                                   "price_low": getattr(z, 'price_low', 0), "price_high": getattr(z, 'price_high', 0),
                                   "strength": getattr(z, 'strength', 1.0)}
                                  for z in zones_raw]
            except Exception as exc:
                logger.warning("[FOCUS] lock_market analysis failed: %s — using HOLD (no entry)", exc)

            self.selected_market = locked
            self.selected_direction = direction
            self.state = FocusState.HUNT
            self.last_scan_ts = now
            self._save_config()
            logger.info("[FOCUS] LOCKED %s %s → WATCHING", locked, direction)
            return {"state": "HUNT", "market": locked, "direction": direction, "locked": True}

        try:
            from app.manager.focus_coin_selector import select_focus_coin
            result = select_focus_coin(
                self.system,
                self._get_client(),
                direction_mode=self.config.direction_mode,
                primary_tf=self.config.primary_tf,
            )
        except Exception as exc:
            logger.warning("[FOCUS] coin selection failed: %s", exc)
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "HUNT", "error": str(exc)}

        if not result or not result.get("market"):
            logger.info("[FOCUS] No coin passed 3-point confirmation → IDLE")
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "HUNT", "result": "no_candidate"}

        # ★ blacklist check (exclude order-rejected coins for 10 min)
        bl = getattr(self, '_temp_blacklist', {})
        if result["market"] in bl and bl[result["market"]] > time.time():
            logger.info("[FOCUS] %s blacklisted (%.0fs remaining) — IDLE",
                        result["market"], bl[result["market"]] - time.time())
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "DORMANT", "skip": "blacklisted"}

        # skip if the coin is already held
        held_markets = {p.market for p in self.positions}
        if result["market"] in held_markets:
            logger.info("[FOCUS] %s already held — skipping", result["market"])
            self.state = FocusState.DORMANT
            return {"state": "DORMANT", "skip": "already_held"}

        # Coin selected!
        self.selected_market = result["market"]
        self.selected_direction = result.get("direction", "")
        self.zones = result.get("zones", [])
        self.primary_sig = result.get("primary_sig")

        # ★ register the selected coin with price_store -> receive live WebSocket prices
        try:
            if self.system:
                feed = getattr(self.system, "price_feed", None)
                if feed and hasattr(feed, "add_symbol"):
                    feed.add_symbol(result["market"])
                    logger.info("[FOCUS] Added %s to price feed subscription", result["market"])
        except Exception as exc:
            logger.debug("[FOCUS] price feed subscription failed: %s", exc)

        # strong signal (conf >= 70%) -> skip ZONE_WAIT/WATCHING, enter directly
        conf = float(result.get("confidence", 0) or 0)
        if conf >= 0.85:
            price = self._get_current_price(self.selected_market)
            if price and price > 0:
                atr = float(result.get("atr", 0) or price * 0.02)
                logger.info("[FOCUS] Strong signal %.0f%% — FAST ENTRY %s %s @ %.2f",
                            conf * 100, self.selected_direction, self.selected_market, price)
                return self._execute_entry({
                    "enter": True,
                    "direction": self.selected_direction,
                    "market": self.selected_market,  # ★ M15 FIX
                    "price": price,
                    "atr": atr,
                    "reason": f"fast_entry_conf:{conf:.0%}",
                })

        self.state = FocusState.ALERT
        self._save_config()
        logger.info("[FOCUS] Selected %s %s (conf=%.0f%%) → ZONE_WAIT", self.selected_market, self.selected_direction, conf * 100)
        return {"state": "ALERT", "market": self.selected_market, "direction": self.selected_direction}

    def _handle_zone_wait(self, now: float) -> Dict:
        """Wait for H4 PA SIG at Zone."""
        # re-analyze each scan interval (zones need updating even with lock_market)
        if now - self.last_scan_ts >= self.config.scan_interval_sec:
            self.last_scan_ts = now
            if not self.config.lock_market:
                self.state = FocusState.HUNT
                logger.info("[FOCUS] ZONE_WAIT → re-scan for better coin")
                return self._handle_selecting(now)
            else:
                # ★ lock_market: don't change the coin but refresh zones/signals
                try:
                    from app.strategy.greenpen import full_analysis
                    from app.strategy.greenpen.pa_detector import OHLCV
                    raw = None
                    for _kl_try in range(2):
                        try:
                            raw = self._get_client().get_kline(self.config.lock_market, interval=self.config.primary_tf, limit=50)
                            break
                        except (ConnectionError, OSError) as _ke:
                            if _kl_try == 0:
                                import time as _kt; _kt.sleep(1)
                            else:
                                logger.warning("[FOCUS] ZONE_WAIT kline retry failed: %s", _ke)
                    if not raw:
                        raise RuntimeError("kline fetch failed")
                    candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                    if len(candles) >= 20:
                        analysis = full_analysis(candles)
                        zones_raw = getattr(analysis, 'zones', []) or []
                        self.zones = [{"type": getattr(z, 'type', {}).value if hasattr(getattr(z, 'type', None), 'value') else str(getattr(z, 'type', '')),
                                       "price_low": getattr(z, 'price_low', 0), "price_high": getattr(z, 'price_high', 0),
                                       "strength": getattr(z, 'strength', 1.0)}
                                      for z in zones_raw]
                        # also refresh ATR + direction
                        struct = getattr(analysis, 'structure', None)
                        trend_val = ""
                        if struct and hasattr(struct, 'trend'):
                            trend_val = struct.trend.value if hasattr(struct.trend, 'value') else str(struct.trend)
                        atr_val = getattr(analysis, 'atr', 0) or 0
                        if trend_val:
                            self.selected_direction = "LONG" if trend_val == "UPTREND" else ("SHORT" if trend_val == "DOWNTREND" else self.selected_direction)
                        self.primary_sig = {
                            # [2026-04-18] removed LONG fallback -- in case this dead code is reactivated
                            "pattern": "-", "direction": self.selected_direction or "HOLD",
                            "confidence": 0, "atr": atr_val,
                        }
                        logger.info("[FOCUS] ZONE_WAIT refresh: %d zones, ATR=%.2f, trend=%s",
                                    len(self.zones), atr_val, trend_val or "-")
                        self._save_config()
                except Exception as exc:
                    logger.warning("[FOCUS] ZONE_WAIT zone refresh failed: %s", exc)

        try:
            from app.manager.focus_entry_signal import check_primary_sig
            sig = check_primary_sig(
                self._get_client(),
                self.selected_market,
                self.zones,
                self.config.primary_tf,
            )
        except Exception as exc:
            logger.warning("[FOCUS] PRIMARY SIG check failed: %s", exc)
            return {"state": "ALERT", "error": str(exc)}

        if sig and sig.get("valid"):
            self.primary_sig = sig
            self.state = FocusState.HUNT
            self._save_config()
            logger.info("[FOCUS] PRIMARY SIG confirmed → WATCHING: %s", sig.get("pattern"))
            return {"state": "HUNT", "sig": sig}

        # ★ store ATR even without a PA pattern (Harpoon needs ATR)
        if not self.primary_sig or not isinstance(self.primary_sig, dict) or not self.primary_sig.get("atr"):
            try:
                from app.strategy.greenpen.pa_detector import OHLCV
                from app.strategy.greenpen import _simple_atr
                raw = self._get_client().get_kline(self.selected_market, interval=self.config.primary_tf, limit=20)
                candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                if len(candles) >= 5:
                    atr = _simple_atr(candles)
                    self.primary_sig = {
                        # [2026-04-18] removed LONG fallback -- in case this dead code is reactivated
                        "pattern": "-", "direction": self.selected_direction or "HOLD",
                        "confidence": 0, "atr": atr,
                    }
            except Exception as exc:
                logger.debug("[FOCUS] import OHLCV failed: %s", exc)

        return {"state": "ALERT", "market": self.selected_market}

    def _handle_watching(self, now: float, btc_price: float) -> Dict:
        """Wait for M5 precision entry signal."""
        # each scan interval, re-check for a better coin (no re-scan needed if lock_market)
        if not self.config.lock_market and now - self.last_scan_ts >= self.config.scan_interval_sec:
            self.last_scan_ts = now
            self.state = FocusState.HUNT
            logger.info("[FOCUS] WATCHING → re-scan for better coin")
            return self._handle_selecting(now)

        # [2026-04-18] removed LONG fallback -- don't enter without direction
        _watch_dir = self.selected_direction or (self.primary_sig or {}).get("direction")
        if _watch_dir not in ("LONG", "SHORT"):
            return {"state": "ALERT", "skip": "no_direction"}

        try:
            from app.manager.focus_entry_signal import check_m5_entry
            entry = check_m5_entry(
                self._get_client(),
                self.selected_market,
                _watch_dir,
                self.config.entry_tf,
                btc_price=btc_price,
                zones=self.zones,
            )
        except Exception as exc:
            logger.warning("[FOCUS] M5 entry check failed: %s", exc)
            return {"state": "HUNT", "error": str(exc)}

        if entry and entry.get("enter"):
            entry.setdefault("market", self.selected_market)
            return self._execute_entry(entry)

        # if PRIMARY SIG confidence is 70%+, enter directly without M5 confirmation (waiting misses the chance)
        primary_conf = float((self.primary_sig or {}).get("confidence", 0) or 0)
        if primary_conf >= 0.85 and not entry:
            # [2026-04-18] removed LONG fallback -- don't enter if direction is unclear
            primary_dir = self.selected_direction or (self.primary_sig or {}).get("direction") or "HOLD"
            if primary_dir not in ("LONG", "SHORT"):
                return {"state": "ALERT", "skip": "no_direction"}
            price = self._get_current_price(self.selected_market)
            if price and price > 0:
                from app.strategy.greenpen import _simple_atr
                from app.strategy.greenpen.pa_detector import OHLCV
                candles = []
                try:
                    raw = self._get_client().get_kline(self.selected_market, interval=self.config.entry_tf, limit=20)
                    candles = [OHLCV(float(r[1]),float(r[2]),float(r[3]),float(r[4])) for r in raw if len(r)>=5]
                    atr = _simple_atr(candles) if len(candles) >= 5 else price * 0.02
                except Exception as exc:
                    logger.debug("[FOCUS] raw failed (fallback): %s", exc)
                    atr = price * 0.02

                # -- minimal M5 trend confirmation (block counter-trend direct entry even at high confidence) --
                if len(candles) >= 10:
                    try:
                        from app.strategy.greenpen.market_structure import analyze_structure as _az
                        _m5s = _az(candles, lookback=3)
                        _m5t = _m5s.trend.value if hasattr(_m5s.trend, 'value') else str(_m5s.trend)
                        if primary_dir == "LONG" and _m5t == "DOWNTREND":
                            logger.info("[FOCUS] PRIMARY conf %.0f%% but M5 DOWNTREND — skip direct entry",
                                        primary_conf * 100)
                            return {"state": "HUNT", "market": self.selected_market}
                        if primary_dir == "SHORT" and _m5t == "UPTREND":
                            logger.info("[FOCUS] PRIMARY conf %.0f%% but M5 UPTREND — skip direct entry",
                                        primary_conf * 100)
                            return {"state": "HUNT", "market": self.selected_market}
                    except Exception as exc:
                        logger.debug("[FOCUS] import analyze_structure as _az failed: %s", exc)  # on analysis failure, prefer the H4 high-confidence allow

                logger.info("[FOCUS] PRIMARY conf %.0f%% >= 70%% — direct entry %s %s @ %.2f",
                            primary_conf * 100, primary_dir, self.selected_market, price)
                return self._execute_entry({
                    "enter": True, "direction": primary_dir,
                    "market": self.selected_market,  # ★ M15 FIX
                    "price": price, "atr": atr,
                    "reason": f"primary_high_conf:{primary_conf:.0%}",
                })

        return {"state": "HUNT", "market": self.selected_market}

    def _handle_positioned(self, now: float, btc_price: float) -> Dict:
        """LEGACY -- not called directly from tick(). Replaced by _manage_all_positions.
        API disabled -> referenced only indirectly via the _execute_exit path."""
        if not self.position:
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "POSITIONED", "error": "no_position"}

        price = self._get_current_price(self.position.market)
        if not price or price <= 0:
            return {"state": "POSITIONED", "market": self.position.market, "price": "unavailable"}

        from app.strategy.greenpen.cycle_tp import (
            CycleTargets, should_partial_exit, should_full_exit,
        )

        targets = CycleTargets(
            tp1=self.position.tp1,
            tp2=self.position.tp2,
            sl=self.position.sl,
            rr_ratio=0,
            atr_used=self.position.atr_used,
            direction=self.position.direction,
        )

        # Check SL / TP2
        exit_reason = should_full_exit(
            price, self.position.entry_price, self.position.direction, targets,
        )
        if exit_reason:
            return self._execute_exit(exit_reason, is_sl="SL hit" in exit_reason)

        # Check TP1 partial
        partial = should_partial_exit(
            price, self.position.entry_price, self.position.direction, targets,
            partial_pct=self.config.partial_exit_pct,
            already_partial=self.position.partial_done,
        )
        if partial:
            return self._execute_partial(partial, price)

        # -- multi-tier emergency exit (Upbit friend system) --
        if self.config.emergency_tp_tiers and btc_price > 0:
            try:
                from app.core.hyper_price_store import price_store
                btc_prices = price_store.get_prices("BTCUSDT", count=60)
                if btc_prices and len(btc_prices) >= 10:
                    btc_recent = [float(p) for p in btc_prices[-10:] if p]
                    if btc_recent and btc_recent[0] > 0:
                        btc_change_pct = (btc_recent[-1] / btc_recent[0] - 1) * 100
                        # Tier 1: BTC -3% -> shrink TP 50%
                        if btc_change_pct < -3.0:
                            reduced_tp1 = self.position.entry_price + (self.position.tp1 - self.position.entry_price) * 0.5
                            if self.position.direction == "SHORT":
                                reduced_tp1 = self.position.entry_price - (self.position.entry_price - self.position.tp1) * 0.5
                            self.position.tp1 = reduced_tp1
                            logger.warning("[FOCUS] Emergency Tier1: BTC %.1f%% → TP1 tightened to %.2f", btc_change_pct, reduced_tp1)
                        # Tier 2: BTC -5% -> exit immediately
                        if btc_change_pct < -5.0:
                            return self._execute_exit(f"BTC_CRASH:{btc_change_pct:.1f}%", is_sl=True)
            except Exception as exc:
                logger.warning("[FOCUS] emergency tier check failed: %s", exc)

        pnl_pct = ((price / self.position.entry_price) - 1) * 100
        if self.position.direction == "SHORT":
            pnl_pct = -pnl_pct

        return {
            "state": "POSITIONED",
            "market": self.position.market,
            "direction": self.position.direction,
            "entry": self.position.entry_price,
            "current": price,
            "pnl_pct": round(pnl_pct, 2),
            "tp1": self.position.tp1,
            "sl": self.position.sl,
        }

    def _handle_trailing(self, now: float, btc_price: float) -> Dict:
        """LEGACY -- not called directly from tick(). Replaced by _manage_all_positions."""
        if not self.position:
            self.state = FocusState.DORMANT
            self._save_config()
            return {"state": "POSITIONED", "error": "no_position"}

        price = self._get_current_price(self.position.market)
        if not price or price <= 0:
            return {"state": "POSITIONED", "price": "unavailable"}

        # Update trailing watermark
        if self.position.direction == "LONG":
            if price > self.position.trailing_high:
                self.position.trailing_high = price
        else:
            if self.position.trailing_low <= 0 or price < self.position.trailing_low:
                self.position.trailing_low = price

        from app.strategy.greenpen.cycle_tp import CycleTargets, should_full_exit

        targets = CycleTargets(
            tp1=self.position.tp1, tp2=self.position.tp2,
            sl=self.position.sl, rr_ratio=0,
            atr_used=self.position.atr_used, direction=self.position.direction,
        )

        exit_reason = should_full_exit(
            price, self.position.entry_price, self.position.direction, targets,
            trailing_high=self.position.trailing_high,
            trailing_low=self.position.trailing_low,
            trailing_pct=self.config.trailing_pct,
        )
        if exit_reason:
            return self._execute_exit(exit_reason, is_sl="SL hit" in exit_reason)

        return {"state": "POSITIONED", "market": self.position.market, "price": price}

    def _handle_cooldown(self, now: float) -> Dict:
        # -- flip opportunity: a LONG-exit condition = a SHORT chance (and vice versa) --
        # on a BB+MACD-based exit, a direction-flip chance -> shorten the cooldown to 30 sec
        if self._pending_flip:
            flip_cooldown = 30.0  # only 30 sec, to not miss the chance
            elapsed = now - self.cooldown_start_ts
            if elapsed >= flip_cooldown:
                flip_dir = self._pending_flip
                self._pending_flip = ""
                # v2: if the flip is the same direction, run the re-entry-block check
                price = self._get_current_price(self._last_exit_market or self.config.lock_market or "BTCUSDT") or 0
                if flip_dir == self._last_exit_direction and price > 0:
                    if not self._check_reentry_allowed(flip_dir, self._last_exit_market, price):
                        logger.info("[FOCUS] Flip %s blocked by reentry filter → DORMANT", flip_dir)
                        self.state = FocusState.DORMANT
                        self._save_config()
                        return {"state": "DORMANT", "flip_blocked": flip_dir}
                self.selected_direction = flip_dir
                self.state = FocusState.HUNT
                self.last_scan_ts = 0  # re-scan immediately
                self._save_config()
                logger.info("[FOCUS] FLIP COOLDOWN → HUNT (direction=%s)", flip_dir)
                return {"state": "HUNT", "flip": flip_dir}
            return {"state": "COOLDOWN", "remaining_sec": round(flip_cooldown - elapsed), "pending_flip": self._pending_flip}

        # -- normal Adaptive Cooldown: increase cooldown on a losing streak --
        base_cooldown = self.config.cooldown_sec
        if self.config.adaptive_cooldown and self.daily_sl_count >= 2:
            cd_mult = min(2.5, 1.0 + (self.daily_sl_count - 2) * 0.5)
            base_cooldown *= cd_mult

        elapsed = now - self.cooldown_start_ts
        remaining = max(0, base_cooldown - elapsed)
        if remaining <= 0:
            self._pending_flip = ""
            self.state = FocusState.DORMANT
            self._save_config()
            logger.info("[FOCUS] COOLDOWN → DORMANT")
            return {"state": "DORMANT"}
        return {"state": "COOLDOWN", "remaining_sec": round(remaining)}

    # ── Execution ───────────────────────────────────────────

    def _get_effective_budget(self, market: str) -> float:
        """Budget=0 uses the existing system budget-allocation logic; >0 is a fixed budget.
        Guarantees a minimum of $5 in any case."""
        MIN_BUDGET = 5.0
        if self.config.budget_usdt > 0:
            return max(MIN_BUDGET, self.config.budget_usdt)

        # Budget=0: get an allocation from the existing slot-budget system
        try:
            system = self.system
            if system:
                # 1) use budget_usdt if it's already allocated in OMA
                oma_budget = None
                try:
                    oma_budget = system.oma_registry.get_budget_usdt(market)
                except Exception as exc:
                    logger.debug("[FOCUS] oma_budget failed: %s", exc)
                if oma_budget and float(oma_budget) > 0:
                    return max(MIN_BUDGET, float(oma_budget))

                # 2) split evenly by equity / active slot count
                equity = float(getattr(system, '_last_equity_usdt', 0) or 0)
                # ★ subtract Nunnaya-deployed capital (prevent double-spend)
                try:
                    from app.core.cross_strategy_guard import get_total_deployed_usdt
                    _, _nunnaya_deployed = get_total_deployed_usdt(system)
                    if _nunnaya_deployed > 0:
                        equity = max(0.0, equity - _nunnaya_deployed)
                except Exception as exc:
                    logger.debug("[FOCUS] import get_total_deployed_usdt failed: %s", exc)
                deploy_ratio = float(getattr(system, 'deploy_ratio', 0.5) or 0.5)
                active_count = max(1, len(system.oma_registry.list_active()) + 1)
                auto_budget = (equity * deploy_ratio) / active_count
                if auto_budget > 0:
                    auto_budget = max(MIN_BUDGET, auto_budget)
                    logger.info("[FOCUS] Budget=0 → auto budget: $%.2f (equity=%.0f × %.0f%% / %d slots)",
                                auto_budget, equity, deploy_ratio * 100, active_count)
                    return auto_budget
        except Exception as exc:
            logger.warning("[FOCUS] auto budget calc failed: %s", exc)

        # final fallback -- guarantee minimum $5 (Q.min_order)
        return max(MIN_BUDGET, 10.0)

    def _check_portfolio_sl_rate_pause(self) -> tuple:
        """#2A -- block new entries if M+ SL hits within recent N min (simultaneous-SL defense).

        4-26 this agent's review: addresses the SL scenario accompanying a BTC sharp move at full 6-slot load.
        No conflict with the owner's endurance spirit -- "even if hit once, defend the next additional loss".
        Returns: (paused: bool, reason: str)
        """
        if not getattr(self.config, "portfolio_sl_rate_enabled", True):
            return False, ""
        now = time.time()
        # if pause is active, keep it
        until = getattr(self, "_portfolio_sl_pause_until", 0.0)
        if until > now:
            return True, f"portfolio_sl_pause: {(until - now)/60:.1f}min remaining"
        # count recent SL hits
        window_min = float(getattr(self.config, "portfolio_sl_rate_window_min", 5))
        threshold = int(getattr(self.config, "portfolio_sl_rate_threshold", 3))
        cutoff = now - window_min * 60
        sl_ts_list = getattr(self, "_recent_sl_ts", []) or []
        recent = [t for t in sl_ts_list if t >= cutoff]
        self._recent_sl_ts = recent  # clean up outside the window
        if len(recent) >= threshold:
            pause_min = float(getattr(self.config, "portfolio_sl_rate_pause_min", 15))
            self._portfolio_sl_pause_until = now + pause_min * 60.0
            logger.warning("[FOCUS] ★ PORTFOLIO SL PAUSE: %d SL hits in %.0fmin -> pause %.0fmin (simultaneous-SL defense)",
                           len(recent), window_min, pause_min)
            return True, f"portfolio_sl_pause: {len(recent)} SL/{window_min:.0f}min"
        return False, ""

    def _record_sl_hit(self, market: str = ""):
        """#2A record an SL hit -- called on _close_position / SERVER_SL EXIT."""
        if not hasattr(self, "_recent_sl_ts"):
            self._recent_sl_ts = []
        self._recent_sl_ts.append(time.time())
        # clean up entries older than 30 min
        cutoff = time.time() - 1800
        self._recent_sl_ts = [t for t in self._recent_sl_ts if t >= cutoff]

    def _check_regime_reversal_pause(self) -> tuple:
        """#7 -- BTC EMA gap convergence + ADX weakening together = inflection -> pause new entries.

        Owner memory: "the inflection = the most expensive-tuition zone; waiting is the most expensive investment"
        Returns: (paused: bool, reason: str)
        """
        if not getattr(self.config, "regime_reversal_pause_enabled", True):
            return False, ""
        now = time.time()
        # if an existing pause is active, keep it
        until = getattr(self, "_regime_pause_until", 0.0)
        if until > now:
            return True, f"regime_reversal_pause: {(until - now)/60:.1f}min remaining"
        # check the trigger conditions
        gap_th = float(getattr(self.config, "regime_reversal_ema_gap_threshold_pct", 0.3))
        adx_th = float(getattr(self.config, "regime_reversal_adx_threshold", 20.0))
        btc_gap = getattr(self, "_btc_ema_gap_pct", None)
        btc_adx = getattr(self, "_btc_adx_value", 0)  # ★ BTC-only (2026-06-04 bug fix: _last_adx_value referenced an arbitrary coin's ADX)
        if btc_gap is None or btc_adx <= 0:
            return False, ""
        if btc_gap < gap_th and btc_adx < adx_th:
            pause_min = float(getattr(self.config, "regime_reversal_pause_min", 15.0))
            self._regime_pause_until = now + pause_min * 60.0
            logger.info("[FOCUS] ★ REGIME REVERSAL PAUSE: gap=%.3f%% adx=%.1f -> pause %.0fmin (avoid inflection tuition)",
                        btc_gap, btc_adx, pause_min)
            return True, f"regime_reversal_pause: gap={btc_gap:.3f}% adx={btc_adx:.1f}"
        return False, ""

    def _btc_trend_conv_bonus(self, direction: str) -> int:
        """#4 -- on BTC UPTREND LONG +N / on DOWNTREND SHORT +N conviction bonus."""
        if not getattr(self.config, "btc_trend_conv_bonus_enabled", True):
            return 0
        bonus = int(getattr(self.config, "btc_trend_conv_bonus", 2))
        regime = getattr(self, "_b11_regime_state", ("", 0.0))
        regime_label = (regime[0] if regime and len(regime) > 0 else "").upper()
        d = (direction or "").upper()
        if regime_label in ("BULL", "UPTREND") and d == "LONG":
            return bonus
        if regime_label in ("BEAR", "DOWNTREND") and d == "SHORT":
            return bonus
        return 0

    def _conv_sizing_multiplier(self, conviction: float) -> float:
        """[2026-05-17 100-pt ×10] conviction-weighted budget multiplier.
        low<=50: 0.5x / mid: 1.0x / high>=80: 1.5x (old 5/9 -> 50/80)"""
        if not getattr(self.config, "conv_sizing_enabled", True):
            return 1.0
        low = float(getattr(self.config, "conv_sizing_low_threshold", 50.0))    # [100-pt ×10] 5->50
        high = float(getattr(self.config, "conv_sizing_high_threshold", 90.0))  # [100-pt ×10] 9->90
        if conviction <= low:
            return 0.5
        if conviction >= high:
            return 1.5
        return 1.0

    def _conv_risk_factor(self, conviction: float) -> float:
        """[entry score = conviction, 2026-06-13 owner] guard score -> risk multiplier. entry threshold (guard_score_threshold) anchor + inverted-U.
        threshold=1.0x (conviction baseline) -> linear rise to peak_conv (peak_mult) -> topping (>=chop_conv)=chop_mult cut.
        budget×conv gets eaten by the cap -> multiply into risk_pct to hit qty directly. default OFF -> 1.0."""
        if not getattr(self.config, "conv_risk_scale_enabled", False):
            return 1.0
        try:
            thr = float(getattr(self.config, "guard_score_threshold", 50.0))   # ★ dynamic anchor (not nailed to 50)
            peak_c = float(getattr(self.config, "conv_risk_peak_conv", 65.0))
            peak_m = float(getattr(self.config, "conv_risk_peak_mult", 1.5))
            chop_c = float(getattr(self.config, "conv_risk_chop_conv", 80.0))
            chop_m = float(getattr(self.config, "conv_risk_chop_mult", 0.6))
            floor_m = float(getattr(self.config, "conv_risk_floor_mult", 0.5))
            max_m = float(getattr(self.config, "conv_risk_max_mult", 2.0))
            c = float(conviction)
            if c < thr:
                f = floor_m                       # below threshold (anomalous) -- safely small
            elif c >= chop_c:
                f = chop_m                        # topping cut (80+ = lagging)
            elif c >= peak_c:
                f = peak_m                        # sweet-spot peak (65~80)
            else:
                span = max(1e-9, peak_c - thr)    # threshold(1.0) -> peak_conv(peak_m) linear
                f = 1.0 + (c - thr) / span * (peak_m - 1.0)
            return max(0.1, min(max_m, f))
        except Exception:
            return 1.0

    def _multi_be_lock_target(self, peak_pct: float, pos: Optional["FocusPosition"] = None) -> float:
        """#6 -- multi-stage BE Lock. Tighten the lock per peak stage.

        [2026-05-21 owner] added ATR-adaptive mode.
          ON mode (default): stage trigger = ATR% × stage_atr_mult
            - high-volatility coins must move farther to BE -- prevents early cut
            - e.g. BTC ATR ~1% -> stage1=0.3, HYPE ATR ~3% -> stage1=0.9
            - lock values scale too (stage2 lock = stage1 trigger, stage3 lock = stage2 trigger, etc.)
          OFF mode: the old fixed % (stage1=0.4, stage2=1.0, stage3=2.0, stage4=3.0)

        [2026-05-16 owner] if stage1 is 0.0 (price-BE), the 0.11% fee is still a loss.
        SUI case: peak +0.64% -> SL=entry -> fee cut -$0.78. fee_cushion makes it a true BE.
        """
        cfg = self.config
        if not getattr(cfg, "multi_be_lock_enabled", True):
            return 0.0

        fee_cushion = float(getattr(cfg, "multi_be_lock_fee_cushion_pct", 0.15))
        adaptive = getattr(cfg, "multi_be_lock_atr_adaptive_enabled", True)
        atr_pct = 0.0

        if adaptive and pos is not None:
            try:
                market = getattr(pos, "market", "") or ""
                if market:
                    tf = str(getattr(cfg, "multi_be_lock_atr_tf", "60") or "60")
                    period = int(getattr(cfg, "multi_be_lock_atr_period", 14))
                    raw = self._get_mtf_kline(market, tf, limit=period + 5)
                    if raw and len(raw) >= period + 2:
                        ordered = list(raw)
                        trs = []
                        for i in range(1, len(ordered)):
                            h = float(ordered[i][2])
                            l = float(ordered[i][3])
                            pc = float(ordered[i - 1][4])
                            tr = max(h - l, abs(h - pc), abs(l - pc))
                            trs.append(tr)
                        if len(trs) >= period:
                            atr = sum(trs[-period:]) / period
                            last_close = float(ordered[-1][4])
                            if last_close > 0 and atr > 0:
                                atr_pct = atr / last_close * 100.0
            except Exception as exc:
                logger.debug("[FOCUS] multi_be_lock ATR computation failed (fixed-mode fallback): %s", exc)

        if adaptive and atr_pct > 0:
            # ATR-adaptive mode -- trigger = ATR% × mult, lock = proportional to the prior stage trigger
            s1 = atr_pct * float(getattr(cfg, "multi_be_lock_stage1_atr_mult", 0.3))
            s2 = atr_pct * float(getattr(cfg, "multi_be_lock_stage2_atr_mult", 0.7))
            s3 = atr_pct * float(getattr(cfg, "multi_be_lock_stage3_atr_mult", 1.4))
            s4 = atr_pct * float(getattr(cfg, "multi_be_lock_stage4_atr_mult", 2.2))
            # [2026-05-29 owner 5th->6th fix] stage1 trigger floor -- protect low-volatility coins from noise cuts
            # HYPE peak 0.094% incident: small ATR made the trigger ~0.05% -> BE lock fired right after entry -> noise cut
            min_s1 = float(getattr(cfg, "multi_be_lock_atr_min_stage1_trigger_pct", 0.3))
            if s1 < min_s1:
                s1 = min_s1
            # ★ [2026-06-13 owner] stage1 trigger cap -- even extreme-ATR coins BE-lock at +N% (block defenseless give-back)
            max_s1 = float(getattr(cfg, "multi_be_lock_atr_max_stage1_trigger_pct", 3.0))
            if max_s1 > 0 and s1 > max_s1:
                s1 = max_s1
            lock_s4 = s3   # at peak >= s4, SL=entry+s3
            lock_s3 = s2
            lock_s2 = s1
        else:
            # fixed-% mode (existing)
            s1 = float(getattr(cfg, "multi_be_lock_stage1_pct", 0.4))
            s2 = float(getattr(cfg, "multi_be_lock_stage2_pct", 1.0))
            s3 = float(getattr(cfg, "multi_be_lock_stage3_pct", 2.0))
            s4 = float(getattr(cfg, "multi_be_lock_stage4_pct", 3.0))
            lock_s4 = 2.0
            lock_s3 = 1.0
            lock_s2 = 0.3

        if peak_pct >= s4: return lock_s4
        if peak_pct >= s3: return lock_s3
        if peak_pct >= s2: return lock_s2
        if peak_pct >= s1: return max(0.0, fee_cushion)
        return -999.0  # BE not yet reached

    def _effective_coin_loss_cap(self) -> float:
        """Equity-scaled coin loss cap (4-26 owner decision -- auto-adapts to $1000/$2000/$5000).

        Basis: coin_loss_cap_amount is the absolute value at equity $1000.
        actual cap = amount × (equity / 1000). As equity grows, the cap scales up.
        """
        base_amount = float(getattr(self.config, "coin_loss_cap_amount", 200.0))
        try:
            equity = float(getattr(self.system, '_last_equity_usdt', 0) or 0)
            if equity > 0:
                return base_amount * (equity / 1000.0)
        except Exception:
            pass
        return base_amount

    def _get_available_margin(self) -> float:
        """Query the actual available margin of the Bybit Unified Account.

        [2026-05-25 owner] in paper/dry mode return the virtual balance (bypass the real Bybit API).
        Separate from the _get_client() wrapper, this calls requests directly, so it needs the paper branch too.
        """
        _live = self._live_active()  # ★ [2026-06-23 audit] reflect _force_paper (block subclass paper leak)
        if not _live:
            return float(os.getenv("DRY_INITIAL_USDT", "1000") or "1000")
        try:
            # ★ [2026-06-23] exchange abstraction -- via client.get_available_margin() (live=real client).
            return float(self._get_client().get_available_margin() or 0.0)
        except Exception as exc:
            logger.debug("[FOCUS] available margin check failed: %s", exc)
            return 0.0

    def _execute_entry(self, entry: Dict) -> Dict:
        """Place market order to enter position."""
        market = entry.get("market") or self.selected_market
        if not market:
            logger.error("[FOCUS] _execute_entry: no market specified!")
            return {"state": "DORMANT", "error": "no_market"}

        # [2026-04-18] extract direction early -- needed before the coin_loss_cap check
        #   BUG FIX: after Phase 2-2 (direction-split coin_loss_cap),
        #            direction was used before it was extracted, causing UnboundLocalError
        #            the real cause of the 5-hour-long RAVE entry failure
        direction = entry.get("direction")
        if not direction or direction not in ("LONG", "SHORT"):
            logger.error("[FOCUS] _execute_entry: no valid direction (%s) — rejected", direction)
            return {"state": "HUNT", "error": "no_direction"}

        # ★ [2026-05-16 owner] 5m Microtiming Gate -- WAIT/DEFER not BLOCK
        # Check a conviction-passing candidate via 3 5m RSI/MACD/BB inflections. Defer if score is short.
        # The caller (scanner), if state != POSITIONED, naturally proceeds to the next candidate -- no BLOCK count accrued.
        # Phase K (regime transition) entries are exempt by option (prioritize catching market transitions).
        # ★ [2026-05-16] when _manual=True (manual entry), bypass the microtiming gate.
        _is_manual = bool(entry.get("_manual"))
        if _is_manual:
            logger.warning("[FOCUS] ★ MANUAL ENTRY — bypass microtiming/EE/MTF gates: %s %s", market, direction)
        # -- [2026-05-16 owner vision #4] Coin State Machine -- classify state at entry + stamp the entry dict --
        if not _is_manual and getattr(self.config, "coin_state_machine_enabled", True):
            try:
                _cs_label, _cs_adj = self._classify_coin_state(market, direction)
                if _cs_label:
                    entry["_coin_state"] = _cs_label
                    entry["_coin_state_conv_adj"] = _cs_adj
                    logger.info("[FOCUS] 🎭 coin_state %s = %s (conv_adj=%+d)", market, _cs_label, _cs_adj)
                    # apply conviction adjustment (default OFF -- ON after verification)
                    if getattr(self.config, "coin_state_apply_conv_adjust", False) and _cs_adj != 0:
                        _orig_conv = float(entry.get("conviction_score", 0) or 0)  # [2026-05-17 100-pt]
                        _new_conv = max(0.0, _orig_conv + float(_cs_adj))
                        entry["conviction_score"] = _new_conv
                        logger.info("[FOCUS] 🎭 coin_state conv adjust: %d -> %d (state=%s, adj=%+d)",
                                    _orig_conv, _new_conv, _cs_label, _cs_adj)
            except Exception as exc:
                logger.debug("[FOCUS] coin_state classification failed: %s", exc)
        # -- [2026-05-27 owner] ★ Phase 6 score integration -- evaluate guards as conv additions/deductions --
        #   Owner's insight: "Enter by score regardless of long/short. All guards must be *properly evaluated*".
        #   When active: bypass all entry guards -> evaluate the score -> enter directly if it passes the threshold.
        #   When inactive: the old serial guard-blocking flow.
        #   Safety nets (drawdown / hard_roe_cap / btc_emergency / portfolio_sl_rate, already checked above) unchanged.
        if not _is_manual and self._guard_score_mode_active():
            _gs_total, _gs_breakdown = self._compute_guard_score_modifiers(market, direction, entry)
            _base_conv = float(entry.get("conviction_score", 0) or 0)
            _final_conv = _base_conv + _gs_total
            # ★ [patch v1] topping ceiling post-guards -- block the hole where a demoted topping revives via bonuses
            if (getattr(self.config, "conviction_ceiling_enabled", False)
                    and getattr(self.config, "conviction_ceiling_post_guards", False)):
                _pcc_start = float(getattr(self.config, "conviction_ceiling_start", 65.0))
                if _final_conv >= _pcc_start:
                    _pcc_target = float(getattr(self.config, "conviction_ceiling_target", 50.0))
                    _pcc_exempt = float(getattr(self.config, "conviction_ceiling_adx_exempt", 30.0))
                    _pcc_adx = float(getattr(self, "_conv_adx_cache", {}).get((market or "").upper(), 0.0) or 0.0)
                    if _pcc_exempt > 0 and _pcc_adx >= _pcc_exempt:
                        logger.info("[FOCUS] ②' topping exempt (wall-riding, post): %s %s conv=%.0f ADX=%.0f>=%.0f",
                                    market, direction, _final_conv, _pcc_adx, _pcc_exempt)
                    else:
                        logger.info("[FOCUS] ②' topping ceiling (post-guards): %s %s conv %.0f->%.0f (ADX=%.0f<%.0f)",
                                    market, direction, _final_conv, min(_final_conv, _pcc_target), _pcc_adx, _pcc_exempt)
                        _final_conv = min(_final_conv, _pcc_target)
            _gs_threshold = float(getattr(self.config, "guard_score_threshold", 80.0))
            logger.info("[FOCUS] 🎯 GuardScore %s %s: base=%.1f + guards=%+.1f = %.1f (threshold %.0f)",
                        market, direction, _base_conv, _gs_total, _final_conv, _gs_threshold)
            logger.info("[FOCUS]   breakdown: %s", _gs_breakdown)
            # ★ [2026-05-28] guard-score cache (for the scan-list API's separate column) -- store both pass/fail
            _disp_total = 0.0 if abs(_final_conv) < 0.05 else _final_conv  # prevent showing -0
            _bd_short = _gs_breakdown.replace(" | ", ",").replace("++", "+")
            self._last_guard_score[market.upper()] = {
                "base": _base_conv,
                "deduction": _gs_total,
                "total": _disp_total,
                "threshold": _gs_threshold,
                "breakdown": _bd_short,
            }
            # -- [2026-06-07 owner] guard-accuracy measurement log (read-only, no behavior effect) --
            #   Owner "how do I know the guards are accurate" -> append 1 line per entry eval. Both pass/fail.
            #   scripts/guard_accuracy.py joins this log + journal EXITs to compute per-guard hit rate.
            try:
                from app.manager.trade_journal import JOURNAL_PATH as _JP
                _ge_path = os.path.join(os.path.dirname(self._journal_path), "guard_eval.jsonl")
                _ge_rec = {
                    "ts": round(time.time(), 1), "market": market.upper(), "direction": direction,
                    "base": round(_base_conv, 1), "guards": round(_gs_total, 1),
                    "final": round(_final_conv, 1), "threshold": _gs_threshold,
                    "passed": bool(_final_conv >= _gs_threshold), "breakdown": _gs_breakdown,
                }
                with open(_ge_path, "a", encoding="utf-8") as _gf:
                    _gf.write(json.dumps(_ge_rec, ensure_ascii=False) + "\n")
            except Exception as _ge_exc:
                logger.debug("[FOCUS] guard_eval log failed: %s", _ge_exc)
            if _final_conv < _gs_threshold:
                try:
                    from app.manager.trade_journal import journal as _jnl
                    self._journal.record_blocked("FOCUS", market, direction,
                                        reason="guard_score_below_threshold",
                                        detail=("final=%.1f<%.0f | %s" % (_final_conv, _gs_threshold, _gs_breakdown))[:300])
                except Exception as exc:
                    logger.debug("[FOCUS] guard_score journal failed: %s", exc)
                # status text = breakdown only (the score formula is shown in the separate column)
                return {"state": "HUNT", "error": _bd_short}
            # -- [2026-05-28 owner] final pre-entry guard -- "this alone is enough" --
            #   ★ [2026-05-28 evening owner "the single one" rule] D1-alignment mandatory check (first)
            #   "as long as it doesn't go against the Day candle, somehow profit. Resolves within 72h."
            #   D1=DOWN vs LONG / D1=UP vs SHORT = block entry.
            _fd1_blocked, _fd1_reason = self._final_d1_alignment_check(market, direction)
            if _fd1_blocked:
                # ★ [2026-06-09 owner] D1 score absorption -- the D1 gate is a legacy of the old long-stuck (72h) premise.
                #   Now long-stuck is prevented by 🐢/BE/reverse_drift/fast-rotation -> the rationale faded (data: D1 block = 59% opportunity loss).
                #   If conviction is high enough, pass D1 counter (strong signal only, backed by exit guards). regime_opposed (macro) is absorption-excluded.
                _fd1_byp = float(getattr(self.config, "final_d1_bypass_conviction", 0.0) or 0.0)
                _fd1_regime = "regime_opposed" in (_fd1_reason or "")
                _fd1_cmp = _base_conv if getattr(self.config, "final_bypass_use_base", False) else _final_conv  # ★ [patch v1]
                if _fd1_byp > 0 and _fd1_cmp >= _fd1_byp and not _fd1_regime:
                    logger.info("[FOCUS] 🎯 final_d1 score-absorption BYPASS (conv %.0f>=%.0f): %s %s -- %s -> allow entry (D1 faded, backed by exit guards)",
                                _fd1_cmp, _fd1_byp, market, direction, _fd1_reason)
                else:
                    logger.warning("[FOCUS] 🎯 GuardScore PASS but D1 ALIGNMENT BLOCK: %s %s — %s",
                                   market, direction, _fd1_reason)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        self._journal.record_blocked("FOCUS", market, direction, reason="final_d1_alignment", detail=_fd1_reason)
                    except Exception:
                        pass
                    self._record_near_miss(market, direction, _final_conv, "final_d1: " + _fd1_reason)
                    return {"state": "HUNT", "error": "PASS but D1(%s)" % _fd1_reason}
            #   (1) re-confirm 30M+15M direction (2) 5M RSI/MACD/BB concord
            _f30_blocked, _f30_reason = self._final_30m15m_check(market, direction)
            if _f30_blocked:
                # ★ [2026-06-09 owner] score absorption -- pass if conviction is high enough (resolves the 30M/15M-counter double punishment).
                #   regime_opposed (macro counter = falling knife) is absorption-excluded = real risk. Absorb only simple upper-TF lag.
                _f30_byp = float(getattr(self.config, "final_30m15m_bypass_conviction", 0.0) or 0.0)
                _f30_regime = "regime_opposed" in (_f30_reason or "")
                #   ★ [2026-06-09 owner] macro-counter-include toggle -- if True, macro counter also bypasses via score.
                _f30_inc_regime = bool(getattr(self.config, "final_30m15m_bypass_include_regime", False))
                _f30_cmp = _base_conv if getattr(self.config, "final_bypass_use_base", False) else _final_conv  # ★ [patch v1]
                if _f30_byp > 0 and _f30_cmp >= _f30_byp and (not _f30_regime or _f30_inc_regime):
                    logger.info("[FOCUS] 🎯 final_30m15m score-absorption BYPASS (conv %.0f>=%.0f): %s %s -- %s -> allow entry",
                                _f30_cmp, _f30_byp, market, direction, _f30_reason)
                else:
                    logger.info("[FOCUS] 🎯 GuardScore PASS but FINAL 30M+15M BLOCK: %s %s — %s",
                                market, direction, _f30_reason)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        self._journal.record_blocked("FOCUS", market, direction, reason="final_30m15m", detail=_f30_reason)
                    except Exception:
                        pass
                    self._record_near_miss(market, direction, _final_conv, "final_30m15m: " + _f30_reason)
                    return {"state": "HUNT", "error": "PASS but final_30m15m(%s)" % _f30_reason}
            _f5_blocked, _f5_reason = self._final_5m_simple_check(market, direction)
            if _f5_blocked:
                logger.info("[FOCUS] 🎯 GuardScore PASS but FINAL 5M BLOCK: %s %s — %s",
                            market, direction, _f5_reason)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    self._journal.record_blocked("FOCUS", market, direction, reason="final_5m_simple", detail=_f5_reason)
                except Exception:
                    pass
                self._record_near_miss(market, direction, _final_conv, "final_5m: " + _f5_reason)
                return {"state": "HUNT", "error": "PASS but final_5m(%s)" % _f5_reason}
            # -- [2026-06-06 owner] Peer Brief = hard block ❌ -> soft reference ⭕ --
            #   Owner's correction: "the neighbor is a reference to think once more before entering on your own logic."
            #   - neighbor holding = not a block reason (two servers may hold the same spot OK)
            #   - neighbor's recent SL on the same coin+direction = guard_score soft penalty (PeerSL, in the _compute stage)
            #   - even on SL, if core indicators bounce, the score passes the penalty and enters -> naturally handles the "bounce bonus"
            #   The hard block (return) is abandoned. peer signals are reflected only in the score (PeerWin/PeerSL).
            # passed -- mark to bypass all guards (each guard checks _guard_score_pass and skips)
            entry["_guard_score_pass"] = True
            entry["_guard_score"] = _final_conv
            entry["_guard_breakdown"] = _gs_breakdown
            logger.info("[FOCUS] 🎯 GuardScore PASS %s %s -- score %.1f >= %.0f | %s | %s",
                        market, direction, _final_conv, _gs_threshold,
                        _f30_reason or "30M15M_ok", _f5_reason or "5M_ok")
        # -- [2026-05-16 owner] Same-coin Flip Cooldown -- block the TAO both-ways case --
        if not _is_manual and not entry.get("_guard_score_pass"):
            _flip_blocked, _flip_reason = self._check_same_coin_flip_cooldown(market, direction)
            if _flip_blocked:
                logger.info("[FOCUS] %s — %s %s", _flip_reason, market, direction)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    self._journal.record_blocked("FOCUS", market, direction, reason="same_coin_flip_cooldown", detail=_flip_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] same_coin_flip_cooldown journal failed: %s", exc)
                return {"state": "HUNT", "error": "same_coin_flip_cooldown"}
        # -- [2026-05-16 owner insight] 5m Raw Body Guard -- block SHORT at a BILL buy-energy spot --
        if not _is_manual and not entry.get("_guard_score_pass"):
            _raw_blocked, _raw_reason = self._check_raw_body_guard(market, direction)
            if _raw_blocked:
                logger.info("[FOCUS] %s — %s %s", _raw_reason, market, direction)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    self._journal.record_blocked("FOCUS", market, direction, reason="raw_body_guard", detail=_raw_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] raw_body_guard journal failed: %s", exc)
                return {"state": "HUNT", "error": "raw_body_guard"}
        # -- [2026-05-26 owner] Frame Guard -- enforce the textbook "Frame (S/R)" (range position) --
        #   Block bottom-catching/top-catching like BTC SHORT @ $76,616 (near the 24h low).
        # -- [2026-05-27 owner] Frame Guard cooldown -- silent-skip repeated tries at the same spot after a block --
        #   Removes the RENDER SHORT 13:16~13:20 12-repeat-block pattern. Skips the frame_guard computation during cooldown too.
        if not _is_manual and not entry.get("_guard_score_pass"):
            _fg_cd_enabled = bool(getattr(self.config, "frame_guard_cooldown_enabled", True))
            _fg_key = (market.upper(), direction)
            if _fg_cd_enabled:
                _cd_until = self._frame_guard_cooldown.get(_fg_key, 0.0)
                _now_ts = time.time()
                if _cd_until > _now_ts:
                    _remain = int(_cd_until - _now_ts)
                    logger.debug("[FOCUS] frame_guard_cooldown active: %s %s remain=%ds (silent)", market, direction, _remain)
                    return {"state": "HUNT", "error": "frame_guard_cooldown(%ds)" % _remain}
            _fg_blocked, _fg_reason = self._check_frame_guard(market, direction)
            if _fg_blocked:
                logger.info("[FOCUS] %s — %s %s", _fg_reason, market, direction)
                # update cooldown -- avoid repeated blocking at the same spot
                if _fg_cd_enabled:
                    _cd_sec = float(getattr(self.config, "frame_guard_cooldown_sec", 90.0))
                    self._frame_guard_cooldown[_fg_key] = time.time() + _cd_sec
                try:
                    from app.manager.trade_journal import journal as _jnl
                    self._journal.record_blocked("FOCUS", market, direction, reason="frame_guard", detail=_fg_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] frame_guard journal failed: %s", exc)
                return {"state": "HUNT", "error": "frame_guard"}
            # clear cooldown on pass (releases immediately if price moved to a good spot)
            elif _fg_cd_enabled and _fg_key in self._frame_guard_cooldown:
                del self._frame_guard_cooldown[_fg_key]
        # -- [2026-05-27 owner] Day Box Guard -- when the 9 o'clock box ping-pongs, block entry inside the box --
        #   The owner's gut "1~4h ping-pong after D1 start = all-day upper/lower bound" + the textbook กรอบวัน.
        #   per-market box tracking; when locked, SHORT near top / LONG near bottom / block both inside the box.
        if not _is_manual and not entry.get("_guard_score_pass") and self._day_box_guard_active():
            _box_price = 0.0
            try:
                _box_price = float(entry.get("price", 0) or 0)
            except Exception:
                _box_price = 0.0
            if _box_price <= 0:
                try:
                    _box_price = float(self._get_client()._linear_last_price(market) or 0)
                except Exception:
                    _box_price = 0.0
            if _box_price > 0:
                self._update_day_box(market, _box_price)
                _box_blocked, _box_reason = self._check_day_box_guard(market, direction, _box_price)
                if _box_blocked:
                    logger.info("[FOCUS] %s — %s %s", _box_reason, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        self._journal.record_blocked("FOCUS", market, direction, reason="day_box", detail=_box_reason)
                    except Exception as exc:
                        logger.debug("[FOCUS] day_box journal failed: %s", exc)
                    return {"state": "HUNT", "error": "day_box"}
        # -- [2026-05-26 owner] H4 Close Pulse Only -- enter only in the window right after H4 close --
        # -- [2026-05-27 owner] H1 PA Pulse OR -- additionally allow entry on H1 PA recognition --
        #   Enforces the textbook "enter right after H4 PA" timing + the orthodox "SIG counts as a round only on H1+".
        #   H4 pulse OR H1 PA pulse = OK if either passes. The H1 PA is a PA trigger (not a time window).
        if not _is_manual and not entry.get("_guard_score_pass") and self._h4_pulse_only_active():
            _pulse_ok, _pulse_reason = self._in_h4_pulse_window()
            if _pulse_ok:
                # H4 pulse passed -- mark which pulse it entered via + H1 overlap info
                entry["_pulse_via"] = "h4"
                _h1_also = ""
                if self._h1_pa_pulse_active():
                    _h1_ok2, _h1_info2 = self._h1_pa_detected(market, direction)
                    if _h1_ok2:
                        _h1_also = " (+ h1_pa overlap)"
                logger.info("[FOCUS] ⏰ Pulse OK %s %s via h4 %s%s",
                            market, direction, _pulse_reason, _h1_also)
            else:
                # H1 PA pulse OR -- bypass the H4 block on H1 PA recognition + day_direction alignment
                _h1_ok, _h1_info = (False, "")
                if self._h1_pa_pulse_active():
                    _h1_ok, _h1_info = self._h1_pa_detected(market, direction)
                if _h1_ok:
                    entry["_pulse_via"] = "h1_pa"
                    logger.info("[FOCUS] ⏰ Pulse OK %s %s via h1_pa -- bypass H4 block (%s)",
                                market, direction, _h1_info)
                    # passed -- on to the next guard
                else:
                    _block_detail = _pulse_reason
                    if _h1_info:
                        _block_detail += " | " + _h1_info
                    logger.info("[FOCUS] %s -- %s %s blocked", _block_detail, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        self._journal.record_blocked("FOCUS", market, direction, reason="h4_pulse_only", detail=_block_detail)
                    except Exception as exc:
                        logger.debug("[FOCUS] h4_pulse journal failed: %s", exc)
                    return {"state": "HUNT", "error": "h4_pulse_only"}
        # -- [2026-05-27 owner] PA Completion Guard -- verify Sig + ไส้หลัง closed (H4 OR H1) --
        #   In the spirit of textbook XAUUSD 88 / GreenPen "no entry on any candle outside Pat 1/2/3".
        #   Owner's correction (2026-05-27): "whether H4 or H1, any of the table candles counts as a valid entry".
        #   -> pass if PA Pat 1/2/3 is complete on *either* TF (H4 OR H1).
        #   -> block only if both fail.
        #   Bot defect (today 18:35 BTC SHORT): entered the instant it saw Sig -> didn't wait for ไส้หลัง -> loss.
        if not _is_manual and not entry.get("_guard_score_pass") and self._pa_completion_active():
            # check H4 first
            _h4_pa_ok, _h4_pa_reason = self._check_pa_completion(market, direction, "240")
            _h1_pa_ok, _h1_pa_reason = (False, "")
            # if H4 fails, try H1 too (OR)
            if not _h4_pa_ok:
                _h1_pa_ok, _h1_pa_reason = self._check_pa_completion(market, direction, "60")
            if _h4_pa_ok:
                entry["_pa_via"] = "h4"
                logger.info("[FOCUS] 🐟 PA OK %s %s via H4 — %s", market, direction, _h4_pa_reason)
            elif _h1_pa_ok:
                entry["_pa_via"] = "h1"
                logger.info("[FOCUS] 🐟 PA OK %s %s via H1 (H4 failed: %s) -- %s",
                            market, direction, _h4_pa_reason, _h1_pa_reason)
            else:
                _pa_block_detail = "H4: %s | H1: %s" % (_h4_pa_reason, _h1_pa_reason)
                logger.info("[FOCUS] 🐟 PA incomplete (both H4+H1 fail) -- %s %s | %s",
                            market, direction, _pa_block_detail)
                try:
                    from app.manager.trade_journal import journal as _jnl
                    self._journal.record_blocked("FOCUS", market, direction,
                                        reason="pa_completion", detail=_pa_block_detail[:300])
                except Exception as exc:
                    logger.debug("[FOCUS] pa_completion journal failed: %s", exc)
                return {"state": "HUNT", "error": "pa_completion"}
        # -- [2026-05-16 owner vision] Momentum Derivative Guard -- RSI/MACD change-rate guard --
        if not _is_manual and not entry.get("_guard_score_pass"):
            _md_blocked, _md_reason = self._check_momentum_derivative_guard(market, direction)
            if _md_blocked:
                # ★ CFID bypass -- an imminent-inflection spot takes priority over momentum_deriv's "opposite to current flow"
                _cfid_bypass = False
                if getattr(self.config, "cfid_bypass_momentum_deriv", True):
                    _cfid_dir, _cfid_str = self._detect_coin_flip_imminent(market)
                    if ((direction.upper() == "LONG" and _cfid_dir == "BULL_IMMINENT") or
                        (direction.upper() == "SHORT" and _cfid_dir == "BEAR_IMMINENT")):
                        _cfid_bypass = True
                        logger.info("[FOCUS] 🚀 CFID %s (strength=%.1f) -> bypass momentum_deriv %s %s",
                                    _cfid_dir, _cfid_str, market, direction)
                if not _cfid_bypass:
                    logger.info("[FOCUS] %s — %s %s", _md_reason, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        self._journal.record_blocked("FOCUS", market, direction, reason="momentum_deriv_guard", detail=_md_reason)
                    except Exception as exc:
                        logger.debug("[FOCUS] momentum_deriv_guard journal failed: %s", exc)
                    return {"state": "HUNT", "error": "momentum_deriv_guard"}
        # -- [2026-05-16 owner vision #2] MTF Momentum Alignment -- cross-TF flow consistency --
        if not _is_manual and not entry.get("_guard_score_pass"):
            _mtf_blocked, _mtf_reason = self._check_mtf_momentum_alignment(market, direction)
            if _mtf_blocked:
                # ★ CFID bypass -- an imminent-inflection spot takes priority over the mtf_align BLOCK
                _cfid_bypass2 = False
                if getattr(self.config, "cfid_bypass_mtf_align", True):
                    _cfid_dir2, _cfid_str2 = self._detect_coin_flip_imminent(market)
                    if ((direction.upper() == "LONG" and _cfid_dir2 == "BULL_IMMINENT") or
                        (direction.upper() == "SHORT" and _cfid_dir2 == "BEAR_IMMINENT")):
                        _cfid_bypass2 = True
                        logger.info("[FOCUS] 🚀 CFID %s (strength=%.1f) -> bypass mtf_align %s %s",
                                    _cfid_dir2, _cfid_str2, market, direction)
                if not _cfid_bypass2:
                    logger.info("[FOCUS] %s — %s %s", _mtf_reason, market, direction)
                    try:
                        from app.manager.trade_journal import journal as _jnl
                        self._journal.record_blocked("FOCUS", market, direction, reason="mtf_momentum_align", detail=_mtf_reason[:300])
                    except Exception as exc:
                        logger.debug("[FOCUS] mtf_momentum_align journal failed: %s", exc)
                    return {"state": "HUNT", "error": "mtf_momentum_align"}
        # -- [2026-05-27 owner] Anchor Proximity Fast-Track -- bypass microtiming when near the anchor --
        #   "if you found something more important than the 5m, ignoring it is the answer" -- owner 2026-05-27.
        #   An anchor-close spot right after the H4 pulse = the cycle start point = immediate entry is correct.
        #   The microtiming 5M-trigger wait (up to 30 min) only matters at spots far from the anchor (2nd retest).
        if not _is_manual and not entry.get("_guard_score_pass") and self._anchor_fasttrack_active():
            _ft_ok, _ft_prox, _ft_info = self._check_anchor_fasttrack(market, direction)
            if _ft_ok:
                entry["_bypass_microtiming"] = True
                entry["_anchor_fasttrack"] = True
                logger.info("[FOCUS] ⚡ ANCHOR FAST-TRACK %s %s: %s -> bypass microtiming", market, direction, _ft_info)
        if getattr(self.config, "microtiming_5m_enabled", False) and not _is_manual and not entry.get("_guard_score_pass"):
            _mt_phase_k_exempt = bool(getattr(self.config, "microtiming_5m_phase_k_exempt", True))
            _is_phase_k = bool(entry.get("_phase_k"))
            # ★ [2026-05-18] Leading Entry bypass -- bypass microtiming in CFID/PATTERN mode
            # ★ [2026-05-27] Anchor fast-track bypass -- _anchor_fasttrack also uses the same _bypass_microtiming marker
            _is_leading_bypass = bool(entry.get("_bypass_microtiming") and
                                     (entry.get("_leading_entry") or entry.get("_anchor_fasttrack")))
            if _is_leading_bypass:
                if entry.get("_anchor_fasttrack"):
                    logger.info("[FOCUS] microtiming_5m BYPASS: %s %s (ANCHOR_FASTTRACK)", market, direction)
                else:
                    _leading_mode = entry.get("_leading_mode", "?")
                    logger.info("[FOCUS] microtiming_5m BYPASS: %s %s (%s_LEAD)", market, direction, _leading_mode)
            elif not (_mt_phase_k_exempt and _is_phase_k):
                _now_ts = time.time()
                _defer_map = getattr(self, "_microtiming_defer", {})
                _key = (market.upper(), direction)
                _defer_state = _defer_map.get(_key)
                # 1) still within the defer time -> quietly refuse to pass
                if _defer_state and _defer_state[0] > _now_ts:
                    _remain = int(_defer_state[0] - _now_ts)
                    logger.debug("[FOCUS] microtiming_5m DEFER active: %s %s remain=%ds (defers=%d)",
                                 market, direction, _remain, _defer_state[1])
                    # ★ force state=HUNT -- if returned as POSITIONED, the caller (scanner) mistakes it for ENTERED.
                    # also add the microtiming_deferred flag -- so the scanner recognizes it explicitly.
                    return {"state": "HUNT", "error": f"microtiming_5m_defer_active({_remain}s)", "microtiming_deferred": True}
                # 2) check -- compute the score
                _mt_ok, _mt_label, _mt_score = self._check_microtiming_5m(market, direction)
                if _mt_ok:
                    # GO -- clean up the defer record
                    if _key in _defer_map:
                        del _defer_map[_key]
                    logger.info("[FOCUS] microtiming_5m PASS: %s %s %s", market, direction, _mt_label)
                else:
                    # score short -> defer (but on exceeding max, natural expiry = next entry passes immediately)
                    _max_defers = int(getattr(self.config, "microtiming_5m_max_defers", 3))
                    _defer_sec = float(getattr(self.config, "microtiming_5m_defer_sec", 600.0))
                    _prev_defers = _defer_state[1] if _defer_state else 0
                    _new_defers = _prev_defers + 1
                    if _new_defers > _max_defers:
                        # natural expiry -- delete the record, but don't pass this time; defer once more, next entry passes
                        # (safe: even on natural expiry, unmet = don't enter. Re-evaluate on the next _scan tick)
                        if _key in _defer_map:
                            del _defer_map[_key]
                        logger.info("[FOCUS] microtiming_5m EXPIRED: %s %s %s defers=%d -> natural expiry",
                                    market, direction, _mt_label, _prev_defers)
                        return {"state": "HUNT", "error": f"microtiming_5m_expired({_mt_label})", "microtiming_deferred": True}
                    _defer_map[_key] = (_now_ts + _defer_sec, _new_defers)
                    self._microtiming_defer = _defer_map
                    logger.info("[FOCUS] microtiming_5m DEFER %ds: %s %s %s defers=%d/%d",
                                int(_defer_sec), market, direction, _mt_label, _new_defers, _max_defers)
                    return {"state": "HUNT", "error": f"microtiming_5m_defer({_mt_label})", "microtiming_deferred": True}

        # ★ [2026-06-05 owner] 1M micro-check -- verify "this exact moment" timing
        # After passing 5M microtiming, a final 1M-level check (counter candle/volume exhaustion/RSI overheat)
        if not _is_manual and getattr(self.config, "micro_1m_check_enabled", True):
            try:
                _1m_ok, _1m_reason = self._check_micro_1m(market, direction)
                if not _1m_ok:
                    logger.info("[FOCUS] ⛔ 1M micro: %s %s -> %s", direction, market, _1m_reason)
                    try:
                        from app.manager.trade_journal import journal
                        self._journal.record_blocked("FOCUS", market, direction,
                                               reason="micro_1m", detail=_1m_reason)
                    except Exception:
                        pass
                    return {"state": "HUNT", "skip": f"micro_1m:{_1m_reason}"}
            except Exception as _1m_exc:
                logger.debug("[FOCUS] micro_1m failed (fail-open): %s", _1m_exc)

        # ★ [2026-04-19] REENTRY FINAL GATE -- scan/execute race defense
        # The scanner's _check_reentry_allowed is called only at candidate-filtering time.
        # If an existing position exits during the seconds~tens-of-seconds gap to execute,
        # B9 Post-Trade Pause / B8 Direction Exhaustion / coin_repeat_brake are all bypassed.
        # Example: 2026-04-19 AAVE SHORT EXIT(1776567899) -> ENTRY(1776567916) = 17-sec re-entry.
        # Fix: call _check_reentry_allowed once more right before execute. Duplicate cost is in ms.
        # ★ [2026-05-16 owner] when _manual=True, bypass the reentry guard -- don't block the owner's intentional re-entry from chart-reading.
        _exec_price = float(entry.get("entry_price") or entry.get("price") or 0.0)
        if not _is_manual and not self._check_reentry_allowed(direction, market, _exec_price):
            logger.warning(
                "[FOCUS] ★ ENTRY BLOCKED at execute (scan/execute race guard): %s %s",
                market, direction)
            return {"state": self.state.value, "error": "reentry_blocked_at_execute"}

        # ★ ANTI-GAMBLER FINAL GATE: re-check coin_loss_cap right before entry
        # Blocks the chance of bypassing _check_reentry_allowed (always run on every entry path)
        # [2026-04-18] direction-separated -- check only the cumulative loss for the entry direction
        if self.config.coin_loss_cap_enabled and market:
            _loss = self._get_coin_loss_total(market, direction)
            _cap = self._effective_coin_loss_cap()
            logger.debug("[FOCUS] Coin Loss Cap CHECK: %s %s total_loss=$%.2f cap=$%.2f enabled=%s",
                         market, direction, _loss, _cap, self.config.coin_loss_cap_enabled)
            if _loss < 0 and abs(_loss) >= _cap:
                logger.warning(
                    "[FOCUS] ★ ANTI-GAMBLER FINAL GATE: %s %s 24h loss $%.2f >= cap $%.2f — ENTRY DENIED",
                    market, direction, _loss, _cap)
                return {"state": self.state.value, "error": f"coin_loss_cap_final_{market}"}

        # ★ Cross-strategy guard: final check right before order (scan->execute race defense)
        try:
            from app.core.cross_strategy_guard import is_market_owned_by_other
            _other = is_market_owned_by_other(self.system, market, "FOCUS")
            if _other:
                logger.warning("[FOCUS] ENTRY BLOCKED at execute: %s held by %s (qty=%.4f)",
                               market, _other.owner, _other.qty)
                return {"state": self.state.value, "error": "cross_strategy_conflict_at_execute"}
        except Exception as exc:
            logger.debug("[FOCUS] cross_strategy_guard execute check: %s", exc)

        # ★ block duplicate entry into one's own position (final safety net)
        if any(p.market.upper() == market.upper() for p in self.positions):
            logger.warning("[FOCUS] ENTRY BLOCKED: %s already in self.positions", market)
            return {"state": self.state.value, "error": "already_held_self"}

        # ★ [2026-04-18] direct Bybit query -- prevent duplicate entry when internal state and the live Bybit balance diverge
        #   prevents recurrence of today's SOL double-entry (-$21), ORDI double-entry (-$14) incidents
        #   blocks the case where internal positions is empty but Bybit has an actual position
        try:
            # ★ [2026-05-25 owner] paper/dry mode: skip the live-exchange query -- prevents a leftover real-account position
            #   from false-flagging a virtual entry as DUPLICATE and blocking it. paper dups are handled by the self.positions guard below.
            if not self._is_live_mode():
                _bybit_pos = []
            else:
                _bybit_pos = self._get_client().list_open_positions()
            for _bp in (_bybit_pos or []):
                _bp_market = (_bp.get("symbol") or _bp.get("market") or "").upper()
                _bp_size = abs(float(_bp.get("size", 0) or 0))
                if _bp_market == market.upper() and _bp_size > 0:
                    logger.warning(
                        "[FOCUS] ★ DUPLICATE ENTRY BLOCKED: %s already open on Bybit (qty=%.4f) — internal state desync",
                        market, _bp_size)
                    # a Bybit position exists but isn't in internal -> restore into internal
                    try:
                        _bp_dir = "LONG" if (_bp.get("side") or "").lower() == "buy" else "SHORT"
                        _bp_entry = float(_bp.get("avgPrice", 0) or _bp.get("entry_price", 0) or 0)
                        if _bp_entry > 0 and not any(p.market.upper() == market.upper() for p in self.positions):
                            logger.warning("[FOCUS] Bybit pos detected, restoring to internal: %s %s qty=%.4f @ $%.4f",
                                           market, _bp_dir, _bp_size, _bp_entry)
                            # reference only, block entry -- SYNC restores it on the next tick
                    except Exception as exc:
                        logger.debug("[FOCUS] Bybit pos restore hint failed: %s", exc)
                    return {"state": self.state.value, "error": f"bybit_duplicate_{market}"}
        except Exception as exc:
            logger.debug("[FOCUS] Bybit duplicate check failed (safe to skip): %s", exc)

        # ★ HARPOON conflict defense: force-close the HARPOON position before entry
        try:
            hm = getattr(self.system, 'harpoon_manager', None) if self.system else None
            if hm and hm.current_scalp:
                logger.warning("[FOCUS] Closing HARPOON scalp before entry — leverage conflict prevention")
                hp = hm._get_current_price(hm.current_scalp.market) or 0
                hm._execute_scalp_exit("FOCUS_ENTRY_PREEMPT", hp)
        except Exception as exc:
            logger.debug("[FOCUS] HARPOON preempt check failed (safe to ignore): %s", exc)

        # ★ lock_market enforcement: block entry into other coins (scanner / manual exceptions)
        is_scanner_entry = entry.get("_scanner_entry", False)
        _lock_is_manual = bool(entry.get("_manual"))
        if self.config.lock_market and market.upper() != self.config.lock_market.upper():
            if not (is_scanner_entry and self.config.scanner_entry) and not _lock_is_manual:
                logger.warning("[FOCUS] BLOCKED: %s != locked %s — skipping entry", market, self.config.lock_market)
                return {"state": self.state.value, "error": f"locked_to_{self.config.lock_market}"}
            if _lock_is_manual and market.upper() != self.config.lock_market.upper():
                logger.warning("[FOCUS] ★ MANUAL ENTRY bypassing lock_market=%s for %s", self.config.lock_market, market)
        # [2026-04-18] direction-diversification final guard -- applied on all Primary/Scanner paths
        # old: the max_same_direction check existed only on the Scanner, not the Primary path
        #       so all 5 slots could be LONG (bias cause #2)
        # [2026-04-19 Option B] only the original direction saturated -> pass to keep the MTF FLIP chance.
        #   _mtf_gate includes dir_limit as one condition -> naturally flows into the opposite attempt.
        #   Hard-block only when both directions are saturated.
        _same_dir = sum(1 for p in self.positions if p.direction == direction)
        _opp_tmp = "SHORT" if direction == "LONG" else "LONG"
        _opp_dir_count = sum(1 for p in self.positions if p.direction == _opp_tmp)
        _same_cap_final = self._effective_dir_cap(direction)
        _opp_cap_final = self._effective_dir_cap(_opp_tmp)
        if _same_dir >= _same_cap_final and _opp_dir_count >= _opp_cap_final:
            logger.info("[FOCUS] direction limit: both saturated (%s=%d/%d, %s=%d/%d) — entry blocked",
                        direction, _same_dir, _same_cap_final, _opp_tmp, _opp_dir_count, _opp_cap_final)
            try:
                from app.manager.trade_journal import journal
                self._journal.record_blocked("FOCUS", market, direction,
                                       reason="direction_limit_both",
                                       detail=f"{direction}={_same_dir}/{_same_cap_final},{_opp_tmp}={_opp_dir_count}/{_opp_cap_final}")
            except Exception as exc:
                logger.debug("[FOCUS] record_blocked failed: %s", exc)
            return {"state": "HUNT", "skip": "direction_limit_both"}
        # if only the original direction is full, log and continue -- the MTF gate handles it
        if _same_dir >= _same_cap_final:
            logger.info("[FOCUS] direction %s saturated (%d/%d) — deferring to MTF FLIP (opposite %s=%d/%d)",
                        direction, _same_dir, _same_cap_final,
                        _opp_tmp, _opp_dir_count, _opp_cap_final)

        price = entry.get("price", 0)

        if not price or price <= 0:
            price = self._get_current_price(market) or 0
        if price <= 0:
            return {"state": "HUNT", "error": "no_price"}

        # -- ★ [2026-04-18 evening] MTF filter + auto direction flip --
        #   user note: "always blocking isn't the answer. Trade LONG or SHORT per the
        #             1h/30m/15m flow. If you block everything, when does a chance ever come?"
        #
        #   1. check Anti-Knife + H4 Context in the original direction (entry's direction)
        #   2. both pass -> enter in the original direction
        #   3. either fails -> re-check in the opposite direction
        #        - both pass for the opposite -> FLIP (flip direction then enter)
        #        - opposite also fails -> only then truly skip
        #
        #   e.g. ETH BUY signal but H4 5-bar decline -> re-check SHORT -> pass -> enter SHORT
        #       if both directions are ambiguous -> skip (no chance = don't enter)
        def _mtf_gate(_dir):
            # [2026-04-19 Option B] include dir_limit as one MTF-gate condition.
            #   if the original direction is saturated it naturally fails -> flows into the opposite attempt.
            # [2026-04-20] replaced with the per-direction cap (_effective_dir_cap) -- separate LONG/SHORT control
            _dir_cnt = sum(1 for p in self.positions if p.direction == _dir)
            _dir_cap = self._effective_dir_cap(_dir)
            if _dir_cnt >= _dir_cap:
                return False, f"dir_full({_dir_cnt}/{_dir_cap})"
            # ★ [2026-05-20 owner decision] 100% bypass for manual entry -- skip knife/primary guards.
            #   Owner explicit: "on a manual entry, same or opposite direction, do exactly what the operator says, 10000000%".
            #   Keep only the slot cap (dir_full) for capital protection. Bypass market-signal guards to respect the owner's intent.
            if _is_manual:
                logger.warning("[FOCUS] ★ MANUAL ENTRY %s %s -- _mtf_gate bypass (skip knife/primary guards, respecting owner's 100%% intent)",
                               market, _dir)
                return True, "manual_bypass"
            k_ok, k_r = self._anti_falling_knife_check(market, _dir)
            if not k_ok:
                return False, f"knife:{k_r}"
            h_ok, h_r = self._primary_context_filter(market, _dir)
            if not h_ok:
                return False, f"primary:{h_r}"
            return True, ""

        _pass, _fail_reason = _mtf_gate(direction)
        if not _pass:
            # ★ [2026-05-20 protect owner intent] never flip direction on a manual entry
            # Owner clicks L (LONG) -> MTF fail -> bot auto-flips to SHORT -> SHORT entry incident (HYPE/ETH case).
            # Manual intent is clear, so original-direction fail = return fail as-is. Never trigger FLIP.
            if _is_manual:
                logger.warning("[FOCUS] ★ MANUAL ENTRY %s %s MTF fail (%s) -- FLIP blocked, return original intent as fail",
                               market, direction, _fail_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked("FOCUS", market, direction,
                                           reason="manual_mtf_fail",
                                           detail=f"manual {direction} mtf fail: {_fail_reason} (FLIP blocked)")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked manual_mtf failed: %s", exc)
                return {"state": "HUNT", "skip": f"manual_mtf_fail:{_fail_reason}"}
            # ★ [2026-05-28 owner ICP incident] block FLIP for auto entries too --
            # ICPUSDT incident: bot auto-evaluates LONG -> MTF fail -> SHORT FLIP -> SHORT entry.
            # Owner's intent: for auto entries too, original-direction fail = return fail. No opposite auto entry.
            # An auto-entry extension of the `_is_manual` block (5-20 fix).
            if not bool(getattr(self.config, "entry_auto_flip_enabled", False)):
                logger.warning("[FOCUS] ★ AUTO FLIP DISABLED %s %s mtf fail (%s) — FLIP blocked, return fail",
                               market, direction, _fail_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked("FOCUS", market, direction,
                                           reason="auto_flip_disabled",
                                           detail=f"auto {direction} mtf fail: {_fail_reason}; FLIP off (ICP incident fix)")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked auto_flip failed: %s", exc)
                return {"state": "HUNT", "skip": f"auto_flip_disabled:{_fail_reason}"}
            _opp = "SHORT" if direction == "LONG" else "LONG"
            # if the opposite hits its per-direction cap too, the flip is meaningless
            _opp_same = sum(1 for p in self.positions if p.direction == _opp)
            _opp_cap_mtf = self._effective_dir_cap(_opp)
            if _opp_same >= _opp_cap_mtf:
                logger.info("[FOCUS] MTF fail (%s: %s) + opposite %s saturated (%d/%d) → skip",
                            direction, _fail_reason, _opp, _opp_same, _opp_cap_mtf)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked("FOCUS", market, direction,
                                           reason="mtf_both_blocked",
                                           detail=f"orig={_fail_reason};opp_saturated")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked mtf_both failed: %s", exc)
                return {"state": "HUNT", "skip": f"mtf_fail_{_fail_reason}"}

            _opp_pass, _opp_fail = _mtf_gate(_opp)
            if _opp_pass:
                # re-check coin_loss_cap for the opposite direction too
                if self.config.coin_loss_cap_enabled:
                    _opp_loss = self._get_coin_loss_total(market, _opp)
                    _opp_cap = self._effective_coin_loss_cap()
                    if _opp_loss < 0 and abs(_opp_loss) >= _opp_cap:
                        logger.info("[FOCUS] MTF flip blocked: %s %s opp_loss $%.2f >= cap $%.2f",
                                    market, _opp, _opp_loss, _opp_cap)
                        return {"state": "HUNT", "skip": "flip_coin_loss_cap"}

                # ★ Phase D-1 (2026-04-20): re-verify reentry/regime after the MTF FLIP
                # This agent's diagnosis (07:05 AAVE incident): on FLIP, B11 (regime) wasn't re-verified for the new direction
                # -> BULL regime + LONG fail -> SHORT bypass entry (cause of the big loss). _check_reentry_allowed contains all of B6/B7/B9/B10/B11.
                if not self._check_reentry_allowed(_opp, market, price):
                    logger.info("[FOCUS] MTF flip blocked by reentry/regime gate: %s %s (was %s)",
                                market, _opp, direction)
                    try:
                        from app.manager.trade_journal import journal
                        self._journal.record_blocked("FOCUS", market, _opp,
                                               reason="flip_blocked",
                                               detail=f"flip {direction}->{_opp} denied by reentry/regime gate")
                    except Exception as exc:
                        logger.debug("[FOCUS] record_blocked flip failed: %s", exc)
                    return {"state": "HUNT", "skip": f"flip_blocked_{_opp}"}

                # -- ★ FLIP Alignment Gate (2026-05-15 owner) --
                # DOGE pattern: scanner LONG -> Anti-Knife block -> SHORT flip. If both H1+30M are UPTR, it's counter-trend -> block.
                # "passing _mtf_gate" is a weak gate that only checks Anti-Knife + primary_context, indifferent to upper-TF alignment.
                # Here, catch only simultaneous H1+30M counter; if only one is opposite, pass (preserve the FLIP's purpose).
                if getattr(self.config, "entry_flip_require_alignment", False):
                    try:
                        from app.strategy.greenpen.market_structure import analyze_structure as _fl_az
                        from app.strategy.greenpen.pa_detector import OHLCV as _fl_O
                        def _fl_trend(_interval):
                            _r = self._get_mtf_kline(market, _interval)
                            if not _r or len(_r) < 10:
                                return "?"
                            _cs = [_fl_O(float(rr[1]), float(rr[2]), float(rr[3]), float(rr[4]))
                                   for rr in _r if len(rr) >= 5]
                            if len(_cs) < 10:
                                return "?"
                            _st = _fl_az(_cs)
                            return _st.trend.value if hasattr(_st.trend, 'value') else str(_st.trend)
                        _fl_h1 = _fl_trend("60")
                        _fl_m30 = _fl_trend("30")
                        _both_against = (
                            (_opp == "SHORT" and _fl_h1 == "UPTREND" and _fl_m30 == "UPTREND") or
                            (_opp == "LONG" and _fl_h1 == "DOWNTREND" and _fl_m30 == "DOWNTREND")
                        )
                        # ★ [2026-05-16] when _manual=True (manual entry), bypass FLIP alignment
                        if _both_against and not _is_manual:
                            logger.info("[FOCUS] ⛔ FLIP alignment block: %s %s→%s but H1=%s 30M=%s (counter-trend)",
                                        market, direction, _opp, _fl_h1, _fl_m30)
                            try:
                                from app.manager.trade_journal import journal
                                self._journal.record_blocked("FOCUS", market, _opp,
                                                       reason="flip_alignment_blocked",
                                                       detail=f"flip {direction}->{_opp} blocked: H1={_fl_h1} 30M={_fl_m30}")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked flip_alignment failed: %s", exc)
                            return {"state": "HUNT", "skip": f"flip_align:{_opp}_vs_H1{_fl_h1[:4]}_30M{_fl_m30[:4]}"}
                    except Exception as _fl_exc:
                        logger.debug("[FOCUS] FLIP alignment check error: %s", _fl_exc)

                logger.info("[FOCUS] ★ DIRECTION FLIPPED: %s %s → %s (original failed: %s, opposite passed MTF + reentry/regime)",
                            market, direction, _opp, _fail_reason)
                direction = _opp
                entry["direction"] = _opp  # downstream-logic consistency
            else:
                logger.info("[FOCUS] MTF fail both directions — true skip: %s (orig=%s, opp=%s)",
                            market, _fail_reason, _opp_fail)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked("FOCUS", market, direction,
                                           reason="mtf_both_blocked",
                                           detail=f"orig={_fail_reason};opp={_opp_fail}")
                except Exception as exc:
                    logger.debug("[FOCUS] record_blocked mtf_both failed: %s", exc)
                return {"state": "HUNT", "skip": f"mtf_both_{_fail_reason}"}

        # -- Entry Quality Filter (M5 microtiming) --
        # [2026-04-18] SW_UPPER_BB/SW_LOWER_BB exempt -- Entry Quality checks trend persistence
        #   (m5_momentum, nbar_trend-based), which structurally conflicts with mean-reversion signals
        #   exempt SW the same way as H4 counter_trend/Peak Fade/H1 penalty
        _entry_is_sw = entry.get("_is_sw_bb", False)
        if self.config.entry_quality_enabled and not _entry_is_sw:
            eq_ok, eq_reason = self._entry_quality_check(market, direction, price)
            if not eq_ok:
                logger.info("[FOCUS] Entry Quality BLOCKED: %s %s @ %.4f — %s",
                            direction, market, price, eq_reason)
                try:
                    from app.manager.trade_journal import journal
                    self._journal.record_blocked("FOCUS", market, direction,
                                           reason="entry_quality", detail=eq_reason)
                except Exception as exc:
                    logger.debug("[FOCUS] import journal failed: %s", exc)
                return {"state": "HUNT", "skip": f"entry_quality({eq_reason})"}
        elif _entry_is_sw:
            logger.info("[FOCUS] Entry Quality EXEMPT (SW mean reversion): %s %s", direction, market)

        # ★ price sanity check: double-check via the Bybit API
        try:
            verified_price = self._get_client()._linear_last_price(market)
            if verified_price and verified_price > 0:
                # if price differs by 50%+, it's untrustworthy -> use the API price
                ratio = price / verified_price if verified_price > 0 else 0
                if ratio < 0.5 or ratio > 2.0:
                    logger.warning("[FOCUS] Price sanity FAIL: price=%.6f vs API=%.6f (ratio=%.2f) → using API price",
                                   price, verified_price, ratio)
                    price = verified_price
                elif abs(ratio - 1.0) > 0.05:
                    logger.info("[FOCUS] Price drift: price=%.6f vs API=%.6f → using API price", price, verified_price)
                    price = verified_price
        except Exception as exc:
            logger.debug("[FOCUS] price verification failed: %s", exc)

        # decide budget: 0 = existing system, >0 = fixed
        effective_budget = self._get_effective_budget(market)

        # Compute position size (Green Pen 3M)
        from app.strategy.greenpen.cycle_tp import compute_cycle_targets, compute_position_size

        # ★ ATR: Primary = H4 ATR (primary_sig), Scanner = per-coin individual ATR (entry)
        #    on Scanner entry, primary_sig is another coin's (primary's) ATR, so don't use it
        atr = 0
        if entry.get("_scanner_entry") and entry.get("atr", 0) > 0:
            atr = entry["atr"]  # Scanner: the coin's own ATR (primary_sig is for the primary coin)
        elif self.primary_sig and self.primary_sig.get("atr", 0) > 0:
            atr = self.primary_sig["atr"]  # Primary: the H4-strategy ATR
        if atr <= 0:
            atr = entry.get("atr", price * 0.02)

        # ATR sanity check + cap
        if price > 0 and atr > 0:
            atr_pct = atr / price * 100
            MAX_ATR_PCT = float(getattr(self.config, "max_atr_pct", 5.0))  # [2026-04-26] config-exposed
            if atr_pct > MAX_ATR_PCT:
                old_atr = atr
                atr = price * (MAX_ATR_PCT / 100.0)
                logger.warning("[FOCUS] ATR capped: %.4f (%.1f%%) → %.4f (%.1f%%) for %s",
                               old_atr, atr_pct, atr, MAX_ATR_PCT, market)
            elif atr_pct < 0.1:
                atr = price * 0.015
                logger.warning("[FOCUS] ATR too small → 1.5%% fallback: %.4f for %s", atr, market)

        # ★ Phase K (2026-04-21): regime_transition-tagged entries swap the tp/sl multipliers
        _k_tp_mult = float(entry.get("_phase_k_tp_mult", 0) or 0)
        _k_sl_mult = float(entry.get("_phase_k_sl_mult", 0) or 0)
        if entry.get("_phase_k") and _k_tp_mult > 0 and _k_sl_mult > 0:
            _tp1 = self.config.cycle_tp1_mult * _k_tp_mult
            _tp2 = self.config.cycle_tp2_mult * _k_tp_mult
            _sl = self.config.cycle_sl_mult * _k_sl_mult
            logger.info("[FOCUS] Phase K TP/SL mults: tp1=%.2f→%.2f sl=%.2f→%.2f",
                        self.config.cycle_tp1_mult, _tp1, self.config.cycle_sl_mult, _sl)
        else:
            _tp1 = self.config.cycle_tp1_mult
            _tp2 = self.config.cycle_tp2_mult
            _sl = self.config.cycle_sl_mult

        # ★ [2026-05-15] min TP fee-guard: prevent a TP next to the entry price (protect low-volatility coins)
        _min_tp_pct = float(getattr(self.config, "min_tp_distance_pct", 0.30)) \
            if getattr(self.config, "min_tp_distance_enabled", False) else 0.0
        targets = compute_cycle_targets(
            price, direction, atr,
            tp1_mult=_tp1,
            tp2_mult=_tp2,
            sl_mult=_sl,
            min_rr=float(getattr(self.config, "cycle_min_rr", 1.0)),  # ★ [2026-04-26] config-exposed
            min_tp_distance_pct=_min_tp_pct,
        )

        # ★ regime TP/SL scaling + fee-awareness (reuse existing infra)
        targets = self._apply_regime_scaling(market, price, targets)

        # -- ★ Entry Expectation (2026-05-14 owner -- entry-expectation mechanism) --
        # Compute reward_target/risk_invalidation from the H4 S/R structure -> unify with the exchange TP/SL.
        # If not computable (no S/R·swing found), keep the ATR targets computed above (fallback).
        _exp_reward_target = 0.0
        _exp_risk_invalidation = 0.0
        _exp_rr_ratio = 0.0
        _exp_source = ""
        if getattr(self.config, "entry_expectation_enabled", False):
            try:
                from app.manager.entry_expectation import compute_entry_expectation, atr_from_ohlcv
                from app.strategy.greenpen.pa_detector import OHLCV as _EE_OHLCV
                _ee_client = self._get_client()
                _raw_primary = _ee_client.get_kline(market, interval=self.config.primary_tf, limit=60)
                _primary_candles = [_EE_OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                               for r in _raw_primary if len(r) >= 5]
                _raw_m15 = _ee_client.get_kline(market, interval="15", limit=60)
                _m15_candles = [_EE_OHLCV(float(r[1]), float(r[2]), float(r[3]), float(r[4]))
                                for r in _raw_m15 if len(r) >= 5]
                _m15_atr = atr_from_ohlcv(_m15_candles)
                _exp = compute_entry_expectation(
                    direction, price, _primary_candles, atr,
                    m15_candles=_m15_candles, m15_atr=_m15_atr,
                )
                if _exp.is_valid:
                    _exp_reward_target = _exp.reward_target
                    _exp_risk_invalidation = _exp.risk_invalidation
                    _exp_rr_ratio = _exp.rr_ratio
                    _exp_source = f"{_exp.reward_source}/{_exp.risk_source}"
                    # ★ [2026-05-16 owner SUI incident] if EE is worse than cycle_tp, keep cycle_tp.
                    # Case: SUI dropping on 1m -> EE overwrote TP with the H1 stale zone $1.099 -> reward 0.06% / RR 0.01 -> blocked.
                    # But cycle_tp TP $1.064 (-2.9%) = the real spot. EE only narrows it.
                    # Fix: if EE.TP has less reward than cycle_tp.TP, keep cycle_tp.TP (improvement only, no narrowing).
                    #       likewise if EE.SL has more risk than cycle_tp.SL, keep cycle_tp.SL (safety first).
                    _ee_tp_better = False
                    _ee_sl_better = False
                    if direction == "LONG":
                        # LONG: TP is above (higher = more reward) / SL is below (lower = more risk, closer = safer)
                        _ee_tp_better = _exp_reward_target > targets.tp2  # EE TP is higher
                        _ee_sl_better = _exp_risk_invalidation > targets.sl  # EE SL is higher (closer = safer)
                    elif direction == "SHORT":
                        # SHORT: TP is below (lower = more reward) / SL is above (lower = closer = safer)
                        _ee_tp_better = _exp_reward_target < targets.tp2  # EE TP is lower
                        _ee_sl_better = _exp_risk_invalidation < targets.sl  # EE SL is lower (closer = safer)
                    # unify targets -- adopt only the side where EE is better. Keep cycle_tp where it's worse.
                    _orig_tp2 = targets.tp2
                    _orig_sl = targets.sl
                    if _ee_tp_better:
                        targets.tp2 = _exp_reward_target
                    if _ee_sl_better:
                        targets.sl = _exp_risk_invalidation
                    # if neither EE side is adopted, recompute RR (on the cycle_tp basis)
                    if not (_ee_tp_better and _ee_sl_better):
                        try:
                            if direction == "LONG":
                                _new_reward = (targets.tp2 - price) / price * 100.0
                                _new_risk = (price - targets.sl) / price * 100.0
                            else:
                                _new_reward = (price - targets.tp2) / price * 100.0
                                _new_risk = (targets.sl - price) / price * 100.0
                            _new_risk = max(_new_risk, 0.001)
                            _exp_rr_ratio = _new_reward / _new_risk
                            _exp_source += f"|cycle_tp_kept(tp={_ee_tp_better},sl={_ee_sl_better})"
                            logger.info(
                                "[FOCUS] EE/cycle_tp blend: TP %s SL %s → reward=%.2f%% risk=%.2f%% RR=%.2f",
                                "EE" if _ee_tp_better else f"cycle($%.4g)" % _orig_tp2,
                                "EE" if _ee_sl_better else f"cycle($%.4g)" % _orig_sl,
                                _new_reward, _new_risk, _exp_rr_ratio,
                            )
                            # also update the _exp object's rr_ratio (for the EE Gate comparison)
                            _exp.rr_ratio = _exp_rr_ratio
                            _exp.reward_pct = _new_reward
                            _exp.risk_pct = _new_risk
                        except Exception as _blend_exc:
                            logger.debug("[FOCUS] EE/cycle_tp blend recalc failed: %s", _blend_exc)
                    # if TP1 (partial exit) overshoots TP2, reset it to the halfway point of the target
                    if direction == "LONG" and targets.tp1 >= targets.tp2:
                        targets.tp1 = price + (targets.tp2 - price) * 0.5
                    elif direction == "SHORT" and targets.tp1 <= targets.tp2:
                        targets.tp1 = price - (price - targets.tp2) * 0.5
                    logger.info(
                        "[FOCUS] ★ Entry Expectation: %s %s reward=%.2f%% risk=%.2f%% RR=%.2f (%s) → TP2=$%.6g SL=$%.6g",
                        direction, market, _exp.reward_pct, _exp.risk_pct, _exp.rr_ratio,
                        _exp_source, targets.tp2, targets.sl,
                    )
                    # -- ★ Entry Expectation Gate (2026-05-15 owner -- RR/risk threshold block) --
                    # Block obvious garbage entries like SIREN RR=0.18. If not computable, fail-open (this block isn't reached).
                    # ★ [2026-05-16] when _manual=True (manual entry), bypass the EE Gate
                    if (getattr(self.config, "entry_expectation_gate_enabled", False) and not _is_manual
                            and not entry.get("_guard_score_pass")
                            and self._is_yellow_guard_active("entry")):  # [2026-05-28 owner evening] yellow master toggle
                        _min_rr = float(getattr(self.config, "entry_expectation_min_rr", 1.0))
                        _max_risk = float(getattr(self.config, "entry_expectation_max_risk_pct", 6.0))
                        _min_reward = float(getattr(self.config, "entry_expectation_min_reward_pct", 0.8))
                        if _exp.rr_ratio < _min_rr:
                            logger.info("[FOCUS] ⛔ EE Gate: %s %s RR=%.2f < %.2f → SKIP entry",
                                        direction, market, _exp.rr_ratio, _min_rr)
                            try:
                                from app.manager.trade_journal import journal
                                self._journal.record_blocked("FOCUS", market, direction,
                                                       reason="ee_gate_rr_low",
                                                       detail=f"RR={_exp.rr_ratio:.2f}<{_min_rr:.2f}")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked ee_gate_rr failed: %s", exc)
                            return {"state": "HUNT", "skip": f"ee_gate_rr_low:{_exp.rr_ratio:.2f}"}
                        # [2026-05-20 5-14 blueprint Phase 2] block reward < min_reward -- "is there anywhere to go from this spot"
                        if _exp.reward_pct < _min_reward:
                            logger.info("[FOCUS] ⛔ EE Gate: %s %s reward=%.2f%% < %.2f%% → SKIP entry",
                                        direction, market, _exp.reward_pct, _min_reward)
                            try:
                                from app.manager.trade_journal import journal
                                self._journal.record_blocked("FOCUS", market, direction,
                                                       reason="ee_gate_reward_low",
                                                       detail=f"reward={_exp.reward_pct:.2f}%<{_min_reward:.2f}%")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked ee_gate_reward failed: %s", exc)
                            return {"state": "HUNT", "skip": f"ee_gate_reward_low:{_exp.reward_pct:.2f}%"}
                        if _exp.risk_pct > _max_risk:
                            logger.info("[FOCUS] ⛔ EE Gate: %s %s risk=%.2f%% > %.2f%% → SKIP entry",
                                        direction, market, _exp.risk_pct, _max_risk)
                            try:
                                from app.manager.trade_journal import journal
                                self._journal.record_blocked("FOCUS", market, direction,
                                                       reason="ee_gate_risk_high",
                                                       detail=f"risk={_exp.risk_pct:.2f}%>{_max_risk:.2f}%")
                            except Exception as exc:
                                logger.debug("[FOCUS] record_blocked ee_gate_risk failed: %s", exc)
                            return {"state": "HUNT", "skip": f"ee_gate_risk_high:{_exp.risk_pct:.2f}%"}

                    # -- ★ gap-check gate (2026-06-03 owner "if there isn't enough gap, the entry is meaningless") --
                    # If distance to the N-bar high (LONG)/low (SHORT) on the chosen TF (5/15/30/60M) < min_pct -> reject entry.
                    if (not _is_manual
                            and getattr(self.config, "gap_check_enabled", True)
                            and float(getattr(self.config, "gap_check_min_pct", 0.0)) > 0
                            and price > 0):
                        try:
                            _gc_tf   = str(getattr(self.config, "gap_check_tf", "15"))
                            _gc_bars = int(getattr(self.config, "gap_check_lookback_bars", 12))
                            _gc_min  = float(getattr(self.config, "gap_check_min_pct", 0.0))
                            _gc_raw  = self._get_mtf_kline(market, _gc_tf, limit=_gc_bars + 2, ttl=60.0)
                            if _gc_raw and len(_gc_raw) >= _gc_bars:
                                _gc_recent = _gc_raw[-_gc_bars:]
                                if direction == "LONG":
                                    _gc_wall = max(float(r[2]) for r in _gc_recent if len(r) >= 5)
                                    _gc_gap  = (_gc_wall - price) / price * 100.0
                                else:
                                    _gc_wall = min(float(r[3]) for r in _gc_recent if len(r) >= 5)
                                    _gc_gap  = (price - _gc_wall) / price * 100.0
                                # ★ ATR-adaptive -- high-range coins need a bigger gap (block top-chasing, 2026-06-07 owner)
                                _gc_eff = _gc_min
                                if (getattr(self.config, "gap_check_atr_adaptive_enabled", True)
                                        and price > 0 and atr > 0):
                                    _gc_atrp = atr / price * 100.0
                                    _gc_need = _gc_atrp * float(getattr(self.config, "gap_check_atr_mult", 0.7))
                                    _gc_cap  = float(getattr(self.config, "gap_check_atr_cap_pct", 1.5))
                                    _gc_eff  = max(_gc_min, min(_gc_need, _gc_cap))
                                if _gc_gap < _gc_eff:
                                    logger.info(
                                        "[FOCUS] ⛔ gapGate: %s %s %sM×%d-bar gap=%.2f%%<%.2f%%(ATR-adaptive) (wall=%.4f) -> SKIP",
                                        direction, market, _gc_tf, _gc_bars, _gc_gap, _gc_eff, _gc_wall,
                                    )
                                    try:
                                        from app.manager.trade_journal import journal
                                        self._journal.record_blocked(
                                            "FOCUS", market, direction,
                                            reason="gap_check",
                                            detail=f"gap={_gc_gap:.2f}%<{_gc_eff:.2f}%(min{_gc_min:.2f}/ATR-adaptive,{_gc_tf}M×{_gc_bars}bars,wall={_gc_wall:.4f})",
                                        )
                                    except Exception:
                                        pass
                                    return {"state": "HUNT", "skip": f"gap_check:{_gc_tf}M={_gc_gap:.2f}%<{_gc_eff:.2f}%"}
                        except Exception as _gc_exc:
                            logger.debug("[FOCUS] gap_check failed (fail-open): %s", _gc_exc)

                    # -- ★ volatility-reachability gate (2026-05-23 owner "can it reach TP with enough swing") --
                    # Even if the reward distance (resistance) is far, with dead volatility it can't get there (bad entry 29%, peak=0 -> 4h endure -> loss).
                    # The recent N-bar actual swing (high-low range) must be >= min_reach_ratio of the reward distance to enter.
                    if (getattr(self.config, "entry_volatility_gate_enabled", True)
                            and not _is_manual and _exp.reward_pct > 0
                            and not entry.get("_guard_score_pass")
                            and self._is_yellow_guard_active("entry")):  # [2026-05-28 owner evening] yellow master toggle
                        try:
                            _vol_tf = str(getattr(self.config, "entry_volatility_lookback_tf", "5"))
                            _vol_bars = int(getattr(self.config, "entry_volatility_lookback_bars", 12))
                            _vol_min_ratio = float(getattr(self.config, "entry_volatility_min_reach_ratio", 0.6))
                            _raw_vol = self._get_mtf_kline(market, _vol_tf, limit=_vol_bars + 2, ttl=30.0)
                            if _raw_vol and len(_raw_vol) >= _vol_bars and price > 0:
                                _recent_vol = _raw_vol[-_vol_bars:]
                                _vol_highs = [float(r[2]) for r in _recent_vol if len(r) >= 5]
                                _vol_lows = [float(r[3]) for r in _recent_vol if len(r) >= 5]
                                if _vol_highs and _vol_lows:
                                    _recent_range_pct = (max(_vol_highs) - min(_vol_lows)) / price * 100.0
                                    _reach_ratio = _recent_range_pct / _exp.reward_pct if _exp.reward_pct > 0 else 0.0
                                    if _reach_ratio < _vol_min_ratio:
                                        logger.info(
                                            "[FOCUS] ⛔ volatility Gate: %s %s recent %d-bar swing=%.2f%% / reward=%.2f%% = reach %.2f < %.2f -> SKIP (dead sideways spot)",
                                            direction, market, _vol_bars, _recent_range_pct, _exp.reward_pct, _reach_ratio, _vol_min_ratio,
                                        )
                                        try:
                                            from app.manager.trade_journal import journal
                                            self._journal.record_blocked(
                                                "FOCUS", market, direction,
                                                reason="volatility_gate",
                                                detail=f"reach={_reach_ratio:.2f}<{_vol_min_ratio:.2f}(range={_recent_range_pct:.2f}%/rw={_exp.reward_pct:.2f}%)",
                                            )
                                        except Exception as exc:
                                            logger.debug("[FOCUS] record_blocked volatility_gate failed: %s", exc)
                                        return {"state": "HUNT", "skip": f"volatility_gate:reach{_reach_ratio:.2f}"}
                        except Exception as _vol_exc:
                            logger.debug("[FOCUS] volatility gate failed (fail-open): %s", _vol_exc)
                else:
                    logger.info("[FOCUS] Entry Expectation: %s %s not computable -- keep ATR targets (%s)",
                                direction, market, _exp.note)
            except Exception as _exp_exc:
                logger.warning("[FOCUS] Entry Expectation failed (keep ATR targets): %s", _exp_exc)

        sl_distance = abs(price - targets.sl)

        # ★★★ SL-distance minimum: config-exposed (default 0.5%) ★★★
        # [2026-04-26 owner fix] 0.1% -> 0.5% -- prevent instant death (entry==sl) after rounding for low-priced coins
        MIN_SL_PCT = float(getattr(self.config, "min_sl_pct", 0.005))
        min_sl_distance = price * MIN_SL_PCT
        if sl_distance < min_sl_distance:
            logger.warning("[FOCUS] SL distance too small: %.4f (%.4f%%) → floor %.4f (%.2f%%) for %s",
                           sl_distance, sl_distance / price * 100 if price > 0 else 0,
                           min_sl_distance, MIN_SL_PCT * 100, market)
            sl_distance = min_sl_distance
            # ★ also fix the actual SL price -- if the SL sent to Bybit is too tight, instant death!
            if direction == "LONG":
                targets.sl = price - min_sl_distance
            else:
                targets.sl = price + min_sl_distance
            logger.info("[FOCUS] SL price adjusted → $%.4f (%.2f%% floor from $%.4f)", targets.sl, MIN_SL_PCT * 100, price)

        # ★★★ Sanity check -- absolutely prevent instant death (entry == sl) (4-26 owner order) ★★★
        if direction == "LONG":
                if targets.sl >= price * 0.999:  # risky if SL is >= 99.9% of entry
                    targets.sl = price * 0.99  # force 1% below
                    sl_distance = price - targets.sl
                    logger.warning("[FOCUS] ⚠ SANITY: LONG sl too close to entry — forced 1%% below ($%.4f)", targets.sl)
        else:
                if targets.sl <= price * 1.001:  # risky if SL is <= 100.1% of entry
                    targets.sl = price * 1.01  # force 1% above
                    sl_distance = targets.sl - price
                    logger.warning("[FOCUS] ⚠ SANITY: SHORT sl too close to entry — forced 1%% above ($%.4f)", targets.sl)

        # ★★★★★ [2026-04-26 owner absolute order] PARENT ROE GUARD ★★★★★
        # "no matter what, there must never be a liquidation down to -31%"
        # Force the SL distance to the ROE -31% point -- SL distance = entry × (31% / leverage)
        # leverage 5 -> SL distance 6.2% / leverage 7 -> 4.43%
        if getattr(self.config, "parent_roe_guard_enabled", True):
            parent_roe_cap = float(getattr(self.config, "parent_max_roe_loss_pct", 31.0))
            lev = max(1, int(getattr(self.config, "leverage", 5)))
            parent_min_pct = parent_roe_cap / lev
            parent_min_distance = price * (parent_min_pct / 100.0)
            current_sl_pct = (sl_distance / price * 100) if price > 0 else 0
            if sl_distance < parent_min_distance:
                logger.warning("[FOCUS] ★★ PARENT ROE GUARD: SL %.2f%% -> %.2f%% (guarantee enduring ROE -31%%, lev=%d, %s)",
                               current_sl_pct, parent_min_pct, lev, market)
                sl_distance = parent_min_distance
                if direction == "LONG":
                    targets.sl = price - parent_min_distance
                else:
                    targets.sl = price + parent_min_distance

        # ★★★ SL-distance absolute cap: config-exposed (default 99.0%, owner "if it can't profit, it can't exit") ★★★
        # ★ Override Slot (2026-05-10): on an override-eligible entry, apply a close SL (5%) (in case of betrayal)
        if bool(entry.get("_is_override", False)):
            MAX_SL_DISTANCE_PCT = float(getattr(self.config, "override_max_sl_distance_pct", 5.0))
        else:
            MAX_SL_DISTANCE_PCT = float(getattr(self.config, "max_sl_distance_pct", 99.0))
        sl_distance_pct = abs(price - targets.sl) / price * 100 if price > 0 else 0
        if sl_distance_pct > MAX_SL_DISTANCE_PCT:
            logger.warning("[FOCUS] SL distance %.2f%% capped to %.1f%% for %s",
                           sl_distance_pct, MAX_SL_DISTANCE_PCT, market)
            if direction == "LONG":
                targets.sl = price * (1 - MAX_SL_DISTANCE_PCT / 100)
            else:
                targets.sl = price * (1 + MAX_SL_DISTANCE_PCT / 100)
            sl_distance = abs(price - targets.sl)
            logger.info("[FOCUS] SL capped → $%.4f (%.1f%% ceiling from $%.4f)", targets.sl, MAX_SL_DISTANCE_PCT, price)

        # -- 🌋 [2026-06-11 owner] volatility-awakening SL adaptation -- on awakening + Day-aligned, widen SL (size auto-down, risk fixed) --
        #   Widening sl_distance here (after SL finalize, before TP R:R, before budget) -> the TP R:R·compute_position_size below
        #   auto-reflect the new sl_distance (TP expands alongside + size shrinks). default OFF.
        if getattr(self.config, "awaken_sl_enabled", False):
            try:
                _aw_dist, _aw_sl, _aw_lbl = self._volatility_awakening_sl(
                    market, price, atr, direction, sl_distance)
                if _aw_sl is not None and _aw_dist > sl_distance:
                    targets.sl = _aw_sl
                    sl_distance = _aw_dist
                    logger.info("[FOCUS] 🌋 volatility-awakening SL adaptation: %s", _aw_lbl)
            except Exception as _aw_exc:
                logger.debug("[FOCUS] awaken sl apply error: %s", _aw_exc)

        # ★ also guarantee a minimum TP: it must not be smaller than SL (min R:R 1:1)
        tp1_dist = abs(targets.tp1 - price)
        if tp1_dist < sl_distance:
            if direction == "LONG":
                targets.tp1 = price + sl_distance
            else:
                targets.tp1 = price - sl_distance
            logger.info("[FOCUS] TP1 adjusted for min R:R 1:1 → $%.2f", targets.tp1)

        # -- v2: conviction-based budget (removed DCA/Scout/Anti-Martingale/TimeVolatility) --
        conviction_score = float(entry.get("conviction_score", 0))  # [2026-05-17 100-pt] removed int truncation
        conviction_budget = float(entry.get("conviction_budget", 0))
        if conviction_budget > 0:
            effective_budget = conviction_budget
        # if there's no conviction, keep the existing effective_budget (fallback)

        # ★ [2026-04-25 owner new] Dynamic Leverage -- per-coin differentiation by ATR%
        # low-volatility coins (like ETH) -> lower lev / high-volatility -> higher lev
        _atr_pct_for_lev = (atr / price * 100) if (price > 0 and atr > 0) else 2.0
        _dyn_lev = self._compute_dynamic_leverage(_atr_pct_for_lev, market=market)
        # set per-symbol leverage on Bybit (proceed even if it fails -- fallback is Bybit default)
        try:
            client = self._get_client()
            if client and hasattr(client, "set_leverage"):
                client.set_leverage(market, _dyn_lev)
                logger.debug("[FOCUS] Bybit set_leverage %s → %dx OK", market, _dyn_lev)
        except Exception as _lev_exc:
            logger.warning("[FOCUS] set_leverage failed %s lev=%d: %s (fallback to Bybit default leverage)",
                           market, _dyn_lev, _lev_exc)

        # ★★★ Per-Coin Size Cap (2026-05-08 owner decision) ★★★
        # Resolves the cause of the 4-26 single -$202 incident after full operation.
        # No conflict with the "if you don't sell it eventually comes back" tenet (95%) -- don't sell, but size small.
        # ★ Override Slot (2026-05-10): on an override-eligible entry, apply a separate cap (8%) (in case of betrayal)
        _is_override_entry = bool(entry.get("_is_override", False))
        if _is_override_entry:
            _cap_pct = float(getattr(self.config, "override_size_cap_pct", 8.0))
        elif getattr(self.config, "per_coin_size_cap_enabled", False):
            _cap_pct = float(getattr(self.config, "per_coin_size_cap_pct", 20.0))
        else:
            _cap_pct = 0.0
        if _cap_pct > 0:
            _equity_for_cap = float(getattr(self.system, '_last_equity_usdt', 0) or 0)
            if _equity_for_cap > 0:
                _max_size_usd = _equity_for_cap * (_cap_pct / 100.0)
                if effective_budget > _max_size_usd:
                    _label = "Override size cap" if _is_override_entry else "Per-coin size cap"
                    logger.warning(
                        "[FOCUS] %s %s: $%.2f → $%.2f (%.1f%% of equity $%.2f)",
                        _label, market, effective_budget, _max_size_usd, _cap_pct, _equity_for_cap
                    )
                    effective_budget = _max_size_usd

        # [2026-05-29 owner] Slot Auto Expand size shrink -- capital protection (default 50%)
        if entry.get("_slot_expand", False):
            _se_ratio = float(getattr(self.config, "slot_auto_expand_size_ratio", 0.5))
            _orig_budget = effective_budget
            effective_budget = effective_budget * _se_ratio
            logger.warning(
                "[FOCUS] ★ Slot Auto Expand size: $%.2f -> $%.2f (×%.2f, capital protection) %s",
                _orig_budget, effective_budget, _se_ratio, market,
            )

        logger.info("[FOCUS] Sizing inputs: budget=$%.2f conviction=%d sl_dist=%.8f price=%.6f lev=%d(dyn) market=%s",
                    effective_budget, conviction_score, sl_distance, price, _dyn_lev, market)

        # ★ [entry score = conviction] risk scaling by guard score (inverted-U) -- bypasses the cap, hits qty directly
        _anchor_conv = float(entry.get("_guard_score", conviction_score) or conviction_score or 0)
        _crf = self._conv_risk_factor(_anchor_conv)
        _eff_risk_pct = self.config.risk_pct * _crf
        if _crf != 1.0:
            logger.info("[FOCUS] conv-risk scale: %s guardconv=%.0f risk %.2f%%->%.2f%% (×%.2f, entry score=conviction)",
                        market, _anchor_conv, self.config.risk_pct, _eff_risk_pct, _crf)

        sizing = compute_position_size(
            effective_budget, _eff_risk_pct,
            sl_distance, price,
            leverage=_dyn_lev,
            max_daily_plans=self.config.max_daily_plans,
        )

        if sizing.leverage_qty <= 0:
            return {"state": "HUNT", "error": "qty_zero"}

        # ★ Phase L (2026-04-22) -- S3 Fee-Aware net_ev Gate ★
        # review item #3: after all defenses (B11/B10/B8/B9/J v2/Morning Shield etc.)
        # review item #5: if paper_mode=True, allow entry + only the virtual counter
        # review item #10: default OFF + paper_mode=True double safety net (Phase K pattern)
        # ★ this agent's letter PASS (2026-04-22 21:05) 1 MED fix:
        #   the old `tp_mult = cycle_tp1_mult * _tp1` double-multiply (_tp1 already includes cycle_tp1_mult)
        #   -> bug where gross_ev was inflated by cycle_tp1_mult, loosening the Gate
        #   fix: `tp_mult = _tp1` (already the full multiplier)
        try:
            _l3_pa_double = bool(entry.get("_pa_double_confirmed", False))
            _s3_allow, _s3_reason, _s3_stats = self._check_s3_fee_gate(
                market=market,
                direction=direction,
                price=price,
                atr=atr,
                size_usdt=effective_budget,
                leverage=int(_dyn_lev),   # ★ [2026-04-25] dynamic leverage (ATR tier)
                tp_mult=float(_tp1),   # ★ FIX: _tp1 already includes cycle_tp1_mult (+ Phase K mult)
                sl_mult=float(_sl),    # ★ FIX: _sl already includes cycle_sl_mult (+ Phase K mult)
                pa_double_confirmed=_l3_pa_double,
            )
            # review items #4 + #8: persist stats (always recorded, paper/live regardless)
            if _s3_stats:
                self._persist_s3_gate_stats(_s3_stats)
            # block only in live mode
            if not _s3_allow:
                return {"state": "HUNT", "error": "s3_fee_gate_blocked", "reason": _s3_reason}
        except Exception as _s3_exc:
            # edge: on an S3 Gate exception, don't block entry (safe fallback) -- the "cautious approach" from this agent's letter #11
            logger.warning("[S3_GATE] check exception (fallback PASS): %s", _s3_exc, exc_info=True)

        # Switch to one-way mode + set leverage
        client = self._get_client()
        try:
            client.switch_position_mode(market, mode="MergedSingle")
        except Exception as exc:
            err_str = str(exc)
            # retCode=110025 "Position mode is not modified" = already MergedSingle -> same as success
            if "110025" in err_str or "not modified" in err_str.lower():
                logger.debug("[FOCUS] position mode already MergedSingle — OK")
            elif "position" in err_str.lower() and ("exist" in err_str.lower() or "mode" in err_str.lower()):
                # ★ a real Hedge Mode conflict (can't switch due to an open position, etc.)
                logger.error("[FOCUS] ABORT ENTRY: position mode switch failed (hedge mode conflict): %s", exc)
                return {"state": self.state.value, "error": f"position_mode_conflict: {exc}"}
            else:
                logger.warning("[FOCUS] switch_position_mode: %s (assuming one-way)", exc)
        try:
            client.set_leverage(market, self.config.leverage)
        except Exception as exc:
            logger.debug("[FOCUS] set_leverage: %s (may already be set)", exc)

        # ★★★ prevent QTY explosion: notional-value cap check ★★★
        order_qty = sizing.leverage_qty
        # ★ [patch v2-A] Pre-Close lead entry = before close confirmation -> half size (then passes the lot/margin clamp)
        if entry.get("preclose"):
            _pc_ratio = max(0.05, min(1.0, float(getattr(self.config, "preclose_size_ratio", 0.5))))
            if _pc_ratio < 1.0:
                order_qty = order_qty * _pc_ratio
                entry["_preclose_ratio"] = _pc_ratio  # ★ [v2-A2] for computing the remaining half on close-confirmation top-up
                logger.info("[FOCUS] ⏩ Pre-Close lead entry: %s %s -- size ×%.2f (%s)",
                            market, direction, _pc_ratio, entry.get("_preclose_rsn", ""))
        notional_value = order_qty * price
        max_notional = effective_budget * self.config.leverage * 2  # within budget×leverage×2 (reduced 5->2: prevents over-entry when SL is tight)
        if max_notional < 100:
            max_notional = 100  # minimum $100
        if notional_value > max_notional:
            logger.error("[FOCUS] QTY EXPLOSION BLOCKED: qty=%.0f notional=$%.0f > max=$%.0f for %s "
                         "(budget=$%.2f sl_dist=%.8f price=%.6f)",
                         order_qty, notional_value, max_notional, market,
                         effective_budget, sl_distance, price)
            # recompute with a safe qty
            safe_qty = (effective_budget * self.config.leverage) / price
            order_qty = safe_qty
            logger.info("[FOCUS] Safe qty fallback: %.4f (notional=$%.2f)", order_qty, order_qty * price)

        # Adjust qty precision -- fetch instrument info via the client (exchange abstraction)
        try:
            _inst = client.get_instrument_info(market)
            if _inst and (_inst.get("qty_step") or _inst.get("min_qty")):
                qty_step = float(_inst.get("qty_step", 0.01) or 0.01)
                min_qty = float(_inst.get("min_qty", 0.01) or 0.01)
                max_order_qty = float(_inst.get("max_qty", 0) or 0)
                # Round down to qtyStep
                import math
                if qty_step > 0:
                    order_qty = math.floor(order_qty / qty_step) * qty_step
                    order_qty = round(order_qty, 8)
                # ★ maxOrderQty check -- block if qty exceeds the Bybit limit
                if max_order_qty > 0 and order_qty > max_order_qty:
                    logger.error("[FOCUS] QTY BLOCKED: %.0f > maxOrderQty %.0f for %s — blacklisting coin",
                                 order_qty, max_order_qty, market)
                    tbl = getattr(self, '_temp_blacklist', {})
                    tbl[market] = time.time() + 600  # 10-min blacklist
                    self._temp_blacklist = tbl
                    self.selected_market = ""
                    self.state = FocusState.DORMANT
                    self._save_config()
                    return {"state": "DORMANT", "error": f"qty>{max_order_qty:.0f}"}
                if order_qty < min_qty:
                    logger.warning("[FOCUS] qty %.8f < minOrderQty %.8f for %s — skipping", order_qty, min_qty, market)
                    return {"state": "HUNT", "error": f"qty_below_min({order_qty}<{min_qty})"}
                logger.info("[FOCUS] qty adjusted: %.8f (step=%.4f min=%.4f max=%.0f)", order_qty, qty_step, min_qty, max_order_qty)
        except Exception as exc:
            logger.warning("[FOCUS] instrument info fetch failed: %s — using raw qty %.8f", exc, order_qty)

        # ★ Margin cap -- shrink qty when notional/leverage exceeds the available balance
        _avail = self._get_available_margin()  # Bybit API (accurate)
        if _avail <= 0:
            # fall back to the internal estimate on API failure
            _equity = float(getattr(self.system, '_last_equity_usdt', 0) or 0)
            _used = sum(abs(p.qty) * p.entry_price / max(1, self.config.leverage) for p in self.positions)
            _avail = max(0.0, _equity - _used)
        if _avail > 0:
            margin_needed = (order_qty * price) / max(1, self.config.leverage)
            margin_limit = _avail * 0.95  # 5% buffer
            if margin_needed > margin_limit:
                old_qty = order_qty
                order_qty = (margin_limit * self.config.leverage) / price
                # re-apply qty_step
                try:
                    _qs = qty_step
                    if _qs > 0:
                        import math
                        order_qty = math.floor(order_qty / _qs) * _qs
                        order_qty = round(order_qty, 8)
                except NameError:
                    pass
                logger.warning("[FOCUS] Margin cap: qty %.4f → %.4f (margin $%.0f > avail $%.0f × 95%%)",
                               old_qty, order_qty, margin_needed, _avail)
                if order_qty <= 0 or (order_qty * price) < 5:
                    logger.warning("[FOCUS] Margin insufficient: avail=$%.2f, need=$%.2f — skip %s",
                                   _avail, margin_needed, market)
                    return {"state": "HUNT", "error": f"margin_insufficient(avail=${_avail:.0f})"}

        # -- 🪙 ★ orderbook-depth size adaptation (2026-06-09 owner "an exchange with no change") --
        # A large order the thin book can't absorb = an unfilled bomb. Clamp to capacity / skip if too thin.
        if getattr(self.config, "orderbook_depth_sizing_enabled", False):
            try:
                from app.core.hyper_price_store import orderbook_store
                _ob = orderbook_store.get(market)
                _units = (_ob or {}).get("units") or []
                if _units and price > 0:
                    _ob_slip = float(getattr(self.config, "orderbook_depth_max_slippage_pct", 0.3))
                    _ob_min_ratio = float(getattr(self.config, "orderbook_depth_min_fill_ratio", 0.5))
                    _avail_qty = 0.0
                    if direction == "LONG":
                        _lim = price * (1 + _ob_slip / 100.0)
                        for _u in _units:
                            _ap = float(_u.get("ask_price", 0) or 0); _asz = float(_u.get("ask_size", 0) or 0)
                            if 0 < _ap <= _lim:
                                _avail_qty += _asz
                    else:
                        _lim = price * (1 - _ob_slip / 100.0)
                        for _u in _units:
                            _bp = float(_u.get("bid_price", 0) or 0); _bsz = float(_u.get("bid_size", 0) or 0)
                            if _bp >= _lim and _bp > 0:
                                _avail_qty += _bsz
                    if _avail_qty > 0 and order_qty > _avail_qty:
                        _fill_ratio = _avail_qty / order_qty
                        if _fill_ratio < _ob_min_ratio:
                            logger.warning(
                                "[FOCUS] 🪙 orderbook thin SKIP: %s %s intended=%.4f > capacity=%.4f (%.0f%%<min%.0f%%, slip%.2f%%, %d levels) -- an exchange with no change",
                                direction, market, order_qty, _avail_qty, _fill_ratio * 100, _ob_min_ratio * 100, _ob_slip, len(_units),
                            )
                            return {"state": "HUNT", "error": f"orderbook_too_thin({_fill_ratio*100:.0f}%<{_ob_min_ratio*100:.0f}%)"}
                        _old_q = order_qty
                        order_qty = _avail_qty
                        try:  # re-apply the lot step (if qty_step is in scope)
                            if qty_step and qty_step > 0:
                                order_qty = round(math.floor(order_qty / qty_step) * qty_step, 8)
                        except NameError:
                            pass
                        logger.info(
                            "[FOCUS] 🪙 orderbook size adaptation: %s %s qty %.4f->%.4f (book capacity, slip%.2f%%) -- prevent non-fill",
                            direction, market, _old_q, order_qty, _ob_slip,
                        )
            except Exception as _ob_exc:
                logger.debug("[FOCUS] orderbook depth sizing skip (fail-open): %s", _ob_exc)

        logger.info("[FOCUS] Attempting entry: %s %s qty=%.8f (raw=%.8f) price=%.2f",
                     "Buy" if direction == "LONG" else "Sell", market, order_qty, sizing.leverage_qty, price)

        # Place order
        try:
            side = "Buy" if direction == "LONG" else "Sell"
            order = client.place_order(
                market=market, side=side, ord_type="market",
                volume=order_qty,
            )
            # ★ [2026-06-11] cowork ①② -- extract the actual fill price/qty (best-effort).
            #   The final non-fill judgment is handled by the verify block below (real position query after 0.5s settle).
            #   Raising here risks a delayed-market fill becoming an untracked position -> defer to the authoritative query.
            _fill_price, _filled_qty, _ostate, _is_filled = self._extract_fill(
                order, fallback_price=price, fallback_qty=order_qty)
            _entry_price_actual = _fill_price if _fill_price > 0 else price
            _entry_qty_actual = _filled_qty if _filled_qty > 0 else order_qty
            logger.info("[FOCUS] Entry order placed: %s %s qty=%.8f @ $%.4f (intended $%.4f, state=%s)",
                        side, market, _entry_qty_actual, _entry_price_actual, price, _ostate)
            # ★ [2026-06-11] cowork ③ -- set the server SL/TP immediately after entry (previously a ~2.5s gap after direction-verify+sleep).
            #   First-line protection here. Direction correction (below)·on failure, the lower block resets/retries.
            try:
                client.set_trading_stop(market, take_profit=targets.tp2, stop_loss=targets.sl)
                logger.info("[FOCUS] ⚡ immediate SL/TP set after entry: SL=$%.4f TP=$%.4f", targets.sl, targets.tp2)
            except Exception as _esl:
                logger.warning("[FOCUS] immediate post-entry SL set failed (will retry below): %s", _esl)
            # ★ [2026-06-11] the journal record (record_entry) moved to after the verify (non-fill judgment) below --
            #   so a ghost journal entry isn't left on a non-fill abort.
        except Exception as exc:
            err_msg = str(exc)
            # ★ insufficient margin OR qty over OR other Bybit rejection -> retry is pointless
            is_fatal = (
                "ab not enough" in err_msg or "110007" in err_msg
                or "exceeds maximum" in err_msg or "10001" in err_msg
                or "max_qty" in err_msg
                or "110125" in err_msg or "Trading Terms" in err_msg
            )
            if is_fatal:
                logger.warning("[FOCUS] ORDER REJECTED for %s: %s — blacklisting coin, re-selecting", market, err_msg[:120])
                # ★ Bybit terms not agreed (110125) etc. -> auto-add to the permanent blacklist
                if ("110125" in err_msg or "Trading Terms" in err_msg) and market not in self.config.scanner_blacklist:
                    self.config.scanner_blacklist.append(market)
                    logger.warning("[FOCUS] %s → PERMANENT scanner blacklist (Bybit terms required)", market)
                # ★ temp-blacklist this coin (prevent repeated entry into the same coin)
                bl = getattr(self, '_temp_blacklist', {})
                bl[market] = time.time() + 600  # skip this coin for 10 min
                self._temp_blacklist = bl
                self._entry_fail_count = 0
                self.selected_market = ""
                self.state = FocusState.DORMANT
                self.last_scan_ts = time.time() + 60  # re-scan to another coin after 1 min
                self._save_config()
                return {"state": "DORMANT", "reason": f"order_rejected_reselect: {err_msg[:80]}"}

            logger.error("[FOCUS] Entry order FAILED: %s", exc, exc_info=True)
            fail_count = getattr(self, '_entry_fail_count', 0) + 1
            self._entry_fail_count = fail_count
            if fail_count >= 3:
                logger.warning("[FOCUS] 3 entry failures on %s — re-selecting coin", market)
                self._entry_fail_count = 0
                self.selected_market = ""
                self.state = FocusState.DORMANT
                self._save_config()
                return {"state": "DORMANT", "reason": f"entry_failed_3x_reselect: {exc}"}
            return {"state": "HUNT", "error": f"order_failed({fail_count}/3): {exc}"}

        # ★ verify the actual Bybit position direction right after entry -- detect direction mismatch immediately
        # ★ [2026-05-25 owner] paper/dry mode: skip the live-exchange query -- a virtual entry isn't on the real Bybit,
        #   so prevent the error where the paper direction gets pulled to a same-coin position incidentally left on the real account.
        _actual_leverage = None  # ★ [2026-06-11] cowork ④ -- the exchange's actual leverage
        _verified_size = None     # ★ [2026-06-11] cowork ② -- the exchange's actual filled size
        _position_found = False   # ★ [2026-06-11] cowork ② -- confirm an actual position exists after entry (non-fill judgment)
        _verify_ok = False        # whether the query itself succeeded (don't assume non-fill on failure)
        try:
            if self._live_active():  # ★ [2026-06-23 audit] skip exchange verify if paper (avoid discarding the virtual position·DORMANT)
                import time as _vt; _vt.sleep(0.5)  # wait for the fill to reflect
                pos_list = client.list_open_positions(symbol=market)
                _verify_ok = True
                for bp in pos_list:
                    if float(bp.get("size", 0)) > 0:
                        _position_found = True
                        _verified_size = float(bp.get("size", 0))
                        bybit_side = bp.get("side", "")
                        bybit_dir = "LONG" if bybit_side == "Buy" else "SHORT"
                        # ★ [2026-06-11] cowork ④ -- verify the actual leverage. Alert on mismatch with intent (exposure/liq-price off).
                        try:
                            _actual_leverage = float(bp.get("leverage", 0) or 0)
                            if _actual_leverage > 0 and abs(_actual_leverage - _dyn_lev) >= 0.5:
                                logger.error("[FOCUS] ⚠ LEVERAGE MISMATCH %s: intended %dx != exchange %.0fx "
                                             "-- suspect set_leverage failure, exposure/liq-price off",
                                             market, _dyn_lev, _actual_leverage)
                        except (TypeError, ValueError):
                            _actual_leverage = None
                        # ★ [2026-06-11] cowork ⑤ -- absorb a direction mismatch as Bybit truth but alert on the cause (prior leftover/double fill).
                        if bybit_dir != direction:
                            logger.error("[FOCUS] ⚠ DIRECTION MISMATCH after entry! Intended=%s but Bybit=%s(%s) size=%.8f "
                                         "-- suspect prior-position leftover/double fill. Correcting to the Bybit direction",
                                         direction, bybit_dir, bybit_side, _verified_size)
                            direction = bybit_dir  # Bybit is the final truth
                        # ★ [2026-06-11] cowork ② -- size check: alert on a 5%+ difference from the intended qty (partial/double fill).
                        if order_qty > 0 and abs(_verified_size - order_qty) / order_qty > 0.05:
                            logger.warning("[FOCUS] ⚠ SIZE MISMATCH %s: intended qty=%.8f != exchange size=%.8f (suspect partial/double fill)",
                                           market, order_qty, _verified_size)
                        break
        except Exception as vexc:
            logger.debug("[FOCUS] Post-entry position verify failed (non-critical): %s", vexc)
        # ★ [2026-06-11] cowork ② -- if the query succeeded but there's no position, non-fill is confirmed -> don't create the position (ghost prevention).
        #   (On query failure _verify_ok=False, don't assume -- proceed as before, the next tick's SYNC cleans up.)
        if self._live_active() and _verify_ok and not _position_found:
            logger.error("[FOCUS] ⚠ no position on the exchange after entry %s -- non-fill confirmed, not creating the position (ghost prevention)", market)
            fail_count = getattr(self, '_entry_fail_count', 0) + 1
            self._entry_fail_count = fail_count
            if fail_count >= 3:
                self._entry_fail_count = 0
                self.selected_market = ""
                self.state = FocusState.DORMANT
                self._save_config()
                return {"state": "DORMANT", "reason": "entry_unconfirmed_3x_reselect"}
            return {"state": "HUNT", "error": f"entry_unconfirmed_no_position({fail_count}/3)"}
        # ★ [2026-06-11] correct the position record with the exchange-verified values (in live, size/leverage are the truth)
        if _verified_size and _verified_size > 0:
            _entry_qty_actual = _verified_size
        _pos_leverage = int(round(_actual_leverage)) if (_actual_leverage and _actual_leverage > 0) else _dyn_lev

        # ★ recompute TP/SL after direction correction (the Bybit actual direction may differ from the targets direction)
        if direction != entry.get("direction", direction):
            # direction changed during Bybit verification -> targets must be recomputed
            from app.strategy.greenpen.cycle_tp import compute_cycle_targets
            _min_tp_pct_2 = float(getattr(self.config, "min_tp_distance_pct", 0.30)) \
                if getattr(self.config, "min_tp_distance_enabled", False) else 0.0
            targets = compute_cycle_targets(
                price, direction, atr,
                tp1_mult=self.config.cycle_tp1_mult,
                tp2_mult=self.config.cycle_tp2_mult,
                sl_mult=self.config.cycle_sl_mult,
                min_tp_distance_pct=_min_tp_pct_2,
            )
            # ★ invalidate Entry Expectation -- _exp_* is based on the old direction and untrustworthy.
            #   Clearing to 0 auto-disables progress-based exit -> the old LHT is the fallback.
            _exp_reward_target = 0.0
            _exp_risk_invalidation = 0.0
            _exp_rr_ratio = 0.0
            _exp_source = ""
            logger.warning("[FOCUS] TP/SL recalculated for corrected direction %s: TP1=$%.2f TP2=$%.2f SL=$%.2f (Entry Expectation invalidated)",
                           direction, targets.tp1, targets.tp2, targets.sl)

        # ★ [2026-05-26 owner] TF-round anchor TP/SL override (textbook-faithful, default OFF)
        #   When ON: discard the cycle_tp/EE/regime result and replace with the trade-TF round (ATR×mult) + anchor (the prior H4 high).
        #   ★ [2026-05-27 owner] split TF by entry["_pa_via"] (H4 PA->H4 anchor / H1 PA->H1 anchor).
        if self._tf_round_active():
            try:
                _pa_via = entry.get("_pa_via", "")
                _tf_override = "60" if _pa_via == "h1" else "240"  # h4 or default = 240
                _rnd = self._compute_tf_round_targets(market, direction, tf_override=_tf_override)
                if _rnd:
                    _tn_tp1, _tn_tp2, _tn_sl, _rnd_atr = _rnd
                    # ★ [2026-05-28 owner] SL safety net -- anchor on the wrong side of entry OR SL distance too short -> fallback
                    #   Owner's spirit (internal memo/GreenPen): TP1 ATR×1, TP2 ATR×2, SL=TP1×⅓ (RR 1:3) -- H1 uses the same ratio.
                    #   When the forming candle is short, the anchor low/high is near entry, risking instant SL hit -> guarantee a minimum distance.
                    _min_sl_chk = float(getattr(self.config, "min_sl_pct", 0.005)) or 0.005
                    _sl_wrong = False
                    _wrong_reason = ""
                    # condition 1: SL on the wrong side (LONG SL >= price or SHORT SL <= price)
                    if direction == "LONG" and _tn_sl >= price * (1 - _min_sl_chk):
                        _sl_wrong = True; _wrong_reason = "SL≥entry(LONG)"
                    elif direction == "SHORT" and _tn_sl <= price * (1 + _min_sl_chk):
                        _sl_wrong = True; _wrong_reason = "SL≤entry(SHORT)"
                    # condition 2: SL distance too short (below min_sl_pct)
                    _sl_dist_pct = abs(_tn_sl - price) / price if price > 0 else 0
                    if not _sl_wrong and _sl_dist_pct < _min_sl_chk:
                        _sl_wrong = True; _wrong_reason = f"SL_dist<{_min_sl_chk*100:.2f}%"
                    # ★ [2026-05-28 owner] condition 3: TP on the wrong side -- XLM case (entry 0.178 / TP2 0.151)
                    #   LONG TP <= entry or SHORT TP >= entry -> the anchor is at an old price level, so TP is on the wrong side of entry.
                    #   Instant TP hit on entry = a meaningless exit. anchor=price recompute is required.
                    if not _sl_wrong:
                        if direction == "LONG" and (_tn_tp1 <= price or _tn_tp2 <= price):
                            _sl_wrong = True
                            _wrong_reason = "TP<=entry(LONG, anchor old price)"
                        elif direction == "SHORT" and (_tn_tp1 >= price or _tn_tp2 >= price):
                            _sl_wrong = True
                            _wrong_reason = "TP>=entry(SHORT, anchor old price)"
                    if _sl_wrong and _rnd_atr and _rnd_atr > 0:
                        # force anchor=price + keep the ATR ratio + guarantee SL distance >= min_sl_pct
                        _tp_mult_f = float(getattr(self.config, "tf_round_tp_atr_mult", 1.0))
                        _tp2_mult_f = float(getattr(self.config, "tf_round_tp2_atr_mult", 2.0))
                        _sl_ratio_f = float(getattr(self.config, "tf_round_sl_ratio", 0.333)) or 0.333
                        _round1_f = _rnd_atr * _tp_mult_f
                        _round2_f = _rnd_atr * _tp2_mult_f
                        _sl_dist_atr = _round1_f * _sl_ratio_f
                        # SL distance = max(ATR×⅓, price×min_sl_pct) -- 0.5% minimum (absorbs normal market moves)
                        _sl_dist_min = price * _min_sl_chk
                        _sl_dist_f = max(_sl_dist_atr, _sl_dist_min)
                        if direction == "LONG":
                            _new_tp1 = price + _round1_f
                            _new_tp2 = price + _round2_f
                            _new_sl  = price - _sl_dist_f
                        else:
                            _new_tp1 = price - _round1_f
                            _new_tp2 = price - _round2_f
                            _new_sl  = price + _sl_dist_f
                        logger.warning("[FOCUS] ⛔ TF-round anchor unfit [%s] (%s entry=$%.4f orig: TP1=$%.4f TP2=$%.4f SL=$%.4f dist=%.3f%%) -> anchor=price recompute (ATR=%.4f, SL_dist=$%.4f=max(ATR×⅓,price×%.3f%%)) -> TP1=$%.4f TP2=$%.4f SL=$%.4f",
                                       _wrong_reason, direction, price, _tn_tp1, _tn_tp2, _tn_sl, _sl_dist_pct * 100, _rnd_atr, _sl_dist_f, _min_sl_chk * 100, _new_tp1, _new_tp2, _new_sl)
                        _tn_tp1, _tn_tp2, _tn_sl = _new_tp1, _new_tp2, _new_sl
                    targets.tp1, targets.tp2, targets.sl = _tn_tp1, _tn_tp2, _tn_sl
                    atr = _rnd_atr  # match the atr_used record
                    logger.warning("[FOCUS] ★ TF-round TP/SL applied %s %s: TP1=$%.4f TP2=$%.4f SL=$%.4f",
                                   market, direction, targets.tp1, targets.tp2, targets.sl)
                else:
                    logger.warning("[FOCUS] TF-round TP/SL computation failed -> cycle_tp fallback (%s)", market)
            except Exception as _rexc:
                logger.warning("[FOCUS] TF-round TP/SL error → cycle_tp fallback: %s", _rexc)

        # ★★★ [2026-06-13 owner "fix it now"] re-apply the PARENT ROE GUARD final floor (right before sending to the exchange) ★★★
        #   Bug: the TF-round recompute (SL=0.5% min on anchor-unfit, L17088) *overwrote* the SL widened by parent_roe_guard above (L16582)
        #   -> INJ home 31-sec churn (server-a's anchor was fine so it didn't fire = same bug, different manifestation).
        #   Guarantee the "never liquidate down to -31% no matter what" absolute order *at the end*. Widen only when too narrow (preserve a wide SL).
        #   Override slots intend tightness -> limit within max_sl_cap to prevent regression.
        if getattr(self.config, "parent_roe_guard_enabled", True) and price > 0:
            try:
                _prf_cap = float(getattr(self.config, "parent_max_roe_loss_pct", 31.0))
                _prf_lev = max(1, int(getattr(self.config, "leverage", 5)))
                _prf_min_dist = price * (_prf_cap / _prf_lev / 100.0)
                _prf_max_pct = (float(getattr(self.config, "override_max_sl_distance_pct", 5.0))
                                if entry.get("_is_override", False)
                                else float(getattr(self.config, "max_sl_distance_pct", 99.0)))
                _prf_min_dist = min(_prf_min_dist, price * (_prf_max_pct / 100.0))   # don't exceed the cap
                _prf_cur = abs(price - targets.sl)
                if _prf_cur < _prf_min_dist - 1e-9:   # widen to the floor only when too narrow
                    _prf_old = targets.sl
                    targets.sl = (price - _prf_min_dist) if direction == "LONG" else (price + _prf_min_dist)
                    logger.warning("[FOCUS] ★★ PARENT ROE GUARD final floor re-applied (prevent TF-round overwrite): %s %s SL $%.4f->$%.4f (%.2f%%->%.2f%%)",
                                   market, direction, _prf_old, targets.sl, _prf_cur / price * 100, _prf_min_dist / price * 100)
            except Exception as _prfexc:
                logger.debug("[FOCUS] parent_roe final floor error: %s", _prfexc)

        # Set server-side TP/SL safety net (3 attempts; keep the position even on failure -> retry on tick)
        _tp_sl_set = False
        for _tp_attempt in range(3):
            try:
                client.set_trading_stop(market, take_profit=targets.tp2, stop_loss=targets.sl)
                logger.info("[FOCUS] TP/SL set on Bybit: TP=$%.2f SL=$%.2f (dir=%s)", targets.tp2, targets.sl, direction)
                _tp_sl_set = True
                break
            except Exception as exc:
                logger.warning("[FOCUS] set_trading_stop attempt %d/3 failed: %s", _tp_attempt + 1, exc)
                if _tp_attempt < 2:
                    import time as _sl_t; _sl_t.sleep(1)
        if not _tp_sl_set:
            # ★ keep the position even if TP/SL fails -- FOCUS's own SL watch is the first safety net
            # the next tick's _manage_all_positions checks SL + _update_bybit_sl retries
            logger.warning("[FOCUS] TP/SL FAILED 3x for %s — position KEPT, will retry on next tick", market)
            self._notify(f"⚠️ {market} TP/SL set failed -- protected by the FOCUS SL watch, retrying next tick")

        # -- journal record (★ [2026-06-11] moved to after fill confirmation -- reflects the actual fill price/qty/direction/leverage) --
        try:
            from app.manager.trade_journal import journal
            _modifiers = entry.get("_conviction_modifiers", "")
            _phase = f"conviction={conviction_score}"
            if _modifiers:
                _phase += f",{_modifiers}"
            if entry.get("preclose"):  # ★ [patch v2-A] lifeline of separate performance measurement -- don't drop the tag
                _phase += ",preclose=1"
            # ★ Phase K (2026-04-21): regime_transition tag -- for win-rate analysis at EXIT
            if entry.get("_phase_k"):
                _phase += f",phase_k={entry.get('_phase_k_reason','')}"
            # ★ [2026-05-27 owner] which pulse (H4 / H1) it passed via -- to verify the frequency-up effect
            _pulse_via = entry.get("_pulse_via", "")
            if _pulse_via:
                _phase += f",pulse={_pulse_via}"
            # ★ [2026-05-27 owner] PA Completion: which TF's (H4 OR H1) Pat 1/2/3 it passed via
            _pa_via = entry.get("_pa_via", "")
            if _pa_via:
                _phase += f",pa={_pa_via}"
            # ★ [2026-05-27 owner] Phase 6 score integration -- whether it entered via guard_score + the score
            if entry.get("_guard_score_pass"):
                _gs = entry.get("_guard_score", 0)
                _phase += f",guard_score={_gs:.0f}"
            # ★ also mark Anchor Fast-Track (identify microtiming-bypass entries)
            if entry.get("_anchor_fasttrack"):
                _phase += ",fasttrack=1"
            self._journal.record_entry(
                strategy="FOCUS", market=market, direction=direction,
                price=_entry_price_actual, qty=_entry_qty_actual,  # ★ actual fill price/qty (replaces the pre-order estimate price/order_qty)
                leverage=_pos_leverage,   # ★ [2026-06-11] the exchange's actual leverage
                phase=_phase,
            )
        except Exception as exc:
            logger.debug("[FOCUS] self._journal.record_entry failed: %s", exc)

        # ★ [solution B] GateLedger -- entry succeeded = ENTRY pass (observe only, doesn't affect entry) -- UI toggle
        if getattr(self, "_gate_ledger", None) is not None and self.config.gate_ledger_enabled:
            try:
                self._gate_ledger.record(market, "ENTRY", passed=True, direction=direction)
            except Exception:  # noqa: BLE001
                pass

        # Record position → multi-position list
        new_pos = FocusPosition(
            market=market,
            direction=direction,
            entry_price=_entry_price_actual,  # ★ [2026-06-11] actual fill price (reflects slippage -> accurate PnL/BE/SL)
            qty=_entry_qty_actual,            # ★ [2026-06-11] actual filled qty (exchange-verified size)
            leverage=_pos_leverage,           # ★ [2026-06-11] the exchange's actual leverage (corrected on mismatch)
            tp1=targets.tp1,
            tp2=targets.tp2,
            sl=targets.sl,
            atr_used=atr,
            entry_ts=time.time(),
            conviction_score=conviction_score,
        )
        new_pos.entry_source = "scanner" if entry.get("_scanner_entry", False) else "primary"
        new_pos.original_sl = targets.sl      # Decay baseline (fixed at entry)
        new_pos.original_tp1 = targets.tp1    # Decay baseline (fixed at entry)
        # ★ store the Entry Expectation result (basis for progress-based exit -- 0 = not computed/disabled)
        # [2026-05-16 owner BTC-incident root fix] if EE grabs a narrow H1 zone, _exp_reward_target is narrow
        # -> progress is overstated (BTC -113% case). After blending, store the final targets.tp2 (the value where
        # the larger cycle_tp was adopted) as reward_target = progress is computed against the real target.
        # If EE wasn't computed (_exp_reward_target=0), store cycle_tp targets.tp2 as-is.
        new_pos.reward_target = targets.tp2 if targets.tp2 > 0 else _exp_reward_target
        new_pos.risk_invalidation = _exp_risk_invalidation
        new_pos.rr_ratio = _exp_rr_ratio
        new_pos.expectation_source = _exp_source
        # ★ Override Slot marker (2026-05-10): fires the Hard ROE -10% cut / applies separate rules
        new_pos.is_override = bool(entry.get("_is_override", False))
        # [2026-05-29 owner] propagate the Slot Auto Expand marker (mark temp-slot occupancy until exit)
        new_pos.is_slot_expand = bool(entry.get("_slot_expand", False))
        # ★ [patch v2-A2] mark Pre-Close pending top-up on close confirmation (half entry -> the other half once confirmed after H4 close)
        new_pos.preclose_pending_topup = False
        new_pos.preclose_topup_qty = 0.0
        new_pos.preclose_entry_ts = 0.0
        if entry.get("preclose") and getattr(self.config, "preclose_topup_enabled", False):
            try:
                _pcr = float(entry.get("_preclose_ratio", 0.5) or 0.5)
                if 0.0 < _pcr < 1.0:
                    import time as _t_pc
                    new_pos.preclose_topup_qty = float(new_pos.qty) * (1.0 / _pcr - 1.0)
                    new_pos.preclose_entry_ts = _t_pc.time()
                    new_pos.preclose_pending_topup = new_pos.preclose_topup_qty > 0
                    logger.info("[FOCUS] ⏩ Pre-Close top-up pending registered: %s %s -- on close confirmation +qty=%.4f",
                                market, direction, new_pos.preclose_topup_qty)
            except Exception as _pcexc:
                logger.debug("[FOCUS] preclose topup registration error: %s", _pcexc)
        # ★ [2026-05-28 owner] entry via the guard_score 100-pt system OR manual entry = bypass the old EXITs
        # Manual-entry miss incident (5-28 DOGE 297s pre_be_stall):
        #   a manual entry doesn't set entry["_guard_score_pass"] -> the old EXIT ran -> cut in 4 min.
        #   The owner's manual entry = the owner's gut/judgment = the old time-based guards must not interfere.
        _entry_is_manual = bool(entry.get("_manual"))
        new_pos.guard_score_entry = (
            bool(entry.get("_guard_score_pass", False)) or _entry_is_manual
        )
        if new_pos.guard_score_entry:
            _reason = "MANUAL" if _entry_is_manual else "GUARD_SCORE"
            logger.info(
                "[FOCUS] ★ %s ENTRY: %s %s -- bypassing all old EXIT guards (fast_reject/reverse_drift/"
                "pre_be_stall/long_hold/trend_reversal/quick_tp/bb_macd_sw/thesis_invalidation)",
                _reason, market, direction,
            )
        if new_pos.is_override:
            logger.warning(
                "[FOCUS] ★ OVERRIDE SLOT entered: %s %s conviction=%d adx=%.1f size=$%.2f sl=$%.4f",
                market, direction, conviction_score, float(entry.get("adx", 0) or 0),
                effective_budget, targets.sl,
            )
        # -- ★ [2026-05-21 Phase 6 Stage 8 re-redesign] store the baseline at entry --
        # The owner's real rule: "profit + signs of score recovery -> small exit". Existing guards unchanged.
        try:
            new_pos.entry_baseline_conv = float(self._last_scan_conviction.get(market, 0.0) or 0.0)
            _hist_b = self._confidence_history.get(market)
            if _hist_b and len(_hist_b) > 0:
                new_pos.entry_baseline_trend = str(_hist_b[-1][1])
            logger.info("[FOCUS] Stage 8 baseline %s %s: conv=%.1f trend=%s (score-recovery exit basis)",
                        market, direction, new_pos.entry_baseline_conv, new_pos.entry_baseline_trend or "(unknown)")
        except Exception as exc:
            logger.debug("[FOCUS] Stage 8 baseline save error %s: %s", market, exc)

        self.positions.append(new_pos)
        self.position = new_pos  # legacy compatibility
        self.daily_plans_used += 1
        if entry.get("preclose"):  # ★ [patch v2-A] lead-entry daily counter (increments on fill)
            self.preclose_used_today = getattr(self, "preclose_used_today", 0) + 1
        self._entry_fail_count = 0
        self.state = FocusState.POSITIONED
        self._save_config()

        # Phase C-2 (2026-04-20): WebSocket push -- live UI update. fire-and-forget, no trade-path effect.
        try:
            from app.api.websocket_router import state_broadcast_safe
            state_broadcast_safe("POSITION_OPEN", {
                "market": market, "direction": direction,
                "entry_price": price, "qty": order_qty,
                "conviction": conviction_score,
            })
        except Exception:
            pass

        logger.info("[FOCUS] POSITIONED %s %s @ %.2f | TP1=%.2f TP2=%.2f SL=%.2f [%d/%d slots]",
                     direction, market, price, targets.tp1, targets.tp2, targets.sl,
                     len(self.positions), self.config.max_positions)
        try:
            self.system.ledger.append(
                "FOCUS_ENTRY", market=market,
                direction=direction, qty=order_qty, entry_price=price,
                tp1=targets.tp1, tp2=targets.tp2, sl=targets.sl,
                leverage=_dyn_lev, conviction=conviction_score,   # ★ [2026-04-25] dynamic lev
                budget_usdt=effective_budget,
            )
        except Exception as exc:
            logger.debug("[FOCUS] self.system.ledger.append failed: %s", exc)
        self._notify(f"🟢 ENTRY {direction} {market}\n@ ${price:.2f} qty={order_qty}\nTP1=${targets.tp1:.2f} SL=${targets.sl:.2f}\nConviction: {conviction_score:.1f}/100 Budget: ${effective_budget:.0f}")
        return {"state": "POSITIONED", "market": market, "direction": direction, "entry": price,
                "positions": len(self.positions)}

    def _execute_partial(self, partial, price: float) -> Dict:
        """Execute TP1 partial exit."""
        pos = self.position
        close_qty = pos.qty * (partial.exit_pct / 100.0)

        client = self._get_client()
        try:
            side = "Sell" if pos.direction == "LONG" else "Buy"
            client.place_order(market=pos.market, side=side, ord_type="market", volume=close_qty)
            logger.info("[FOCUS] Partial exit %.0f%% @ %.2f", partial.exit_pct, price)
            try:
                self.system.ledger.append(
                    "FOCUS_PARTIAL", market=pos.market,
                    direction=pos.direction, qty=close_qty,
                    exit_pct=partial.exit_pct, price=price,
                    entry_price=pos.entry_price,
                    conviction=pos.conviction_score,
                )
            except Exception as exc:
                logger.debug("[FOCUS] self.system.ledger.append failed: %s", exc)
        except Exception as exc:
            logger.error("[FOCUS] Partial exit FAILED: %s", exc, exc_info=True)
            return {"state": "POSITIONED", "error": f"partial_failed: {exc}"}

        # Update position
        pos.partial_done = True
        pos.qty -= close_qty
        pos.sl = partial.new_sl  # Move SL to breakeven
        if pos.direction == "LONG":
            pos.trailing_high = price
        else:
            pos.trailing_low = price

        # Update server TP/SL
        try:
            client.set_trading_stop(pos.market, take_profit=pos.tp2, stop_loss=pos.sl)
        except Exception as exc:
            logger.warning("[FOCUS] update trading_stop after partial: %s", exc)

        # v2: removed the TRAILING state -- POSITIONED handles DT
        self._save_config()
        logger.info("[FOCUS] TP1 partial done — DT handles trailing (SL breakeven %.2f)", pos.sl)
        return {"state": "POSITIONED", "partial_pct": partial.exit_pct}

    def _execute_exit(self, reason: str, is_sl: bool = False) -> Dict:
        """Close remaining position(s) fully.
        ★ H8 FIX: multi-position support -- iterate and close all open positions."""
        # multi-position: collect all positions
        targets = list(self.positions) if self.positions else []
        if not targets and self.position:
            targets = [self.position]
        if not targets:
            self.state = FocusState.COOLDOWN
            self.cooldown_start_ts = time.time()
            self._save_config()
            return {"state": "COOLDOWN", "reason": reason}

        client = self._get_client()
        _failed = []  # ★ [2026-06-11] cowork ② -- preserve positions that failed to close (retry next tick, ghost prevention)
        for pos in targets:
            try:
                side = "Sell" if pos.direction == "LONG" else "Buy"
                # ★ [2026-06-11] reduce_only=True -- prevent the close intent from becoming an opposite new entry (consistent with _close_position)
                order = client.place_order(market=pos.market, side=side, ord_type="market",
                                           volume=pos.qty, reduce_only=True)
                # ★ [2026-06-11] cowork ① -- confirm the actual fill. Don't treat a non-fill as success.
                _fp, _fq, _ost, _isf = self._extract_fill(order, fallback_price=pos.entry_price, fallback_qty=pos.qty)
                if self._is_live_mode() and not _isf:
                    logger.error("[FOCUS] Full exit non-fill %s (state=%s qty=%s) -- preserving position", pos.market, _ost, _fq)
                    _failed.append(pos)
                    continue
                logger.info("[FOCUS] Full exit %s %s %.6f: %s (state=%s)", pos.direction, pos.market, pos.qty, reason, _ost)
                try:
                    self.system.ledger.append(
                        "FOCUS_EXIT", market=pos.market,
                        direction=pos.direction, qty=pos.qty,
                        entry_price=pos.entry_price, reason=reason,
                        is_sl=is_sl, conviction=pos.conviction_score,
                    )
                except Exception as exc:
                    logger.debug("[FOCUS] self.system.ledger.append failed: %s", exc)
            except Exception as exc:
                exc_str = str(exc)
                # ★ 110017 = position is zero -> already closed on the server = success (don't preserve)
                if "110017" in exc_str or "position is zero" in exc_str.lower():
                    logger.info("[FOCUS] Full exit %s: already closed on the server (110017) -- treated as success", pos.market)
                else:
                    logger.error("[FOCUS] Full exit FAILED %s: %s -- preserving position, retry next tick", pos.market, exc, exc_info=True)
                    _failed.append(pos)

        if is_sl:
            self.daily_sl_count += 1
            logger.info("[FOCUS] SL count: %d/%d", self.daily_sl_count, self.config.max_daily_sl)

        # ★ [2026-06-11] cowork ② -- if any close failed, preserve it and don't enter COOLDOWN (prevent ghost desync).
        if _failed:
            self.positions = _failed
            self.position = _failed[0]
            logger.critical("[FOCUS] _execute_exit: %d/%d close failed -- preserved, keeping POSITIONED (retry next tick)",
                            len(_failed), len(targets))
            self._save_config()
            return {"state": "POSITIONED", "reason": reason, "is_sl": is_sl,
                    "closed": len(targets) - len(_failed), "exit_failed": len(_failed)}

        # clear all (all succeeded)
        self.positions.clear()
        self.position = None
        self.selected_market = ""
        self.selected_direction = ""
        self.primary_sig = None
        self.cooldown_start_ts = time.time()
        self.state = FocusState.COOLDOWN
        self._save_config()

        return {"state": "COOLDOWN", "reason": reason, "is_sl": is_sl, "closed": len(targets)}

    # -- Regime Scaling (reuse existing infra) --

    def _apply_regime_scaling(self, market: str, price: float, targets) -> object:
        """Adjust TP/SL by regime multiplier + fee-awareness.

        Uses regime_tp/sl_multiplier from strategy_tp_sl_policy.json.
        Same logic as the existing engine (hyper_nunnaya_engine.py:600-642).
        """
        try:
            import json as _json

            # 1. load the policy file (cached)
            policy = getattr(self, "_tp_sl_policy_cache", None)
            if policy is None:
                with open("runtime/strategy_tp_sl_policy.json", "r", encoding="utf-8") as f:
                    policy = _json.load(f)
                self._tp_sl_policy_cache = policy

            if not policy.get("enabled"):
                return targets

            # 2. detect the regime
            from app.core.market_regime import RegimeDetector
            det = getattr(self, "_regime_detector", None)
            if det is None:
                det = RegimeDetector()
                self._regime_detector = det

            regime_result = det.detect("BTCUSDT")
            regime = str(getattr(regime_result, "regime", "SIDEWAYS")).upper()
            # extract the value from the enum
            if "." in regime:
                regime = regime.split(".")[-1]

            # 3. apply the regime multiplier
            tp_mults = policy.get("regime_tp_multiplier", {})
            sl_mults = policy.get("regime_sl_multiplier", {})
            tp_mult = float(tp_mults.get(regime, 1.0))
            sl_mult = float(sl_mults.get(regime, 1.0))

            direction = targets.direction
            old_tp1, old_tp2, old_sl = targets.tp1, targets.tp2, targets.sl

            if direction == "LONG":
                tp1_dist = (targets.tp1 - price) * tp_mult
                tp2_dist = (targets.tp2 - price) * tp_mult
                sl_dist = (price - targets.sl) * sl_mult
                targets.tp1 = round(price + tp1_dist, 8)
                targets.tp2 = round(price + tp2_dist, 8)
                targets.sl = round(price - sl_dist, 8)
            else:  # SHORT
                tp1_dist = (price - targets.tp1) * tp_mult
                tp2_dist = (price - targets.tp2) * tp_mult
                sl_dist = (targets.sl - price) * sl_mult
                targets.tp1 = round(price - tp1_dist, 8)
                targets.tp2 = round(price - tp2_dist, 8)
                targets.sl = round(price + sl_dist, 8)

            # 4. fee-awareness: prevent a TP lower than the round-trip fee
            if policy.get("fee_aware_tp"):
                fee_rate = float(policy.get("fee_rate", 0.00055))
                spread_bps = 0.0
                try:
                    from app.core.hyper_price_store import orderbook_store
                    ob = orderbook_store.get(market)
                    if ob:
                        bid = float(ob.get("best_bid", 0) or 0)
                        ask = float(ob.get("best_ask", 0) or 0)
                        if bid > 0 and ask > 0:
                            spread_bps = (ask - bid) / bid * 10000
                except Exception as exc:
                    logger.debug("[FOCUS] import orderbook_store failed: %s", exc)
                fee_cost_pct = (fee_rate * 2 + spread_bps / 10000) * 100
                min_tp_dist = price * fee_cost_pct * 1.2 / 100
                if direction == "LONG" and (targets.tp1 - price) < min_tp_dist:
                    targets.tp1 = round(price + min_tp_dist, 8)
                elif direction == "SHORT" and (price - targets.tp1) < min_tp_dist:
                    targets.tp1 = round(price - min_tp_dist, 8)

            if tp_mult != 1.0 or sl_mult != 1.0:
                logger.info("[FOCUS] Regime %s: TP×%.1f SL×%.1f | TP1: %.4f→%.4f TP2: %.4f→%.4f SL: %.4f→%.4f",
                            regime, tp_mult, sl_mult,
                            old_tp1, targets.tp1, old_tp2, targets.tp2, old_sl, targets.sl)

        except Exception as exc:
            logger.debug("[FOCUS] regime scaling skipped: %s", exc)

        return targets

